// =============================================================================
// CONSTANTES GLOBALES
// Logo, tipos de pago, comisiones y configuracion base del sistema.
// =============================================================================

const LOGO_INH = `${import.meta.env.BASE_URL}logo-inh.png`
const obtenerUrlAbsolutaLogoInh = () =>
  new URL(LOGO_INH, window.location.origin).href

const PORCENTAJE_GASTOS_COBRANZA_DEFECTO = 10
const TIPOS_COMISION_DEPOSITO = ['Administración', 'Solo arrendar']
const TIPOS_PAGO_LIQUIDACION_DEPOSITO = [
  'Proporcional a propietarios',
  'Solo al depositario',
]
const CRITERIO_LIQUIDACION_CANON_PAGO_FIJO = 'Pago fijo'
const CRITERIO_LIQUIDACION_CANON_PAGOS_PARCIALES = 'Pagos parciales'
const CRITERIOS_LIQUIDACION_CANON_DEPOSITO = [
  CRITERIO_LIQUIDACION_CANON_PAGO_FIJO,
  CRITERIO_LIQUIDACION_CANON_PAGOS_PARCIALES,
]
const MEDIOS_PAGO_INH = ['Transferencia o consignación', 'Cheque o efectivo']
const MEDIOS_PAGO_DEPOSITANTE = ['Consignación', 'Transferencia', 'Cheque', 'Efectivo']
const TIPOS_CUENTA_BANCARIA_INH = ['Ahorros', 'Corriente']
const PAGO_SOLO_DEPOSITARIO_LEGACY = 'Solo al contratante'

const pagoEsSoloAlDepositario = (tipo) =>
  tipo === 'Solo al depositario' || tipo === PAGO_SOLO_DEPOSITARIO_LEGACY

const normalizarMedioPagoInh = (medio = '') => {
  if (medio === 'Cheque' || medio === 'Efectivo') return 'Cheque o efectivo'
  return medio || ''
}

const requiereCuentaBancariaPagoInh = (medioPago) =>
  normalizarMedioPagoInh(medioPago) === 'Transferencia o consignación'

const normalizarCuentaPagoInh = (cuenta = {}) => ({
  numeroCuenta: String(cuenta?.numeroCuenta || '').trim(),
  tipoCuenta: cuenta?.tipoCuenta || '',
  banco: String(cuenta?.banco || '').trim(),
  nombreCuenta: String(cuenta?.nombreCuenta || '').trim().toUpperCase(),
})

const normalizarCondicionesPagoInh = (condiciones = {}) => {
  const medioPago = normalizarMedioPagoInh(condiciones?.medioPago)
  const cuentasPropietarios = Array.isArray(condiciones?.cuentasPropietarios)
    ? condiciones.cuentasPropietarios.map((item) => ({
        clave: item?.clave || item?.idPropietario || item?.numeroDocumento || '',
        idPropietario: item?.idPropietario || '',
        nombrePropietario: item?.nombrePropietario || item?.nombre || '',
        numeroDocumento: item?.numeroDocumento || '',
        porcentaje: Number(item?.porcentaje || 0),
        ...normalizarCuentaPagoInh(item),
      }))
    : []

  const cuentaRaiz = normalizarCuentaPagoInh(condiciones)

  return {
    medioPago,
    ...cuentaRaiz,
    cuentasPropietarios,
  }
}

const construirCondicionesPagoInhDesdeFormulario = ({
  medioPago = '',
  beneficiarios = [],
  cuentasPorBeneficiario = {},
} = {}) => {
  const medio = normalizarMedioPagoInh(medioPago)
  const cuentasPropietarios = beneficiarios.map((beneficiario) => ({
    clave: beneficiario.clave,
    idPropietario: beneficiario.idPropietario || '',
    nombrePropietario: (beneficiario.nombre || '').trim().toUpperCase(),
    numeroDocumento: beneficiario.numeroDocumento || '',
    porcentaje: Number(beneficiario.porcentaje || 0),
    ...normalizarCuentaPagoInh(cuentasPorBeneficiario[beneficiario.clave] || {}),
  }))

  const primera = cuentasPropietarios[0] || normalizarCuentaPagoInh()

  return {
    medioPago: medio,
    numeroCuenta: primera.numeroCuenta,
    tipoCuenta: primera.tipoCuenta,
    banco: primera.banco,
    nombreCuenta: primera.nombreCuenta,
    cuentasPropietarios,
  }
}

const obtenerCuentaPagoBeneficiario = (
  condiciones,
  { idPropietario, numeroDocumento, clave } = {}
) => {
  const datos = normalizarCondicionesPagoInh(condiciones)
  if (!requiereCuentaBancariaPagoInh(datos.medioPago)) return null

  const encontrada = datos.cuentasPropietarios.find(
    (item) =>
      (idPropietario && item.idPropietario === idPropietario) ||
      (clave && item.clave === clave) ||
      (numeroDocumento && item.numeroDocumento === numeroDocumento)
  )

  if (encontrada) return encontrada
  if (datos.numeroCuenta || datos.banco || datos.nombreCuenta) return { ...datos }
  return null
}

const obtenerEtiquetaPagoInhContrato = (tipoPagoLiquidacion) =>
  pagoEsSoloAlDepositario(tipoPagoLiquidacion)
    ? 'Pago de INH al depositario'
    : 'Pago de INH a los propietarios'

const validarCondicionesPagoInh = (condiciones = {}, { tipoPagoLiquidacion } = {}) => {
  const datos = normalizarCondicionesPagoInh(condiciones)
  if (!datos.medioPago) {
    return 'Seleccione cómo realizará INH el pago mensual.'
  }
  if (!requiereCuentaBancariaPagoInh(datos.medioPago)) return ''

  const cuentas = datos.cuentasPropietarios.length ? datos.cuentasPropietarios : [datos]

  if (!cuentas.length) {
    return 'Indique los datos de cuenta para el pago.'
  }

  for (const cuenta of cuentas) {
    const etiqueta = cuenta.nombrePropietario
      ? `${cuenta.nombrePropietario} (${cuenta.porcentaje || 0}%)`
      : pagoEsSoloAlDepositario(tipoPagoLiquidacion)
      ? 'el depositario'
      : 'cada propietario'

    if (!cuenta.numeroCuenta) return `Indique el número de cuenta para ${etiqueta}.`
    if (!cuenta.tipoCuenta) return `Seleccione el tipo de cuenta para ${etiqueta}.`
    if (!cuenta.banco) return `Indique el banco de la cuenta para ${etiqueta}.`
    if (!cuenta.nombreCuenta) return `Indique el nombre de la cuenta para ${etiqueta}.`
  }

  return ''
}

// =============================================================================
// LIQUIDACION INH - NORMALIZACION DE PAGOS
// Medios de pago, cuentas bancarias y validaciones INH.
// =============================================================================

const normalizarTipoPagoLiquidacionDeposito = (tipo) => {
  if (tipo === PAGO_SOLO_DEPOSITARIO_LEGACY) return 'Solo al depositario'
  return tipo || 'Proporcional a propietarios'
}

// =============================================================================
// CONTRATOS DEPOSITO - CRITERIO LIQUIDACION CANON
// Pago fijo mensual o liquidacion segun recaudo del arrendatario.
// =============================================================================

const normalizarCriterioLiquidacionCanonDeposito = (criterio) =>
  criterio === CRITERIO_LIQUIDACION_CANON_PAGO_FIJO
    ? CRITERIO_LIQUIDACION_CANON_PAGO_FIJO
    : CRITERIO_LIQUIDACION_CANON_PAGOS_PARCIALES

// =============================================================================
// CONTRATOS DEPOSITO - CRITERIO PAGO FIJO
// Indica si el contrato liquida canon con pago fijo mensual al depositante.
// =============================================================================

const esPagoFijoLiquidacionCanonDeposito = (contrato) =>
  normalizarCriterioLiquidacionCanonDeposito(contrato?.criterioLiquidacionCanon) ===
  CRITERIO_LIQUIDACION_CANON_PAGO_FIJO

// =============================================================================
// CONTRATOS DEPOSITO - CRITERIO PAGOS PARCIALES
// Indica si la liquidacion al depositante depende del recaudo del arrendatario.
// =============================================================================

const esPagosParcialesLiquidacionCanonDeposito = (contrato) =>
  !esPagoFijoLiquidacionCanonDeposito(contrato)

const contratoArriendoActivoEnMes = (contrato, mes) => {
  if (!contrato || !mes) return false
  if (contrato.estado && contrato.estado !== 'Activo') return false
  const inicio = (contrato.fechaInicio || '').slice(0, 7)
  if (!inicio || mes < inicio) return false
  if (contrato.fechaFin && mes > contrato.fechaFin.slice(0, 7)) return false
  return true
}
const CALIDADES_CONTRATANTE_DEPOSITO = ['Propietario', 'Autorizado']

// =============================================================================
// CONTRATOS DEPOSITO - PROPIETARIOS Y BENEFICIARIOS
// Participacion de propietarios y beneficiarios de liquidacion.
// =============================================================================

const obtenerPropietariosContratoDeposito = (contrato, predioPropietarios = []) => {
  if (!contrato) return []

  if (contrato.propietarios?.length) {
    return contrato.propietarios.map((item) => ({
      idPropietario: item.idPropietario,
      porcentaje: Number(item.porcentaje || 0),
    }))
  }

  if (contrato.codigoPredio) {
    return (predioPropietarios || [])
      .filter((relacion) => relacion.codigoPredio === contrato.codigoPredio)
      .map((relacion) => ({
        idPropietario: relacion.idPropietario,
        porcentaje: Number(relacion.porcentaje || 0),
      }))
  }

  if (contrato.idPropietario) {
    return [{ idPropietario: contrato.idPropietario, porcentaje: 100 }]
  }

  return []
}

const obtenerBeneficiariosLiquidacionContrato = (contrato, predioPropietarios = []) => {
  const tipoPago = contrato?.tipoPagoLiquidacion || 'Proporcional a propietarios'
  const propietariosContrato = obtenerPropietariosContratoDeposito(contrato, predioPropietarios)

  if (pagoEsSoloAlDepositario(tipoPago)) {
    const idDepositante = obtenerIdDepositanteContrato(contrato)
    if (!idDepositante) return []
    return [{ idPropietario: idDepositante, porcentaje: 100, esContratante: true }]
  }

  return propietariosContrato.map((item) => ({
    ...item,
    esContratante: item.idPropietario === obtenerIdDepositanteContrato(contrato),
  }))
}

const requiereObservacionesAutorizacionPago = ({
  idContratante,
  propietariosContrato = [],
  tipoPagoLiquidacion,
  calidadContratante,
}) => {
  if (calidadContratante === 'Autorizado') return true
  if (!pagoEsSoloAlDepositario(tipoPagoLiquidacion)) return false
  if (!idContratante || propietariosContrato.length === 0) return false

  const idsPropietarios = propietariosContrato.map((item) => item.idPropietario)
  const contratanteEsPropietario = idsPropietarios.includes(idContratante)

  if (!contratanteEsPropietario) return true
  if (propietariosContrato.length > 1 && contratanteEsPropietario) return true

  return false
}

const obtenerTextoBusquedaContratoDeposito = (
  contrato,
  contratosDeposito,
  predioPropietarios,
  propietarios,
  predios
) => {
  const numeroContrato = obtenerNumeroContratoDepositoVisible(contrato, contratosDeposito)
  const contratante = propietarios.find(
    (item) =>
      item.id ===
      (contrato.idDepositante || contrato.idContratante || contrato.idPropietario)
  )
  const propietariosContrato = obtenerPropietariosContratoDeposito(contrato, predioPropietarios)
  const predio = predios.find((item) => item.codigo === contrato.codigoPredio)
  const textoPropietarios = propietariosContrato
    .map((item) => {
      const propietario = propietarios.find((registro) => registro.id === item.idPropietario)
      return `${propietario?.nombre || ''} ${propietario?.numeroDocumento || ''} ${item.porcentaje}%`
    })
    .join(' ')

  return [
    numeroContrato,
    contrato.numeroContrato,
    contrato.codigoPredio,
    contrato.estado,
    contrato.tipoComision,
    contrato.tipoPagoLiquidacion,
    contrato.incluyeSeguimientoPredial,
    contrato.incluyeAseguradora,
    contrato.observaciones,
    contrato.observacionesAutorizacionPago,
    contrato.calidadContratante,
    contrato.condicionesPagoInh?.medioPago,
    ...(contrato.condicionesPagoInh?.cuentasPropietarios || []).flatMap((cuenta) => [
      cuenta.nombrePropietario,
      cuenta.numeroDocumento,
      cuenta.numeroCuenta,
      cuenta.tipoCuenta,
      cuenta.banco,
      cuenta.nombreCuenta,
    ]),
    contrato.condicionesPagoInh?.numeroCuenta,
    contrato.condicionesPagoInh?.tipoCuenta,
    contrato.condicionesPagoInh?.banco,
    contrato.condicionesPagoInh?.nombreCuenta,
    contratante?.nombre,
    contratante?.numeroDocumento,
    textoPropietarios,
    predio?.ciudad,
    predio?.barrio,
    predio?.direccion,
  ]
    .join(' ')
    .toLowerCase()
}

// =============================================================================
// CONTRATOS DEPOSITO - NORMALIZACION
// Estructura y validacion de contratos de administracion.
// =============================================================================

const normalizarIncluyeAseguradoraDeposito = (valor) => (valor === 'Sí' ? 'Sí' : 'No')

const contratoDepositoRequiereAseguradora = (contrato) =>
  normalizarIncluyeAseguradoraDeposito(contrato?.incluyeAseguradora) === 'Sí'

// =============================================================================
// CONTRATOS DEPOSITO - NORMALIZACION
// Estructura y validacion de contratos de administracion.
// =============================================================================

const normalizarContratosDeposito = (lista = []) =>
  (lista || []).map((contrato) => {
    const propietariosContrato = contrato?.propietarios?.length
      ? contrato.propietarios.map((item) => ({
          idPropietario: item.idPropietario,
          porcentaje: Number(item.porcentaje || 0),
        }))
      : contrato?.idPropietario
      ? [{ idPropietario: contrato.idPropietario, porcentaje: 100 }]
      : []

    const idPropietarioPrincipal =
      contrato?.idPropietario || propietariosContrato[0]?.idPropietario || ''

    return {
      ...contrato,
      propietarios: propietariosContrato,
      idPropietario: idPropietarioPrincipal,
      idContratante: contrato?.idContratante || idPropietarioPrincipal,
      calidadContratante: contrato?.calidadContratante || 'Propietario',
      tipoPagoLiquidacion: normalizarTipoPagoLiquidacionDeposito(contrato?.tipoPagoLiquidacion),
      criterioLiquidacionCanon: normalizarCriterioLiquidacionCanonDeposito(
        contrato?.criterioLiquidacionCanon
      ),
      observacionesAutorizacionPago: contrato?.observacionesAutorizacionPago || '',
      incluyeAseguradora: normalizarIncluyeAseguradoraDeposito(contrato?.incluyeAseguradora),
      condicionesPagoInh: normalizarCondicionesPagoInh(contrato?.condicionesPagoInh),
    }
  })

const obtenerContratoDepositoActivoPredio = (codigoPredio, contratosDeposito) =>
  (contratosDeposito || []).find(
    (contrato) => contrato.codigoPredio === codigoPredio && contrato.estado === 'Activo'
  )

const obtenerContratoDepositoPredio = (codigoPredio, contratosDeposito = []) => {
  if (!codigoPredio) return null

  return (
    obtenerContratoDepositoActivoPredio(codigoPredio, contratosDeposito) ||
    contratosDeposito.find((contrato) => contrato.codigoPredio === codigoPredio) ||
    null
  )
}

const contratoDepositoIncluyePredial = (contrato) => {
  if (!contrato || contrato.tipoComision !== 'Administración') return false
  return contrato.incluyeSeguimientoPredial === 'Sí'
}

const contratoDepositoPendienteInmueble = (contrato) =>
  !!contrato &&
  (contrato.estado === 'Pendiente inmueble' || !contrato.codigoPredio)

const predioRequiereInformacionPredial = (codigoPredio, contratosDeposito) => {
  if (!codigoPredio) return false

  const contrato = obtenerContratoDepositoPredio(codigoPredio, contratosDeposito)
  return contratoDepositoIncluyePredial(contrato)
}

// =============================================================================
// IMPUESTO PREDIAL - VIGENCIAS Y SALDOS
// Anios de vigencia, extractos por propietario y saldo pendiente.
// =============================================================================

const obtenerAnioInicioVigenciasPredial = (predio, contratosDeposito = [], anioReferencia = null) => {
  const anioActualSistema =
    Number(anioReferencia) || new Date().getFullYear()
  const contrato = obtenerContratoDepositoPredio(predio?.codigo, contratosDeposito)
  const anioDesdeContrato = contrato?.fechaInicio
    ? Number(String(contrato.fechaInicio).slice(0, 4))
    : null
  const anioDesdePredio = predio?.anioInicioPredial
    ? Number(predio.anioInicioPredial)
    : null

  const candidatos = [anioDesdeContrato, anioDesdePredio].filter(
    (anio) => Number.isFinite(anio) && anio > 1900
  )

  if (!candidatos.length) return anioActualSistema

  return Math.min(...candidatos, anioActualSistema)
}

const extractoTieneVigenciasSinActualizar = (extracto) =>
  (extracto?.movimientos || []).some(
    (movimiento) => movimiento.estadoMovimiento === 'Falta actualizar valor'
  )

const contarVigenciasSinActualizarPredial = (extracto) =>
  (extracto?.movimientos || []).filter(
    (movimiento) => movimiento.estadoMovimiento === 'Falta actualizar valor'
  ).length

// =============================================================================
// PREDIAL - EXTRACTO PREDIOS POR PROPIETARIO
// Saldo pendiente y vigencias sin actualizar para la columna Predial pendiente.
// =============================================================================

const obtenerPredialPendientePredioExtracto = (
  codigoPredio,
  extractosPrediales = [],
  contratosDeposito = []
) => {
  if (!predioRequiereInformacionPredial(codigoPredio, contratosDeposito)) {
    return { aplicaPredial: false, requiereActualizacion: false, saldoPendiente: 0 }
  }

  const extracto = extractosPrediales.find((item) => item.predio?.codigo === codigoPredio)
  if (!extracto) {
    return { aplicaPredial: true, requiereActualizacion: true, saldoPendiente: 0 }
  }

  const requiereActualizacion =
    extractoTieneVigenciasSinActualizar(extracto) ||
    extracto.resumen?.estadoGeneral === 'Pendiente de actualización'
  const saldoPendiente = Math.max(0, Number(extracto.resumen?.saldoPendiente || 0))

  return { aplicaPredial: true, requiereActualizacion, saldoPendiente }
}

// =============================================================================
// PREDIAL - AVALUO EN EXTRACTO PREDIOS POR PROPIETARIO
// Avaluo del ultimo ano vigente actualizado o pendiente por actualizar.
// =============================================================================

const obtenerAvaluoPredioExtractoPropietario = (
  predio,
  extractosPrediales = [],
  valoresPrediales = [],
  contratosDeposito = []
) => {
  const codigoPredio = predio.codigo
  const predialInfo = obtenerPredialPendientePredioExtracto(
    codigoPredio,
    extractosPrediales,
    contratosDeposito
  )

  if (!predialInfo.aplicaPredial) {
    const avaluo = Number(predio.avaluoCatastral || 0)
    if (!avaluo) {
      return { requiereActualizacion: true, valorAvaluoTotal: 0, anioAvaluo: null }
    }
    return { requiereActualizacion: false, valorAvaluoTotal: avaluo, anioAvaluo: null }
  }

  if (predialInfo.requiereActualizacion) {
    return { requiereActualizacion: true, valorAvaluoTotal: 0, anioAvaluo: null }
  }

  const extracto = extractosPrediales.find((item) => item.predio?.codigo === codigoPredio)
  const ultimoAnioActualizado = (extracto?.movimientos || [])
    .filter((movimiento) => movimiento.estadoMovimiento !== 'Falta actualizar valor')
    .sort((a, b) => Number(b.anio) - Number(a.anio))[0]

  if (!ultimoAnioActualizado) {
    return { requiereActualizacion: true, valorAvaluoTotal: 0, anioAvaluo: null }
  }

  const valorAnual = valoresPrediales.find(
    (item) =>
      item.codigoPredio === codigoPredio &&
      Number(item.anio) === Number(ultimoAnioActualizado.anio)
  )

  const valorAvaluoTotal = Number(
    valorAnual?.valorAvaluoCatastral ?? predio.avaluoCatastral ?? 0
  )

  if (!valorAvaluoTotal) {
    return {
      requiereActualizacion: true,
      valorAvaluoTotal: 0,
      anioAvaluo: ultimoAnioActualizado.anio,
    }
  }

  return {
    requiereActualizacion: false,
    valorAvaluoTotal,
    anioAvaluo: ultimoAnioActualizado.anio,
  }
}

// =============================================================================
// PREDIAL - FILAS EXTRACTO PREDIOS PROPIETARIO
// Detalle de inmuebles, avaluo y predial pendiente por participacion del propietario.
// =============================================================================

const construirExtractoPrediosPorPropietario = ({
  idPropietario,
  predioPropietarios = [],
  predios = [],
  unidadesNegocio = [],
  extractosPrediales = [],
  valoresPrediales = [],
  contratosDeposito = [],
}) => {
  const relaciones = predioPropietarios.filter((rel) => rel.idPropietario === idPropietario)

  const filas = relaciones
    .map((rel, index) => {
      const predio = predios.find((item) => item.codigo === rel.codigoPredio)
      if (!predio) return null

      const porcentaje = Number(rel.porcentaje || 0)
      const cantidadUnidades =
        unidadesNegocio.filter((unidad) => unidad.codigoPredio === predio.codigo).length ||
        Number(predio.cantidadUnidades || 0) ||
        0
      const predialExtracto = obtenerPredialPendientePredioExtracto(
        predio.codigo,
        extractosPrediales,
        contratosDeposito
      )
      const saldoPredialPredio = predialExtracto.saldoPendiente
      const predialPendiente = Math.round(saldoPredialPredio * (porcentaje / 100))
      const avaluoExtracto = obtenerAvaluoPredioExtractoPropietario(
        predio,
        extractosPrediales,
        valoresPrediales,
        contratosDeposito
      )
      const valorAvaluo = Math.round(avaluoExtracto.valorAvaluoTotal * (porcentaje / 100))
      const direccion = [predio.direccion, predio.barrio, predio.ciudad].filter(Boolean).join(' · ')

      return {
        item: index + 1,
        codigoPredio: predio.codigo,
        direccion,
        cantidadUnidades,
        porcentaje,
        aplicaPredial: predialExtracto.aplicaPredial,
        requiereActualizacionPredial:
          predialExtracto.aplicaPredial && predialExtracto.requiereActualizacion,
        requiereActualizacionAvaluo: avaluoExtracto.requiereActualizacion,
        anioAvaluo: avaluoExtracto.anioAvaluo,
        predialPendiente,
        valorAvaluo,
      }
    })
    .filter(Boolean)

  const totales = filas.reduce(
    (acc, fila) => ({
      cantidadUnidades: acc.cantidadUnidades + fila.cantidadUnidades,
      predialPendiente: acc.predialPendiente + fila.predialPendiente,
      valorAvaluo: acc.valorAvaluo + fila.valorAvaluo,
    }),
    {
      cantidadUnidades: 0,
      predialPendiente: 0,
      valorAvaluo: 0,
    }
  )

  return { filas, totales }
}

// =============================================================================
// DEPOSITANTES - IDENTIFICACION Y DATOS
// Depositantes, documentos asociados y predios vinculados.
// =============================================================================

const obtenerIdDepositanteContrato = (contrato) =>
  contrato?.idDepositante || contrato?.idContratante || contrato?.idPropietario || ''

const obtenerDepositantePorId = (idDepositante, propietarios = []) =>
  propietarios.find((item) => item.id === idDepositante) || null

const obtenerEtiquetaDepositante = (depositante) => {
  if (!depositante) return 'Sin depositante'
  const documento = depositante.numeroDocumento || 'Sin documento'
  const nombre = depositante.nombre || 'Sin nombre'
  const prefijo = depositante.tipoDocumento || 'Doc.'
  return `${prefijo} ${documento} – ${nombre}`
}

const TIPOS_PERSONA_DEPOSITANTE = ['Persona natural', 'Persona jurídica']

const esDepositantePersonaJuridica = (depositante, tipoPersona = '') =>
  (tipoPersona || depositante?.tipoPersona) === 'Persona jurídica'

const obtenerNumeroIdentificacionDepositante = (depositante, contrato = null) =>
  contrato?.numeroIdentificacionDepositante || depositante?.numeroDocumento || ''

const obtenerDocumentoDepositarioVisible = (depositante, contrato = null) => {
  const numero = obtenerNumeroIdentificacionDepositante(depositante, contrato)
  if (!numero) return 'Sin documento'
  const tipo = depositante?.tipoDocumento || contrato?.tipoDocumentoDepositante || 'Doc.'
  return `${tipo} ${numero}`
}

const obtenerRepresentanteLegalDepositante = (depositante, propietarios = []) => {
  if (!depositante?.idRepresentanteLegal) return null
  return propietarios.find((item) => item.id === depositante.idRepresentanteLegal) || null
}

const registrarRepresentanteLegalEnMaestro = ({
  propietarios = [],
  idRepresentanteActual = '',
  nombre = '',
  tipoDocumento = 'Cédula de ciudadanía',
  numeroDocumento = '',
  telefono = '',
  correo = '',
  idDepositanteEmpresa = '',
}) => {
  const documentoLimpio = numeroDocumento.trim()
  const payload = {
    nombre: nombre.trim().toUpperCase(),
    tipoDocumento,
    numeroDocumento: documentoLimpio,
    telefono: telefono.trim(),
    correo: correo.trim().toUpperCase(),
    tipoPersona: 'Persona natural',
    rolDepositante: 'Representante legal',
    idDepositanteEmpresa,
  }

  const existente =
    propietarios.find(
      (item) => item.tipoDocumento === tipoDocumento && item.numeroDocumento === documentoLimpio
    ) ||
    (idRepresentanteActual
      ? propietarios.find((item) => item.id === idRepresentanteActual)
      : null)

  if (existente) {
    return {
      idRepresentanteLegal: existente.id,
      propietariosActualizados: propietarios.map((item) =>
        item.id === existente.id ? { ...item, ...payload } : item
      ),
    }
  }

  const idRepresentanteLegal = generarIdPropietario()
  return {
    idRepresentanteLegal,
    propietariosActualizados: [{ id: idRepresentanteLegal, ...payload }, ...propietarios],
  }
}

const obtenerDocumentosDepositante = (
  depositanteOId,
  contratosDeposito = [],
  propietarios = [],
  predioPropietarios = []
) => {
  const depositante =
    typeof depositanteOId === 'object' && depositanteOId !== null
      ? depositanteOId
      : resolverDepositanteRegistrado(depositanteOId, contratosDeposito, propietarios)

  if (!depositante) return []

  const contratos = new Map()
  ;(contratosDeposito || []).forEach((contrato) => {
    if (contratoPerteneceADepositante(contrato, depositante)) {
      contratos.set(contrato.id, contrato)
    }
  })

  return [...contratos.values()]
}

const obtenerPrediosAsociadosDepositante = (
  depositante,
  predios = [],
  predioPropietarios = [],
  contratosDeposito = [],
  propietarios = []
) => {
  if (!depositante) return []

  const codigos = new Set()
  obtenerDocumentosDepositante(
    depositante,
    contratosDeposito,
    propietarios,
    predioPropietarios
  ).forEach((contrato) => {
    if (contrato.codigoPredio) codigos.add(contrato.codigoPredio)
  })

  if (depositante.esDepositante) {
    obtenerCodigosPrediosDepositante(depositante, predioPropietarios).forEach((codigo) =>
      codigos.add(codigo)
    )
  }

  return (predios || []).filter((predio) => codigos.has(predio.codigo))
}

const normalizarNumeroDocumentoDepositante = (valor = '') => String(valor).replace(/\D/g, '')

const documentosDepositanteCoinciden = (docA = '', docB = '') => {
  const a = normalizarNumeroDocumentoDepositante(docA)
  const b = normalizarNumeroDocumentoDepositante(docB)
  return Boolean(a && b && a === b)
}

const documentoDepositanteCoincideBusqueda = (documento = '', busqueda = '') => {
  const doc = normalizarNumeroDocumentoDepositante(documento)
  const q = normalizarNumeroDocumentoDepositante(busqueda)
  if (!doc || !q) return false
  if (doc === q) return true
  return q.length >= 3 && doc.includes(q)
}

const depositanteCoincideBusquedaDocumentos = (depositante, busqueda, propietarios = []) => {
  if (!depositante || !busqueda?.trim()) return false

  const representanteLegal = obtenerRepresentanteLegalDepositante(depositante, propietarios)

  return (
    textoCoincideBusquedaDocumentos(
      busqueda,
      depositante.nombre,
      depositante.numeroDocumento,
      depositante.tipoDocumento,
      depositante.telefono,
      depositante.correo,
      depositante.whatsapp,
      depositante.direccion,
      representanteLegal?.nombre,
      representanteLegal?.numeroDocumento
    ) ||
    documentoDepositanteCoincideBusqueda(depositante.numeroDocumento, busqueda) ||
    documentosDepositanteCoinciden(depositante.numeroDocumento, busqueda)
  )
}

const contratoCoincideBusquedaDocumentosAdmin = (
  contrato,
  busqueda,
  contratosDeposito = [],
  propietarios = []
) => {
  if (!contrato || !busqueda?.trim()) return false

  const depositante = resolverDepositanteDesdeContrato(contrato, propietarios)

  return (
    textoCoincideBusquedaDocumentos(
      busqueda,
      obtenerNumeroContratoDepositoVisible(contrato, contratosDeposito),
      contrato.numeroContrato,
      contrato.codigoPredio,
      contrato.numeroIdentificacionDepositante,
      contrato.nombreDepositante,
      contrato.nombreContratante,
      contrato.contratanteNombre,
      depositante?.nombre,
      depositante?.numeroDocumento,
      depositante?.correo
    ) ||
    documentoDepositanteCoincideBusqueda(contrato.numeroIdentificacionDepositante, busqueda) ||
    documentosDepositanteCoinciden(contrato.numeroIdentificacionDepositante, busqueda) ||
    (depositante && depositanteCoincideBusquedaDocumentos(depositante, busqueda, propietarios))
  )
}

const obtenerContratosDepositoPorDepositante = (
  depositante,
  contratosDeposito = [],
  propietarios = [],
  predioPropietarios = []
) => {
  const contratos = obtenerDocumentosDepositante(
    depositante,
    contratosDeposito,
    propietarios,
    predioPropietarios
  )

  if (contratos.length) return contratos

  if (!depositante?.numeroDocumento) return []

  return (contratosDeposito || []).filter(
    (contrato) =>
      documentosDepositanteCoinciden(
        depositante.numeroDocumento,
        contrato.numeroIdentificacionDepositante
      ) ||
      (depositante.id &&
        [contrato.idDepositante, contrato.idContratante].includes(depositante.id))
  )
}

const obtenerCodigosPrediosDepositante = (depositante, predioPropietarios = []) => {
  if (!depositante?.id) return new Set()

  return new Set(
    (predioPropietarios || [])
      .filter((relacion) => relacion.idPropietario === depositante.id)
      .map((relacion) => relacion.codigoPredio)
      .filter(Boolean)
  )
}

const personaEsDepositanteRegistrado = (contrato, persona) => {
  if (!persona || !contrato) return false

  const idsDepositante = [contrato.idDepositante, contrato.idContratante].filter(Boolean)

  if (persona.id && idsDepositante.includes(persona.id)) return true

  return documentosDepositanteCoinciden(
    persona.numeroDocumento,
    contrato.numeroIdentificacionDepositante
  )
}

const resolverDepositanteDesdeContrato = (contrato, propietarios = []) => {
  if (!contrato) return null

  const idsDepositante = [contrato.idDepositante, contrato.idContratante].filter(Boolean)
  for (const idDepositante of idsDepositante) {
    const porId = propietarios.find((item) => item.id === idDepositante)
    if (porId) return porId
  }

  const idDepositante = idsDepositante[0] || ''

  if (contrato.numeroIdentificacionDepositante) {
    const porDocumento = propietarios.find((item) =>
      documentosDepositanteCoinciden(
        item.numeroDocumento,
        contrato.numeroIdentificacionDepositante
      )
    )
    if (porDocumento) return porDocumento
  }

  if (!contrato.numeroIdentificacionDepositante && !idDepositante) return null

  return {
    id: idDepositante || `depositante-contrato-${contrato.id}`,
    nombre:
      contrato.nombreDepositante ||
      contrato.nombreContratante ||
      contrato.contratanteNombre ||
      'Depositante registrado',
    tipoDocumento: contrato.tipoDocumentoDepositante || 'Cédula de ciudadanía',
    numeroDocumento: contrato.numeroIdentificacionDepositante || '',
    telefono: contrato.telefonoDepositante || contrato.telefonoContratante || '',
    whatsapp: '',
    correo: contrato.correoDepositante || contrato.correoContratante || '',
    direccion: '',
    esDepositante: true,
    origenSintetico: true,
  }
}

const contratoPerteneceADepositante = (contrato, depositante) =>
  personaEsDepositanteRegistrado(contrato, depositante)

const claveUnicaDepositante = (depositante) => {
  const documento = normalizarNumeroDocumentoDepositante(depositante?.numeroDocumento)
  if (documento) return `doc:${documento}`
  return depositante?.id ? `id:${depositante.id}` : ''
}

const esRolAuxiliarDepositante = (persona) =>
  ['Representante legal', 'Autorizado'].includes(persona?.rolDepositante)

const resolverDepositanteRegistrado = (idDepositante, contratosDeposito = [], propietarios = []) => {
  if (!idDepositante) return null

  const persona = propietarios.find((item) => item.id === idDepositante)
  if (persona) return persona

  const contratoReferencia = (contratosDeposito || []).find(
    (contrato) => obtenerIdDepositanteContrato(contrato) === idDepositante
  )
  const documento = contratoReferencia?.numeroIdentificacionDepositante
  if (!documento) return null

  return (
    propietarios.find((item) =>
      documentosDepositanteCoinciden(item.numeroDocumento, documento)
    ) || null
  )
}

// =============================================================================
// DEPOSITANTES - REGISTRO Y CONSULTA
// Listado y busqueda de depositantes registrados.
// =============================================================================

const obtenerDepositantesRegistrados = (contratosDeposito = [], propietarios = []) => {
  const depositantesPorClave = new Map()

  const registrarDepositante = (persona) => {
    if (!persona || esRolAuxiliarDepositante(persona)) return

    const clave = claveUnicaDepositante(persona)
    if (!clave) return

    const existente = depositantesPorClave.get(clave)
    if (!existente) {
      depositantesPorClave.set(clave, persona)
      return
    }

    const preferirNuevo =
      (existente.origenSintetico && !persona.origenSintetico) ||
      (!existente.esDepositante && persona.esDepositante) ||
      (!existente.nombre && persona.nombre) ||
      (!existente.numeroDocumento && persona.numeroDocumento)

    if (preferirNuevo) {
      depositantesPorClave.set(clave, { ...existente, ...persona, origenSintetico: false })
    }
  }

  ;(contratosDeposito || []).forEach((contrato) => {
    const persona = resolverDepositanteDesdeContrato(contrato, propietarios)
    if (persona && personaEsDepositanteRegistrado(contrato, persona)) {
      registrarDepositante(persona)
    }
  })

  ;(propietarios || []).forEach((persona) => {
    if (persona?.esDepositante) registrarDepositante(persona)
  })

  return [...depositantesPorClave.values()].sort((a, b) =>
    String(a.nombre || '').localeCompare(String(b.nombre || ''))
  )
}

const obtenerPrediosDocumento = (idDocumento, predios = [], contratosDeposito = []) => {
  const porRelacion = (predios || []).filter((predio) => predio.idDocumento === idDocumento)
  if (porRelacion.length) return porRelacion

  const contrato = (contratosDeposito || []).find((item) => item.id === idDocumento)
  if (!contrato?.codigoPredio) return []

  return (predios || []).filter((predio) => predio.codigo === contrato.codigoPredio)
}

const normalizarContratosDepositoJerarquia = (lista = [], propietarios = []) =>
  lista.map((contrato) => {
    const idDepositante = obtenerIdDepositanteContrato(contrato)
    const depositante = obtenerDepositantePorId(idDepositante, propietarios)

    return {
      ...contrato,
      idDepositante,
      numeroIdentificacionDepositante:
        contrato.numeroIdentificacionDepositante || depositante?.numeroDocumento || '',
      tipoPersonaDepositante:
        contrato.tipoPersonaDepositante || depositante?.tipoPersona || 'Persona natural',
      idRepresentanteLegal:
        contrato.idRepresentanteLegal || depositante?.idRepresentanteLegal || '',
    }
  })

// =============================================================================
// PREDIOS - JERARQUIA Y NORMALIZACION
// Estructura organizacional y normalizacion de predios.
// =============================================================================

const normalizarPrediosJerarquia = (predios = [], contratosDeposito = []) =>
  (predios || []).map((predio) => {
    if (predio.idDocumento) return predio

    const contrato =
      (contratosDeposito || []).find(
        (item) =>
          item.codigoPredio === predio.codigo &&
          (item.estado === 'Activo' || item.estado === 'Pendiente inmueble')
      ) || null

    return {
      ...predio,
      idDocumento: contrato?.id || '',
    }
  })

const sincronizarIdsDepositanteEnContratos = (contratosDeposito = [], propietarios = []) =>
  (contratosDeposito || []).map((contrato) => {
    const idActual = obtenerIdDepositanteContrato(contrato)
    const depositante =
      resolverDepositanteRegistrado(idActual, contratosDeposito, propietarios) ||
      resolverDepositanteDesdeContrato(contrato, propietarios)

    if (!depositante || depositante.origenSintetico) return contrato

    const numeroIdentificacion =
      depositante.numeroDocumento || contrato.numeroIdentificacionDepositante || ''

    if (
      idActual === depositante.id &&
      String(contrato.numeroIdentificacionDepositante || '').trim() ===
        String(numeroIdentificacion).trim()
    ) {
      return contrato
    }

    return {
      ...contrato,
      idDepositante: depositante.id,
      idContratante: depositante.id,
      numeroIdentificacionDepositante: numeroIdentificacion,
    }
  })

const migrarJerarquiaDocumental = (predios = [], contratosDeposito = [], propietarios = []) => {
  const contratosConDepositante = sincronizarIdsDepositanteEnContratos(
    contratosDeposito,
    propietarios
  )
  const contratosNormalizados = normalizarContratosDepositoJerarquia(
    contratosConDepositante,
    propietarios
  )
  const prediosNormalizados = normalizarPrediosJerarquia(predios, contratosNormalizados)

  return {
    predios: prediosNormalizados,
    contratosDeposito: contratosNormalizados,
  }
}

// =============================================================================
// PREDIOS - CADENA ORGANIZACIONAL
// Niveles jerarquicos ciudad, barrio y predio.
// =============================================================================

const construirCadenaOrganizacional = ({
  codigoPredio,
  predios = [],
  contratosDeposito = [],
  propietarios = [],
  unidadesNegocio = [],
  contratosArriendo = [],
  idUnidad = '',
  idContratoArriendo = '',
}) => {
  const predio = (predios || []).find((item) => item.codigo === codigoPredio) || null
  const contratoDocumento =
    (contratosDeposito || []).find((item) => item.id === predio?.idDocumento) ||
    obtenerContratoDepositoPredio(codigoPredio, contratosDeposito)
  const depositante = contratoDocumento
    ? obtenerDepositantePorId(obtenerIdDepositanteContrato(contratoDocumento), propietarios) ||
      resolverDepositanteDesdeContrato(contratoDocumento, propietarios)
    : null
  const unidad = idUnidad
    ? (unidadesNegocio || []).find(
        (item) =>
          item.id === idUnidad &&
          (!codigoPredio || item.codigoPredio === codigoPredio)
      )
    : null
  const contratoArriendo = idContratoArriendo
    ? (contratosArriendo || []).find(
        (item) => obtenerIdContrato(item) === idContratoArriendo
      )
    : null

  return [
    depositante || contratoDocumento
      ? {
          etiqueta: 'Documento del depositario',
          valor: obtenerDocumentoDepositarioVisible(depositante, contratoDocumento),
        }
      : null,
    predio
      ? {
          etiqueta: 'Predio',
          valor: predio.codigo,
        }
      : null,
    contratoDocumento
      ? {
          etiqueta: 'Contrato de depósito',
          valor: obtenerNumeroContratoDepositoVisible(contratoDocumento, contratosDeposito),
        }
      : null,
    unidad
      ? {
          etiqueta: 'Unidad de negocio',
          valor: unidad.nombre || unidad.id,
        }
      : null,
    contratoArriendo
      ? {
          etiqueta: 'Contrato de arriendo unidad',
          valor: obtenerNumeroContratoVisible(contratoArriendo, predios, contratosArriendo),
        }
      : null,
  ].filter(Boolean)
}

const construirCadenaJerarquicaPredio = (opciones = {}) => construirCadenaOrganizacional(opciones)

const PREFIJO_UNIDAD_POR_TIPO = {
  Local: 'LOC',
  Oficina: 'OFI',
  Apartamento: 'APT',
  Bodega: 'BOD',
}

// =============================================================================
// UNIDADES DE NEGOCIO - IDS Y CONSECUTIVOS
// Prefijos, IDs legacy y servicios por unidad.
// =============================================================================

const obtenerPrefijoUnidad = (tipo = 'Local') => PREFIJO_UNIDAD_POR_TIPO[tipo] || 'UNI'

const escaparRegex = (texto = '') =>
  String(texto).replace(/[.*+?^${}()|[\]\\]/g, '\\$&')

const esIdUnidadConCodigoPredio = (idUnidad = '', codigoPredio = '') => {
  if (!idUnidad || !codigoPredio) return false
  return String(idUnidad).startsWith(`${codigoPredio}-`)
}

const obtenerConsecutivoIdUnidadLegacy = (idUnidad = '', tipo = 'Local') => {
  const prefijo = obtenerPrefijoUnidad(tipo)
  const match =
    String(idUnidad).match(new RegExp(`^${prefijo}-(\\d{3,4})$`)) ||
    String(idUnidad).match(/^UNI-(\d{3,4})$/)
  return match ? Number(match[1]) : null
}

const obtenerIdUnidadLegacyDesdeId = (idUnidad = '') => {
  const match = String(idUnidad).match(/-(LOC|APT|OFI|BOD|UNI)-(\d{3,4})$/)
  return match ? `${match[1]}-${match[2]}` : null
}

const generarCodigoUnidad = (codigoPredio, tipo = 'Local', unidades = []) => {
  const codigoPredioLimpio = String(codigoPredio || '').trim()
  if (!codigoPredioLimpio) return 'UNI-001'

  const prefijo = obtenerPrefijoUnidad(tipo)
  const patronNuevo = new RegExp(
    `^${escaparRegex(codigoPredioLimpio)}-${prefijo}-(\\d{3,4})$`
  )
  const patronLegacy = new RegExp(`^${prefijo}-(\\d{3,4})$`)

  const maxConsecutivo = (unidades || []).reduce((max, unidad) => {
    if (unidad.codigoPredio !== codigoPredioLimpio) return max
    const id = String(unidad.id || '')
    const matchNuevo = id.match(patronNuevo)
    if (matchNuevo) return Math.max(max, Number(matchNuevo[1]))
    const matchLegacy = id.match(patronLegacy)
    if (matchLegacy) return Math.max(max, Number(matchLegacy[1]))
    return max
  }, 0)

  return `${codigoPredioLimpio}-${prefijo}-${String(maxConsecutivo + 1).padStart(3, '0')}`
}

const crearMapaMigracionIdsUnidades = (unidades = []) => {
  const mapaIds = new Map()
  const contadores = new Map()
  const unidadesMigradas = []

  ;(unidades || []).forEach((unidad) => {
    if (!unidad?.codigoPredio) {
      unidadesMigradas.push(unidad)
      return
    }

    if (esIdUnidadConCodigoPredio(unidad.id, unidad.codigoPredio)) {
      unidadesMigradas.push(unidad)
      const prefijo = obtenerPrefijoUnidad(unidad.tipo)
      const match = String(unidad.id).match(
        new RegExp(`^${escaparRegex(unidad.codigoPredio)}-${prefijo}-(\\d{3,4})$`)
      )
      if (match) {
        const clave = `${unidad.codigoPredio}|${prefijo}`
        contadores.set(clave, Math.max(contadores.get(clave) || 0, Number(match[1])))
      }
      return
    }

    const claveMapa = `${unidad.codigoPredio}|${unidad.id}`
    if (mapaIds.has(claveMapa)) {
      unidadesMigradas.push({ ...unidad, id: mapaIds.get(claveMapa) })
      return
    }

    const prefijo = obtenerPrefijoUnidad(unidad.tipo)
    const claveContador = `${unidad.codigoPredio}|${prefijo}`
    const legacy = obtenerConsecutivoIdUnidadLegacy(unidad.id, unidad.tipo)
    const actual = contadores.get(claveContador) || 0
    const consecutivo = legacy != null ? Math.max(legacy, actual + 1) : actual + 1
    contadores.set(claveContador, consecutivo)

    const idNuevo = `${unidad.codigoPredio}-${prefijo}-${String(consecutivo).padStart(3, '0')}`
    mapaIds.set(claveMapa, idNuevo)
    unidadesMigradas.push({ ...unidad, id: idNuevo })
  })

  return { unidadesMigradas, mapaIds }
}

const resolverIdUnidadMigrado = (idUnidad, codigoPredio, mapaIds) => {
  if (!idUnidad) return idUnidad
  if (codigoPredio && esIdUnidadConCodigoPredio(idUnidad, codigoPredio)) return idUnidad
  const clave = `${codigoPredio || ''}|${idUnidad}`
  return mapaIds.get(clave) || idUnidad
}

const propagarMapaIdsUnidadesEnDatos = (datos = {}, mapaIds = new Map()) => {
  if (!mapaIds.size) return datos

  const migrarId = (idUnidad, codigoPredio) =>
    resolverIdUnidadMigrado(idUnidad, codigoPredio, mapaIds)

  const actualizarCampoIdUnidad = (item) => {
    const idUnidad = migrarId(item.idUnidad, item.codigoPredio)
    return idUnidad === item.idUnidad ? item : { ...item, idUnidad }
  }

  return {
    ...datos,
    contratosArriendo: (datos.contratosArriendo || []).map(actualizarCampoIdUnidad),
    pagosArriendo: (datos.pagosArriendo || []).map(actualizarCampoIdUnidad),
    pagosAdministracion: (datos.pagosAdministracion || []).map(actualizarCampoIdUnidad),
    facturasServiciosPublicos: (datos.facturasServiciosPublicos || []).map(actualizarCampoIdUnidad),
    pagosServiciosPublicos: (datos.pagosServiciosPublicos || []).map(actualizarCampoIdUnidad),
    documentos: (datos.documentos || []).map(actualizarCampoIdUnidad),
    gestionesCartera: (datos.gestionesCartera || []).map(actualizarCampoIdUnidad),
    ajustesAdministracion: (datos.ajustesAdministracion || []).map(actualizarCampoIdUnidad),
  }
}

const migrarIdsUnidadesNegocio = (datos = {}) => {
  const { unidadesMigradas, mapaIds } = crearMapaMigracionIdsUnidades(
    datos.unidadesNegocio || []
  )

  return {
    ...propagarMapaIdsUnidadesEnDatos(
      { ...datos, unidadesNegocio: unidadesMigradas },
      mapaIds
    ),
    unidadesNegocio: unidadesMigradas,
  }
}

const coincideUnidadNegocio = (unidadA, unidadB) => {
  if (!unidadA || !unidadB) return false
  if (unidadA.id && unidadB.id && unidadA.id === unidadB.id) return true
  return (
    String(unidadA.id || '') === String(unidadB.id || '') &&
    String(unidadA.codigoPredio || '') === String(unidadB.codigoPredio || '')
  )
}

const idsServicioUnidadEquivalentes = (unidad, index) => {
  const idUnidad = unidad?.id || 'SIN-UNIDAD'
  const codigoPredio = unidad?.codigoPredio || 'SIN-PREDIO'
  const ids = new Set([
    `${idUnidad}-${index}`,
    `${codigoPredio}-${idUnidad}-${index}`,
  ])
  const legacy = obtenerIdUnidadLegacyDesdeId(idUnidad)
  if (legacy) {
    ids.add(`${legacy}-${index}`)
    ids.add(`${codigoPredio}-${legacy}-${index}`)
  }
  return [...ids]
}

const generarIdServicioUnidad = (unidad, index) =>
  idsServicioUnidadEquivalentes(unidad, index)[0]

const contextoMovimientoServicioUnidad = (unidad, servicioIndex) => ({
  idUnidad: unidad.id,
  idServicio: generarIdServicioUnidad(unidad, servicioIndex),
  codigoPredio: unidad.codigoPredio,
  unidad,
  servicioIndex,
})

const facturaPerteneceAUnidadServicio = (factura, unidad, index, idServicio = null) => {
  if (!factura || !unidad) return false

  const idsValidos = idServicio
    ? [idServicio, ...idsServicioUnidadEquivalentes(unidad, index)]
    : index != null
      ? idsServicioUnidadEquivalentes(unidad, index)
      : [factura.idServicio].filter(Boolean)

  if (!idsValidos.includes(factura.idServicio)) return false

  return (
    factura.idUnidad === unidad.id &&
    (!factura.codigoPredio || factura.codigoPredio === unidad.codigoPredio)
  )
}

const extractoPerteneceAUnidadServicio = (extracto, unidad, index) =>
  !!extracto &&
  !!unidad &&
  coincideUnidadNegocio(extracto.unidad, unidad) &&
  idsServicioUnidadEquivalentes(unidad, index).includes(extracto.idServicio)

const generarClaveExtractoServicio = (extracto) =>
  `${extracto.unidad.codigoPredio}::${extracto.unidad.id}::${extracto.idServicio}`

const coincideClaveExtractoServicio = (extracto, clave) =>
  !!extracto &&
  !!clave &&
  (generarClaveExtractoServicio(extracto) === clave ||
    `${extracto.unidad.id}::${extracto.idServicio}` === clave)

const PATRON_NUMERO_CONTRATO_DEPOSITO = /^DEP-(\d{4})-(\d+)$/

const extraerCuatroDigitosIdentificacionDepositante = (documento = '') => {
  const soloDigitos = String(documento).replace(/\D/g, '')
  if (!soloDigitos) return '0000'
  return soloDigitos.slice(-4).padStart(4, '0')
}

const esNumeroContratoDepositoValido = (numero = '') =>
  PATRON_NUMERO_CONTRATO_DEPOSITO.test(numero)

const obtenerIdentificacionDepositanteContrato = (contrato, propietarios = []) => {
  if (!contrato) return ''
  const idDepositante = obtenerIdDepositanteContrato(contrato)
  const depositante = obtenerDepositantePorId(idDepositante, propietarios)
  return (
    contrato.numeroIdentificacionDepositante ||
    depositante?.numeroDocumento ||
    ''
  )
}

// =============================================================================
// CONTRATOS - GENERACION DE IDENTIFICADORES
// IDs internos para contratos de deposito y arriendo.
// =============================================================================

const generarIdContratoDeposito = () =>
  `DEP-${Date.now()}-${Math.floor(Math.random() * 10000)}`

const generarIdInternoContratoArriendo = () =>
  `ARR-${Date.now()}-${Math.floor(Math.random() * 10000)}`

const asignarIdsInternosContratosArriendo = (lista = []) =>
  (lista || []).map((contrato, index) => {
    if (contrato?.id) return contrato
    return {
      ...contrato,
      id: `ARR-LEGACY-${index}-${contrato?.codigoPredio || 'SIN'}-${contrato?.idUnidad || 'SIN'}-${contrato?.fechaInicio || index}`,
    }
  })

const construirIndiceClavesLegacyContrato = (contratos = []) => {
  const indice = new Map()

  contratos.forEach((contrato) => {
    const idInterno = contrato?.id
    if (!idInterno) return

    const claves = new Set(
      [
        contrato.idContrato,
        `${contrato.codigoPredio}-${contrato.idUnidad || 'SIN-UNIDAD'}-${contrato.numeroDocumento}`,
      ].filter(Boolean)
    )

    claves.forEach((clave) => {
      if (!indice.has(clave)) indice.set(clave, [])
      const lista = indice.get(clave)
      if (!lista.includes(idInterno)) lista.push(idInterno)
    })
  })

  return indice
}

const resolverIdInternoContratoDesdeReferencia = (
  referencia,
  contratos = [],
  indice = new Map(),
  contexto = {}
) => {
  if (!referencia) return referencia
  if (contratos.some((contrato) => contrato.id === referencia)) return referencia

  const candidatos = indice.get(referencia) || []
  if (candidatos.length === 1) return candidatos[0]

  if (candidatos.length > 1) {
    const contrato = contratos.find(
      (item) =>
        candidatos.includes(item.id) &&
        (!contexto.idUnidad || item.idUnidad === contexto.idUnidad) &&
        (!contexto.numeroDocumento ||
          String(item.numeroDocumento) === String(contexto.numeroDocumento))
    )
    if (contrato) return contrato.id
  }

  return referencia
}

const migrarReferenciasContratosArriendo = (
  contratos = [],
  pagos = [],
  ajustes = [],
  gestiones = []
) => {
  const indice = construirIndiceClavesLegacyContrato(contratos)

  const migrarReferencia = (registro, contexto = {}) => {
    const idResuelto = resolverIdInternoContratoDesdeReferencia(
      registro.idContrato,
      contratos,
      indice,
      contexto
    )
    return idResuelto === registro.idContrato
      ? registro
      : { ...registro, idContrato: idResuelto }
  }

  return {
    contratos,
    pagosArriendo: pagos.map((pago) =>
      migrarReferencia(pago, {
        idUnidad: pago.idUnidad,
        numeroDocumento: pago.numeroDocumento,
      })
    ),
    ajustesAdministracion: ajustes.map((ajuste) =>
      migrarReferencia(ajuste, { idUnidad: ajuste.idUnidad })
    ),
    gestionesCartera: gestiones.map((gestion) => migrarReferencia(gestion)),
  }
}

const generarNumeroContratoDeposito = (
  contratosDeposito = [],
  numeroIdentificacionDepositante = ''
) => {
  const cuatroDigitos = extraerCuatroDigitosIdentificacionDepositante(
    numeroIdentificacionDepositante
  )
  const patron = new RegExp(`^DEP-${cuatroDigitos}-(\\d+)$`)

  const maxConsecutivo = (contratosDeposito || []).reduce((max, contrato) => {
    const numero = contrato?.numeroContrato || ''
    const match = numero.match(patron)
    if (!match) return max
    return Math.max(max, Number(match[1]))
  }, 0)

  return `DEP-${cuatroDigitos}-${String(maxConsecutivo + 1).padStart(3, '0')}`
}

const PATRON_NUMERO_CONTRATO_ARRIENDO = /^([A-Z]{3})-(\d{4})-(\d{4})$/

const esNumeroContratoArriendoValido = (numero = '') =>
  PATRON_NUMERO_CONTRATO_ARRIENDO.test(String(numero || ''))

const generarNumeroContratoArriendo = ({
  contratosArriendo = [],
  predios = [],
  codigoPredio = '',
  numeroDocumento = '',
}) => {
  const predioContrato = (predios || []).find((predio) => predio.codigo === codigoPredio)
  const codigoCiudad = obtenerCodigoCiudad(predioContrato?.ciudad || 'SIN')
  const cuatroDigitos = extraerCuatroDigitosIdentificacionDepositante(numeroDocumento)
  const patron = new RegExp(`^${codigoCiudad}-${cuatroDigitos}-(\\d+)$`)

  const maxConsecutivo = (contratosArriendo || []).reduce((max, contrato) => {
    const numero = contrato?.idContrato || ''
    const match = String(numero).match(patron)
    if (!match) return max
    return Math.max(max, Number(match[1]))
  }, 0)

  return `${codigoCiudad}-${cuatroDigitos}-${String(maxConsecutivo + 1).padStart(4, '0')}`
}

const normalizarCodigosContratosArriendo = (lista = [], predios = []) => {
  const contratos = [...(lista || [])]
  const numerosPorId = new Map()
  const maxPorClave = new Map()
  const grupos = new Map()

  const obtenerClaveContrato = (contrato) => {
    const predioContrato = (predios || []).find((predio) => predio.codigo === contrato.codigoPredio)
    const codigoCiudad = obtenerCodigoCiudad(predioContrato?.ciudad || 'SIN')
    const cuatroDigitos = extraerCuatroDigitosIdentificacionDepositante(
      contrato?.numeroDocumento || ''
    )
    return `${codigoCiudad}|${cuatroDigitos}`
  }

  contratos.forEach((contrato) => {
    const clave = obtenerClaveContrato(contrato)
    if (!grupos.has(clave)) grupos.set(clave, [])
    grupos.get(clave).push(contrato)

    const numero = String(contrato?.idContrato || '')
    const match = numero.match(PATRON_NUMERO_CONTRATO_ARRIENDO)
    const [codigoCiudad, cuatroDigitos] = clave.split('|')

    if (match && match[1] === codigoCiudad && match[2] === cuatroDigitos) {
      const actual = maxPorClave.get(clave) || 0
      maxPorClave.set(clave, Math.max(actual, Number(match[3])))
      if (contrato.id) numerosPorId.set(contrato.id, numero)
    }
  })

  grupos.forEach((grupo, clave) => {
    let consecutivo = maxPorClave.get(clave) || 0

    const ordenados = [...grupo].sort((a, b) => {
      const fechaA = a.fechaInicio || ''
      const fechaB = b.fechaInicio || ''
      if (fechaA !== fechaB) return fechaA.localeCompare(fechaB)
      return String(a.id || '').localeCompare(String(b.id || ''))
    })

    ordenados.forEach((contrato) => {
      const contratoKey = contrato.id
      if (!contratoKey || numerosPorId.has(contratoKey)) return

      const predioContrato = (predios || []).find((predio) => predio.codigo === contrato.codigoPredio)
      const codigoCiudad = obtenerCodigoCiudad(predioContrato?.ciudad || 'SIN')
      const cuatroDigitos = extraerCuatroDigitosIdentificacionDepositante(
        contrato?.numeroDocumento || ''
      )

      consecutivo += 1
      numerosPorId.set(
        contratoKey,
        `${codigoCiudad}-${cuatroDigitos}-${String(consecutivo).padStart(4, '0')}`
      )
    })
  })

  return contratos.map((contrato) => ({
    ...contrato,
    idContrato:
      (contrato.id && numerosPorId.get(contrato.id)) ||
      String(contrato.idContrato || '').trim(),
  }))
}

const obtenerNumeroContratoDepositoVisible = (
  contrato,
  contratosDeposito = [],
  propietarios = []
) => {
  if (!contrato) return 'Sin número'

  if (contrato.numeroContrato && esNumeroContratoDepositoValido(contrato.numeroContrato)) {
    return contrato.numeroContrato
  }

  const identificacion = obtenerIdentificacionDepositanteContrato(contrato, propietarios)
  const cuatroDigitos = extraerCuatroDigitosIdentificacionDepositante(identificacion)
  const idDepositante = obtenerIdDepositanteContrato(contrato)

  const delMismoDepositante = [...(contratosDeposito || [])]
    .filter((item) => obtenerIdDepositanteContrato(item) === idDepositante)
    .sort((a, b) => {
      const fechaA = a.fechaInicio || ''
      const fechaB = b.fechaInicio || ''
      if (fechaA !== fechaB) return fechaA.localeCompare(fechaB)
      return String(a.id).localeCompare(String(b.id))
    })

  const posicion = delMismoDepositante.findIndex((item) => item.id === contrato.id)
  const consecutivo = posicion >= 0 ? posicion + 1 : delMismoDepositante.length + 1

  return `DEP-${cuatroDigitos}-${String(consecutivo).padStart(3, '0')}`
}

const asignarNumerosContratosDepositoFaltantes = (lista = [], propietarios = []) => {
  const contratos = [...(lista || [])]
  const numerosPorId = new Map()
  const maxPorClave = new Map()
  const grupos = new Map()

  const obtenerClaveDepositante = (contrato) => {
    const id = obtenerIdDepositanteContrato(contrato)
    const identificacion = obtenerIdentificacionDepositanteContrato(contrato, propietarios)
    const cuatroDigitos = extraerCuatroDigitosIdentificacionDepositante(identificacion)
    return `${id || 'sin-id'}|${cuatroDigitos}`
  }

  contratos.forEach((contrato) => {
    const clave = obtenerClaveDepositante(contrato)
    if (!grupos.has(clave)) grupos.set(clave, [])
    grupos.get(clave).push(contrato)

    const numero = contrato?.numeroContrato || ''
    const match = numero.match(PATRON_NUMERO_CONTRATO_DEPOSITO)
    const cuatroDigitos = clave.split('|')[1]
    if (match && match[1] === cuatroDigitos) {
      const actual = maxPorClave.get(clave) || 0
      maxPorClave.set(clave, Math.max(actual, Number(match[2])))
      numerosPorId.set(contrato.id, numero)
    }
  })

  grupos.forEach((grupo, clave) => {
    const cuatroDigitos = clave.split('|')[1]
    let consecutivo = maxPorClave.get(clave) || 0

    const ordenados = [...grupo].sort((a, b) => {
      const fechaA = a.fechaInicio || ''
      const fechaB = b.fechaInicio || ''
      if (fechaA !== fechaB) return fechaA.localeCompare(fechaB)
      return String(a.id).localeCompare(String(b.id))
    })

    ordenados.forEach((contrato) => {
      if (numerosPorId.has(contrato.id)) return
      consecutivo += 1
      numerosPorId.set(
        contrato.id,
        `DEP-${cuatroDigitos}-${String(consecutivo).padStart(3, '0')}`
      )
    })
  })

  return contratos.map((contrato) => ({
    ...contrato,
    numeroContrato: numerosPorId.get(contrato.id) || contrato.numeroContrato || '',
  }))
}

const generarIdPagoLiquidacionDeposito = () =>
  `PAG-DEP-${Date.now()}-${Math.floor(Math.random() * 10000)}`

const contratoDepositoVigenteEnMes = (contrato, mes) => {
  if (!contrato || contrato.estado !== 'Activo' || !mes) return false
  const inicioMes = (contrato.fechaInicio || '').slice(0, 7)
  if (!inicioMes || mes < inicioMes) return false
  if (contrato.fechaFin && mes > contrato.fechaFin.slice(0, 7)) return false
  return true
}

// =============================================================================
// LIQUIDACION DEPOSITO - MES INICIO CONTRATOS
// Mes mas antiguo entre contrato de deposito y arriendos del predio.
// =============================================================================

const obtenerMesInicioLiquidacionDeposito = ({
  contratoDeposito,
  contratoArriendo = null,
  contratosArriendo = [],
  codigoPredio = '',
} = {}) => {
  const meses = [
    (contratoDeposito?.fechaInicio || '').slice(0, 7),
    (contratoArriendo?.fechaInicio || '').slice(0, 7),
    ...(contratosArriendo || [])
      .filter(
        (contrato) =>
          contrato.codigoPredio === (codigoPredio || contratoDeposito?.codigoPredio || '')
      )
      .map((contrato) => (contrato.fechaInicio || '').slice(0, 7)),
  ].filter(Boolean)

  return meses.sort()[0] || ''
}

// =============================================================================
// LIQUIDACION DEPOSITARIO - RECAUDO MENSUAL
// Recaudo del predio, claves de unidad y meses liquidables.
// =============================================================================

const obtenerRecaudoPredioMes = (codigoPredio, mes, contratosArriendo, pagosArriendo) => {
  const idsContratos = contratosArriendo
    .filter((contrato) => contrato.codigoPredio === codigoPredio)
    .map((contrato) => obtenerIdContrato(contrato))

  return pagosArriendo
    .filter((pago) => idsContratos.includes(pago.idContrato) && pago.mes === mes)
    .reduce((total, pago) => total + Number(pago.valorPagado || 0), 0)
}

// =============================================================================
// LIQUIDACION DEPOSITARIO - CLAVE UNIDAD
// Clave estable para liquidar y filtrar una unidad de negocio.
// =============================================================================

const obtenerClaveUnidadLiquidacion = ({
  idUnidad = '',
  unidad = '',
  idContratoArriendo = '',
  idContrato = '',
} = {}) =>
  idUnidad || `${unidad || 'sin-unidad'}-${idContratoArriendo || idContrato || ''}`

const coincideLineaUnidadLiquidacion = (linea, unidadLiquidacion) => {
  if (!unidadLiquidacion?.claveUnidad) return true

  const idContratoLinea =
    linea.idContratoVisible ||
    linea.idContrato ||
    linea.pago?.idContrato ||
    linea.contrato?.id ||
    ''
  const idContratoUnidad = unidadLiquidacion.idContratoArriendo || ''

  if (idContratoLinea && idContratoUnidad && idContratoLinea === idContratoUnidad) {
    const idUnidadLinea = linea.idUnidad || linea.pago?.idUnidad || ''
    const idUnidadRef = unidadLiquidacion.idUnidad || ''
    if (!idUnidadLinea || !idUnidadRef || idUnidadLinea === idUnidadRef) return true

    const unidadLinea = String(linea.unidad || linea.pago?.nombreUnidad || '')
      .trim()
      .toLowerCase()
    const unidadRef = String(unidadLiquidacion.unidad || '').trim().toLowerCase()
    if (unidadLinea && unidadRef && unidadLinea === unidadRef) return true
  }

  const claveLinea = obtenerClaveUnidadLiquidacion({
    idUnidad: linea.idUnidad || linea.pago?.idUnidad || '',
    unidad: linea.unidad,
    idContratoArriendo: idContratoLinea,
  })

  return claveLinea === unidadLiquidacion.claveUnidad
}

// =============================================================================
// LIQUIDACION DEPOSITO - COINCIDENCIA PAGO Y UNIDAD
// Empareja pagos y liquidaciones aunque la clave de unidad difiera del recibo.
// =============================================================================

const coincidePagoContratoArriendo = (pago, contrato) => {
  if (!pago || !contrato) return false
  const idContrato = obtenerIdContrato(contrato)
  if (!idContrato) return false

  if (
    pago.idContrato === idContrato ||
    pago.idContrato === contrato.id ||
    (pago.idContratoArriendo && pago.idContratoArriendo === idContrato)
  ) {
    return true
  }

  const codigoPredioPago = pago.codigoPredio || ''
  const codigoPredioContrato = contrato.codigoPredio || ''
  if (!codigoPredioPago || codigoPredioPago !== codigoPredioContrato) return false

  const idUnidadContrato = contrato.idUnidad || ''
  const idUnidadPago = pago.idUnidad || ''
  if (idUnidadContrato && idUnidadPago) return idUnidadContrato === idUnidadPago

  const unidadContrato = String(contrato.nombreUnidad || '').trim().toLowerCase()
  const unidadPago = String(pago.nombreUnidad || pago.unidad || '').trim().toLowerCase()
  if (unidadContrato && unidadPago) return unidadContrato === unidadPago

  return false
}

const coincideLiquidacionDepositoUnidadArriendo = ({
  liquidacion,
  idContratoArriendo = '',
  claveUnidad = '',
  contratoArriendo = null,
}) => {
  if (!liquidacion) return false

  const idContratoLiq = liquidacion.idContratoArriendo || ''
  if (idContratoArriendo && idContratoLiq === idContratoArriendo) return true

  const claveLiq =
    liquidacion.claveUnidad ||
    obtenerClaveUnidadLiquidacion({
      idUnidad: liquidacion.idUnidad || '',
      unidad: liquidacion.unidad || '',
      idContratoArriendo: idContratoLiq,
    })
  if (claveUnidad && claveLiq === claveUnidad) return true

  if (!contratoArriendo || !claveUnidad) return false

  return coincideLineaUnidadLiquidacion(
    {
      idContratoVisible: idContratoLiq,
      idUnidad: liquidacion.idUnidad,
      unidad: liquidacion.unidad,
    },
    {
      claveUnidad,
      idContratoArriendo,
      idUnidad: contratoArriendo.idUnidad || '',
      unidad: contratoArriendo.nombreUnidad || '',
    }
  )
}

const puntuacionLiquidacionDepositoMes = (liquidacion = {}) => {
  const detalleConValor = (liquidacion.detallePagos || []).filter(
    (pago) =>
      Number(pago.valorBruto || 0) > 0 ||
      Number(pago.valorCanonLiquidacion || 0) > 0 ||
      Number(pago.montoLiquidableAsignado || 0) > 0
  ).length

  return (
    detalleConValor * 1_000_000_000 +
    Number(liquidacion.totalRecaudadoPredio || 0) +
    Number(liquidacion.valorBrutoPropietario || 0) +
    Number(liquidacion.valorNetoTotal || 0)
  )
}

const consolidarLiquidacionesDepositoPorMes = (liquidaciones = []) => {
  const mapa = new Map()

  ;(liquidaciones || []).forEach((liquidacion) => {
    const mes = liquidacion.mes
    if (!mes) return

    const claveConsolidacion = `${mes}::${liquidacion.claveUnidad || liquidacion.idContratoArriendo || ''}`
    const actual = mapa.get(claveConsolidacion)
    if (
      !actual ||
      puntuacionLiquidacionDepositoMes(liquidacion) > puntuacionLiquidacionDepositoMes(actual)
    ) {
      mapa.set(claveConsolidacion, liquidacion)
    }
  })

  return [...mapa.values()].sort((a, b) => String(a.mes).localeCompare(String(b.mes)))
}

const encontrarLiquidacionDeposito = (
  liquidaciones = [],
  { idContratoDeposito, mes, idPropietario, claveUnidad = '' }
) => {
  const candidatas = (liquidaciones || []).filter(
    (item) =>
      item.idContratoDeposito === idContratoDeposito &&
      String(item.mes) === String(mes) &&
      String(item.idPropietario) === String(idPropietario)
  )

  const exacta = candidatas.find((item) => (item.claveUnidad || '') === (claveUnidad || ''))
  if (exacta) return exacta

  return (
    candidatas.find((item) =>
      coincideLiquidacionDepositoUnidadArriendo({
        liquidacion: item,
        claveUnidad,
        idContratoArriendo: item.idContratoArriendo || '',
      })
    ) || null
  )
}

const obtenerMesesLiquidacionPredio = ({
  codigoPredio,
  contratoDeposito,
  contratosArriendo,
  pagosArriendo,
  pagosLiquidacionDeposito = [],
  idPropietario = null,
}) => {
  if (!codigoPredio || !contratoDeposito) return []

  const inicioMes = obtenerMesInicioLiquidacionDeposito({
    contratoDeposito,
    contratosArriendo,
    codigoPredio,
  })
  const idsContratos = contratosArriendo
    .filter((contrato) => contrato.codigoPredio === codigoPredio)
    .map((contrato) => obtenerIdContrato(contrato))

  const mesesRecaudo = [
    ...new Set(
      pagosArriendo
        .filter(
          (pago) =>
            idsContratos.includes(pago.idContrato) &&
            Number(pago.valorPagado || 0) > 0 &&
            (!inicioMes || pago.mes >= inicioMes)
        )
        .map((pago) => pago.mes)
    ),
  ]

  const mesesConAbonoLiquidacion = pagosLiquidacionDeposito
    .filter(
      (pago) =>
        pago.codigoPredio === codigoPredio &&
        (!idPropietario || pago.idPropietario === idPropietario)
    )
    .map((pago) => pago.mes)

  const hoy = obtenerMesActualCalendarioISO()
  let mesFin = hoy
  const finContrato = (contratoDeposito.fechaFin || '').slice(0, 7)
  if (finContrato && finContrato < mesFin) mesFin = finContrato

  const mesesArriendo = contratosArriendo
    .filter((contrato) => contrato.codigoPredio === codigoPredio)
    .flatMap((contrato) => obtenerRangoMesesCausadosContrato(contrato, pagosArriendo))

  ;[...mesesRecaudo, ...mesesArriendo].forEach((mes) => {
    if (mes > mesFin) mesFin = mes
  })

  const mesesVigentesContrato =
    inicioMes && mesFin >= inicioMes
      ? listarMesesEntre(inicioMes, mesFin).filter((mes) =>
          contratoDepositoVigenteEnMes(contratoDeposito, mes)
        )
      : []

  return [...new Set([...mesesVigentesContrato, ...mesesRecaudo, ...mesesConAbonoLiquidacion])]
    .filter((mes) => contratoDepositoVigenteEnMes(contratoDeposito, mes))
    .sort()
}

// =============================================================================
// LIQUIDACION DEPOSITO - MESES LIQUIDABLES CONTRATO
// Meses a liquidar segun criterio fijo o recaudo parcial del arrendatario.
// =============================================================================

const obtenerMesesLiquidacionContratoDeposito = ({
  codigoPredio,
  contratoDeposito,
  contratosArriendo,
  pagosArriendo,
  pagosLiquidacionDeposito = [],
  idPropietario = null,
}) => {
  if (esPagoFijoLiquidacionCanonDeposito(contratoDeposito)) {
    const inicio = obtenerMesInicioLiquidacionDeposito({
      contratoDeposito,
      contratosArriendo,
      codigoPredio,
    })
    if (!inicio) return []

    const hoy = obtenerMesActualCalendarioISO()
    let mesFin = hoy
    const finContrato = (contratoDeposito.fechaFin || '').slice(0, 7)
    if (finContrato && finContrato < mesFin) mesFin = finContrato

    const mesesArriendo = contratosArriendo
      .filter((contrato) => contrato.codigoPredio === codigoPredio)
      .flatMap((contrato) => obtenerRangoMesesCausadosContrato(contrato, pagosArriendo))

    mesesArriendo.forEach((mes) => {
      if (mes > mesFin) mesFin = mes
    })

    if (mesFin < inicio) return [inicio]

    return listarMesesEntre(inicio, mesFin).filter((mes) =>
      contratoDepositoVigenteEnMes(contratoDeposito, mes)
    )
  }

  return obtenerMesesLiquidacionPredio({
    codigoPredio,
    contratoDeposito,
    contratosArriendo,
    pagosArriendo,
    pagosLiquidacionDeposito,
    idPropietario,
  })
}

const obtenerUnidadesLiquidacionMesDeposito = ({
  mes,
  codigoPredio,
  contrato,
  beneficiario,
  asignacionPredio,
  pagosLiquidacionDeposito,
  contratosArriendo,
}) => {
  const mapa = new Map()

  const agregarUnidad = (datos = {}) => {
    const claveUnidad = obtenerClaveUnidadLiquidacion(datos)
    if (!claveUnidad || mapa.has(claveUnidad)) return

    mapa.set(claveUnidad, {
      idUnidad: datos.idUnidad || '',
      unidad: datos.unidad || 'Sin unidad',
      idContratoArriendo: datos.idContratoArriendo || '',
      claveUnidad,
    })
  }

  if (esPagoFijoLiquidacionCanonDeposito(contrato)) {
    contratosArriendo
      .filter(
        (item) =>
          item.codigoPredio === codigoPredio && contratoArriendoActivoEnMes(item, mes)
      )
      .forEach((item) => {
        agregarUnidad({
          idUnidad: item.idUnidad || '',
          unidad: item.nombreUnidad,
          idContratoArriendo: obtenerIdContrato(item),
        })
      })
  } else {
    contratosArriendo
      .filter(
        (item) =>
          item.codigoPredio === codigoPredio && contratoArriendoActivoEnMes(item, mes)
      )
      .forEach((item) => {
        agregarUnidad({
          idUnidad: item.idUnidad || '',
          unidad: item.nombreUnidad,
          idContratoArriendo: obtenerIdContrato(item),
        })
      })

    ;(asignacionPredio?.asignacionGlobalPorMes?.get(mes) || []).forEach((linea) => {
      if (Number(linea.valorCanonLiquidacion || 0) <= 0) return
      agregarUnidad({
        idUnidad: linea.contrato?.idUnidad || linea.idUnidad || linea.pago?.idUnidad || '',
        unidad: linea.unidad || linea.contrato?.nombreUnidad,
        idContratoArriendo:
          linea.idContratoVisible || linea.idContrato || linea.contrato?.id || '',
      })
    })
  }

  pagosLiquidacionDeposito
    .filter(
      (pago) =>
        pago.codigoPredio === codigoPredio &&
        pago.idContratoDeposito === contrato.id &&
        String(pago.idPropietario) === String(beneficiario.idPropietario) &&
        String(pago.mes) === String(mes)
    )
    .forEach((pago) => {
      if (pago.claveUnidad || pago.idUnidad) {
        agregarUnidad({
          idUnidad: pago.idUnidad || '',
          unidad: pago.unidad,
          idContratoArriendo: pago.idContratoArriendo || '',
        })
        return
      }

      const unidadesAbono = pago.detalleUnidades || []
      if (unidadesAbono.length === 1) {
        agregarUnidad(unidadesAbono[0])
      }
    })

  return [...mapa.values()].sort((a, b) => String(a.unidad).localeCompare(String(b.unidad)))
}

const obtenerIdPagoArriendo = (pago) =>
  pago.id ||
  `${pago.idContrato}-${pago.mes}-${pago.recibo || 'sin-recibo'}-${pago.fechaPago || 'sin-fecha'}`

const obtenerPagosArriendoPredioMes = (codigoPredio, mes, contratosArriendo, pagosArriendo) => {
  const contratosPredio = contratosArriendo.filter(
    (contrato) => contrato.codigoPredio === codigoPredio
  )
  const idsContratos = contratosPredio.map((contrato) => obtenerIdContrato(contrato))

  return pagosArriendo
    .filter(
      (pago) =>
        idsContratos.includes(pago.idContrato) &&
        pago.mes === mes &&
        Number(pago.valorPagado || 0) > 0
    )
    .map((pago) => {
      const contrato = contratosPredio.find(
        (item) => obtenerIdContrato(item) === pago.idContrato
      )

      return {
        ...pago,
        idPagoArriendo: obtenerIdPagoArriendo(pago),
        contrato,
        idContratoVisible: contrato ? obtenerIdContrato(contrato) : pago.idContrato,
        unidad: pago.nombreUnidad || contrato?.nombreUnidad || 'Sin unidad',
      }
    })
    .sort((a, b) => String(a.fechaPago || '').localeCompare(String(b.fechaPago || '')))
}

const obtenerDetalleRecaudoPredioMes = (
  codigoPredio,
  mes,
  contratosArriendo,
  pagosArriendo
) => obtenerPagosArriendoPredioMes(codigoPredio, mes, contratosArriendo, pagosArriendo)

const pagoArriendoLiquidadoParaBeneficiario = (
  pago,
  idPropietario,
  codigoPredio,
  pagosLiquidacionDeposito,
  claveUnidadLiquidacion = ''
) => {
  const idPago = pago.idPagoArriendo || pago.claveAsignacion || obtenerIdPagoArriendo(pago)
  const mesAsignado = pago.mesAsignado || pago.mes
  const idPagoBase = idPago.includes('::') ? idPago.split('::')[0] : idPago
  const claveMes = mesAsignado ? `${idPagoBase}::${mesAsignado}` : idPago
  const claveAsignacionPago = pago.claveAsignacion || ''

  const coincideUnidadLiquidacion = (liquidacion) => {
    const claveRegistro = liquidacion.claveUnidad || ''
    if (!claveUnidadLiquidacion && !claveRegistro) return true
    if (claveRegistro === claveUnidadLiquidacion) return true
    return coincideLiquidacionDepositoUnidadArriendo({
      liquidacion: { claveUnidad: claveRegistro, idContratoArriendo: liquidacion.idContratoArriendo },
      claveUnidad: claveUnidadLiquidacion,
    })
  }

  const coincideIdLiquidacion = (idLiquidado) =>
    idLiquidado === idPago ||
    idLiquidado === claveMes ||
    idLiquidado === idPagoBase ||
    (claveAsignacionPago && idLiquidado === claveAsignacionPago)

  if (
    pagosLiquidacionDeposito.some(
      (liquidacion) =>
        liquidacion.idPropietario === idPropietario &&
        coincideUnidadLiquidacion(liquidacion) &&
        (coincideIdLiquidacion(liquidacion.idPagoArriendo) ||
          liquidacion.idsPagosArriendo?.some(coincideIdLiquidacion))
    )
  ) {
    return true
  }

  return pagosLiquidacionDeposito.some(
    (liquidacion) =>
      liquidacion.idPropietario === idPropietario &&
      liquidacion.codigoPredio === codigoPredio &&
      liquidacion.mes === mesAsignado &&
      coincideUnidadLiquidacion(liquidacion) &&
      !liquidacion.idsPagosArriendo?.length &&
      !liquidacion.idPagoArriendo
  )
}

const administracionIncluidaEnCanonContrato = (contrato) =>
  contrato?.administracionIncluidaEnCanon === 'Sí'

const contratoAplicaAdministracion = (contrato) =>
  contrato?.aplicaAdministracion === 'Sí'

const obtenerAdministracionCobroArrendatario = (contrato, administracion) =>
  contratoAplicaAdministracion(contrato) && !administracionIncluidaEnCanonContrato(contrato)
    ? Number(administracion || 0)
    : 0

// =============================================================================
// ARRIENDOS - CALCULO DE CANON Y ADMINISTRACION
// Canon puro, administracion y estructura del mes.
// =============================================================================

const calcularMontoCanonArrendatarioMes = ({
  canonBase,
  administracion,
  ivaCanon,
  contrato,
}) => {
  const adminCobro = obtenerAdministracionCobroArrendatario(contrato, administracion)
  return Number(canonBase || 0) + adminCobro + Number(ivaCanon || 0)
}

// =============================================================================
// ARRIENDOS - BASE LIQUIDACION ESTADO DE CUENTA
// Canon e IVA del canon sin administracion (modulo aparte).
// =============================================================================

const calcularBaseLiquidacionEstadoCuentaArriendoMes = (movimiento, contrato) => {
  const canonBase = Number(movimiento?.canonBase || 0)
  const ivaCanonMes = contratoAplicaIvaArriendo(contrato)
    ? calcularIvaArriendo(canonBase, contrato)
    : 0

  return {
    canonBase,
    ivaCanonMes,
    baseLiquidacion: canonBase + ivaCanonMes,
    baseMoraCanon: canonBase,
  }
}

const calcularPorcionPagoSobreCanonBaseArriendo = ({
  valorPagado = 0,
  canonBase = 0,
  ivaCanonMes = 0,
}) => {
  const canon = Number(canonBase || 0)
  const iva = Number(ivaCanonMes || 0)
  const pagado = Number(valorPagado || 0)
  const totalCausado = canon + iva
  if (pagado <= 0 || canon <= 0) return 0
  if (totalCausado <= 0) return Math.min(canon, pagado)
  return Math.min(canon, Math.round(pagado * (canon / totalCausado)))
}

const calcularPagadoCanonBaseArriendoMes = ({
  pagos = [],
  canonBase = 0,
  ivaCanonMes = 0,
}) =>
  (pagos || []).reduce((total, pago) => {
    const abonoCapital = obtenerAbonoCapitalPagoArriendo(pago)
    if (abonoCapital <= 0) return total
    return (
      total +
      calcularPorcionPagoSobreCanonBaseArriendo({
        valorPagado: abonoCapital,
        canonBase,
        ivaCanonMes,
      })
    )
  }, 0)

const calcularSaldoCanonBasePendienteArriendoMes = ({
  canonBase = 0,
  ivaCanonMes = 0,
  totalDescuento = 0,
  pagos = [],
}) => {
  const pagadoCanonBase = calcularPagadoCanonBaseArriendoMes({
    pagos,
    canonBase,
    ivaCanonMes,
  })
  return Math.max(0, Number(canonBase || 0) - Number(totalDescuento || 0) - pagadoCanonBase)
}

const reducirCapitalMoraPorPagoArriendo = (
  pago,
  { canonBase = 0, ivaCanonMes = 0, moraSobreCanonSinIva = false, saldoCapital = null }
) => {
  const abonoCapital = obtenerAbonoCapitalPagoArriendo(pago)
  if (pago?.abonoLiquidacionPeriodo) {
    const capitalReferencia =
      saldoCapital != null ? Number(saldoCapital) : Number(canonBase || 0)
    return Math.min(abonoCapital, Math.max(0, capitalReferencia))
  }
  if (!moraSobreCanonSinIva) return abonoCapital
  return calcularPorcionPagoSobreCanonBaseArriendo({
    valorPagado: abonoCapital,
    canonBase,
    ivaCanonMes,
  })
}

const calcularPorcionAsignacionLiquidacionArriendo = (asignacion) => {
  const valorAsignado = Number(asignacion?.valorCanonLiquidacion || 0)
  const canonArrendamiento = Number(asignacion?.canonArrendamientoMes || 0)
  if (valorAsignado <= 0) return 0
  if (canonArrendamiento <= 0) return valorAsignado

  const contrato = asignacion?.contrato
  const adminCobro = Number(asignacion?.administracionMes || 0)
  const baseLiquidacionArriendo =
    contratoAplicaAdministracion(contrato) &&
    !administracionIncluidaEnCanonContrato(contrato)
      ? Math.max(0, canonArrendamiento - adminCobro)
      : canonArrendamiento

  if (baseLiquidacionArriendo <= 0) return 0
  return Math.round(valorAsignado * (baseLiquidacionArriendo / canonArrendamiento))
}

const calcularMontoLiquidablePropietarioMes = ({
  canonBase,
  administracion,
  ivaCanon,
  contrato,
}) => {
  const base = Number(canonBase || 0)
  const iva = Number(ivaCanon || 0)
  const admin = contratoAplicaAdministracion(contrato) ? Number(administracion || 0) : 0

  if (administracionIncluidaEnCanonContrato(contrato)) {
    return Math.max(0, base - admin + iva)
  }

  return base + iva
}

const obtenerCanonComisionBaseMes = (contrato, canonBase, administracion) => {
  if (
    administracionIncluidaEnCanonContrato(contrato) &&
    contratoAplicaAdministracion(contrato)
  ) {
    return Math.max(0, Number(canonBase || 0) - Number(administracion || 0))
  }

  return Number(canonBase || 0)
}

const obtenerCanonArrendamientoDesdePago = (pago, contrato = null) => {
  const canonBase = Number(pago?.canonBase || 0)
  const administracion = Number(pago?.administracion || 0)
  const iva = Number(pago?.iva || 0)

  if (contrato) {
    return calcularMontoCanonArrendatarioMes({
      canonBase,
      administracion,
      ivaCanon: iva,
      contrato,
    })
  }

  if (canonBase > 0 || administracion > 0 || iva > 0) {
    return canonBase + administracion + iva
  }

  return Number(pago?.canonCausado || 0)
}

const obtenerAdministracionContratoPuro = (contrato, anioPago, ajustesAdministracion = []) => {
  if (!contrato || contrato.aplicaAdministracion !== 'Sí') return 0

  const idContratoActual = obtenerIdContrato(contrato)
  const ajusteAplicable = (ajustesAdministracion || [])
    .filter(
      (ajuste) =>
        ajuste.idContrato === idContratoActual && Number(ajuste.anio) <= Number(anioPago)
    )
    .sort((a, b) => Number(b.anio) - Number(a.anio))[0]

  if (ajusteAplicable) return Number(ajusteAplicable.valorAdministracion || 0)

  return Number(contrato.valorAdministracion || 0)
}

const resolverCanonBaseMesArriendo = (contrato, mes, incrementosArriendo = []) => {
  if (!contrato?.fechaInicio || !mes) {
    return { canonBase: 0, incrementoAplicado: 0 }
  }

  const anioPago = Number(mes.substring(0, 4))
  const mesRenovacionCanon = contrato.fechaRenovacionCanon
    ? String(contrato.fechaRenovacionCanon).slice(0, 7)
    : null
  const tieneRenovacionCanon =
    mesRenovacionCanon && contrato.canonMensualAnterior != null

  const buscarIncrementoAnio = (anio) => {
    const incrementoDelAnio = (incrementosArriendo || []).find(
      (incremento) =>
        incremento.codigoPredio === contrato.codigoPredio &&
        Number(incremento.anio) === Number(anio)
    )
    return incrementoDelAnio?.porcentaje ?? Number(contrato.incrementoAnual || 0)
  }

  let canonBase = 0
  let incrementoAplicado = 0

  if (tieneRenovacionCanon && mes >= mesRenovacionCanon) {
    canonBase = Number(contrato.canonMensual || 0)
    const anioRenovacion = Number(mesRenovacionCanon.substring(0, 4))
    for (let anio = anioRenovacion + 1; anio <= anioPago; anio += 1) {
      const porcentaje = buscarIncrementoAnio(anio)
      canonBase = Math.round(canonBase * (1 + porcentaje / 100))
      if (anio === anioPago) incrementoAplicado = porcentaje
    }
    return { canonBase, incrementoAplicado }
  }

  if (tieneRenovacionCanon && mes < mesRenovacionCanon) {
    canonBase = Number(contrato.canonMensualAnterior ?? contrato.canonMensual ?? 0)
  } else {
    canonBase = Number(contrato.canonMensual || 0)
  }

  const anioInicio = Number(contrato.fechaInicio.substring(0, 4))
  for (let anio = anioInicio + 1; anio <= anioPago; anio += 1) {
    const porcentaje = buscarIncrementoAnio(anio)
    canonBase = Math.round(canonBase * (1 + porcentaje / 100))
    if (anio === anioPago) incrementoAplicado = porcentaje
  }

  return { canonBase, incrementoAplicado }
}

const calcularCanonArriendoPuro = (
  contrato,
  mes,
  incrementosArriendo = [],
  ajustesAdministracion = []
) => {
  if (!contrato || !mes || !contrato.fechaInicio) {
    return { canonBase: 0, administracion: 0, iva: 0, canonCausado: 0 }
  }

  const anioPago = Number(mes.substring(0, 4))
  const { canonBase } = resolverCanonBaseMesArriendo(contrato, mes, incrementosArriendo)

  const administracion = obtenerAdministracionContratoPuro(
    contrato,
    anioPago,
    ajustesAdministracion
  )
  const aplicaIva = contrato.aplicaIva === 'Sí'
  const iva = aplicaIva ? Math.round(canonBase * 0.19) : 0
  const administracionCobro = obtenerAdministracionCobroArrendatario(contrato, administracion)
  const canonCausado = canonBase + administracionCobro + iva

  return {
    canonBase,
    administracion,
    administracionCobro,
    administracionIncluidaEnCanon: administracionIncluidaEnCanonContrato(contrato),
    iva,
    canonCausado,
    aplicaIvaCanon: aplicaIva,
  }
}

const obtenerEstructuraCanonMes = ({
  contrato,
  mes,
  pagoReferencia = null,
  incrementosArriendo = [],
  ajustesAdministracion = [],
}) => {
  const calculoContrato = calcularCanonArriendoPuro(
    contrato,
    mes,
    incrementosArriendo,
    ajustesAdministracion
  )

  let canonBase = Number(calculoContrato.canonBase || 0)
  let administracion = Number(calculoContrato.administracion || 0)
  const aplicaIvaCanon = calculoContrato.aplicaIvaCanon ?? contrato?.aplicaIva === 'Sí'
  let ivaCanon = aplicaIvaCanon ? Number(calculoContrato.iva || 0) : 0

  if (pagoReferencia && Number(pagoReferencia.canonBase || 0) > 0) {
    canonBase = Number(pagoReferencia.canonBase || 0)

    const administracionPago = Number(pagoReferencia.administracion || 0)
    administracion =
      administracionPago > 0
        ? administracionPago
        : contrato?.aplicaAdministracion === 'Sí'
        ? Number(calculoContrato.administracion || 0)
        : 0

    ivaCanon = aplicaIvaCanon ? Number(pagoReferencia.iva || calculoContrato.iva || 0) : 0
  }

  const canonComisionBase = obtenerCanonComisionBaseMes(contrato, canonBase, administracion)
  const administracionCobro = obtenerAdministracionCobroArrendatario(contrato, administracion)
  const canonArrendamiento = canonBase + administracionCobro + ivaCanon
  const montoLiquidablePropietario = calcularMontoLiquidablePropietarioMes({
    canonBase,
    administracion,
    ivaCanon,
    contrato,
  })

  return {
    canonBase,
    administracion,
    administracionCobro,
    administracionIncluidaEnCanon: administracionIncluidaEnCanonContrato(contrato),
    ivaCanon,
    canonComisionBase,
    canonArrendamiento,
    montoLiquidablePropietario,
    aplicaIvaCanon,
  }
}

const listarMesesEntre = (mesInicio, mesFin) => {
  if (!mesInicio) return []
  if (!mesFin || mesFin < mesInicio) return [mesInicio]

  const meses = []
  let anio = Number(mesInicio.slice(0, 4))
  let mes = Number(mesInicio.slice(5, 7))
  const anioFin = Number(mesFin.slice(0, 4))
  const mesFinNum = Number(mesFin.slice(5, 7))

  while (anio < anioFin || (anio === anioFin && mes <= mesFinNum)) {
    meses.push(`${anio}-${String(mes).padStart(2, '0')}`)
    mes += 1
    if (mes > 12) {
      mes = 1
      anio += 1
    }
  }

  return meses
}

// =============================================================================
// CALENDARIO - RESTAR MESES ISO
// Resta meses a una fecha YYYY-MM sin cambiar el dia.
// =============================================================================

const restarMesesCalendarioISO = (mesISO = '', cantidad = 0) => {
  if (!mesISO || cantidad <= 0) return mesISO

  let anio = Number(mesISO.slice(0, 4))
  let mes = Number(mesISO.slice(5, 7))
  mes -= cantidad

  while (mes <= 0) {
    mes += 12
    anio -= 1
  }

  return `${anio}-${String(mes).padStart(2, '0')}`
}

const obtenerMesActualCalendarioISO = () => new Date().toISOString().slice(0, 7)

const obtenerTopeMesCausacionContrato = (contrato) => {
  const hoy = obtenerMesActualCalendarioISO()
  const finContrato = (contrato?.fechaFin || '').slice(0, 7)
  if (finContrato && finContrato < hoy) return finContrato
  return hoy
}

const obtenerRangoMesesCausadosContrato = (contrato, pagosContrato = []) => {
  const inicio = (contrato?.fechaInicio || '').slice(0, 7)
  if (!inicio) return []

  const mesesRegistro = [...new Set((pagosContrato || []).map((pago) => pago.mes).filter(Boolean))]
    .sort()
  const mesesFecha = [...new Set(
    (pagosContrato || [])
      .map((pago) => (pago.fechaPago || '').slice(0, 7))
      .filter(Boolean)
  )].sort()

  const ultimoMesRegistro = mesesRegistro[mesesRegistro.length - 1] || ''
  const ultimoMesFecha = mesesFecha[mesesFecha.length - 1] || ''
  let mesFin = obtenerTopeMesCausacionContrato(contrato)

  if (ultimoMesRegistro && ultimoMesRegistro > mesFin) mesFin = ultimoMesRegistro
  if (ultimoMesFecha && ultimoMesFecha > mesFin) mesFin = ultimoMesFecha

  if (mesFin < inicio) return [inicio]
  return listarMesesEntre(inicio, mesFin)
}

// =============================================================================
// LIQUIDACION DEPOSITO - ASIGNACION PROPORCIONAL PAGOS PARCIALES
// Canon e IVA liquidables segun la proporcion del abono sobre la obligacion total.
// Excluye mora, gastos de cobranza y sus IVA de la liquidacion al depositante.
// =============================================================================

const calcularAsignacionCanonDepositoDesdeAbonoParcial = ({
  valorAbonoPeriodo = 0,
  saldoObligacionPeriodo = 0,
  montoLiquidableMes = 0,
  montoLiquidablePendiente = 0,
  canonArrendamientoMes = 0,
  canonPendiente = 0,
  periodoLiquidadoTotal = false,
}) => {
  if (periodoLiquidadoTotal) {
    return {
      montoLiquidableAsignado: Math.max(0, Number(montoLiquidablePendiente || 0)),
      valorCanonLiquidacion: Math.max(0, Number(canonPendiente || 0)),
      ratioObligacion: 1,
    }
  }

  const saldoObligacion = Math.max(0, Number(saldoObligacionPeriodo || 0))
  const valorAbono = Math.max(0, Number(valorAbonoPeriodo || 0))
  if (valorAbono <= 0 || saldoObligacion <= 0) {
    return { montoLiquidableAsignado: 0, valorCanonLiquidacion: 0, ratioObligacion: 0 }
  }

  const ratioObligacion = Math.min(1, valorAbono / saldoObligacion)
  const montoLiquidableMesNum = Math.max(0, Number(montoLiquidableMes || 0))
  const montoLiquidableAsignado = Math.min(
    Math.max(0, Number(montoLiquidablePendiente || 0)),
    Math.round(montoLiquidableMesNum * ratioObligacion)
  )
  const ratioCanon =
    montoLiquidableMesNum > 0 ? Number(canonArrendamientoMes || 0) / montoLiquidableMesNum : 1
  const valorCanonLiquidacion = Math.min(
    Math.max(0, Number(canonPendiente || 0)),
    Math.round(montoLiquidableAsignado * ratioCanon)
  )

  return { montoLiquidableAsignado, valorCanonLiquidacion, ratioObligacion }
}

// =============================================================================
// LIQUIDACION DEPOSITARIO - CANON DESDE CASCADA PERIODO
// Aplica abonos del arrendatario en cascada sobre canon + IVA liquidable por mes.
// =============================================================================

const registrarAsignacionCanonLiquidacionDepositoMes = ({
  asignacionesPorMes,
  estadoMeses,
  mes,
  pago,
  montoLiquidableAsignado,
  valorCanonLiquidacion,
  saldoLiquidableAntesAbono,
  contrato,
  saldoObligacionPeriodoAntesAbono = 0,
}) => {
  const estado = estadoMeses.get(mes)
  if (!estado || montoLiquidableAsignado <= 0 || valorCanonLiquidacion <= 0) return

  estado.montoLiquidablePendiente = Math.max(
    0,
    estado.montoLiquidablePendiente - montoLiquidableAsignado
  )
  estado.canonPendiente = Math.max(0, estado.canonPendiente - valorCanonLiquidacion)
  estado.canonAcumuladoCubierto += valorCanonLiquidacion
  estado.montoLiquidableAcumuladoCubierto += montoLiquidableAsignado

  const montoLiquidableMes = Number(estado.montoLiquidablePropietario || 0)
  const porcentajeAbonoCanonAcumulado =
    montoLiquidableMes > 0
      ? Math.min(
          100,
          Math.round(
            (estado.montoLiquidableAcumuladoCubierto / montoLiquidableMes) * 10000
          ) / 100
        )
      : estado.canonArrendamiento > 0
      ? Math.min(
          100,
          Math.round(
            (estado.canonAcumuladoCubierto / estado.canonArrendamiento) * 10000
          ) / 100
        )
      : estado.montoLiquidableAcumuladoCubierto > 0
      ? 100
      : 0

  const porcentajeAbonoCanonPago =
    montoLiquidableMes > 0
      ? Math.min(
          100,
          Math.round((montoLiquidableAsignado / montoLiquidableMes) * 10000) / 100
        )
      : estado.canonArrendamiento > 0
      ? Math.min(
          100,
          Math.round((valorCanonLiquidacion / estado.canonArrendamiento) * 10000) / 100
        )
      : montoLiquidableAsignado > 0
      ? 100
      : 0

  const mesPagadoEnTotalidad = porcentajeAbonoCanonAcumulado >= 100
  const canonComisionBaseMes = Number(estado.canonComisionBase || 0)
  const baseComisionAsignada = mesPagadoEnTotalidad
    ? Math.round(canonComisionBaseMes)
    : montoLiquidableMes > 0
      ? Math.round(canonComisionBaseMes * (montoLiquidableAsignado / montoLiquidableMes))
      : estado.canonArrendamiento > 0
        ? Math.round(canonComisionBaseMes * (valorCanonLiquidacion / estado.canonArrendamiento))
        : 0
  const claveAsignacion = obtenerIdPagoArriendo(pago)
  const claveMesPago = `${claveAsignacion}::${mes}`

  asignacionesPorMes.get(mes).set(claveMesPago, {
    claveAsignacion: claveMesPago,
    idPagoArriendo: claveAsignacion,
    valorCanonLiquidacion,
    montoLiquidableAsignado,
    baseComisionAsignada,
    canonBaseMes: estado.canonBase,
    administracionMes: estado.administracion,
    ivaCanonMes: estado.ivaCanon,
    montoLiquidablePropietario: estado.montoLiquidablePropietario,
    canonArrendamientoMes: estado.canonArrendamiento,
    canonComisionBaseMes: estado.canonComisionBase,
    contrato,
    canonAcumuladoCubierto: estado.canonAcumuladoCubierto,
    montoLiquidableAcumuladoCubierto: estado.montoLiquidableAcumuladoCubierto,
    porcentajeAbonoCanonAcumulado,
    porcentajeAbonoCanonPago,
    saldoPeriodoAntesAbono: Number(saldoLiquidableAntesAbono || 0),
    saldoObligacionPeriodoAntesAbono: Number(saldoObligacionPeriodoAntesAbono || 0),
    mesAsignado: mes,
    mesPagoOriginal: pago.mes,
    fechaPago: pago.fechaPago || '',
    esAbonoParcial: porcentajeAbonoCanonAcumulado < 100,
    esPagoTotalMes: porcentajeAbonoCanonAcumulado >= 100,
    tipoLiquidacionMes:
      porcentajeAbonoCanonAcumulado >= 100 ? 'Pago total mes' : 'Abono parcial mes',
    pago,
  })
}

// =============================================================================
// LIQUIDACION DEPOSITARIO - CANON DESDE CASCADA PERIODO
// Replica la cascada del arriendo y extrae solo canon + IVA liquidable al depositante.
// =============================================================================

const asignarPagosCanonLiquidacionContratoMultimes = ({
  contrato,
  pagosContrato = [],
  incrementosArriendo = [],
  ajustesAdministracion = [],
  gestionesCartera = [],
}) => {
  const asignacionesPorMes = new Map()
  const pagosOrdenados = ordenarPagosArriendoCronologico(
    (pagosContrato || []).filter((pago) => Number(pago.valorPagado || 0) > 0)
  )

  if (pagosOrdenados.length === 0) return asignacionesPorMes

  const mesesCausados = obtenerRangoMesesCausadosContrato(contrato, pagosOrdenados)
  const estadoMeses = new Map()

  mesesCausados.forEach((mes) => {
    const pagoReferencia = pagosOrdenados.find((pago) => pago.mes === mes)
    const canonInfo = obtenerEstructuraCanonMes({
      contrato,
      mes,
      pagoReferencia,
      incrementosArriendo,
      ajustesAdministracion,
    })

    estadoMeses.set(mes, {
      mes,
      ...canonInfo,
      canonPendiente: canonInfo.canonArrendamiento,
      montoLiquidablePendiente: canonInfo.montoLiquidablePropietario,
      canonAcumuladoCubierto: 0,
      montoLiquidableAcumuladoCubierto: 0,
    })
    asignacionesPorMes.set(mes, new Map())
  })

  const asignacionesPeriodo = asignarPagosLiquidacionPeriodoContratoMultimes({
    contrato,
    pagosContrato: pagosOrdenados,
    incrementosArriendo,
    ajustesAdministracion,
    gestionesCartera,
  })

  ;[...mesesCausados].sort().forEach((mes) => {
    const asignacionesMes = asignacionesPeriodo.get(mes)
    if (!asignacionesMes?.size) return

    const asignacionesOrdenadas = [...asignacionesMes.values()].sort((a, b) => {
      const fechaA = a.fechaPago || a.pago?.fechaPago || ''
      const fechaB = b.fechaPago || b.pago?.fechaPago || ''
      const fechaComparacion = String(fechaA).localeCompare(String(fechaB))
      if (fechaComparacion !== 0) return fechaComparacion
      return String(a.claveAsignacion || '').localeCompare(String(b.claveAsignacion || ''))
    })

    asignacionesOrdenadas.forEach((asignacionPeriodo) => {
      const estado = estadoMeses.get(mes)
      if (!estado || estado.montoLiquidablePendiente <= 0) return

      const saldoLiquidableAntesAbono = estado.montoLiquidablePendiente
      const { montoLiquidableAsignado, valorCanonLiquidacion } =
        calcularAsignacionCanonDepositoDesdeAbonoParcial({
          valorAbonoPeriodo: Number(asignacionPeriodo.valorLiquidacionPeriodo || 0),
          saldoObligacionPeriodo: Number(asignacionPeriodo.saldoPeriodoAntesAbono || 0),
          montoLiquidableMes: estado.montoLiquidablePropietario,
          montoLiquidablePendiente: estado.montoLiquidablePendiente,
          canonArrendamientoMes: estado.canonArrendamiento,
          canonPendiente: estado.canonPendiente,
          periodoLiquidadoTotal: Boolean(asignacionPeriodo.periodoLiquidadoTotal),
        })

      if (montoLiquidableAsignado <= 0 || valorCanonLiquidacion <= 0) return

      registrarAsignacionCanonLiquidacionDepositoMes({
        asignacionesPorMes,
        estadoMeses,
        mes,
        pago: asignacionPeriodo.pago,
        montoLiquidableAsignado,
        valorCanonLiquidacion,
        saldoLiquidableAntesAbono,
        contrato,
        saldoObligacionPeriodoAntesAbono: Number(asignacionPeriodo.saldoPeriodoAntesAbono || 0),
      })
    })
  })

  return asignacionesPorMes
}

// =============================================================================
// ARRIENDO - MOVIMIENTO VIRTUAL LIQUIDACION
// Simula un mes con abonos asignados para calcular saldo pendiente a una fecha.
// =============================================================================

const obtenerDescuentoMesPagosArriendo = (mes, pagosContrato = []) =>
  (pagosContrato || [])
    .filter((pago) => pago.mes === mes)
    .reduce((total, pago) => total + Number(pago.descuento || 0), 0)

const obtenerMoraGestionMesContrato = (idContrato, mes, gestionesCartera = []) =>
  (gestionesCartera || [])
    .filter((gestion) => gestion.idContrato === idContrato && gestion.mes === mes)
    .reduce((total, gestion) => total + Number(gestion.mora || 0), 0)

// =============================================================================
// ARRIENDO - MOVIMIENTO VIRTUAL LIQUIDACION
// Simula un mes con abonos asignados para calcular saldo pendiente a una fecha.
// =============================================================================

const construirMovimientoVirtualLiquidacionMesArriendo = ({
  contrato,
  mes,
  pagosAsignados = [],
  pagosContrato = [],
  incrementosArriendo = [],
  ajustesAdministracion = [],
  gestionesCartera = [],
}) => {
  const idContrato = obtenerIdContrato(contrato)
  const pagoReferencia = (pagosContrato || []).find((pago) => pago.mes === mes)
  const canonInfo = obtenerEstructuraCanonMes({
    contrato,
    mes,
    pagoReferencia,
    incrementosArriendo,
    ajustesAdministracion,
  })
  const pagosLiquidacion = (pagosAsignados || []).map((asignacion) => ({
    ...asignacion.pago,
    valorPagado: Number(asignacion.valorAsignado || 0),
    mora: 0,
    abonoLiquidacionPeriodo: true,
  }))
  const totalPagado = pagosLiquidacion.reduce(
    (total, pago) => total + Number(pago.valorPagado || 0),
    0
  )

  return {
    mes,
    canonBase: canonInfo.canonBase,
    administracion: canonInfo.administracion,
    descuento: obtenerDescuentoMesPagosArriendo(mes, pagosContrato),
    moraGestion: obtenerMoraGestionMesContrato(idContrato, mes, gestionesCartera),
    pagosLiquidacionArriendoMes: pagosLiquidacion,
    pagosMes: pagosLiquidacion,
    pagado: totalPagado,
    totalPagadoLiquidacionArriendo: totalPagado,
  }
}

// =============================================================================
// ARRIENDO - SALDO PENDIENTE CASCADA LIQUIDACION
// Saldo liquidado del periodo a una fecha menos abonos ya asignados en cascada.
// =============================================================================

const calcularSaldoPendienteAsignacionLiquidacionPeriodoArriendo = ({
  contrato,
  mes,
  fechaCorte = '',
  pagosAsignadosPeriodo = [],
  pagosContrato = [],
  incrementosArriendo = [],
  ajustesAdministracion = [],
  gestionesCartera = [],
}) => {
  const obligacionPeriodo = calcularObligacionBrutaLiquidacionPeriodoArriendo({
    contrato,
    mes,
    fechaCorte,
    pagosContrato,
    incrementosArriendo,
    ajustesAdministracion,
    gestionesCartera,
  })
  const pagadoAsignado = (pagosAsignadosPeriodo || []).reduce(
    (total, asignacion) => total + Number(asignacion.valorAsignado || 0),
    0
  )

  return Math.max(0, obligacionPeriodo - pagadoAsignado)
}

// =============================================================================
// ARRIENDO - OBLIGACION BRUTA LIQUIDACION PERIODO
// Total causado del periodo a una fecha sin reducir mora por abonos asignados.
// =============================================================================

const calcularObligacionBrutaLiquidacionPeriodoArriendo = ({
  contrato,
  mes,
  fechaCorte = '',
  pagosContrato = [],
  incrementosArriendo = [],
  ajustesAdministracion = [],
  gestionesCartera = [],
}) => {
  const movimientoBruto = construirMovimientoVirtualLiquidacionMesArriendo({
    contrato,
    mes,
    pagosAsignados: [],
    pagosContrato,
    incrementosArriendo,
    ajustesAdministracion,
    gestionesCartera,
  })
  const liquidacion = calcularCargosLiquidadosPeriodoExtractoArriendo({
    contrato,
    movimiento: movimientoBruto,
    fechaCorte,
  })

  return Math.max(
    0,
    Number(liquidacion.totalCargosPeriodo || 0) - Number(movimientoBruto.descuento || 0)
  )
}

const calcularTotalCargosFilasLiquidacionPeriodoArriendo = (liquidacion, movimiento) => {
  const canonBase = Number(movimiento?.canonBase || liquidacion?.baseMoraCanon || 0)
  const ivaCanonMes = Number(liquidacion?.ivaCanonMes || 0)
  const moraContrato = Number(liquidacion?.moraContrato || 0)
  const moraGestion = Number(liquidacion?.moraGestion || 0)
  const ivaMora = Number(liquidacion?.ivaMora || 0)
  const sancionCobranza = Number(liquidacion?.sancionCobranza || 0)
  const ivaGastosCobranza = Number(liquidacion?.ivaGastosCobranza || 0)

  return (
    canonBase +
    ivaCanonMes +
    moraContrato +
    moraGestion +
    ivaMora +
    sancionCobranza +
    ivaGastosCobranza
  )
}

const obtenerFechaCorteLiquidacionPeriodoArriendo = (
  pagosDetalleLiquidacion = [],
  fechaCorteEfectiva = ''
) => {
  const fechasAbono = (pagosDetalleLiquidacion || [])
    .map((pago) => pago?.fechaPago)
    .filter((fecha) => fecha && fecha !== 'Sin pago')

  if (!fechasAbono.length) return fechaCorteEfectiva

  return fechasAbono.sort((a, b) => compararFechasISO(b, a))[0]
}

// =============================================================================
// ARRIENDO - ASIGNACION LIQUIDACION POR PERIODO
// Cascada del valor pagado contra el total liquidado de cada periodo (mas antiguo primero).
// =============================================================================

const asignarPagosLiquidacionPeriodoContratoMultimes = ({
  contrato,
  pagosContrato = [],
  incrementosArriendo = [],
  ajustesAdministracion = [],
  gestionesCartera = [],
}) => {
  const asignacionesPorMes = new Map()
  const pagosOrdenados = ordenarPagosArriendoCronologico(
    (pagosContrato || []).filter((pago) => Number(pago.valorPagado || 0) > 0)
  )

  if (pagosOrdenados.length === 0) return asignacionesPorMes

  const mesesCausados = obtenerRangoMesesCausadosContrato(contrato, pagosOrdenados)
  const asignacionesAcumuladasMes = new Map()

  mesesCausados.forEach((mes) => {
    asignacionesPorMes.set(mes, new Map())
    asignacionesAcumuladasMes.set(mes, [])
  })

  const calcularSaldoPendienteMesEnFecha = (mes, fechaCorte) =>
    calcularSaldoPendienteAsignacionLiquidacionPeriodoArriendo({
      contrato,
      mes,
      fechaCorte,
      pagosAsignadosPeriodo: asignacionesAcumuladasMes.get(mes) || [],
      pagosContrato: pagosOrdenados,
      incrementosArriendo,
      ajustesAdministracion,
      gestionesCartera,
    })

  pagosOrdenados.forEach((pago) => {
    let restante = Math.max(0, Number(pago.valorPagado || 0))
    const claveAsignacion = obtenerIdPagoArriendo(pago)
    const fechaLiquidacion =
      pago.fechaCalculoIntereses ||
      pago.fechaPago ||
      obtenerFechaLocalISO()

    mesesCausados.forEach((mes) => {
      if (restante <= 0) return

      const saldoPendiente = calcularSaldoPendienteMesEnFecha(mes, fechaLiquidacion)
      if (saldoPendiente <= 0) return

      const valorAsignado = Math.min(restante, saldoPendiente)
      if (valorAsignado <= 0) return
      restante -= valorAsignado

      asignacionesAcumuladasMes.get(mes).push({
        pago,
        valorAsignado,
        saldoPeriodoAntesAbono: saldoPendiente,
      })

      const pagoReferencia = pagosOrdenados.find((item) => item.mes === mes)
      const canonInfo = obtenerEstructuraCanonMes({
        contrato,
        mes,
        pagoReferencia,
        incrementosArriendo,
        ajustesAdministracion,
      })
      const claveMesPago = `${claveAsignacion}::${mes}`
      const periodoLiquidadoTotal =
        valorAsignado >= saldoPendiente && saldoPendiente > 0

      asignacionesPorMes.get(mes).set(claveMesPago, {
        claveAsignacion: claveMesPago,
        idPagoArriendo: claveAsignacion,
        valorLiquidacionPeriodo: valorAsignado,
        saldoPeriodoAntesAbono: saldoPendiente,
        periodoLiquidadoTotal,
        canonBaseMes: canonInfo.canonBase,
        administracionMes: canonInfo.administracion,
        montoLiquidablePropietario: canonInfo.montoLiquidablePropietario,
        canonArrendamientoMes: canonInfo.canonArrendamiento,
        canonComisionBaseMes: canonInfo.canonComisionBase,
        contrato,
        mesAsignado: mes,
        mesPagoOriginal: pago.mes,
        fechaPago: pago.fechaPago || '',
        pago,
      })
    })
  })

  return asignacionesPorMes
}

// =============================================================================
// ARRIENDO - APLICACION DE PAGOS POR MES
// Canon asignado con la misma logica multimes que liquidacion depositario.
// =============================================================================

const obtenerAplicacionPagosArriendoMes = (
  contrato,
  mes,
  pagosArriendo = [],
  incrementosArriendo = [],
  ajustesAdministracion = [],
  gestionesCartera = []
) => {
  const idContrato = obtenerIdContrato(contrato)
  const pagosContrato = (pagosArriendo || []).filter(
    (pago) => coincidePagoContratoArriendo(pago, contrato) && Number(pago.valorPagado || 0) > 0
  )
  const pagosRegistroMes = (pagosArriendo || []).filter(
    (pago) => coincidePagoContratoArriendo(pago, contrato) && pago.mes === mes
  )

  const asignacionesCanonPorMes = asignarPagosCanonLiquidacionContratoMultimes({
    contrato,
    pagosContrato,
    incrementosArriendo,
    ajustesAdministracion,
    gestionesCartera,
  })

  const asignacionesLiquidacionPorMes = asignarPagosLiquidacionPeriodoContratoMultimes({
    contrato,
    pagosContrato,
    incrementosArriendo,
    ajustesAdministracion,
    gestionesCartera,
  })

  const asignacionesMes = asignacionesCanonPorMes.get(mes)
  const asignacionesLiquidacionMes = asignacionesLiquidacionPorMes.get(mes)
  const pagosDelMes = []
  const pagosLiquidacionArriendoMes = []
  const pagosDetalle = []
  const pagosDetalleLiquidacionArriendo = []
  let totalCanonAsignadoMes = 0
  let totalPagadoLiquidacionArriendoMes = 0
  let ultimoPago = null

  const registrarLinea = (
    pago,
    valorLinea,
    moraLinea = 0,
    destino = 'completo',
    metaAsignacion = {}
  ) => {
    if (valorLinea <= 0) return

    const pagoLinea = {
      ...pago,
      valorPagado: valorLinea,
      mora: moraLinea,
      valorCanonAsignadoMes: moraLinea > 0 ? 0 : valorLinea,
      mesAsignadoCanon: mes,
      abonoLiquidacionPeriodo: destino === 'liquidacion' || destino === 'ambos',
      saldoPeriodoAntesAbono: Number(metaAsignacion.saldoPeriodoAntesAbono || 0),
      periodoLiquidadoTotal: Boolean(metaAsignacion.periodoLiquidadoTotal),
    }

    const detalleLinea = {
      id:
        pago.id ||
        `${pago.fechaPago || 'sin-fecha'}-${pago.recibo || 'sin-recibo'}-${mes}-${valorLinea}`,
      fechaPago: pago.fechaPago || 'Sin pago',
      recibo: pago.recibo || 'Sin recibo',
      valorPagado: valorLinea,
      saldoPeriodoAntesAbono: Number(metaAsignacion.saldoPeriodoAntesAbono || 0),
      periodoLiquidadoTotal: Boolean(metaAsignacion.periodoLiquidadoTotal),
      concepto: pago.concepto || '',
      medioPago: pago.medioPago || '',
      mora: moraLinea,
    }

    if (destino === 'completo' || destino === 'ambos') {
      pagosDelMes.push(pagoLinea)
      pagosDetalle.push(detalleLinea)
    }

    if (destino === 'liquidacion' || destino === 'ambos') {
      pagosLiquidacionArriendoMes.push(pagoLinea)
      pagosDetalleLiquidacionArriendo.push(detalleLinea)
    }

    if (!ultimoPago || compararFechasISO(pago.fechaPago, ultimoPago.fechaPago) > 0) {
      ultimoPago = pago
    }
  }

  if (asignacionesMes?.size) {
    asignacionesMes.forEach((asignacion) => {
      const pago = asignacion.pago
      const valorCanon = Number(asignacion.valorCanonLiquidacion || 0)
      if (valorCanon <= 0) return

      totalCanonAsignadoMes += valorCanon
      registrarLinea(pago, valorCanon, 0, 'completo')
    })
  }

  if (asignacionesLiquidacionMes?.size) {
    asignacionesLiquidacionMes.forEach((asignacion) => {
      const pago = asignacion.pago
      const valorPeriodo = Number(asignacion.valorLiquidacionPeriodo || 0)
      if (valorPeriodo <= 0) return

      totalPagadoLiquidacionArriendoMes += valorPeriodo
      registrarLinea(pago, valorPeriodo, 0, 'liquidacion', {
        saldoPeriodoAntesAbono: asignacion.saldoPeriodoAntesAbono,
        periodoLiquidadoTotal: asignacion.periodoLiquidadoTotal,
      })
    })
  }

  const totalDescuentoMes = pagosRegistroMes.reduce(
    (total, pago) => total + Number(pago.descuento || 0),
    0
  )
  const totalPagadoMes = totalCanonAsignadoMes
  const totalPagadoLiquidacionArriendo = totalPagadoLiquidacionArriendoMes
  const totalMoraPagadaRegistro = 0

  const recibosDelMes = [
    ...new Set(
      pagosDetalle
        .map((pago) => pago.recibo)
        .filter((recibo) => recibo && recibo !== 'Sin recibo')
    ),
  ]

  return {
    pagosDelMes,
    pagosLiquidacionArriendoMes,
    totalPagadoMes,
    totalPagadoLiquidacionArriendo,
    totalCanonAsignadoMes,
    totalDescuentoMes,
    totalMoraPagadaRegistro,
    pagosDetalle,
    pagosDetalleLiquidacionArriendo,
    ultimoPago,
    recibosDelMes,
  }
}

// =============================================================================
// LIQUIDACION DEPOSITARIO - ASIGNACION DE CANON
// Agrupa por predio las asignaciones de canon liquidable por unidad.
// =============================================================================

const construirAsignacionCanonLiquidacionPredio = ({
  codigoPredio,
  contratosArriendo,
  pagosArriendo,
  incrementosArriendo = [],
  ajustesAdministracion = [],
  gestionesCartera = [],
}) => {
  const contratosPredio = (contratosArriendo || []).filter(
    (contrato) => contrato.codigoPredio === codigoPredio
  )
  const pagosPredio = (pagosArriendo || []).filter(
    (pago) =>
      contratosPredio.some((contrato) => coincidePagoContratoArriendo(pago, contrato)) &&
      Number(pago.valorPagado || 0) > 0
  )

  const asignacionGlobalPorMes = new Map()
  const mesesConAsignacion = new Set()

  contratosPredio.forEach((contrato) => {
    const idContrato = obtenerIdContrato(contrato)
    const pagosContrato = pagosPredio.filter((pago) => coincidePagoContratoArriendo(pago, contrato))
    const asignacionesContrato = asignarPagosCanonLiquidacionContratoMultimes({
      contrato,
      pagosContrato,
      incrementosArriendo,
      ajustesAdministracion,
      gestionesCartera,
    })

    asignacionesContrato.forEach((asignacionesMes, mes) => {
      if (!asignacionGlobalPorMes.has(mes)) asignacionGlobalPorMes.set(mes, [])
      asignacionesMes.forEach((datos) => {
        if (Number(datos.valorCanonLiquidacion || 0) > 0) {
          asignacionGlobalPorMes.get(mes).push({
            ...datos,
            contrato,
            idContratoVisible: idContrato,
            unidad: datos.pago?.nombreUnidad || contrato?.nombreUnidad || 'Sin unidad',
            idUnidad: contrato?.idUnidad || datos.pago?.idUnidad || '',
            arrendatario: datos.pago?.arrendatario || contrato?.arrendatario || '',
          })
          mesesConAsignacion.add(mes)
        }
      })
    })
  })

  return { asignacionGlobalPorMes, mesesConAsignacion }
}

// =============================================================================
// LIQUIDACION DEPOSITARIO - PAGO POR BENEFICIARIO
// Comision inmobiliaria y liquidacion por pago de arriendo.
// =============================================================================

const calcularLiquidacionBeneficiarioPagoArriendo = ({
  pagoArriendo,
  contratoDeposito,
  participacion,
  codigoPredio,
  contratosArriendo,
  pagosArriendo,
  valorCanonLiquidacion = null,
  datosAsignacionCanon = null,
}) => {
  const contratoArriendo =
    datosAsignacionCanon?.contrato ||
    contratosArriendo?.find(
      (contrato) => obtenerIdContrato(contrato) === pagoArriendo.idContrato
    ) ||
    pagoArriendo.contrato ||
    null
  const valorPagado = Number(pagoArriendo.valorPagado || 0)
  const canonArrendamiento =
    datosAsignacionCanon?.canonArrendamientoMes ||
    obtenerCanonArrendamientoDesdePago(pagoArriendo, contratoArriendo)
  const valorLiquidableAsignado =
    datosAsignacionCanon?.valorCanonLiquidacion ??
    (valorCanonLiquidacion == null ? null : Number(valorCanonLiquidacion || 0))
  const valorLiquidable = Math.max(0, Number(valorLiquidableAsignado ?? 0))
  const montoLiquidablePropietarioMes = Number(
    datosAsignacionCanon?.montoLiquidablePropietario ??
      calcularMontoLiquidablePropietarioMes({
        canonBase:
          datosAsignacionCanon?.canonBaseMes ||
          datosAsignacionCanon?.canonComisionBaseMes ||
          Number(pagoArriendo.canonBase || 0),
        administracion: datosAsignacionCanon?.administracionMes || Number(pagoArriendo.administracion || 0),
        ivaCanon: Number(pagoArriendo.iva || 0),
        contrato: contratoArriendo,
      })
  )
  const ratioPropietario =
    canonArrendamiento > 0 ? montoLiquidablePropietarioMes / canonArrendamiento : 1
  const valorLiquidablePropietario = Math.round(valorLiquidable * ratioPropietario)
  const administracionMes = Number(
    datosAsignacionCanon?.administracionMes || pagoArriendo.administracion || 0
  )
  const canonBaseMes = Number(
    datosAsignacionCanon?.canonBaseMes ||
      datosAsignacionCanon?.canonComisionBaseMes ||
      pagoArriendo.canonBase ||
      0
  )
  const canonComisionBaseMes = Number(
    datosAsignacionCanon?.canonComisionBaseMes ??
      obtenerCanonComisionBaseMes(contratoArriendo, canonBaseMes, administracionMes)
  )
  const esPagoFijoMensualCalculo =
    datosAsignacionCanon?.tipoLiquidacionMes === 'Pago fijo mensual' ||
    datosAsignacionCanon?.esPagoFijoMensual === true
  const mesPagadoEnTotalidad =
    datosAsignacionCanon?.esPagoTotalMes === true ||
    Number(datosAsignacionCanon?.porcentajeAbonoCanonAcumulado || 0) >= 100
  const valorAdministracionDescontada =
    contratoArriendo &&
    administracionIncluidaEnCanonContrato(contratoArriendo) &&
    (esPagoFijoMensualCalculo || mesPagadoEnTotalidad)
      ? Number(administracionMes || 0)
      : 0
  const porcentajeAbonoCanon =
    datosAsignacionCanon?.porcentajeAbonoCanonAcumulado ??
    (canonArrendamiento > 0
      ? Math.min(100, Math.round((valorLiquidable / canonArrendamiento) * 10000) / 100)
      : valorLiquidable > 0
      ? 100
      : 0)
  const porcentajeAbonoCanonPago =
    datosAsignacionCanon?.porcentajeAbonoCanonPago ??
    (canonArrendamiento > 0
      ? Math.min(100, Math.round((valorLiquidable / canonArrendamiento) * 10000) / 100)
      : valorLiquidable > 0
      ? 100
      : 0)
  const canonAcumuladoCubierto = Number(datosAsignacionCanon?.canonAcumuladoCubierto || 0)
  let baseComisionAsignada = Number(
    datosAsignacionCanon?.baseComisionAsignada ??
      (canonArrendamiento > 0
        ? Math.round(canonComisionBaseMes * (valorLiquidable / canonArrendamiento))
        : valorLiquidable)
  )

  const comisionInmobiliariaPredio = calcularComisionInmobiliariaMes(
    contratoDeposito,
    codigoPredio,
    datosAsignacionCanon?.mesAsignado || pagoArriendo.mes,
    baseComisionAsignada,
    contratosArriendo,
    pagosArriendo,
    datosAsignacionCanon?.idUnidad || pagoArriendo.idUnidad || ''
  )

  const valorAdministracionDescontadaBeneficiario = Math.round(
    valorAdministracionDescontada * (participacion / 100)
  )
  const comisionInmobiliaria = Math.round(comisionInmobiliariaPredio * (participacion / 100))
  const valorPagadoTotalRecibo = Number(
    pagoArriendo.valorPagadoTotalRecibo ?? pagoArriendo.valorPagado ?? 0
  )
  const ivaCanonMes = Number(
    datosAsignacionCanon?.ivaCanonMes ?? pagoArriendo.iva ?? 0
  )

  let valorBruto
  let ivaBeneficiario
  let canonBaseBeneficiario
  let ivaLiquidableAsignado
  let canonBaseLiquidableAsignado

  if (esPagoFijoMensualCalculo) {
    const canonBaseMes = Number(
      datosAsignacionCanon?.canonBaseMes ||
        datosAsignacionCanon?.canonComisionBaseMes ||
        0
    )
    canonBaseBeneficiario = Math.round(canonBaseMes * (participacion / 100))
    ivaBeneficiario = Math.round(ivaCanonMes * (participacion / 100))
    valorBruto = canonBaseBeneficiario + ivaBeneficiario
    ivaLiquidableAsignado = ivaCanonMes
    canonBaseLiquidableAsignado = canonBaseMes
  } else {
    valorBruto = Math.round(valorLiquidablePropietario * (participacion / 100))
    const ratioIvaLiquidable =
      montoLiquidablePropietarioMes > 0 ? ivaCanonMes / montoLiquidablePropietarioMes : 0
    ivaLiquidableAsignado = Math.round(valorLiquidablePropietario * ratioIvaLiquidable)
    canonBaseLiquidableAsignado = Math.max(
      0,
      valorLiquidablePropietario - ivaLiquidableAsignado
    )
    ivaBeneficiario = Math.round(ivaLiquidableAsignado * (participacion / 100))
    canonBaseBeneficiario = Math.round(
      canonBaseLiquidableAsignado * (participacion / 100)
    )
  }

  const ivaComisionBeneficiario =
    comisionInmobiliaria > 0 ? calcularIvaComisionInh(comisionInmobiliaria) : 0

  const valorNeto = esPagoFijoMensualCalculo
    ? valorBruto -
      comisionInmobiliaria -
      ivaComisionBeneficiario -
      valorAdministracionDescontadaBeneficiario
    : valorBruto - comisionInmobiliaria - ivaComisionBeneficiario

  return {
    valorPagado,
    valorPagadoTotalRecibo,
    canonArrendamiento,
    canonCausado: canonArrendamiento,
    valorCanonLiquidacion: valorLiquidable,
    valorLiquidablePropietario,
    ivaCanonMes,
    ivaLiquidableAsignado,
    canonBaseLiquidableAsignado,
    ivaBeneficiario,
    canonBaseBeneficiario,
    valorAdministracionDescontada,
    baseComisionAsignada,
    mesAsignado: datosAsignacionCanon?.mesAsignado || pagoArriendo.mes,
    mesPagoOriginal: datosAsignacionCanon?.mesPagoOriginal || pagoArriendo.mes,
    tipoLiquidacionMes: datosAsignacionCanon?.tipoLiquidacionMes || '',
    esAbonoParcial: !!datosAsignacionCanon?.esAbonoParcial,
    porcentajeAbonoCanon,
    porcentajeAbonoCanonPago,
    canonAcumuladoCubierto,
    valorBruto,
    comisionInmobiliaria,
    ivaComisionBeneficiario,
    valorNeto,
    comisionInmobiliariaPredio,
  }
}

const esPrimerMesRecaudoPostContrato = (
  codigoPredio,
  mes,
  fechaInicioContrato,
  contratosArriendo,
  pagosArriendo,
  idUnidad = null
) => {
  const inicioMes = (fechaInicioContrato || '').slice(0, 7)
  if (!inicioMes) return false

  const idsContratos = contratosArriendo
    .filter((contrato) => contrato.codigoPredio === codigoPredio)
    .map((contrato) => obtenerIdContrato(contrato))

  const mesesConRecaudo = [
    ...new Set(
      pagosArriendo
        .filter(
          (pago) =>
            idsContratos.includes(pago.idContrato) &&
            pago.mes >= inicioMes &&
            Number(pago.valorPagado || 0) > 0 &&
            (!idUnidad || pago.idUnidad === idUnidad)
        )
        .map((pago) => pago.mes)
    ),
  ].sort()

  return mesesConRecaudo[0] === mes
}

const calcularComisionInmobiliariaMes = (
  contratoDeposito,
  codigoPredio,
  mes,
  totalRecaudado,
  contratosArriendo,
  pagosArriendo,
  idUnidad = null
) => {
  if (!contratoDeposito || totalRecaudado <= 0) return 0

  const porcentaje = Number(contratoDeposito.porcentajeComision || 0)

  if (contratoDeposito.tipoComision === 'Administración') {
    return Math.round(totalRecaudado * (porcentaje / 100))
  }

  if (contratoDeposito.tipoComision === 'Solo arrendar') {
    const mesComisionCausada = contratoDeposito.mesComisionPrimerArriendo || ''
    if (mesComisionCausada) {
      if (String(mes) !== String(mesComisionCausada)) return 0
    } else if (
      !esPrimerMesRecaudoPostContrato(
        codigoPredio,
        mes,
        contratoDeposito.fechaInicio,
        contratosArriendo,
        pagosArriendo,
        idUnidad
      )
    ) {
      return 0
    }
    return Math.round(totalRecaudado * (porcentaje / 100))
  }

  return 0
}

// =============================================================================
// LIQUIDACION DEPOSITO - PORCENTAJE CANON LIQUIDABLE CUBIERTO
// Porcentaje del canon liquidable al depositario cubierto en el corte mensual.
// =============================================================================

const calcularPorcentajeAbonoCanonMesLiquidacionDeposito = ({
  detallePagos = [],
  totalRecaudadoPredio = 0,
  canonArrendamientoMes = 0,
  montoLiquidablePropietarioMes = 0,
}) => {
  const maxAcumulado = detallePagos.reduce(
    (max, pago) => Math.max(max, Number(pago.porcentajeAbonoCanonAcumulado || 0)),
    0
  )
  if (maxAcumulado > 0) return Math.min(100, maxAcumulado)

  const baseDenominador =
    montoLiquidablePropietarioMes > 0
      ? montoLiquidablePropietarioMes
      : canonArrendamientoMes

  if (baseDenominador <= 0) {
    return totalRecaudadoPredio > 0 ? 100 : 0
  }

  return Math.min(
    100,
    Math.round((totalRecaudadoPredio / baseDenominador) * 10000) / 100
  )
}

// =============================================================================
// LIQUIDACION DEPOSITO - DETALLE PAGO FIJO MENSUAL
// Liquidacion mensual al depositante sin depender del recaudo del arrendatario.
// =============================================================================

const construirDetallePagoFijoLiquidacionDepositoMes = ({
  contrato,
  contratoArriendo,
  mes,
  beneficiario,
  contratosArriendo,
  pagosArriendo,
  pagosLiquidacionDeposito,
  claveUnidadLiquidacion,
  incrementosArriendo = [],
  ajustesAdministracion = [],
}) => {
  if (!contratoArriendo || !contratoArriendoActivoEnMes(contratoArriendo, mes)) return null

  const participacion = Number(beneficiario.porcentaje || 0)
  const canonInfo = obtenerEstructuraCanonMes({
    contrato: contratoArriendo,
    mes,
    incrementosArriendo,
    ajustesAdministracion,
  })

  if (Number(canonInfo.montoLiquidablePropietario || 0) <= 0) return null

  const datosAsignacionCanon = {
    claveAsignacion: `pago-fijo::${mes}::${obtenerIdContrato(contratoArriendo)}`,
    idPagoArriendo: `pago-fijo-${mes}-${obtenerIdContrato(contratoArriendo)}`,
    valorCanonLiquidacion: canonInfo.montoLiquidablePropietario,
    baseComisionAsignada: canonInfo.canonComisionBase,
    canonBaseMes: canonInfo.canonBase,
    administracionMes: canonInfo.administracion,
    ivaCanonMes: canonInfo.ivaCanon,
    montoLiquidablePropietario: canonInfo.montoLiquidablePropietario,
    canonArrendamientoMes: canonInfo.canonArrendamiento,
    canonComisionBaseMes: canonInfo.canonComisionBase,
    contrato: contratoArriendo,
    idContratoVisible: obtenerIdContrato(contratoArriendo),
    idUnidad: contratoArriendo.idUnidad || '',
    unidad: contratoArriendo.nombreUnidad || '',
    arrendatario: contratoArriendo.arrendatario || '',
    canonAcumuladoCubierto: canonInfo.montoLiquidablePropietario,
    porcentajeAbonoCanonAcumulado: 100,
    porcentajeAbonoCanonPago: 100,
    mesAsignado: mes,
    mesPagoOriginal: mes,
    fechaPago: `${mes}-01`,
    esAbonoParcial: false,
    esPagoTotalMes: true,
    tipoLiquidacionMes: 'Pago fijo mensual',
    recibo: 'Pago fijo',
  }

  const calculo = calcularLiquidacionBeneficiarioPagoArriendo({
    pagoArriendo: {
      valorPagado: 0,
      valorPagadoTotalRecibo: 0,
      mes,
      recibo: 'Pago fijo',
      canonBase: canonInfo.canonBase,
      administracion: canonInfo.administracion,
      iva: canonInfo.ivaCanon,
      idContrato: obtenerIdContrato(contratoArriendo),
      contrato: contratoArriendo,
      idUnidad: contratoArriendo.idUnidad || '',
      unidad: contratoArriendo.nombreUnidad || '',
      arrendatario: contratoArriendo.arrendatario || '',
    },
    contratoDeposito: contrato,
    participacion,
    codigoPredio: contrato.codigoPredio,
    contratosArriendo,
    pagosArriendo,
    datosAsignacionCanon,
  })

  const liquidado = pagoArriendoLiquidadoParaBeneficiario(
    {
      idPagoArriendo: datosAsignacionCanon.claveAsignacion,
      claveAsignacion: datosAsignacionCanon.claveAsignacion,
      mes: mes,
      mesAsignado: mes,
    },
    beneficiario.idPropietario,
    contrato.codigoPredio,
    pagosLiquidacionDeposito,
    claveUnidadLiquidacion
  )

  return {
    ...datosAsignacionCanon,
    ...calculo,
    ivaComisionInh: calcularIvaComisionInh(calculo.comisionInmobiliaria),
    valorNeto: calculo.valorNeto,
    liquidado,
    deudaPendienteInh: liquidado ? 0 : calculo.valorNeto,
    esPagoFijoMensual: true,
  }
}

// =============================================================================
// LIQUIDACION DEPOSITARIO - ABONOS INH POR MES Y BENEFICIARIO
// Pagos registrados a depositario que reducen el saldo del corte mensual.
// =============================================================================

const obtenerValorNetoPagoLiquidacionDeposito = (pago = {}) =>
  Math.max(
    0,
    Number(pago.valorNetoPropietario ?? pago.valorNeto ?? pago.valor ?? 0)
  )

// =============================================================================
// LIQUIDACION DEPOSITARIO - COINCIDENCIA PAGO INH SIN MES
// Empareja pagos INH por predio, beneficiario y unidad (sin filtrar mes causado).
// =============================================================================

// =============================================================================
// LIQUIDACION DEPOSITARIO - COINCIDENCIA PAGO INH
// Empareja pagos INH con liquidacion por predio, mes, contrato y unidad flexible.
// =============================================================================

const coincidePagoInhLiquidacionDepositoBeneficiarioBase = (
  pagoInh = {},
  {
    codigoPredio,
    idPropietario,
    claveUnidad = '',
    idContratoDeposito = '',
    idContratoArriendo = '',
    contratoArriendo = null,
  } = {}
) => {
  if (!pagoInh || !codigoPredio || !idPropietario) return false
  if (String(pagoInh.codigoPredio || '') !== String(codigoPredio)) return false
  if (String(pagoInh.idPropietario || '') !== String(idPropietario)) return false

  if (
    idContratoDeposito &&
    pagoInh.idContratoDeposito &&
    String(pagoInh.idContratoDeposito) !== String(idContratoDeposito)
  ) {
    return false
  }

  return coincideLiquidacionDepositoUnidadArriendo({
    liquidacion: {
      claveUnidad: pagoInh.claveUnidad || '',
      idUnidad: pagoInh.idUnidad || '',
      unidad: pagoInh.unidad || '',
      idContratoArriendo: pagoInh.idContratoArriendo || '',
    },
    idContratoArriendo,
    claveUnidad,
    contratoArriendo,
  })
}

const coincidePagoInhLiquidacionDepositoBeneficiario = (
  pagoInh = {},
  {
    codigoPredio,
    mes,
    idPropietario,
    claveUnidad = '',
    idContratoDeposito = '',
    idContratoArriendo = '',
    contratoArriendo = null,
  } = {}
) => {
  if (!mes) return false

  return (
    coincidePagoInhLiquidacionDepositoBeneficiarioBase(pagoInh, {
      codigoPredio,
      idPropietario,
      claveUnidad,
      idContratoDeposito,
      idContratoArriendo,
      contratoArriendo,
    }) && String(pagoInh.mes || '') === String(mes)
  )
}

// =============================================================================
// LIQUIDACION DEPOSITARIO - PAGOS INH DEL MES
// Lista ordenada de pagos al depositario registrados en el corte.
// =============================================================================

const obtenerPagosInhMesLiquidacionDepositoBeneficiario = (
  pagosLiquidacionDeposito = [],
  criterios = {}
) =>
  (pagosLiquidacionDeposito || [])
    .filter((pago) => coincidePagoInhLiquidacionDepositoBeneficiario(pago, criterios))
    .sort((a, b) => {
      const fechaComparacion = String(a.fechaPago || '').localeCompare(String(b.fechaPago || ''))
      if (fechaComparacion !== 0) return fechaComparacion
      return String(a.id || '').localeCompare(String(b.id || ''))
    })

// =============================================================================
// LIQUIDACION DEPOSITARIO - ABONOS INH DEL MES
// Suma de pagos INH que reducen el saldo del corte mensual.
// =============================================================================

const obtenerAbonosInhMesLiquidacionDepositoBeneficiario = (
  pagosLiquidacionDeposito = [],
  criterios = {}
) =>
  obtenerPagosInhMesLiquidacionDepositoBeneficiario(pagosLiquidacionDeposito, criterios).reduce(
    (total, pago) => total + obtenerValorNetoPagoLiquidacionDeposito(pago),
    0
  )

// =============================================================================
// LIQUIDACION DEPOSITARIO - ABONOS INH EN DETALLE
// Distribuye abonos INH en cascada sobre lineas del detalle de pagos.
// =============================================================================

const aplicarAbonosInhADetallePagosLiquidacionDeposito = (
  detallePagos = [],
  abonosInhMes = 0
) => {
  let restanteAbono = Math.max(0, Number(abonosInhMes || 0))

  return (detallePagos || []).map((pago) => {
    const valorNeto = Math.max(0, Number(pago.valorNeto || 0))
    const abonoLinea = Math.min(restanteAbono, valorNeto)
    restanteAbono -= abonoLinea
    const deudaPendienteInh = Math.max(0, valorNeto - abonoLinea)

    return {
      ...pago,
      abonoInhLinea: abonoLinea,
      deudaPendienteInh,
      liquidado: deudaPendienteInh <= 0 && valorNeto > 0,
    }
  })
}

// =============================================================================
// LIQUIDACION DEPOSITARIO - CLAVE Y CASCADA DE ABONOS INH
// Reparte pagos al depositario del corte mas antiguo al mas reciente (igual que extracto).
// =============================================================================

const claveGrupoAbonosInhLiquidacionDeposito = ({
  idContratoDeposito = '',
  idPropietario = '',
  codigoPredio = '',
  claveUnidad = '',
}) => `${idContratoDeposito}::${idPropietario}::${codigoPredio}::${claveUnidad}`

const claveMesAbonosInhLiquidacionDeposito = (liquidacion = {}) =>
  `${liquidacion.mes}::${claveGrupoAbonosInhLiquidacionDeposito(liquidacion)}`

// =============================================================================
// LIQUIDACION DEPOSITARIO - CASCADA ABONOS INH LIQUIDACION
// Reparte pagos al depositario del corte mas antiguo al mas reciente en liquidaciones.
// =============================================================================

const distribuirAbonosInhCascadaLiquidacionDeposito = ({
  pagosLiquidacionDeposito = [],
  liquidacionesSinAbono = [],
  contratosArriendo = [],
}) => {
  const abonosPorClaveMes = new Map()
  const grupos = new Map()

  ;(liquidacionesSinAbono || []).forEach((liquidacion) => {
    const grupo = claveGrupoAbonosInhLiquidacionDeposito(liquidacion)
    if (!grupos.has(grupo)) grupos.set(grupo, [])
    grupos.get(grupo).push(liquidacion)
  })

  grupos.forEach((liquidacionesGrupo) => {
    const referencia = liquidacionesGrupo[0]
    if (!referencia) return

    const contratoArriendo = referencia.idContratoArriendo
      ? contratosArriendo.find(
          (item) => obtenerIdContrato(item) === referencia.idContratoArriendo
        )
      : null
    const criteriosBase = {
      codigoPredio: referencia.codigoPredio,
      idPropietario: referencia.idPropietario,
      claveUnidad: referencia.claveUnidad || '',
      idContratoDeposito: referencia.idContratoDeposito,
      idContratoArriendo: referencia.idContratoArriendo || '',
      contratoArriendo,
    }

    const mesesOrdenados = [...new Set(liquidacionesGrupo.map((item) => item.mes))]
      .filter(Boolean)
      .sort()
    const saldoPendientePorMes = new Map()

    mesesOrdenados.forEach((mes) => {
      const saldoMes = liquidacionesGrupo
        .filter((item) => String(item.mes) === String(mes))
        .reduce((total, item) => total + Number(item.valorNetoTotal || 0), 0)
      saldoPendientePorMes.set(mes, Math.max(0, saldoMes))
    })

    const pagosGrupo = (pagosLiquidacionDeposito || [])
      .filter((pago) => coincidePagoInhLiquidacionDepositoBeneficiarioBase(pago, criteriosBase))
      .sort((a, b) => {
        const fechaComparacion = String(a.fechaPago || '').localeCompare(String(b.fechaPago || ''))
        if (fechaComparacion !== 0) return fechaComparacion
        return String(a.id || '').localeCompare(String(b.id || ''))
      })

    pagosGrupo.forEach((pago) => {
      let restante = obtenerValorNetoPagoLiquidacionDeposito(pago)
      if (restante <= 0) return

      mesesOrdenados.forEach((mes) => {
        if (restante <= 0) return

        const pendiente = Number(saldoPendientePorMes.get(mes) || 0)
        if (pendiente <= 0) return

        const aplicado = Math.min(restante, pendiente)
        if (aplicado <= 0) return

        restante -= aplicado
        saldoPendientePorMes.set(mes, pendiente - aplicado)

        const liquidacionesMes = liquidacionesGrupo.filter(
          (item) => String(item.mes) === String(mes)
        )
        let restanteMes = aplicado

        liquidacionesMes.forEach((liquidacionMes, indice) => {
          const esUltima = indice === liquidacionesMes.length - 1
          const netoMes = Number(liquidacionMes.valorNetoTotal || 0)
          const abonoLinea = esUltima
            ? restanteMes
            : Math.min(restanteMes, netoMes)
          restanteMes -= abonoLinea

          const claveMes = claveMesAbonosInhLiquidacionDeposito(liquidacionMes)
          abonosPorClaveMes.set(
            claveMes,
            (abonosPorClaveMes.get(claveMes) || 0) + abonoLinea
          )
        })
      })
    })
  })

  return abonosPorClaveMes
}

// =============================================================================
// LIQUIDACION DEPOSITARIO - APLICAR ABONOS INH A LIQUIDACION
// Actualiza deuda, estado y detalle tras asignar abonos INH en cascada.
// =============================================================================

const aplicarAbonosInhALiquidacionDepositoBeneficiarioMes = (
  liquidacion,
  abonosInhMes = 0,
  pagosLiquidacionDeposito = [],
  criteriosPagosInh = {}
) => {
  const valorNetoTotal = Number(liquidacion.valorNetoTotal || 0)
  const totalRecaudadoPredio = Number(liquidacion.totalRecaudadoPredio || 0)
  const esPagoFijo = liquidacion.esPagoFijoMensual
  let detallePagos = aplicarAbonosInhADetallePagosLiquidacionDeposito(
    liquidacion.detallePagos,
    abonosInhMes
  )

  if (abonosInhMes > 0 && valorNetoTotal > 0 && abonosInhMes >= valorNetoTotal - 1) {
    detallePagos = detallePagos.map((pago) => ({
      ...pago,
      deudaPendienteInh: 0,
      liquidado: Number(pago.valorNeto || 0) > 0,
    }))
  }

  const deudaInmobiliaria = detallePagos.reduce(
    (total, pago) => total + Number(pago.deudaPendienteInh || 0),
    0
  )
  const valorNetoLiquidado = valorNetoTotal - deudaInmobiliaria
  const pagosPendientes = detallePagos.filter(
    (pago) => Number(pago.deudaPendienteInh || 0) > 0
  )
  const pagosLiquidados = detallePagos.filter(
    (pago) => Number(pago.deudaPendienteInh || 0) <= 0 && Number(pago.valorNeto || 0) > 0
  )

  let estadoPago = esPagoFijo ? 'Pendiente' : 'Sin recaudo'
  if (detallePagos.length > 0 || totalRecaudadoPredio > 0) {
    if (deudaInmobiliaria <= 0 && valorNetoTotal > 0) estadoPago = 'Pagado'
    else if (deudaInmobiliaria <= 0 && valorNetoTotal <= 0) estadoPago = 'Sin canon liquidable'
    else if (abonosInhMes > 0 && deudaInmobiliaria > 0) estadoPago = 'Pendiente parcial'
    else if (valorNetoLiquidado > 0) estadoPago = 'Pendiente parcial'
    else estadoPago = 'Pendiente'
  }

  const pagosInhMes = obtenerPagosInhMesLiquidacionDepositoBeneficiario(
    pagosLiquidacionDeposito,
    criteriosPagosInh
  )
  const pagoRegistrado = pagosInhMes[pagosInhMes.length - 1] || null

  if (abonosInhMes > 0 && deudaInmobiliaria <= 0 && valorNetoTotal > 0) {
    estadoPago = 'Pagado'
  }

  return {
    ...liquidacion,
    detallePagos,
    valorNetoLiquidado,
    deudaInmobiliaria,
    abonoLiquidacionRealizado: abonosInhMes,
    fechaAbonoLiquidacion: pagoRegistrado?.fechaPago || '',
    pagosPendientes,
    pagosLiquidados,
    estadoPago,
    pagoRegistrado,
  }
}

const construirLiquidacionDepositoBeneficiarioMes = ({
  contrato,
  beneficiario,
  mes,
  propietarios,
  predios,
  contratosDeposito,
  contratosArriendo,
  pagosArriendo,
  pagosLiquidacionDeposito,
  asignacionPredio = null,
  unidadLiquidacion = null,
  incrementosArriendo = [],
  ajustesAdministracion = [],
  omitirAbonosInh = false,
}) => {
  const propietario = propietarios.find((item) => item.id === beneficiario.idPropietario)
  if (!propietario) return null

  const participacion = Number(beneficiario.porcentaje || 0)
  const claveUnidadLiquidacion = unidadLiquidacion?.claveUnidad || ''
  const contratoArriendoUnidad = unidadLiquidacion?.idContratoArriendo
    ? contratosArriendo.find(
        (item) => obtenerIdContrato(item) === unidadLiquidacion.idContratoArriendo
      )
    : null
  const esPagoFijo = esPagoFijoLiquidacionCanonDeposito(contrato)
  let lineasAsignacion = (asignacionPredio?.asignacionGlobalPorMes?.get(mes) || []).filter(
    (linea) => coincideLineaUnidadLiquidacion(linea, unidadLiquidacion)
  )

  let detallePagos = []

  if (esPagoFijo && unidadLiquidacion?.idContratoArriendo) {
    const contratoArriendo = contratosArriendo.find(
      (item) => obtenerIdContrato(item) === unidadLiquidacion.idContratoArriendo
    )
    const detallePagoFijo = construirDetallePagoFijoLiquidacionDepositoMes({
      contrato,
      contratoArriendo,
      mes,
      beneficiario,
      contratosArriendo,
      pagosArriendo,
      pagosLiquidacionDeposito,
      claveUnidadLiquidacion,
      incrementosArriendo,
      ajustesAdministracion,
    })
    if (detallePagoFijo) detallePagos = [detallePagoFijo]
  } else {
    detallePagos = lineasAsignacion.map((linea) => {
    const pago = linea.pago
    const pagoOriginal = linea.pago || pago
    const calculo = calcularLiquidacionBeneficiarioPagoArriendo({
      pagoArriendo: {
        ...pago,
        valorPagadoTotalRecibo: Number(pagoOriginal?.valorPagado || 0),
        idPagoArriendo: linea.idPagoArriendo,
        contrato: linea.contrato,
        idContratoVisible: linea.idContratoVisible,
        unidad: linea.unidad,
        idUnidad: linea.idUnidad,
        arrendatario: linea.arrendatario,
      },
      contratoDeposito: contrato,
      participacion,
      codigoPredio: contrato.codigoPredio,
      contratosArriendo,
      pagosArriendo,
      datosAsignacionCanon: linea,
    })

    return {
      ...pago,
      ...linea,
      ...calculo,
      idPagoArriendo: linea.claveAsignacion || linea.idPagoArriendo,
      liquidado: false,
      deudaPendienteInh: calculo.valorNeto,
    }
  })
  }

  if (esPagoFijo && detallePagos.length === 0 && unidadLiquidacion?.idContratoArriendo) {
    return null
  }

  const contratoArriendoReferencia =
    unidadLiquidacion?.idContratoArriendo
      ? contratosArriendo.find(
          (item) => obtenerIdContrato(item) === unidadLiquidacion.idContratoArriendo
        )
      : null
  const canonInfoMes =
    !esPagoFijo && detallePagos.length === 0 && contratoArriendoReferencia
      ? obtenerEstructuraCanonMes({
          contrato: contratoArriendoReferencia,
          mes,
          incrementosArriendo,
          ajustesAdministracion,
        })
      : null

  if (
    !esPagoFijo &&
    detallePagos.length === 0 &&
    (!contratoArriendoReferencia || !contratoArriendoActivoEnMes(contratoArriendoReferencia, mes))
  ) {
    return null
  }

  const canonReferencia = lineasAsignacion[0] || detallePagos[0] || null
  const canonArrendamientoMes = Number(
    canonReferencia?.canonArrendamientoMes ||
      detallePagos[0]?.canonArrendamiento ||
      canonInfoMes?.canonArrendamiento ||
      0
  )
  const totalRecaudadoPredio = detallePagos.reduce(
    (total, pago) =>
      total +
      Number(
        pago.montoLiquidableAsignado ||
          pago.valorLiquidablePropietario ||
          pago.valorBruto ||
          pago.valorCanonLiquidacion ||
          0
      ),
    0
  )
  const montoLiquidablePropietarioMes = Number(
    canonReferencia?.montoLiquidablePropietario ||
      detallePagos[0]?.montoLiquidablePropietario ||
      canonInfoMes?.montoLiquidablePropietario ||
      0
  )
  const ivaCanonMes = Number(
    canonReferencia?.ivaCanonMes || detallePagos[0]?.ivaCanonMes || canonInfoMes?.ivaCanon || 0
  )
  const porcentajeAbonoCanonMes = calcularPorcentajeAbonoCanonMesLiquidacionDeposito({
    detallePagos,
    totalRecaudadoPredio,
    canonArrendamientoMes,
    montoLiquidablePropietarioMes,
  })
  const comisionInmobiliariaPredio = detallePagos.reduce(
    (total, pago) => total + Number(pago.comisionInmobiliariaPredio || 0),
    0
  )
  const valorBrutoPropietario = detallePagos.reduce(
    (total, pago) => total + Number(pago.valorBruto || 0),
    0
  )
  const comisionInmobiliariaPropietario = detallePagos.reduce(
    (total, pago) => total + Number(pago.comisionInmobiliaria || 0),
    0
  )
  const valorAdministracionDescontadaPredio = detallePagos.reduce(
    (total, pago) => total + Number(pago.valorAdministracionDescontada || 0),
    0
  )
  const valorAdministracionDescontadaBeneficiario = Math.round(
    valorAdministracionDescontadaPredio * (participacion / 100)
  )
  const valorNetoTotal = detallePagos.reduce(
    (total, pago) => total + Number(pago.valorNeto || 0),
    0
  )

  const criteriosPagosInh = {
    codigoPredio: contrato.codigoPredio,
    mes,
    idPropietario: beneficiario.idPropietario,
    claveUnidad: claveUnidadLiquidacion,
    idContratoDeposito: contrato.id,
    idContratoArriendo: unidadLiquidacion?.idContratoArriendo || '',
    contratoArriendo: contratoArriendoUnidad,
  }

  if (omitirAbonosInh) {
    detallePagos = detallePagos.map((pago) => ({
      ...pago,
      abonoInhLinea: 0,
      deudaPendienteInh: Math.max(0, Number(pago.valorNeto || 0)),
      liquidado: false,
    }))
  } else {
    const abonosInhMes = obtenerAbonosInhMesLiquidacionDepositoBeneficiario(
      pagosLiquidacionDeposito,
      criteriosPagosInh
    )
    detallePagos = aplicarAbonosInhADetallePagosLiquidacionDeposito(detallePagos, abonosInhMes)

    if (abonosInhMes > 0 && valorNetoTotal > 0 && abonosInhMes >= valorNetoTotal - 1) {
      detallePagos = detallePagos.map((pago) => ({
        ...pago,
        deudaPendienteInh: 0,
        liquidado: Number(pago.valorNeto || 0) > 0,
      }))
    }
  }

  const abonosInhMes = omitirAbonosInh
    ? 0
    : obtenerAbonosInhMesLiquidacionDepositoBeneficiario(pagosLiquidacionDeposito, criteriosPagosInh)

  const deudaInmobiliaria = detallePagos.reduce(
    (total, pago) => total + Number(pago.deudaPendienteInh || 0),
    0
  )
  const valorNetoLiquidado = valorNetoTotal - deudaInmobiliaria
  const pagosPendientes = detallePagos.filter(
    (pago) => Number(pago.deudaPendienteInh || 0) > 0
  )
  const pagosLiquidados = detallePagos.filter(
    (pago) => Number(pago.deudaPendienteInh || 0) <= 0 && Number(pago.valorNeto || 0) > 0
  )

  let estadoPago = esPagoFijo ? 'Pendiente' : 'Sin recaudo'
  if (detallePagos.length > 0 || totalRecaudadoPredio > 0) {
    if (deudaInmobiliaria <= 0 && valorNetoTotal > 0) estadoPago = 'Pagado'
    else if (deudaInmobiliaria <= 0 && valorNetoTotal <= 0) estadoPago = 'Sin canon liquidable'
    else if (abonosInhMes > 0 && deudaInmobiliaria > 0) estadoPago = 'Pendiente parcial'
    else if (valorNetoLiquidado > 0) estadoPago = 'Pendiente parcial'
    else estadoPago = 'Pendiente'
  }

  const pagosInhMes = omitirAbonosInh
    ? []
    : obtenerPagosInhMesLiquidacionDepositoBeneficiario(pagosLiquidacionDeposito, criteriosPagosInh)
  const pagoRegistrado = pagosInhMes[pagosInhMes.length - 1] || null

  if (pagosInhMes.length > 0 && deudaInmobiliaria <= 0 && valorNetoTotal > 0) {
    estadoPago = 'Pagado'
  }

  if (esPagoFijo && detallePagos.length === 0 && pagosInhMes.length === 0) {
    return null
  }

  return {
    idContratoDeposito: contrato.id,
    numeroContrato: obtenerNumeroContratoDepositoVisible(contrato, contratosDeposito),
    codigoPredio: contrato.codigoPredio,
    predio: predios.find((item) => item.codigo === contrato.codigoPredio),
    idPropietario: beneficiario.idPropietario,
    propietario,
    idUnidad: unidadLiquidacion?.idUnidad || '',
    unidad: unidadLiquidacion?.unidad || '',
    idContratoArriendo: unidadLiquidacion?.idContratoArriendo || '',
    claveUnidad: claveUnidadLiquidacion,
    tipoComision: contrato.tipoComision,
    porcentajeComision: contrato.porcentajeComision,
    criterioLiquidacionCanon: normalizarCriterioLiquidacionCanonDeposito(
      contrato.criterioLiquidacionCanon
    ),
    esPagoFijoMensual: esPagoFijo,
    tipoPagoLiquidacion: normalizarTipoPagoLiquidacionDeposito(contrato.tipoPagoLiquidacion),
    condicionesPagoInh: normalizarCondicionesPagoInh(contrato.condicionesPagoInh),
    esContratante: !!beneficiario.esContratante,
    participacion,
    mes,
    canonArrendamientoMes,
    montoLiquidablePropietarioMes,
    ivaCanonMes,
    canonCubiertoMes: totalRecaudadoPredio,
    porcentajeAbonoCanonMes,
    totalRecaudadoPredio,
    comisionInmobiliariaPredio,
    valorBrutoPropietario,
    valorAdministracionDescontadaPredio,
    valorAdministracionDescontadaBeneficiario,
    comisionInmobiliariaPropietario,
    valorNetoPropietario: valorNetoTotal,
    valorNetoTotal,
    valorNetoLiquidado,
    deudaInmobiliaria,
    abonoLiquidacionRealizado: abonosInhMes,
    fechaAbonoLiquidacion: pagoRegistrado?.fechaPago || '',
    detallePagos,
    pagosPendientes,
    pagosLiquidados,
    estadoPago,
    pagoRegistrado,
  }
}

// =============================================================================
// LIQUIDACION DEPOSITARIO - HISTORIAL DE LIQUIDACIONES
// Generacion del historial mensual de liquidaciones.
// =============================================================================

const generarLiquidacionesDepositoHistorial = ({
  contratosDeposito,
  predioPropietarios,
  propietarios,
  predios,
  contratosArriendo,
  pagosArriendo,
  pagosLiquidacionDeposito,
  gestionesCartera = [],
  incrementosArriendo = [],
  ajustesAdministracion = [],
  idPropietarioFiltro = null,
  idContratoDepositoFiltro = null,
  mesFiltro = null,
}) => {
  const contratos = Array.isArray(contratosDeposito) ? contratosDeposito : []
  const liquidaciones = []
  const asignacionPorPredio = new Map()

  contratos
    .filter((contrato) => contrato && contrato.estado === 'Activo' && contrato.codigoPredio)
    .filter((contrato) => !idContratoDepositoFiltro || contrato.id === idContratoDepositoFiltro)
    .forEach((contrato) => {
      if (!asignacionPorPredio.has(contrato.codigoPredio)) {
        asignacionPorPredio.set(
          contrato.codigoPredio,
          construirAsignacionCanonLiquidacionPredio({
            codigoPredio: contrato.codigoPredio,
            contratosArriendo,
            pagosArriendo,
            incrementosArriendo,
            ajustesAdministracion,
            gestionesCartera,
          })
        )
      }

      const asignacionPredio = asignacionPorPredio.get(contrato.codigoPredio)
      const beneficiarios = obtenerBeneficiariosLiquidacionContrato(contrato, predioPropietarios)

      beneficiarios.forEach((beneficiario) => {
        if (idPropietarioFiltro && beneficiario.idPropietario !== idPropietarioFiltro) return

        const mesesAsignacion = [...(asignacionPredio?.mesesConAsignacion || [])]
        const mesesLiquidacion = obtenerMesesLiquidacionContratoDeposito({
          codigoPredio: contrato.codigoPredio,
          contratoDeposito: contrato,
          contratosArriendo,
          pagosArriendo,
          pagosLiquidacionDeposito,
          idPropietario: beneficiario.idPropietario,
        })

        const meses = [...new Set([...mesesAsignacion, ...mesesLiquidacion])]
          .filter((mes) => contratoDepositoVigenteEnMes(contrato, mes))
          .filter((mes) => !mesFiltro || mes === mesFiltro)
          .sort()

        const preliminaresBeneficiario = []

        meses.forEach((mes) => {
          const unidadesMes = obtenerUnidadesLiquidacionMesDeposito({
            mes,
            codigoPredio: contrato.codigoPredio,
            contrato,
            beneficiario,
            asignacionPredio,
            pagosLiquidacionDeposito,
            contratosArriendo,
          })

          unidadesMes.forEach((unidadLiquidacion) => {
            const liquidacionPreliminar = construirLiquidacionDepositoBeneficiarioMes({
              contrato,
              beneficiario,
              mes,
              propietarios,
              predios,
              contratosDeposito,
              contratosArriendo,
              pagosArriendo,
              pagosLiquidacionDeposito,
              asignacionPredio,
              unidadLiquidacion,
              incrementosArriendo,
              ajustesAdministracion,
              omitirAbonosInh: true,
            })

            if (liquidacionPreliminar) preliminaresBeneficiario.push(liquidacionPreliminar)
          })
        })

        const abonosPorClaveMes = distribuirAbonosInhCascadaLiquidacionDeposito({
          pagosLiquidacionDeposito,
          liquidacionesSinAbono: preliminaresBeneficiario,
          contratosArriendo,
        })

        preliminaresBeneficiario.forEach((preliminar) => {
          const claveMes = claveMesAbonosInhLiquidacionDeposito(preliminar)
          const abonosInhMes = abonosPorClaveMes.get(claveMes) || 0
          const contratoArriendoUnidad = preliminar.idContratoArriendo
            ? contratosArriendo.find(
                (item) => obtenerIdContrato(item) === preliminar.idContratoArriendo
              )
            : null

          liquidaciones.push(
            aplicarAbonosInhALiquidacionDepositoBeneficiarioMes(
              preliminar,
              abonosInhMes,
              pagosLiquidacionDeposito,
              {
                codigoPredio: preliminar.codigoPredio,
                mes: preliminar.mes,
                idPropietario: preliminar.idPropietario,
                claveUnidad: preliminar.claveUnidad,
                idContratoDeposito: preliminar.idContratoDeposito,
                idContratoArriendo: preliminar.idContratoArriendo || '',
                contratoArriendo: contratoArriendoUnidad,
              }
            )
          )
        })
      })
    })

  return liquidaciones.sort((a, b) => {
    const mesComparacion = b.mes.localeCompare(a.mes)
    if (mesComparacion !== 0) return mesComparacion
    const contratoComparacion = String(a.numeroContrato).localeCompare(String(b.numeroContrato))
    if (contratoComparacion !== 0) return contratoComparacion
    const unidadComparacion = String(a.unidad || '').localeCompare(String(b.unidad || ''))
    if (unidadComparacion !== 0) return unidadComparacion
    return String(a.propietario?.nombre || '').localeCompare(String(b.propietario?.nombre || ''))
  })
}

// =============================================================================
// LIQUIDACION DEPOSITO - LIQUIDACIONES UNIDAD EXTRACTO
// Regenera y consolida liquidaciones de la unidad para el extracto depositante.
// =============================================================================

const obtenerLiquidacionesDepositoUnidadExtracto = ({
  liquidacionesDepositoHistorial = [],
  contratoDeposito,
  contratoArriendo,
  idContratoArriendo,
  idPropietario,
  claveUnidad,
  predioPropietarios = [],
  propietarios = [],
  predios = [],
  contratosDeposito = [],
  contratosArriendo = [],
  pagosArriendo = [],
  pagosLiquidacionDeposito = [],
  incrementosArriendo = [],
  ajustesAdministracion = [],
  gestionesCartera = [],
}) => {
  const coincideUnidad = (liquidacion) =>
    liquidacion.idPropietario === idPropietario &&
    liquidacion.idContratoDeposito === contratoDeposito.id &&
    coincideLiquidacionDepositoUnidadArriendo({
      liquidacion,
      idContratoArriendo,
      claveUnidad,
      contratoArriendo,
    })

  const liquidacionesRegeneradas = generarLiquidacionesDepositoHistorial({
    contratosDeposito: [contratoDeposito],
    predioPropietarios,
    propietarios,
    predios,
    contratosArriendo,
    pagosArriendo,
    pagosLiquidacionDeposito,
    gestionesCartera,
    incrementosArriendo,
    ajustesAdministracion,
    idPropietarioFiltro: idPropietario,
    idContratoDepositoFiltro: contratoDeposito.id,
  }).filter(coincideUnidad)

  return consolidarLiquidacionesDepositoPorMes(liquidacionesRegeneradas)
}

const agruparDetalleLiquidacionPorUnidad = (detallePagos = []) => {
  const mapa = new Map()

  detallePagos.forEach((pago) => {
    const claveUnidad =
      pago.idUnidad || `${pago.unidad || 'sin-unidad'}-${pago.idContratoVisible || pago.idContrato || ''}`
    const existente = mapa.get(claveUnidad) || {
      idUnidad: pago.idUnidad || '',
      unidad: pago.unidad || 'Sin unidad',
      idContratoArriendo: pago.idContratoVisible || pago.idContrato || '',
      arrendatario: pago.arrendatario || '',
      valorCanonLiquidacion: 0,
      valorBruto: 0,
      valorAdministracionDescontada: 0,
      comisionInhCanon: 0,
      comisionInmobiliaria: 0,
      valorNeto: 0,
      idsPagosArriendo: [],
    }

    existente.valorCanonLiquidacion += Number(pago.valorCanonLiquidacion || 0)
    existente.valorBruto += Number(pago.valorBruto || 0)
    existente.valorAdministracionDescontada += Number(pago.valorAdministracionDescontada || 0)
    existente.comisionInhCanon += Number(pago.comisionInmobiliariaPredio || 0)
    existente.comisionInmobiliaria += Number(pago.comisionInmobiliaria || 0)
    existente.valorNeto += Number(pago.valorNeto || 0)
    existente.idsPagosArriendo.push(pago.idPagoArriendo || obtenerIdPagoArriendo(pago))
    mapa.set(claveUnidad, existente)
  })

  return [...mapa.values()].sort((a, b) => String(a.unidad).localeCompare(String(b.unidad)))
}

const formatearValorMoneda = (valor) =>
  new Intl.NumberFormat('es-CO', {
    style: 'currency',
    currency: 'COP',
    maximumFractionDigits: 0,
  }).format(Number(valor || 0))

// =============================================================================
// PREDIAL - FORMATO CELDA PREDIAL PENDIENTE
// Muestra Por actualizar o el saldo adeudado en extracto de predios.
// =============================================================================

const formatearCeldaPredialPendienteExtractoPropietario = ({ requiereActualizacion, monto }) =>
  requiereActualizacion ? 'Por actualizar' : formatearValorMoneda(monto)

const formatearTotalPredialPendienteExtractoPropietario = (filas, campoMonto) => {
  const filasPredial = filas.filter((fila) => fila.aplicaPredial)
  if (!filasPredial.length) return formatearValorMoneda(0)
  if (filasPredial.every((fila) => fila.requiereActualizacionPredial)) {
    return 'Por actualizar'
  }

  const total = filasPredial.reduce(
    (acc, fila) =>
      acc + (fila.requiereActualizacionPredial ? 0 : Number(fila[campoMonto] || 0)),
    0
  )
  return formatearValorMoneda(total)
}

// =============================================================================
// PREDIAL - FORMATO CELDA AVALUO EXTRACTO PROPIETARIO
// Muestra Pendiente por actualizar o el avaluo del ultimo ano vigente actualizado.
// =============================================================================

const formatearCeldaAvaluoExtractoPropietario = ({ requiereActualizacion, monto }) =>
  requiereActualizacion ? 'Pendiente por actualizar' : formatearValorMoneda(monto)

const formatearTotalAvaluoExtractoPropietario = (filas) => {
  if (!filas.length) return formatearValorMoneda(0)
  if (filas.every((fila) => fila.requiereActualizacionAvaluo)) {
    return 'Pendiente por actualizar'
  }

  const total = filas.reduce(
    (acc, fila) =>
      acc + (fila.requiereActualizacionAvaluo ? 0 : Number(fila.valorAvaluo || 0)),
    0
  )
  return formatearValorMoneda(total)
}

const obtenerDepositariosLiquidacion = (
  contratosDeposito,
  propietarios,
  predioPropietarios = []
) =>
  obtenerDepositantesRegistrados(contratosDeposito, propietarios).filter(
    (depositario) =>
      (contratosDeposito || []).some(
        (contrato) =>
          contrato.estado === 'Activo' &&
          contratoPerteneceADepositante(contrato, depositario)
      )
  )

const contratoArriendoTieneLiquidacionDepositario = (
  contratoArriendo,
  idPropietario,
  liquidacionesDepositoHistorial,
  idContratoDeposito = null
) => {
  const idContrato = obtenerIdContrato(contratoArriendo)
  const claveUnidad = obtenerClaveUnidadLiquidacion({
    idUnidad: contratoArriendo.idUnidad,
    unidad: contratoArriendo.nombreUnidad,
    idContratoArriendo: idContrato,
  })

  return liquidacionesDepositoHistorial.some(
    (liquidacion) =>
      liquidacion.claveUnidad === claveUnidad &&
      liquidacion.idPropietario === idPropietario &&
      (!idContratoDeposito || liquidacion.idContratoDeposito === idContratoDeposito)
  )
}

const obtenerBeneficiariosExtractoLiquidacionArriendo = (
  contratoArriendo,
  contratosDeposito,
  predioPropietarios
) => {
  const contratoDeposito = obtenerContratoDepositoPredio(
    contratoArriendo?.codigoPredio,
    contratosDeposito
  )
  if (!contratoDeposito) return []
  return obtenerBeneficiariosLiquidacionContrato(contratoDeposito, predioPropietarios)
}

const contratoArriendoTieneLiquidacionBeneficiarios = (
  contratoArriendo,
  contratosDeposito,
  predioPropietarios,
  liquidacionesDepositoHistorial
) =>
  obtenerBeneficiariosExtractoLiquidacionArriendo(
    contratoArriendo,
    contratosDeposito,
    predioPropietarios
  ).some((beneficiario) =>
    contratoArriendoTieneLiquidacionDepositario(
      contratoArriendo,
      beneficiario.idPropietario,
      liquidacionesDepositoHistorial
    )
  )

const calcularDeudaLiquidacionArriendoBeneficiarios = ({
  contratoArriendo,
  contratosDeposito,
  predioPropietarios,
  liquidacionesDepositoHistorial,
  idPropietarioFiltro = null,
  idContratoDeposito = null,
}) => {
  const idContrato = obtenerIdContrato(contratoArriendo)
  const claveUnidad = obtenerClaveUnidadLiquidacion({
    idUnidad: contratoArriendo.idUnidad,
    unidad: contratoArriendo.nombreUnidad,
    idContratoArriendo: idContrato,
  })

  return obtenerBeneficiariosExtractoLiquidacionArriendo(
    contratoArriendo,
    contratosDeposito,
    predioPropietarios
  )
    .filter(
      (beneficiario) =>
        !idPropietarioFiltro || beneficiario.idPropietario === idPropietarioFiltro
    )
    .reduce((total, beneficiario) => {
      const deudaBeneficiario = liquidacionesDepositoHistorial
        .filter(
          (liquidacion) =>
            liquidacion.claveUnidad === claveUnidad &&
            liquidacion.idPropietario === beneficiario.idPropietario &&
            (!idContratoDeposito || liquidacion.idContratoDeposito === idContratoDeposito)
        )
        .reduce(
          (subtotal, liquidacion) =>
            subtotal + obtenerDeudaPendienteLiquidacionDeposito(liquidacion),
          0
        )

      return total + deudaBeneficiario
    }, 0)
}

// =============================================================================
// LIQUIDACION DEPOSITARIO - EXTRACTOS POR UNIDAD
// Movimientos y extractos de liquidacion al depositario.
// =============================================================================

const construirExtractosLiquidacionDepositoUnidad = ({
  idContratoArriendo,
  liquidacionesDepositoHistorial,
  pagosLiquidacionDeposito,
  pagosArriendo = [],
  contratosArriendo,
  contratosDeposito,
  predios,
  propietarios,
  predioPropietarios,
  idContratoDeposito = null,
  idPropietarioFiltro = null,
  unidadesNegocio = [],
  facturasServiciosPublicos = [],
  pagosServiciosPublicos = [],
  incrementosArriendo = [],
  ajustesAdministracion = [],
  gestionesCartera = [],
}) => {
  const contratoArriendo = contratosArriendo.find(
    (contrato) => obtenerIdContrato(contrato) === idContratoArriendo
  )
  if (!contratoArriendo) return []

  const beneficiarios = obtenerBeneficiariosExtractoLiquidacionArriendo(
    contratoArriendo,
    contratosDeposito,
    predioPropietarios
  ).filter(
    (beneficiario) =>
      !idPropietarioFiltro || beneficiario.idPropietario === idPropietarioFiltro
  )

  const extractos = beneficiarios
    .map((beneficiario) => {
      const extracto = construirExtractoLiquidacionDepositoUnidad({
        idContratoArriendo,
        idPropietario: beneficiario.idPropietario,
        idContratoDeposito,
        liquidacionesDepositoHistorial,
        pagosLiquidacionDeposito,
        pagosArriendo,
        contratosArriendo,
        contratosDeposito,
        predios,
        propietarios,
        predioPropietarios,
        unidadesNegocio,
        facturasServiciosPublicos,
        pagosServiciosPublicos,
        incrementosArriendo,
        ajustesAdministracion,
        gestionesCartera,
      })

      if (!extracto) return null

      return {
        ...extracto,
        participacion: Number(
          beneficiario.porcentaje || extracto.liquidacionesUnidad?.[0]?.participacion || 0
        ),
      }
    })
    .filter(Boolean)

  return extractos.map((extracto, index) => ({
    ...extracto,
    indiceBeneficiario: index + 1,
    totalBeneficiarios: extractos.length,
  })  )
}

const obtenerContratosDepositoVigentesDepositanteLiquidacion = ({
  idDepositante,
  depositante = null,
  contratosDeposito,
  propietarios = [],
  predioPropietarios = [],
  liquidacionesDepositoHistorial,
  contratosArriendo,
}) => {
  const depositanteRef =
    depositante ||
    resolverDepositanteRegistrado(idDepositante, contratosDeposito, propietarios)

  if (!depositanteRef) return []

  return contratosDeposito
    .filter(
      (contrato) =>
        contrato.estado === 'Activo' &&
        contrato.codigoPredio &&
        contratoPerteneceADepositante(contrato, depositanteRef)
    )
    .map((contrato) => {
      const pendientes = obtenerLiquidacionesPendientesContratoDeposito(
        liquidacionesDepositoHistorial,
        contrato.id
      )
      const deudaPendiente = pendientes.reduce(
        (total, item) => total + obtenerDeudaPendienteLiquidacionDeposito(item),
        0
      )
      const unidadesLiquidables = obtenerContratosArriendoDepositarioLiquidacion({
        idDepositario: depositanteRef.id,
        depositante: depositanteRef,
        contratosDeposito,
        propietarios,
        predioPropietarios,
        contratosArriendo,
        liquidacionesDepositoHistorial,
        idContratoDepositoFiltro: contrato.id,
        codigoPredio: contrato.codigoPredio,
      })
      const beneficiarios = obtenerBeneficiariosLiquidacionContrato(contrato, predioPropietarios)

      return {
        contrato,
        idContratoDeposito: contrato.id,
        numeroContrato: obtenerNumeroContratoDepositoVisible(contrato, contratosDeposito),
        codigoPredio: contrato.codigoPredio,
        tipoComision: contrato.tipoComision,
        porcentajeComision: contrato.porcentajeComision,
        tipoPagoLiquidacion: normalizarTipoPagoLiquidacionDeposito(contrato.tipoPagoLiquidacion),
        deudaPendiente,
        unidadesLiquidables,
        totalUnidades: unidadesLiquidables.length,
        beneficiarios,
      }
    })
    .sort((a, b) =>
      String(a.numeroContrato || '').localeCompare(String(b.numeroContrato || ''))
    )
}

const obtenerContratosArriendoAsociadosDepositante = ({
  idDepositante,
  depositante = null,
  contratosDeposito = [],
  propietarios = [],
  predioPropietarios = [],
  contratosArriendo = [],
  idContratoDepositoFiltro = null,
  soloVigentes = true,
}) => {
  const depositanteRef =
    depositante ||
    resolverDepositanteRegistrado(idDepositante, contratosDeposito, propietarios)

  if (!depositanteRef) return []

  const prediosDepositante = new Set(
    obtenerDocumentosDepositante(
      depositanteRef,
      contratosDeposito,
      propietarios,
      predioPropietarios
    )
      .filter((contrato) => {
        if (!contrato.codigoPredio) return false
        if (idContratoDepositoFiltro && contrato.id !== idContratoDepositoFiltro) return false
        if (soloVigentes && contrato.estado !== 'Activo') return false
        return true
      })
      .map((contrato) => contrato.codigoPredio)
  )

  return contratosArriendo
    .filter((contrato) => prediosDepositante.has(contrato.codigoPredio))
    .filter((contrato) => !soloVigentes || contrato.estado === 'Activo')
    .map((contrato) => ({
      contrato,
      idContrato: obtenerIdContrato(contrato),
    }))
    .sort((a, b) =>
      String(a.contrato.nombreUnidad || '').localeCompare(String(b.contrato.nombreUnidad || ''))
    )
}

const normalizarCodigoPredioLiquidacion = (codigo = '') =>
  String(codigo).trim().toUpperCase()

const construirItemsLiquidacionPredio = ({
  codigoPredio,
  unidadesNegocio = [],
  contratosArriendo = [],
  contratosDeposito = [],
  predioPropietarios = [],
  liquidacionesDepositoHistorial = [],
}) => {
  const codigoNorm = normalizarCodigoPredioLiquidacion(codigoPredio)
  if (!codigoNorm) return []

  const coincideCodigoPredio = (codigo = '') =>
    normalizarCodigoPredioLiquidacion(codigo) === codigoNorm

  const unidadesPredio = (unidadesNegocio || []).filter(
    (unidad) =>
      coincideCodigoPredio(unidad.codigoPredio) ||
      String(unidad.codigoPredio || '').trim() === String(codigoPredio || '').trim()
  )

  const unidadesDesdeLiquidacion = new Map()
  ;(liquidacionesDepositoHistorial || [])
    .filter((liquidacion) => coincideCodigoPredio(liquidacion.codigoPredio))
    .forEach((liquidacion) => {
      const clave =
        liquidacion.claveUnidad ||
        liquidacion.idUnidad ||
        `${liquidacion.unidad || 'sin-unidad'}-${liquidacion.idContratoArriendo || ''}`

      if (!clave || unidadesDesdeLiquidacion.has(clave)) return

      unidadesDesdeLiquidacion.set(clave, {
        id: liquidacion.idUnidad || clave,
        codigoPredio: liquidacion.codigoPredio || codigoPredio,
        nombre: liquidacion.unidad || 'Sin unidad',
        tipo: 'Liquidación',
        estado: 'Liquidable',
      })
    })

  const idsUnidadesPredio = new Set(unidadesPredio.map((unidad) => unidad.id))
  unidadesDesdeLiquidacion.forEach((unidad, clave) => {
    if (!idsUnidadesPredio.has(unidad.id) && !idsUnidadesPredio.has(clave)) {
      unidadesPredio.push(unidad)
      idsUnidadesPredio.add(unidad.id)
    }
  })

  const arriendosPredio = (contratosArriendo || []).filter(
    (contrato) =>
      coincideCodigoPredio(contrato.codigoPredio) ||
      String(contrato.codigoPredio || '').trim() === String(codigoPredio || '').trim() ||
      (contrato.idUnidad && idsUnidadesPredio.has(contrato.idUnidad))
  )

  const arriendosActivos = arriendosPredio.filter((contrato) => contrato.estado === 'Activo')
  const arriendosConLiquidacion = arriendosPredio.filter((contrato) =>
    contratoArriendoTieneLiquidacionBeneficiarios(
      contrato,
      contratosDeposito,
      predioPropietarios,
      liquidacionesDepositoHistorial
    )
  )
  const arriendosListables =
    arriendosActivos.length > 0
      ? arriendosActivos
      : arriendosConLiquidacion.length > 0
        ? arriendosConLiquidacion
        : arriendosPredio

  const construirItemArriendo = (contrato) => {
    const idContrato = obtenerIdContrato(contrato)
    return {
      contrato,
      idContrato,
      claveUnidad: obtenerClaveUnidadLiquidacion({
        idUnidad: contrato.idUnidad,
        unidad: contrato.nombreUnidad,
        idContratoArriendo: idContrato,
      }),
      deuda: calcularDeudaLiquidacionArriendoBeneficiarios({
        contratoArriendo: contrato,
        contratosDeposito,
        predioPropietarios,
        liquidacionesDepositoHistorial,
      }),
      sinContratoArriendo: false,
    }
  }

  const arriendosUsados = new Set()
  const items = []

  unidadesPredio.forEach((unidad) => {
    const contrato =
      arriendosListables.find(
        (item) => !arriendosUsados.has(obtenerIdContrato(item)) && item.idUnidad === unidad.id
      ) ||
      arriendosListables.find(
        (item) =>
          !arriendosUsados.has(obtenerIdContrato(item)) &&
          String(item.nombreUnidad || '').trim().toUpperCase() ===
            String(unidad.nombre || '').trim().toUpperCase()
      ) ||
      null

    if (contrato) {
      arriendosUsados.add(obtenerIdContrato(contrato))
      items.push(construirItemArriendo(contrato))
      return
    }

    items.push({
      contrato: null,
      unidad,
      idContrato: '',
      claveUnidad: unidad.id,
      deuda: 0,
      sinContratoArriendo: true,
    })
  })

  arriendosListables.forEach((contrato) => {
    const idContrato = obtenerIdContrato(contrato)
    if (!arriendosUsados.has(idContrato)) {
      items.push(construirItemArriendo(contrato))
    }
  })

  return items.sort((a, b) => {
    const nombreA = a.contrato?.nombreUnidad || a.unidad?.nombre || ''
    const nombreB = b.contrato?.nombreUnidad || b.unidad?.nombre || ''
    return String(nombreA).localeCompare(String(nombreB))
  })
}

const obtenerContratosArriendoDepositarioLiquidacion = ({
  idDepositario,
  depositante = null,
  contratosDeposito,
  propietarios = [],
  predios = [],
  contratosArriendo,
  liquidacionesDepositoHistorial,
  predioPropietarios,
  unidadesNegocio = [],
  idContratoDepositoFiltro = null,
  codigoPredio = null,
}) => {
  const codigoPredioRef =
    codigoPredio ||
    (idContratoDepositoFiltro
      ? contratosDeposito.find((contrato) => contrato.id === idContratoDepositoFiltro)
          ?.codigoPredio
      : null)

  if (codigoPredioRef) {
    return construirItemsLiquidacionPredio({
      codigoPredio: codigoPredioRef,
      unidadesNegocio,
      contratosArriendo,
      contratosDeposito,
      predioPropietarios,
      liquidacionesDepositoHistorial,
    })
  }

  const depositanteRef =
    depositante ||
    resolverDepositanteRegistrado(idDepositario, contratosDeposito, propietarios)

  if (!depositanteRef) return []

  const prediosPermitidos = new Set()

  if (Array.isArray(predios) && predios.length > 0) {
    obtenerPrediosAsociadosDepositante(
      depositanteRef,
      predios,
      predioPropietarios,
      contratosDeposito,
      propietarios
    ).forEach((predio) => prediosPermitidos.add(normalizarCodigoPredioLiquidacion(predio.codigo)))
  } else {
    obtenerDocumentosDepositante(
      depositanteRef,
      contratosDeposito,
      propietarios,
      predioPropietarios
    ).forEach((contrato) => {
      if (contrato.codigoPredio) {
        prediosPermitidos.add(normalizarCodigoPredioLiquidacion(contrato.codigoPredio))
      }
    })
    obtenerCodigosPrediosDepositante(depositanteRef, predioPropietarios).forEach((codigo) =>
      prediosPermitidos.add(normalizarCodigoPredioLiquidacion(codigo))
    )
  }

  return [...prediosPermitidos].flatMap((codigoNorm) => {
    const predioRef =
      (predios || []).find(
        (predio) => normalizarCodigoPredioLiquidacion(predio.codigo) === codigoNorm
      ) || { codigo: codigoNorm }

    return construirItemsLiquidacionPredio({
      codigoPredio: predioRef.codigo,
      unidadesNegocio,
      contratosArriendo,
      contratosDeposito,
      predioPropietarios,
      liquidacionesDepositoHistorial,
    })
  })
}

const obtenerDepositarioContratoArriendoLiquidacion = (
  contratoArriendo,
  contratosDeposito,
  predioPropietarios
) => {
  const contratoDeposito = obtenerContratoDepositoActivoPredio(
    contratoArriendo.codigoPredio,
    contratosDeposito
  )
  if (!contratoDeposito) return null

  const beneficiarios = obtenerBeneficiariosLiquidacionContrato(
    contratoDeposito,
    predioPropietarios
  )
  const depositario = beneficiarios.find((item) => item.esContratante) || beneficiarios[0]

  return depositario?.idPropietario || obtenerIdDepositanteContrato(contratoDeposito) || null
}

// =============================================================================
// LIQUIDACION DEPOSITO - SERVICIOS PUBLICOS FIJOS POR CORTE
// Recaudo de servicios con cobro fijo mensual liquidable al depositante.
// =============================================================================

const mesActivoEnContratoArriendo = (contrato, mes) =>
  contratoArriendoActivoEnMes(contrato, mes)

// =============================================================================
// LIQUIDACION DEPOSITO - SERVICIOS PUBLICOS FIJOS POR CORTE
// Recaudo de servicios con cobro fijo mensual liquidable al depositante.
// =============================================================================

const construirServiciosPublicosFijosLiquidacionDepositoCorte = ({
  mes,
  contratoArriendo,
  unidadesNegocio = [],
  facturasServiciosPublicos = [],
  pagosServiciosPublicos = [],
  participacion = 100,
  usarValorCausacion = false,
}) => {
  if (!contratoArriendo || !mesActivoEnContratoArriendo(contratoArriendo, mes)) return []

  const unidad = (unidadesNegocio || []).find(
    (item) => item.id === contratoArriendo.idUnidad
  )
  if (!unidad) return []

  return (unidad.serviciosPublicos || [])
    .map((servicio, index) => {
      if (servicio.tipoCobro !== 'Valor fijo mensual') return null

      const valorFijo = Number(servicio.valorFijo || 0)
      if (valorFijo <= 0) return null

      const idServicio = servicio.id || `srv-${index}`
      const movimiento = calcularMovimientoServicioMes(
        mes,
        servicio,
        {
          idUnidad: unidad.id,
          idServicio,
          codigoPredio: contratoArriendo.codigoPredio,
          unidad,
          servicioIndex: index,
        },
        facturasServiciosPublicos,
        pagosServiciosPublicos
      )

      const valorRecaudado = Number(movimiento.pagado || 0)
      const valorCausacion = valorFijo
      if (!usarValorCausacion && valorRecaudado <= 0) return null

      const baseLiquidacion = usarValorCausacion ? valorCausacion : valorRecaudado

      return {
        idServicio,
        concepto: servicio.tipo || `Servicio ${index + 1}`,
        empresa: servicio.empresa || '',
        tipoCobro: servicio.tipoCobro,
        valorFijo,
        valorCausacion,
        valorRecaudado,
        valorBeneficiario: Math.round(baseLiquidacion * (participacion / 100)),
        recibo: movimiento.recibo || '',
        fechaPago: movimiento.fechaPago || '',
        usarValorCausacion,
      }
    })
    .filter(Boolean)
}

// =============================================================================
// LIQUIDACION DEPOSITO - DESGLOSE CARGOS POR CORTE
// Canon base, IVA, comision INH y servicios fijos discriminados cargo a cargo.
// =============================================================================

const construirDesgloseCargosCorteLiquidacionDeposito = ({
  liquidacion,
  participacion = 100,
  porcentajeComision = 0,
  serviciosFijos = [],
  abonoRealizado = 0,
  saldoPendiente = 0,
  esPagoFijoMensual = false,
}) => {
  const items = []
  const detallePagos = (liquidacion?.detallePagos || []).filter(
    (pago) =>
      Number(pago.valorBruto || 0) > 0 ||
      Number(pago.valorCanonLiquidacion || 0) > 0
  )

  let totalCanonBase = detallePagos.reduce(
    (total, pago) => total + Number(pago.canonBaseBeneficiario || 0),
    0
  )
  let totalIva = detallePagos.reduce(
    (total, pago) => total + Number(pago.ivaBeneficiario || 0),
    0
  )
  let totalComision = detallePagos.reduce(
    (total, pago) => total + Number(pago.comisionInmobiliaria || 0),
    0
  )

  if (detallePagos.length === 0 && liquidacion) {
    totalComision = Number(liquidacion.comisionInmobiliariaPropietario || 0)
    if (esPagoFijoMensual) {
      const canonIva = obtenerCanonIvaBeneficiarioLiquidacionDepositoMes({
        liquidacion,
        participacion,
      })
      totalCanonBase = canonIva.canonBaseBeneficiario
      totalIva = canonIva.ivaBeneficiario
    }
  }

  const descuentoAdministracion = Number(
    liquidacion?.valorAdministracionDescontadaBeneficiario || 0
  )
  const totalServiciosFijos = serviciosFijos.reduce(
    (total, servicio) => total + Number(servicio.valorBeneficiario || 0),
    0
  )
  const totalIvaComision = totalComision > 0 ? calcularIvaComisionInh(totalComision) : 0
  const porcentajeAbonoCanon = Number(liquidacion?.porcentajeAbonoCanonMes || 0)
  const sufijoProvisional = obtenerSufijoComisionProvisionalLiquidacionDeposito({
    esPagoFijoMensual,
    porcentajeAbonoCanon,
  })

  const etiquetaCanon = esPagoFijoMensual ? 'Canon de arriendo' : 'Canon base liquidable'
  const etiquetaIvaCanon = esPagoFijoMensual
    ? 'IVA del canon de arriendo'
    : 'IVA del canon al depositante'
  const etiquetaIvaComision = esPagoFijoMensual
    ? `IVA del porcentaje acordado (${porcentajeComision}%)`
    : `IVA comisión INH (${porcentajeComision}%)`

  if (totalCanonBase > 0) {
    items.push({
      concepto: etiquetaCanon,
      tipo: 'canon-base',
      cargo: totalCanonBase,
      abono: 0,
    })
  }

  if (totalIva > 0) {
    items.push({
      concepto: etiquetaIvaCanon,
      tipo: 'iva-canon',
      cargo: totalIva,
      abono: 0,
    })
  }

  serviciosFijos.forEach((servicio) => {
    const empresaEtiqueta = servicio.empresa ? ` (${servicio.empresa})` : ''
    const concepto = esPagoFijoMensual
      ? `Servicio público fijo – ${servicio.concepto}${empresaEtiqueta} – valor de causación`
      : `Servicio público fijo – ${servicio.concepto}${empresaEtiqueta}`
    items.push({
      concepto,
      tipo: 'servicio-publico-fijo',
      cargo: Number(servicio.valorBeneficiario || 0),
      abono: 0,
      valorRecaudado: servicio.valorRecaudado,
      valorFijo: servicio.valorFijo,
      valorCausacion: servicio.valorCausacion,
    })
  })

  if (descuentoAdministracion > 0) {
    items.push({
      concepto: 'Descuento administración de edificio (incluida en canon)',
      tipo: 'descuento-administracion',
      cargo: 0,
      abono: descuentoAdministracion,
    })
  }

  if (totalComision > 0) {
    items.push({
      concepto: esPagoFijoMensual
        ? `Porcentaje acordado – Comisión INH (${porcentajeComision}%)`
        : `Comisión INH (${porcentajeComision}% sobre canon base)${sufijoProvisional}`,
      tipo: 'comision',
      cargo: 0,
      abono: totalComision,
      esProvisional: Boolean(sufijoProvisional),
    })
  }

  if (totalIvaComision > 0) {
    items.push({
      concepto: `${etiquetaIvaComision}${sufijoProvisional}`,
      tipo: 'iva-comision',
      cargo: 0,
      abono: totalIvaComision,
      esProvisional: Boolean(sufijoProvisional),
    })
  }

  if (abonoRealizado > 0) {
    items.push({
      concepto: 'Pago realizado por INH al depositante',
      tipo: 'pago-inh',
      cargo: 0,
      abono: abonoRealizado,
    })
  }

  const totalCargo = totalCanonBase + totalIva + totalServiciosFijos
  const totalAbono =
    totalComision + totalIvaComision + descuentoAdministracion + abonoRealizado
  const totalAPagarCorte =
    totalCanonBase +
    totalIva +
    totalServiciosFijos -
    totalComision -
    totalIvaComision -
    descuentoAdministracion

  return {
    items,
    totalCanonBase,
    totalIva,
    totalComision,
    totalIvaComision,
    totalServiciosFijos,
    descuentoAdministracion,
    totalCargo,
    totalAbono,
    totalAPagarCorte,
    abonoRealizado,
    saldoPendienteCorte: saldoPendiente,
    esPagoFijoMensual,
  }
}

// =============================================================================
// LIQUIDACION DEPOSITO - ORDEN MOVIMIENTOS EXTRACTO
// Orden cronologico por corte y fecha para saldos y tabla mes a mes.
// =============================================================================

const ordenarMovimientosExtractoLiquidacionDeposito = (movimientos = []) =>
  [...movimientos].sort((a, b) => {
    const mesComparacion = String(a.mesCausado || '').localeCompare(String(b.mesCausado || ''))
    if (mesComparacion !== 0) return mesComparacion

    const fechaComparacion = String(a.fecha || '').localeCompare(String(b.fecha || ''))
    if (fechaComparacion !== 0) return fechaComparacion

    const prioridadTipo = (tipo = '') => {
      if (tipo === 'referencia-pago-arrendatario') return 0
      if (tipo === 'canon-base') return 1
      if (tipo === 'iva-canon') return 2
      if (tipo === 'servicio-publico-fijo') return 3
      if (tipo === 'descuento-administracion') return 4
      if (tipo === 'comision') return 5
      if (tipo === 'iva-comision') return 6
      if (tipo === 'pago-inh') return 7
      return 8
    }

    return prioridadTipo(a.tipo) - prioridadTipo(b.tipo)
  })

// =============================================================================
// LIQUIDACION DEPOSITO - ABONOS INH EN CASCADA
// Aplica pagos al depositante del corte mas antiguo al mas reciente.
// =============================================================================

const aplicarAbonosInhCascadaExtractoLiquidacionDeposito = ({
  movimientos = [],
  pagosInh = [],
  mesesOrdenados = [],
}) => {
  const saldoPendientePorMes = new Map()

  mesesOrdenados.forEach((mes) => {
    const saldoMes = movimientos
      .filter((movimiento) => movimiento.mesCausado === mes)
      .reduce((total, movimiento) => total + Number(movimiento.valor || 0), 0)
    saldoPendientePorMes.set(mes, Math.max(0, saldoMes))
  })

  const pagosOrdenados = [...pagosInh].sort((a, b) => {
    const fechaComparacion = String(a.fechaPago || '').localeCompare(String(b.fechaPago || ''))
    if (fechaComparacion !== 0) return fechaComparacion
    return String(a.id || '').localeCompare(String(b.id || ''))
  })

  const abonosMovimientos = []

  pagosOrdenados.forEach((pago) => {
    let restante = obtenerValorNetoPagoLiquidacionDeposito(pago)
    if (restante <= 0) return

    mesesOrdenados.forEach((mes) => {
      if (restante <= 0) return

      const pendiente = Number(saldoPendientePorMes.get(mes) || 0)
      if (pendiente <= 0) return

      const aplicado = Math.min(restante, pendiente)
      if (aplicado <= 0) return

      restante -= aplicado
      saldoPendientePorMes.set(mes, pendiente - aplicado)

      const referenciaArrendatario = obtenerReferenciaPagosArrendatarioPagoInh(pago)
      abonosMovimientos.push({
        fecha: pago.fechaPago || `${mes}-01`,
        mesCausado: mes,
        detalle: `Pago realizado a depositario – Recibo ${pago.numeroRecibo || pago.id}${
          referenciaArrendatario ? ` (ref. ${referenciaArrendatario})` : ''
        }`,
        tipo: 'pago-inh',
        cargo: 0,
        abono: aplicado,
        valor: -aplicado,
        idPagoLiquidacionDeposito: pago.id,
        mesRegistroPago: pago.mes,
      })
    })
  })

  return [...movimientos, ...abonosMovimientos]
}

const construirMovimientosExtractoLiquidacionDeposito = ({
  liquidacionesUnidad = [],
  pagosLiquidacionDeposito = [],
  idPropietario,
  claveUnidad,
  idContratoDeposito,
  contratoArriendo = null,
  unidadesNegocio = [],
  facturasServiciosPublicos = [],
  pagosServiciosPublicos = [],
  mesesVigentes = [],
  esPagosParciales = false,
}) => {
  const pagosUnidad = pagosLiquidacionDeposito
    .filter(
      (pago) =>
        pago.idPropietario === idPropietario &&
        pago.idContratoDeposito === idContratoDeposito &&
        ((pago.claveUnidad || '') === claveUnidad ||
          coincideLiquidacionDepositoUnidadArriendo({
            liquidacion: {
              claveUnidad: pago.claveUnidad,
              idUnidad: pago.idUnidad,
              unidad: pago.unidad,
              idContratoArriendo: pago.idContratoArriendo,
            },
            claveUnidad,
            idContratoArriendo: obtenerIdContrato(contratoArriendo),
            contratoArriendo,
          }))
    )

  const movimientos = []
  const serviciosAgregadosPorMes = new Set()

  ;[...liquidacionesUnidad]
    .sort((a, b) => String(a.mes).localeCompare(String(b.mes)))
    .forEach((liquidacion) => {

      const participacion = Number(liquidacion.participacion || 100)
      const porcentajeComision = liquidacion.porcentajeComision || 0
      const esPagoFijo = !!liquidacion.esPagoFijoMensual
      const detallePagosArrendatario = (liquidacion.detallePagos || []).filter(
        (pago) =>
          Number(pago.valorBruto || 0) > 0 ||
          Number(pago.valorAdministracionDescontada || 0) > 0 ||
          Number(pago.valorCanonLiquidacion || 0) > 0 ||
          Number(pago.montoLiquidableAsignado || 0) > 0
      )
      const tieneRecaudoLiquidable =
        detallePagosArrendatario.length > 0 ||
        Number(liquidacion.valorBrutoPropietario || 0) > 0 ||
        Number(liquidacion.totalRecaudadoPredio || 0) > 0

      if (!esPagoFijo && !tieneRecaudoLiquidable) return

      const usoDetallePagos = detallePagosArrendatario.length > 0

      const serviciosFijos = construirServiciosPublicosFijosLiquidacionDepositoCorte({
        mes: liquidacion.mes,
        contratoArriendo,
        unidadesNegocio,
        facturasServiciosPublicos,
        pagosServiciosPublicos,
        participacion,
        usarValorCausacion: esPagoFijo,
      })

      const agregarMovimiento = (datos) => {
        const cargo = Number(datos.cargo || 0)
        const abono = Number(datos.abono || 0)
        movimientos.push({
          ...datos,
          cargo,
          abono,
          valor: cargo - abono,
        })
      }

      const agregarMovimientosServiciosFijos = (fechaBase) => {
        if (serviciosAgregadosPorMes.has(liquidacion.mes)) return
        serviciosFijos.forEach((servicio) => {
          agregarMovimiento({
            fecha: servicio.fechaPago || fechaBase || `${liquidacion.mes}-28`,
            mesCausado: liquidacion.mes,
            detalle: esPagoFijo
              ? `Servicio público fijo – ${servicio.concepto}${
                  servicio.empresa ? ` (${servicio.empresa})` : ''
                } – Valor de causación ${formatearValorMoneda(servicio.valorCausacion || servicio.valorFijo)}`
              : `Servicio público fijo – ${servicio.concepto}${
                  servicio.empresa ? ` (${servicio.empresa})` : ''
                } – Recaudo ${formatearValorMoneda(servicio.valorRecaudado)}`,
            tipo: 'servicio-publico-fijo',
            cargo: Number(servicio.valorBeneficiario || 0),
            abono: 0,
          })
        })
        if (serviciosFijos.length > 0) serviciosAgregadosPorMes.add(liquidacion.mes)
      }

      const agregarDescuentosComision = (
        fechaMovimiento,
        valorComision,
        recibo = '',
        porcentajeAbonoPago = liquidacion.porcentajeAbonoCanonMes
      ) => {
        if (valorComision <= 0) return
        const sufijoProvisional = obtenerSufijoComisionProvisionalLiquidacionDeposito({
          esPagoFijoMensual: esPagoFijo,
          porcentajeAbonoCanon: porcentajeAbonoPago,
        })
        agregarMovimiento({
          fecha: fechaMovimiento,
          mesCausado: liquidacion.mes,
          detalle: esPagoFijo
            ? `Porcentaje acordado – Comisión INH (${porcentajeComision}%)`
            : `Comisión INH (${porcentajeComision}% sobre canon base) periodo ${liquidacion.mes}${
                recibo ? ` – Recibo ${recibo}` : ''
              }${sufijoProvisional}`,
          tipo: 'comision',
          cargo: 0,
          abono: valorComision,
          esProvisional: Boolean(sufijoProvisional),
        })

        const ivaComision = calcularIvaComisionInh(valorComision)
        if (ivaComision > 0) {
          agregarMovimiento({
            fecha: fechaMovimiento,
            mesCausado: liquidacion.mes,
            detalle: esPagoFijo
              ? `IVA del porcentaje acordado (${porcentajeComision}%)`
              : `IVA comisión INH (${porcentajeComision}%) periodo ${liquidacion.mes}${
                  recibo ? ` – Recibo ${recibo}` : ''
                }${sufijoProvisional}`,
            tipo: 'iva-comision',
            cargo: 0,
            abono: ivaComision,
            esProvisional: Boolean(sufijoProvisional),
          })
        }
      }

      if (usoDetallePagos) {
        detallePagosArrendatario
          .sort((a, b) => String(a.fechaPago || '').localeCompare(String(b.fechaPago || '')))
          .forEach((pago) => {
            const recibo = pago.recibo || pago.numeroRecibo || '—'
            const valorPagadoTotalRecibo = Number(
              pago.valorPagadoTotalRecibo ??
                pago.pago?.valorPagado ??
                pago.valorPagado ??
                0
            )
            const fechaMovimiento = pago.fechaPago || `${liquidacion.mes}-28`
            let canonBaseBeneficiario = Number(pago.canonBaseBeneficiario || 0)
            let ivaBeneficiario = Number(pago.ivaBeneficiario || 0)
            const valorComision = Number(pago.comisionInmobiliaria || 0)
            const valorAdministracionDescontada = Math.round(
              Number(pago.valorAdministracionDescontada || 0) * (participacion / 100)
            )

            if (
              canonBaseBeneficiario <= 0 &&
              ivaBeneficiario <= 0 &&
              valorAdministracionDescontada <= 0
            ) {
              const valorBrutoLinea = Number(pago.valorBruto || 0)
              const montoLiquidableLinea = Number(
                pago.montoLiquidableAsignado ||
                  pago.valorLiquidablePropietario ||
                  pago.montoLiquidablePropietario ||
                  0
              )
              const ivaMesLinea = Number(pago.ivaCanonMes || liquidacion.ivaCanonMes || 0)
              const montoLiquidableMesLinea = Number(
                pago.montoLiquidablePropietario || liquidacion.montoLiquidablePropietarioMes || 0
              )
              const baseBruto =
                valorBrutoLinea > 0
                  ? valorBrutoLinea
                  : montoLiquidableLinea > 0
                    ? Math.round(montoLiquidableLinea * (participacion / 100))
                    : 0

              if (baseBruto > 0) {
                const ratioIva =
                  montoLiquidableMesLinea > 0 ? ivaMesLinea / montoLiquidableMesLinea : 0
                ivaBeneficiario = Math.round(baseBruto * ratioIva)
                canonBaseBeneficiario = Math.max(0, baseBruto - ivaBeneficiario)
              }
            }

            if (
              canonBaseBeneficiario <= 0 &&
              ivaBeneficiario <= 0 &&
              valorAdministracionDescontada <= 0
            ) {
              return
            }

            if (valorPagadoTotalRecibo > 0 && !esPagoFijo) {
              agregarMovimiento({
                fecha: fechaMovimiento,
                mesCausado: liquidacion.mes,
                detalle: `Recaudo arrendatario – Recibo ${recibo} (${formatearValorMoneda(valorPagadoTotalRecibo)})`,
                tipo: 'referencia-pago-arrendatario',
                cargo: 0,
                abono: 0,
                valorPagoArrendatario: valorPagadoTotalRecibo,
                esReferencia: true,
              })
            }

            if (canonBaseBeneficiario > 0) {
              agregarMovimiento({
                fecha: fechaMovimiento,
                mesCausado: liquidacion.mes,
                detalle: esPagoFijo
                  ? `Canon de arriendo periodo ${liquidacion.mes}`
                  : `Canon base liquidable periodo ${liquidacion.mes} – Recibo ${recibo}`,
                tipo: 'canon-base',
                cargo: canonBaseBeneficiario,
                abono: 0,
                valorPagoArrendatario: valorPagadoTotalRecibo,
              })
            }

            if (ivaBeneficiario > 0) {
              agregarMovimiento({
                fecha: fechaMovimiento,
                mesCausado: liquidacion.mes,
                detalle: esPagoFijo
                  ? `IVA canon periodo ${liquidacion.mes}`
                  : `IVA canon al depositante periodo ${liquidacion.mes} – Recibo ${recibo}`,
                tipo: 'iva-canon',
                cargo: ivaBeneficiario,
                abono: 0,
                valorPagoArrendatario: valorPagadoTotalRecibo,
              })
            }

            if (esPagoFijo) {
              agregarMovimientosServiciosFijos(fechaMovimiento)
            }

            if (valorAdministracionDescontada > 0) {
              agregarMovimiento({
                fecha: fechaMovimiento,
                mesCausado: liquidacion.mes,
                detalle: 'Descuento administración de edificio (incluida en canon)',
                tipo: 'descuento-administracion',
                cargo: 0,
                abono: valorAdministracionDescontada,
              })
            }

            agregarDescuentosComision(
              fechaMovimiento,
              valorComision,
              recibo,
              pago.porcentajeAbonoCanon ??
                pago.porcentajeAbonoCanonPago ??
                liquidacion.porcentajeAbonoCanonMes
            )
          })
      } else {
        const fechaRecaudo =
          liquidacion.detallePagos
            ?.map((pago) => pago.fechaPago)
            .filter(Boolean)
            .sort()[0] || `${liquidacion.mes}-28`
        const valorComision = Number(liquidacion.comisionInmobiliariaPropietario || 0)
        const valorAdministracionDescontada = Number(
          liquidacion.valorAdministracionDescontadaBeneficiario || 0
        )

        let canonBaseBeneficiario = 0
        let ivaBeneficiario = 0

        if (esPagoFijo) {
          const canonIva = obtenerCanonIvaBeneficiarioLiquidacionDepositoMes({
            liquidacion,
            participacion,
          })
          canonBaseBeneficiario = canonIva.canonBaseBeneficiario
          ivaBeneficiario = canonIva.ivaBeneficiario
        } else {
          const valorBruto = Number(liquidacion.valorBrutoPropietario || 0)
          const montoLiquidable = Number(liquidacion.montoLiquidablePropietarioMes || 0)
          const ivaMes = Number(liquidacion.ivaCanonMes || 0)
          const ratioIva = montoLiquidable > 0 ? ivaMes / montoLiquidable : 0
          ivaBeneficiario = Math.round(valorBruto * ratioIva)
          canonBaseBeneficiario = Math.max(0, valorBruto - ivaBeneficiario)
        }

        if (canonBaseBeneficiario > 0) {
          agregarMovimiento({
            fecha: fechaRecaudo,
            mesCausado: liquidacion.mes,
            detalle: esPagoFijo
              ? `Canon de arriendo – Corte ${liquidacion.mes}`
              : `Canon base liquidable (${liquidacion.porcentajeAbonoCanonMes || 0}% cubierto)`,
            tipo: 'canon-base',
            cargo: canonBaseBeneficiario,
            abono: 0,
          })
        }

        if (ivaBeneficiario > 0) {
          agregarMovimiento({
            fecha: fechaRecaudo,
            mesCausado: liquidacion.mes,
            detalle: esPagoFijo
              ? `IVA del canon de arriendo – Corte ${liquidacion.mes}`
              : 'IVA del canon al depositante',
            tipo: 'iva-canon',
            cargo: ivaBeneficiario,
            abono: 0,
          })
        }

        if (esPagoFijo) {
          agregarMovimientosServiciosFijos(fechaRecaudo)
        }

        if (valorAdministracionDescontada > 0) {
          agregarMovimiento({
            fecha: fechaRecaudo,
            mesCausado: liquidacion.mes,
            detalle: 'Descuento administración de edificio (incluida en canon)',
            tipo: 'descuento-administracion',
            cargo: 0,
            abono: valorAdministracionDescontada,
          })
        }

        agregarDescuentosComision(fechaRecaudo, valorComision)
      }

      if (!esPagoFijo) {
        serviciosFijos.forEach((servicio) => {
          agregarMovimiento({
            fecha: servicio.fechaPago || `${liquidacion.mes}-28`,
            mesCausado: liquidacion.mes,
            detalle: `Servicio público fijo – ${servicio.concepto}${
              servicio.empresa ? ` (${servicio.empresa})` : ''
            } – Recaudo ${formatearValorMoneda(servicio.valorRecaudado)}`,
            tipo: 'servicio-publico-fijo',
            cargo: Number(servicio.valorBeneficiario || 0),
            abono: 0,
          })
        })
      }
    })

  const mesesOrdenados = [
    ...new Set([
      ...(esPagosParciales ? mesesVigentes : []),
      ...liquidacionesUnidad.map((liquidacion) => liquidacion.mes),
      ...movimientos.map((movimiento) => movimiento.mesCausado),
      ...pagosUnidad.map((pago) => pago.mes),
    ]),
  ]
    .filter(Boolean)
    .sort((a, b) => String(a).localeCompare(String(b)))

  const movimientosConAbonos = aplicarAbonosInhCascadaExtractoLiquidacionDeposito({
    movimientos,
    pagosInh: pagosUnidad,
    mesesOrdenados,
  })

  const movimientosOrdenados = ordenarMovimientosExtractoLiquidacionDeposito(movimientosConAbonos)

  let saldo = 0
  return movimientosOrdenados.map((movimiento) => {
    saldo += Number(movimiento.valor || 0)
    return { ...movimiento, saldo }
  })
}

// =============================================================================
// LIQUIDACION DEPOSITO - MESES CORTES EXTRACTO
// Todos los meses vigentes del contrato de deposito para el detalle por corte.
// =============================================================================

const obtenerMesesCortesVigentesExtractoLiquidacionDeposito = ({
  contratoDeposito,
  contratoArriendo = null,
  contratosArriendo = [],
  pagosArriendo = [],
}) => {
  const inicio = obtenerMesInicioLiquidacionDeposito({
    contratoDeposito,
    contratoArriendo,
    contratosArriendo,
  })
  if (!inicio) return []

  const hoy = obtenerMesActualCalendarioISO()
  let mesFin = hoy

  const finDeposito = (contratoDeposito?.fechaFin || '').slice(0, 7)
  const finArriendo = (contratoArriendo?.fechaFin || '').slice(0, 7)
  ;[finDeposito, finArriendo].filter(Boolean).forEach((fin) => {
    if (fin < mesFin) mesFin = fin
  })

  const idContratoArriendo = contratoArriendo ? obtenerIdContrato(contratoArriendo) : ''
  ;(pagosArriendo || [])
    .filter((pago) => !idContratoArriendo || pago.idContrato === idContratoArriendo)
    .flatMap((pago) => [pago.mes, (pago.fechaPago || '').slice(0, 7)].filter(Boolean))
    .forEach((mes) => {
      if (mes > mesFin && (!finDeposito || mes <= finDeposito)) mesFin = mes
    })

  ;(contratosArriendo || [])
    .filter((contrato) => contrato.codigoPredio === contratoDeposito?.codigoPredio)
    .flatMap((contrato) => obtenerRangoMesesCausadosContrato(contrato, pagosArriendo))
    .forEach((mes) => {
      if (mes > mesFin && (!finDeposito || mes <= finDeposito)) mesFin = mes
    })

  if (mesFin < inicio) return [inicio]

  return listarMesesEntre(inicio, mesFin).filter((mes) =>
    contratoDepositoVigenteEnMes(contratoDeposito, mes)
  )
}

// =============================================================================
// LIQUIDACION DEPOSITO - CORTE CERO EXTRACTO
// Periodo sin liquidacion: valores en ceros en el detalle por corte.
// =============================================================================

const construirCorteCeroExtractoLiquidacionDeposito = ({
  mes,
  porcentajeComision = 0,
  esPagoFijoMensual = false,
}) => {
  const desgloseCargos = construirDesgloseCargosCorteLiquidacionDeposito({
    liquidacion: null,
    participacion: 100,
    porcentajeComision,
    serviciosFijos: [],
    abonoRealizado: 0,
    saldoPendiente: 0,
    esPagoFijoMensual,
  })

  return {
    mes,
    liquidacion: null,
    movimientos: [],
    pagosArrendatario: [],
    totalPagadoArrendatario: 0,
    totalRecaudado: 0,
    montoLiquidable: 0,
    porcentajeCanon: 0,
    valorNetoPropietario: 0,
    comisionInmobiliaria: 0,
    abonoRealizado: 0,
    deudaPendiente: 0,
    saldoPendienteCorte: 0,
    serviciosFijos: [],
    desgloseCargos,
    esPagoFijoMensual,
    totalAPagarCorte: 0,
    estadoPago: esPagoFijoMensual ? 'Sin liquidación' : 'Sin recaudo',
  }
}

// =============================================================================
// LIQUIDACION DEPOSITO - COMPLETAR CORTES EXTRACTO
// Inserta cortes en cero para todos los meses del contrato sin liquidacion.
// =============================================================================

const completarCortesExtractoLiquidacionDeposito = ({
  cortes = [],
  contratoDeposito,
  contratoArriendo = null,
  contratosArriendo = [],
  pagosArriendo = [],
  porcentajeComision = 0,
  esPagoFijoMensual = false,
}) => {
  const meses = obtenerMesesCortesVigentesExtractoLiquidacionDeposito({
    contratoDeposito,
    contratoArriendo,
    contratosArriendo,
    pagosArriendo,
  })
  const mapaCortes = new Map(cortes.map((corte) => [corte.mes, corte]))

  return meses.map((mes) => {
    if (mapaCortes.has(mes)) return mapaCortes.get(mes)
    return construirCorteCeroExtractoLiquidacionDeposito({
      mes,
      porcentajeComision,
      esPagoFijoMensual,
    })
  })
}

// =============================================================================
// DERIVADOS - CORTES EXTRACTO LIQUIDACION DEPOSITO
// Agrupa liquidaciones y movimientos por mes causado (corte mensual).
// =============================================================================

const construirCortesExtractoLiquidacionDeposito = ({
  liquidacionesUnidad = [],
  movimientos = [],
  contratoArriendo = null,
  unidadesNegocio = [],
  facturasServiciosPublicos = [],
  pagosServiciosPublicos = [],
}) => {
  const meses = [
    ...new Set([
      ...liquidacionesUnidad.map((liquidacion) => liquidacion.mes),
      ...movimientos.map((movimiento) => movimiento.mesCausado),
    ]),
  ]
    .filter(Boolean)
    .sort((a, b) => String(a).localeCompare(String(b)))

  return meses.map((mes) => {
    const liquidacion =
      liquidacionesUnidad.find((item) => item.mes === mes) || null
    const movimientosCorte = ordenarMovimientosExtractoLiquidacionDeposito(
      movimientos.filter((movimiento) => movimiento.mesCausado === mes)
    )

    let saldoCorte = 0
    const movimientosConSaldoCorte = movimientosCorte.map((movimiento) => {
      saldoCorte += Number(movimiento.valor || 0)
      return { ...movimiento, saldoCorte }
    })

    const deudaPendiente = liquidacion
      ? obtenerDeudaPendienteLiquidacionDeposito(liquidacion)
      : Math.max(
          0,
          movimientosConSaldoCorte.length
            ? Number(
                movimientosConSaldoCorte[movimientosConSaldoCorte.length - 1].saldoCorte || 0
              )
            : 0
        )
    const saldoPendienteCorte = movimientosConSaldoCorte.length
      ? Math.max(
          0,
          Number(movimientosConSaldoCorte[movimientosConSaldoCorte.length - 1].saldoCorte || 0)
        )
      : deudaPendiente

    const abonoRealizado = Number(liquidacion?.abonoLiquidacionRealizado || 0) > 0
      ? Number(liquidacion.abonoLiquidacionRealizado || 0)
      : movimientosCorte
          .filter((movimiento) => movimiento.tipo === 'pago-inh')
          .reduce((total, movimiento) => total + Number(movimiento.abono || 0), 0)

    const pagosArrendatario = construirPagosArrendatarioDetalleLiquidacionDeposito(liquidacion)
    const totalPagadoArrendatario = [
      ...new Map(
        pagosArrendatario.map((pago) => [
          `${pago.idPagoArriendo || pago.recibo}-${pago.fechaPago}`,
          Number(pago.valorPagadoTotalRecibo || 0),
        ])
      ).values(),
    ].reduce((total, valor) => total + valor, 0)

    const participacion = Number(liquidacion?.participacion || 100)
    const esPagoFijoMensual = !!liquidacion?.esPagoFijoMensual
    const serviciosFijos = construirServiciosPublicosFijosLiquidacionDepositoCorte({
      mes,
      contratoArriendo,
      unidadesNegocio,
      facturasServiciosPublicos,
      pagosServiciosPublicos,
      participacion,
      usarValorCausacion: esPagoFijoMensual,
    })
    const desgloseCargos = construirDesgloseCargosCorteLiquidacionDeposito({
      liquidacion,
      participacion,
      porcentajeComision: liquidacion?.porcentajeComision || 0,
      serviciosFijos,
      abonoRealizado,
      saldoPendiente: saldoPendienteCorte,
      esPagoFijoMensual,
    })

    const totalAPagarCorte = Number(desgloseCargos.totalAPagarCorte || 0)
    const totalRecaudadoCorte = Number(liquidacion?.totalRecaudadoPredio || 0)
    let estadoPago =
      liquidacion?.estadoPago ||
      (movimientosCorte.length ? 'Con movimiento' : 'Sin recaudo')

    if (saldoPendienteCorte <= 0 && abonoRealizado > 0) {
      estadoPago = 'Pagado'
    } else if (abonoRealizado > 0 && saldoPendienteCorte > 0) {
      estadoPago = 'Pendiente parcial'
    } else if (!liquidacion?.estadoPago) {
      if (!esPagoFijoMensual && totalRecaudadoCorte <= 0 && totalAPagarCorte <= 0 && abonoRealizado <= 0) {
        estadoPago = 'Sin recaudo'
      } else if (totalAPagarCorte > 0 || abonoRealizado > 0) {
        if (saldoPendienteCorte <= 0 && abonoRealizado > 0) estadoPago = 'Pagado'
        else if (abonoRealizado > 0 && saldoPendienteCorte > 0) estadoPago = 'Pendiente parcial'
        else if (saldoPendienteCorte > 0 && abonoRealizado <= 0) {
          estadoPago = 'Sin recaudo'
        }
      }
    }

    return {
      mes,
      liquidacion,
      movimientos: movimientosConSaldoCorte,
      pagosArrendatario,
      totalPagadoArrendatario,
      totalRecaudado: Number(liquidacion?.totalRecaudadoPredio || 0),
      montoLiquidable: Number(liquidacion?.montoLiquidablePropietarioMes || 0),
      porcentajeCanon: Number(liquidacion?.porcentajeAbonoCanonMes || 0),
      valorNetoPropietario: Number(liquidacion?.valorNetoPropietario || 0),
      comisionInmobiliaria: Number(liquidacion?.comisionInmobiliariaPropietario || 0),
      abonoRealizado,
      deudaPendiente,
      saldoPendienteCorte,
      serviciosFijos,
      desgloseCargos,
      esPagoFijoMensual,
      totalAPagarCorte,
      estadoPago,
    }
  })
}

// =============================================================================
// DERIVADOS - PAGOS ARRENDATARIO EN LIQUIDACION DEPOSITO
// Detalle de cada pago del arrendatario que alimenta la liquidacion por corte.
// =============================================================================

// =============================================================================
// LIQUIDACION DEPOSITARIO - RECAUDO ARRENDATARIO
// Valida que exista recaudo del arrendatario antes de liquidar al depositante.
// =============================================================================

const liquidacionDepositoTieneRecaudoArrendatario = (liquidacion = {}) => {
  if (!liquidacion) return false
  if (liquidacion.esPagoFijoMensual) return true

  const detalleConValor = (liquidacion.detallePagos || []).filter(
    (pago) =>
      Number(pago.valorBruto || 0) > 0 ||
      Number(pago.valorCanonLiquidacion || 0) > 0 ||
      Number(pago.montoLiquidableAsignado || 0) > 0
  )

  return (
    detalleConValor.length > 0 || Number(liquidacion.totalRecaudadoPredio || 0) > 0
  )
}

// =============================================================================
// LIQUIDACION DEPOSITARIO - REFERENCIA PAGOS ARRENDATARIO
// Texto y detalle de los recibos del arrendatario vinculados al pago INH.
// =============================================================================

const formatearRecibosArrendatarioReferencia = (pagos = []) => {
  const recibos = [
    ...new Set(
      (pagos || [])
        .map((pago) => pago.recibo || pago.numeroRecibo || '')
        .filter((recibo) => recibo && recibo !== '—')
    ),
  ]

  if (!recibos.length) return ''
  if (recibos.length === 1) return `recibo arrendatario ${recibos[0]}`
  return `recibos arrendatario ${recibos.join(', ')}`
}

const obtenerReferenciaPagosArrendatarioPagoInh = (pagoInh = {}) => {
  const detalle = pagoInh.detallePagosArriendo || []
  if (detalle.length) return formatearRecibosArrendatarioReferencia(detalle)

  const ids = pagoInh.idsPagosArriendo || []
  if (!ids.length) return ''

  return `${ids.length} pago(s) de arriendo vinculado(s)`
}

// =============================================================================
// LIQUIDACION DEPOSITARIO - PAGOS ARRENDATARIO POR CORTE
// Detalle de cada pago del arrendatario que alimenta la liquidacion por corte.
// =============================================================================

const construirPagosArrendatarioDetalleLiquidacionDeposito = (liquidacion) =>
  (liquidacion?.detallePagos || [])
    .filter(
      (pago) =>
        Number(pago.valorCanonLiquidacion || pago.valorPagado || pago.valorBruto || 0) > 0
    )
    .map((pago) => {
      const pagoOriginal = pago.pago || pago
      const valorPagadoTotalRecibo = Number(
        pago.valorPagadoTotalRecibo ??
          pagoOriginal?.valorPagado ??
          pago.valorPagado ??
          0
      )

      return {
        idPagoArriendo: pago.idPagoArriendo || pago.claveAsignacion || '',
        recibo: pago.recibo || pago.numeroRecibo || '—',
        fechaPago: pago.fechaPago || '',
        arrendatario: pago.arrendatario || '',
        valorPagadoTotalRecibo,
        valorAsignadoCorte: Number(pago.valorCanonLiquidacion || 0),
        participacion: Number(liquidacion?.participacion || 0),
        valorBrutoBeneficiario: Number(pago.valorBruto || 0),
        comisionInmobiliaria: Number(pago.comisionInmobiliaria || 0),
        valorNetoBeneficiario: Number(pago.valorNeto || 0),
        deudaPendienteInh: Number(
          pago.deudaPendienteInh ?? (pago.liquidado ? 0 : pago.valorNeto) ?? 0
        ),
        liquidadoInh:
          Number(pago.deudaPendienteInh ?? (pago.liquidado ? 0 : pago.valorNeto) ?? 0) <= 0 &&
          Number(pago.valorNeto || 0) > 0,
        mesPagoOriginal: pago.mesPagoOriginal || pago.mes || '',
      }
    })

// =============================================================================
// LIQUIDACION DEPOSITARIO - SALDO PENDIENTE UNIFICADO
// Fuente unica de deuda al depositario (abonos INH y comision provisional).
// =============================================================================

const obtenerDeudaPendienteLiquidacionDeposito = (liquidacion) =>
  Math.max(0, Number(liquidacion?.deudaInmobiliaria ?? 0))

// =============================================================================
// DERIVADOS - DEUDA DISCRIMINADA POR CORTE
// Total de deuda al depositario desglosado por mes causado y pago del arrendatario.
// =============================================================================

const obtenerDeudaPendienteCorteLiquidacionDeposito = (corte) => {
  const movimientos = corte?.movimientos || []
  const saldoDesdeMovimientos = (() => {
    if (!movimientos.length) return null

    let saldo = 0
    movimientos.forEach((movimiento) => {
      const cargo = Number(movimiento.cargo || 0)
      const abono = Number(movimiento.abono || 0)
      saldo += Number(movimiento.valor ?? cargo - abono)
    })

    return Math.max(0, saldo)
  })()

  const tienePagoInh = movimientos.some((movimiento) => movimiento.tipo === 'pago-inh')

  if (tienePagoInh && saldoDesdeMovimientos !== null) {
    return saldoDesdeMovimientos
  }

  if (corte?.liquidacion) {
    const deudaLiquidacion = obtenerDeudaPendienteLiquidacionDeposito(corte.liquidacion)
    if (saldoDesdeMovimientos !== null) {
      return Math.min(deudaLiquidacion, saldoDesdeMovimientos)
    }
    return deudaLiquidacion
  }

  if (saldoDesdeMovimientos !== null) {
    return saldoDesdeMovimientos
  }

  const saldoMovimientos = Number(corte?.saldoPendienteCorte || 0)
  if (saldoMovimientos > 0) return saldoMovimientos

  const pagosArrendatario = corte?.pagosArrendatario || []
  if (pagosArrendatario.length > 0) {
    return pagosArrendatario.reduce(
      (total, pago) => total + Number(pago.deudaPendienteInh || 0),
      0
    )
  }

  const deudaRegistrada = Number(corte?.deudaPendiente || 0)
  if (deudaRegistrada > 0) return deudaRegistrada

  return 0
}

// =============================================================================
// LIQUIDACION DEPOSITARIO - DEUDA DISCRIMINADA POR CORTE
// Total de deuda desglosado por mes causado y pago del arrendatario.
// =============================================================================

const construirDeudaDiscriminadaCortesExtractoLiquidacionDeposito = (cortes = []) => {
  const cortesDeuda = cortes.map((corte) => {
    const pagosArrendatario =
      corte.pagosArrendatario?.length > 0
        ? corte.pagosArrendatario
        : construirPagosArrendatarioDetalleLiquidacionDeposito(corte.liquidacion)

    const deudaCorte = obtenerDeudaPendienteCorteLiquidacionDeposito({
      ...corte,
      pagosArrendatario,
    })

    return {
      mes: corte.mes,
      estadoPago: corte.estadoPago,
      deudaCorte,
      pagosArrendatario,
    }
  })

  const items = cortesDeuda.flatMap((corteDeuda) => {
    if (corteDeuda.pagosArrendatario.length > 0) {
      return corteDeuda.pagosArrendatario.map((pago, indice) => ({
        clave: `${corteDeuda.mes}-${pago.recibo}-${indice}`,
        mes: corteDeuda.mes,
        fechaPago: pago.fechaPago,
        recibo: pago.recibo,
        valorPagadoTotalRecibo: pago.valorPagadoTotalRecibo,
        valorAsignadoCorte: pago.valorAsignadoCorte,
        participacion: pago.participacion,
        valorNetoBeneficiario: pago.valorNetoBeneficiario,
        deuda: pago.deudaPendienteInh,
        estadoPago: pago.liquidadoInh ? 'Pagado INH' : 'Pendiente INH',
        sinPagoArrendatario: false,
      }))
    }

    return [
      {
        clave: `${corteDeuda.mes}-sin-pago`,
        mes: corteDeuda.mes,
        fechaPago: '',
        recibo: '—',
        valorPagadoTotalRecibo: 0,
        valorAsignadoCorte: 0,
        participacion: 0,
        valorNetoBeneficiario: 0,
        deuda: corteDeuda.deudaCorte,
        estadoPago: corteDeuda.estadoPago,
        sinPagoArrendatario: true,
      },
    ]
  })

  const totalDeuda = cortesDeuda.reduce(
    (sum, corte) => sum + Number(corte.deudaCorte || 0),
    0
  )

  return {
    cortes: cortesDeuda,
    items,
    totalDeuda,
    cantidadCortes: cortesDeuda.length,
    cantidadCortesConDeuda: cortesDeuda.filter((corte) => Number(corte.deudaCorte || 0) > 0)
      .length,
    cantidadPagosArrendatario: items.filter((item) => !item.sinPagoArrendatario).length,
  }
}

// =============================================================================
// LIQUIDACION DEPOSITO - PENDIENTE CONSOLIDADO EXTRACTO
// Agrupa en un solo bloque todo lo no pagado al depositante o beneficiario.
// =============================================================================

const MESES_ETIQUETA_CORTE = [
  'enero',
  'febrero',
  'marzo',
  'abril',
  'mayo',
  'junio',
  'julio',
  'agosto',
  'septiembre',
  'octubre',
  'noviembre',
  'diciembre',
]

// =============================================================================
// LIQUIDACION DEPOSITO - ETIQUETA MES CORTE
// Convierte YYYY-MM a nombre de mes y anio para el extracto.
// =============================================================================

const formatearMesCorteLiquidacion = (mesISO = '') => {
  if (!mesISO || !/^\d{4}-\d{2}$/.test(String(mesISO))) return mesISO || '—'

  const [anio, mes] = String(mesISO).split('-')
  const indice = Number(mes) - 1
  const nombreMes = MESES_ETIQUETA_CORTE[indice] || mes

  return `${nombreMes.charAt(0).toUpperCase()}${nombreMes.slice(1)} ${anio}`
}

// =============================================================================
// LIQUIDACION DEPOSITO - RANGO DE CORTES
// Etiqueta desde-hasta para cortes pendientes del extracto.
// =============================================================================

const formatearRangoCortesLiquidacion = (meses = []) => {
  const ordenados = [...meses].filter(Boolean).sort()
  if (ordenados.length === 0) {
    return {
      desde: '',
      hasta: '',
      etiquetaDesde: '—',
      etiquetaHasta: '—',
      etiqueta: '—',
    }
  }

  const desde = ordenados[0]
  const hasta = ordenados[ordenados.length - 1]
  const etiquetaDesde = formatearMesCorteLiquidacion(desde)
  const etiquetaHasta = formatearMesCorteLiquidacion(hasta)
  const etiqueta =
    desde === hasta
      ? `Corte ${etiquetaDesde}`
      : `Desde corte ${etiquetaDesde} hasta corte ${etiquetaHasta}`

  return { desde, hasta, etiquetaDesde, etiquetaHasta, etiqueta }
}

// =============================================================================
// LIQUIDACION DEPOSITO - FORMATO FECHA EXTRACTO
// Fecha dd/mm/aaaa para movimientos del estado de cuenta.
// =============================================================================

const formatearFechaExtractoLiquidacionDeposito = (fecha = '') => {
  if (!fecha) return '—'
  const fechaNormalizada = String(fecha).slice(0, 10)
  const partes = fechaNormalizada.split('-')
  if (partes.length === 3) {
    return `${partes[2]}/${partes[1]}/${partes[0]}`
  }
  return fechaNormalizada
}

// =============================================================================
// LIQUIDACION DEPOSITO - RESUMEN ESTADO DE CUENTA
// Totales pendientes por concepto para el extracto tipo arriendo.
// =============================================================================

const construirResumenExtractoLiquidacionDeposito = (extracto = {}) => {
  const pendiente = extracto.pendienteConsolidado
  const desglose = pendiente?.desglose || {}
  const totalPendiente = obtenerTotalPendienteExtractoLiquidacionDeposito(extracto)

  return {
    totalCanonBase: Number(desglose.totalCanonBase || 0),
    totalIva: Number(desglose.totalIva || 0),
    totalServicios: Number(desglose.totalServiciosFijos || 0),
    totalComision: Number(desglose.totalComision || 0),
    totalIvaComision: Number(desglose.totalIvaComision || 0),
    totalAbonado: Number(extracto.totalAbonado || 0),
    totalPendiente,
    totalDeuda: totalPendiente,
    estadoGeneral: totalPendiente > 0 ? 'Con deuda' : 'Al día',
    rangoCortes: pendiente?.rangoCortes || '—',
    esPagoFijoMensual: !!extracto.esPagoFijoMensual,
  }
}

const MESES_ATRAS_MOVIMIENTOS_EXTRACTO_LIQUIDACION_DEPOSITO = 3

// =============================================================================
// LIQUIDACION DEPOSITO - ULTIMO CORTE PAGADO EXTRACTO
// Mes del corte mas reciente con pago INH completo al depositante.
// =============================================================================

const obtenerMesUltimoCortePagadoExtractoLiquidacionDeposito = (extracto = {}) => {
  const cortesPagados = (extracto.cortes || [])
    .filter((corte) => {
      const abono = Number(corte.abonoRealizado || 0)
      const pendiente = obtenerDeudaPendienteCorteLiquidacionDeposito(corte)
      return abono > 0 && pendiente <= 0
    })
    .map((corte) => corte.mes)
    .filter(Boolean)
    .sort()

  if (cortesPagados.length) return cortesPagados[cortesPagados.length - 1]

  const ultimoDesdeResumen = (extracto.ultimosCortesPagados?.cortes || [])
    .map((corte) => corte.mes)
    .filter(Boolean)
    .sort()

  if (ultimoDesdeResumen.length) return ultimoDesdeResumen[ultimoDesdeResumen.length - 1]

  return ''
}

// =============================================================================
// LIQUIDACION DEPOSITO - RECAUDO DEPOSITANTE POR CORTE
// Meses con recaudo del arrendatario liquidable al depositante.
// =============================================================================

const obtenerMesesConRecaudoDepositanteExtracto = (extracto = {}) =>
  (extracto.cortes || [])
    .filter((corte) => {
      const recaudo = Number(
        corte.totalRecaudado ??
          corte.liquidacion?.totalRecaudadoPredio ??
          corte.liquidacion?.canonCubiertoMes ??
          0
      )
      return recaudo > 0
    })
    .map((corte) => corte.mes)
    .filter(Boolean)

// =============================================================================
// LIQUIDACION DEPOSITO - SALDO ARRENDATARIO PENDIENTE
// Meses con deuda vigente del arrendatario segun liquidacion de arriendo.
// =============================================================================

const obtenerMesesSaldoArrendatarioPendienteLiquidacionDeposito = ({
  contratoArriendo,
  pagosArriendo = [],
  incrementosArriendo = [],
  ajustesAdministracion = [],
  gestionesCartera = [],
  fechaCorte = '',
}) => {
  if (!contratoArriendo) return []

  const pagosContrato = pagosArriendo.filter((pago) =>
    coincidePagoContratoArriendo(pago, contratoArriendo)
  )
  const pagosConValor = pagosContrato.filter((pago) => Number(pago.valorPagado || 0) > 0)
  const inicio = (contratoArriendo.fechaInicio || '').slice(0, 7)
  const mesFin = obtenerTopeMesCausacionContrato(contratoArriendo)
  const meses =
    inicio && mesFin >= inicio
      ? [
          ...new Set([
            ...obtenerRangoMesesCausadosContrato(contratoArriendo, pagosConValor),
            ...listarMesesEntre(inicio, mesFin),
          ]),
        ].sort()
      : obtenerRangoMesesCausadosContrato(contratoArriendo, pagosConValor)

  const fechaCorteEfectiva = fechaCorte || obtenerFechaLocalISO()
  const asignacionesLiquidacion = asignarPagosLiquidacionPeriodoContratoMultimes({
    contrato: contratoArriendo,
    pagosContrato: pagosConValor,
    incrementosArriendo,
    ajustesAdministracion,
    gestionesCartera,
  })

  return meses.filter((mes) => {
    const pagosAsignados = []
    const asignacionesMes = asignacionesLiquidacion.get(mes)
    if (asignacionesMes?.size) {
      asignacionesMes.forEach((asignacion) => {
        pagosAsignados.push({
          pago: asignacion.pago,
          valorAsignado: Number(asignacion.valorLiquidacionPeriodo || 0),
        })
      })
    }

    const movimiento = construirMovimientoVirtualLiquidacionMesArriendo({
      contrato: contratoArriendo,
      mes,
      pagosAsignados,
      pagosContrato,
      incrementosArriendo,
      ajustesAdministracion,
      gestionesCartera,
    })

    return (
      calcularSaldoDeudaPeriodoArriendo(
        contratoArriendo,
        movimiento,
        fechaCorteEfectiva
      ) > 0
    )
  })
}

// =============================================================================
// LIQUIDACION DEPOSITO - CORTES PENDIENTES VENTANA MOVIMIENTOS
// Meses con saldo o pago pendiente al depositante en el extracto.
// =============================================================================

const obtenerMesesCortesPendientesVentanaMovimientosExtractoLiquidacionDeposito = (
  extracto = {}
) =>
  (extracto.cortes || [])
    .filter((corte) => {
      const pendiente = obtenerDeudaPendienteCorteLiquidacionDeposito(corte)
      if (pendiente > 0) return true

      const estado = String(corte.estadoPago || '').trim()
      if (estado === 'Pendiente' || estado === 'Pendiente parcial') {
        return Number(corte.totalAPagarCorte || 0) > Number(corte.abonoRealizado || 0)
      }

      return false
    })
    .map((corte) => corte.mes)
    .filter(Boolean)

// =============================================================================
// LIQUIDACION DEPOSITO - VENTANA MOVIMIENTOS EXTRACTO
// Tres meses atras del ultimo corte pagado, cortes pendientes y saldo arrendatario.
// =============================================================================

const obtenerMesesVentanaMovimientosExtractoLiquidacionDeposito = ({
  extracto = null,
  movimientos = [],
  mesReferencia = '',
} = {}) => {
  const extractoEfectivo = extracto || {}
  const mesUltimoCortePagado =
    obtenerMesUltimoCortePagadoExtractoLiquidacionDeposito(extractoEfectivo)
  const mesesSaldoArrendatario =
    extractoEfectivo.mesesSaldoArrendatarioPendiente || []
  const mesesConRecaudo = obtenerMesesConRecaudoDepositanteExtracto(extractoEfectivo)
  const mesReferenciaHistorico = [
    mesReferencia,
    mesUltimoCortePagado,
    ...mesesSaldoArrendatario,
    ...mesesConRecaudo,
  ]
    .filter(Boolean)
    .sort()
    .pop()
  const mesHastaHistorico = mesReferenciaHistorico || obtenerMesActualCalendarioISO()
  let mesDesdeHistorico = restarMesesCalendarioISO(
    mesHastaHistorico,
    MESES_ATRAS_MOVIMIENTOS_EXTRACTO_LIQUIDACION_DEPOSITO
  )

  const mesInicio = obtenerMesInicioLiquidacionDeposito({
    contratoDeposito: extractoEfectivo.contratoDeposito,
    contratoArriendo: extractoEfectivo.contratoArriendo,
  })
  if (mesInicio && mesDesdeHistorico < mesInicio) mesDesdeHistorico = mesInicio

  const mesesHistorico = listarMesesEntre(mesDesdeHistorico, mesHastaHistorico)
  const mesesPendientes =
    obtenerMesesCortesPendientesVentanaMovimientosExtractoLiquidacionDeposito(
      extractoEfectivo
    )
  const mesesDesdeMovimientos = (movimientos || [])
    .filter((movimiento) => !movimiento.esReferencia)
    .map((movimiento) => movimiento.mesCausado)
    .filter(Boolean)
  const mesesTodosCortes = extractoEfectivo.esPagosParciales
    ? (extractoEfectivo.cortes || []).map((corte) => corte.mes).filter(Boolean)
    : []

  const mesesVentana = [
    ...new Set([
      ...mesesHistorico,
      ...mesesPendientes,
      ...mesesConRecaudo,
      ...mesesSaldoArrendatario,
      ...mesesDesdeMovimientos,
      ...mesesTodosCortes,
    ]),
  ]
    .filter((mes) => !mesInicio || mes >= mesInicio)
    .sort()

  return {
    mesesVentana,
    mesDesde: mesesVentana[0] || '',
    mesHasta: mesesVentana[mesesVentana.length - 1] || '',
    mesUltimoCortePagado: mesUltimoCortePagado || mesHastaHistorico,
    cantidadCortesPendientes: mesesPendientes.length,
    cantidadMesesSaldoArrendatario: mesesSaldoArrendatario.length,
  }
}

const obtenerRangoVentanaMovimientosExtractoLiquidacionDeposito = (opciones = {}) =>
  obtenerMesesVentanaMovimientosExtractoLiquidacionDeposito(opciones)

const obtenerSaldoAlCierreMesExtractoLiquidacionDeposito = (
  filasConSaldo = [],
  mes = ''
) => {
  const filasHastaMes = filasConSaldo.filter(
    (fila) => fila.mesCausado && String(fila.mesCausado) <= String(mes)
  )

  if (!filasHastaMes.length) return 0
  return Number(filasHastaMes[filasHastaMes.length - 1].saldoAcumulado || 0)
}

// =============================================================================
// LIQUIDACION DEPOSITO - FILAS VENTANA MOVIMIENTOS
// Filas de la ventana de movimientos: historico reciente y cortes pendientes.
// =============================================================================

const construirFilasVentanaMovimientosExtractoLiquidacionDeposito = (
  filasConSaldo = [],
  mesesVentana = []
) => {
  const meses = [...mesesVentana].filter(Boolean).sort()
  if (!meses.length) return filasConSaldo
  const filasPorMes = filasConSaldo.reduce((mapa, fila) => {
    if (!fila.mesCausado) return mapa
    if (!mapa.has(fila.mesCausado)) mapa.set(fila.mesCausado, [])
    mapa.get(fila.mesCausado).push(fila)
    return mapa
  }, new Map())

  return mesesVentana.flatMap((mes) => {
    const filasMes = filasPorMes.get(mes) || []

    if (filasMes.length > 0) return filasMes

    return [
      {
        mesCausado: mes,
        mes: formatearMesCorteLiquidacion(mes) || '—',
        fecha: '—',
        detalle: 'Sin recaudo del arrendatario en el periodo',
        valorMovimiento: 0,
        tipo: 'cargo',
        valor: 0,
        descuento: 0,
        esAbonoDestacado: false,
        esPlaceholderVentana: true,
        saldoAcumulado: obtenerSaldoAlCierreMesExtractoLiquidacionDeposito(
          filasConSaldo,
          mes
        ),
      },
    ]
  })
}

// =============================================================================
// LIQUIDACION DEPOSITO - FILAS ESTADO DE CUENTA
// Movimientos mes a mes con el mismo formato que el extracto de arriendo.
// =============================================================================

const construirFilasEstadoCuentaLiquidacionDeposito = (movimientos = []) =>
  ordenarMovimientosExtractoLiquidacionDeposito(movimientos || [])
    .filter((movimiento) => !movimiento.esReferencia)
    .map((movimiento) => {
      const cargo = Number(movimiento.cargo || 0)
      const abono = Number(movimiento.abono || 0)
      const valorMovimiento = cargo - abono

      return {
        mesCausado: movimiento.mesCausado || '',
        mes: formatearMesCorteLiquidacion(movimiento.mesCausado) || '—',
        fecha: formatearFechaExtractoLiquidacionDeposito(movimiento.fecha),
        detalle: movimiento.detalle || '',
        valorMovimiento,
        tipo:
          movimiento.tipo === 'pago-inh' || (abono > 0 && cargo === 0) ? 'pago' : 'cargo',
        valor: cargo,
        descuento: abono,
        esAbonoDestacado: movimiento.tipo === 'pago-inh',
      }
    })

// =============================================================================
// LIQUIDACION DEPOSITO - PENDIENTE CONSOLIDADO EXTRACTO
// Agrupa en un solo bloque todo lo no pagado al depositante o beneficiario.
// =============================================================================

const construirConsolidadoPendienteExtractoLiquidacionDeposito = ({
  cortes = [],
  esPagoFijoMensual = false,
  porcentajeComision = 0,
}) => {
  const cortesPendientes = cortes
    .map((corte) => ({
      ...corte,
      saldoPendiente: obtenerDeudaPendienteCorteLiquidacionDeposito(corte),
    }))
    .filter((corte) => Number(corte.saldoPendiente || 0) > 0)
    .sort((a, b) => String(a.mes).localeCompare(String(b.mes)))

  if (cortesPendientes.length === 0) return null

  let totalCanonBase = 0
  let totalIva = 0
  let totalServiciosFijos = 0
  let totalComision = 0
  let totalIvaComision = 0
  let totalDescuentoAdministracion = 0

  const cortesIncluidos = cortesPendientes.map((corte) => {
    const pendiente = Number(corte.saldoPendiente || 0)
    const totalCorte = Number(corte.totalAPagarCorte || 0)
    const desglose = corte.desgloseCargos || {}
    const ratio = totalCorte > 0 ? pendiente / totalCorte : 1

    const canonPendiente = Math.round(Number(desglose.totalCanonBase || 0) * ratio)
    const ivaPendiente = Math.round(Number(desglose.totalIva || 0) * ratio)
    const serviciosPendiente = Math.round(Number(desglose.totalServiciosFijos || 0) * ratio)
    const comisionPendiente = Math.round(Number(desglose.totalComision || 0) * ratio)
    const ivaComisionPendiente = Math.round(Number(desglose.totalIvaComision || 0) * ratio)
    const descuentoAdminPendiente = Math.round(
      Number(desglose.descuentoAdministracion || 0) * ratio
    )

    totalCanonBase += canonPendiente
    totalIva += ivaPendiente
    totalServiciosFijos += serviciosPendiente
    totalComision += comisionPendiente
    totalIvaComision += ivaComisionPendiente
    totalDescuentoAdministracion += descuentoAdminPendiente

    return {
      mes: corte.mes,
      estadoPago: corte.estadoPago,
      saldoPendiente: pendiente,
      totalCorte,
      abonoRealizado: Number(corte.abonoRealizado || 0),
    }
  })

  const totalPendiente = cortesIncluidos.reduce(
    (total, corte) => total + Number(corte.saldoPendiente || 0),
    0
  )

  const items = []
  const etiquetaCanon = esPagoFijoMensual ? 'Canon de arriendo' : 'Canon base liquidable'
  const etiquetaIvaCanon = esPagoFijoMensual
    ? 'IVA del canon de arriendo'
    : 'IVA del canon al depositante'

  if (totalCanonBase > 0) {
    items.push({
      concepto: etiquetaCanon,
      tipo: 'canon-base',
      cargo: totalCanonBase,
      abono: 0,
    })
  }

  if (totalIva > 0) {
    items.push({
      concepto: etiquetaIvaCanon,
      tipo: 'iva-canon',
      cargo: totalIva,
      abono: 0,
    })
  }

  if (totalServiciosFijos > 0) {
    items.push({
      concepto: esPagoFijoMensual
        ? 'Servicios públicos fijos – valor de causación'
        : 'Servicios públicos fijos',
      tipo: 'servicio-publico-fijo',
      cargo: totalServiciosFijos,
      abono: 0,
    })
  }

  if (totalDescuentoAdministracion > 0) {
    items.push({
      concepto: 'Descuento administración de edificio (incluida en canon)',
      tipo: 'descuento-administracion',
      cargo: 0,
      abono: totalDescuentoAdministracion,
    })
  }

  if (totalComision > 0) {
    items.push({
      concepto: esPagoFijoMensual
        ? `Porcentaje acordado – Comisión INH (${porcentajeComision}%)`
        : `Comisión INH (${porcentajeComision}% sobre canon base)`,
      tipo: 'comision',
      cargo: 0,
      abono: totalComision,
    })
  }

  if (totalIvaComision > 0) {
    items.push({
      concepto: esPagoFijoMensual
        ? `IVA del porcentaje acordado (${porcentajeComision}%)`
        : `IVA comisión INH (${porcentajeComision}%)`,
      tipo: 'iva-comision',
      cargo: 0,
      abono: totalIvaComision,
    })
  }

  const totalCargo = totalCanonBase + totalIva + totalServiciosFijos
  const totalAbono =
    totalComision + totalIvaComision + totalDescuentoAdministracion
  const mesesPendientes = cortesIncluidos.map((corte) => corte.mes)
  const rangoCortes = formatearRangoCortesLiquidacion(mesesPendientes)

  return {
    cortesIncluidos,
    cantidadCortesPendientes: cortesIncluidos.length,
    mesesPendientes,
    corteDesde: rangoCortes.desde,
    corteHasta: rangoCortes.hasta,
    corteDesdeEtiqueta: rangoCortes.etiquetaDesde,
    corteHastaEtiqueta: rangoCortes.etiquetaHasta,
    rangoCortes: rangoCortes.etiqueta,
    totalPendiente,
    desglose: {
      items,
      totalCanonBase,
      totalIva,
      totalComision,
      totalIvaComision,
      totalServiciosFijos,
      descuentoAdministracion: totalDescuentoAdministracion,
      totalCargo,
      totalAbono,
      totalAPagarCorte: totalPendiente,
      esPagoFijoMensual,
    },
    esPagoFijoMensual,
  }
}

// =============================================================================
// LIQUIDACION DEPOSITO - ULTIMOS CORTES PAGADOS EXTRACTO
// Los dos cortes mas recientes liquidados con detalle de pagos INH al depositante.
// =============================================================================

const construirUltimosCortesPagadosExtractoLiquidacionDeposito = ({
  cortes = [],
  pagosLiquidacionDeposito = [],
  idPropietario = '',
  claveUnidad = '',
  idContratoDeposito = '',
  cantidad = 2,
}) => {
  const cortesPagados = cortes
    .filter((corte) => {
      const abono = Number(corte.abonoRealizado || 0)
      const pendiente = obtenerDeudaPendienteCorteLiquidacionDeposito(corte)
      return abono > 0 && pendiente <= 0
    })
    .sort((a, b) => String(b.mes).localeCompare(String(a.mes)))
    .slice(0, cantidad)
    .map((corte) => {
      const pagosDesdeMovimientos = (corte.movimientos || [])
        .filter(
          (movimiento) => movimiento.tipo === 'pago-inh' && Number(movimiento.abono || 0) > 0
        )
        .map((movimiento, index) => ({
          id: movimiento.idPagoLiquidacionDeposito || `mov-${corte.mes}-${index}`,
          numeroRecibo:
            String(movimiento.detalle || '').match(/Recibo\s+(.+?)(?:\s|$)/)?.[1]?.trim() || '—',
          fechaPago: movimiento.fecha || '',
          valorNetoPropietario: Number(movimiento.abono || 0),
          valorBrutoPropietario: 0,
          comisionInmobiliaria: 0,
          medioPago: '',
          observaciones: movimiento.detalle || '',
        }))

      const pagosRegistrados = (pagosLiquidacionDeposito || [])
        .filter((pago) =>
          coincidePagoInhLiquidacionDepositoBeneficiario(pago, {
            codigoPredio: corte.liquidacion?.codigoPredio || '',
            mes: corte.mes,
            idPropietario,
            claveUnidad,
            idContratoDeposito,
            idContratoArriendo: corte.liquidacion?.idContratoArriendo || '',
          })
        )
        .sort((a, b) => String(a.fechaPago || '').localeCompare(String(b.fechaPago || '')))
        .map((pago) => ({
          id: pago.id,
          numeroRecibo: pago.numeroRecibo || pago.id,
          fechaPago: pago.fechaPago || '',
          valorNetoPropietario: Number(pago.valorNetoPropietario || 0),
          valorBrutoPropietario: Number(pago.valorBrutoPropietario || 0),
          comisionInmobiliaria: Number(pago.comisionInmobiliaria || 0),
          medioPago: pago.medioPago || '',
          observaciones: pago.observaciones || '',
        }))

      const pagos = pagosDesdeMovimientos.length > 0 ? pagosDesdeMovimientos : pagosRegistrados

      const totalPagado =
        pagos.reduce((total, pago) => total + Number(pago.valorNetoPropietario || 0), 0) ||
        Number(corte.abonoRealizado || 0)

      return {
        mes: corte.mes,
        mesEtiqueta: formatearMesCorteLiquidacion(corte.mes),
        estadoPago: corte.estadoPago,
        totalAPagarCorte: Number(corte.totalAPagarCorte || 0),
        abonoRealizado: Number(corte.abonoRealizado || 0),
        desgloseCargos: corte.desgloseCargos,
        esPagoFijoMensual: corte.esPagoFijoMensual,
        pagos,
        totalPagado,
      }
    })

  return {
    cortes: cortesPagados,
    cantidad: cortesPagados.length,
  }
}

// =============================================================================
// DERIVADOS - INFORMACION CONTRACTUAL EXTRACTO LIQUIDACION
// Datos del contrato de deposito, arriendo y canon por corte para el extracto.
// =============================================================================

const construirInformacionContratosExtractoLiquidacionDeposito = ({
  contratoDeposito,
  contratoArriendo,
  liquidacionesUnidad = [],
  propietarios = [],
  contratosDeposito = [],
  predio = null,
}) => {
  if (!contratoDeposito || !contratoArriendo) return null

  const depositario = propietarios.find(
    (item) =>
      item.id ===
      (contratoDeposito.idContratante ||
        contratoDeposito.idPropietario ||
        contratoDeposito.idDepositante)
  )

  const mesesLiquidacion = [...liquidacionesUnidad].map((item) => item.mes).filter(Boolean).sort()
  const mesReferenciaCanon =
    mesesLiquidacion[mesesLiquidacion.length - 1] || obtenerMesActualCalendarioISO()
  const liquidacionReferencia = liquidacionesUnidad.find((item) => item.mes === mesReferenciaCanon)

  const canonPorCorte = [...liquidacionesUnidad]
    .sort((a, b) => String(a.mes).localeCompare(String(b.mes)))
    .map((liquidacion) => ({
      mes: liquidacion.mes,
      canonMensual: Number(liquidacion.canonArrendamientoMes || 0),
      montoLiquidable: Number(liquidacion.montoLiquidablePropietarioMes || 0),
      canonLiquidado: Number(liquidacion.totalRecaudadoPredio || 0),
      porcentajeCubierto: Number(liquidacion.porcentajeAbonoCanonMes || 0),
    }))

  return {
    depositario,
    mesReferenciaCanon,
    canonArrendamientoReferencia: Number(
      liquidacionReferencia?.canonArrendamientoMes || contratoArriendo.canonMensual || 0
    ),
    canonPorCorte,
    deposito: {
      numero: obtenerNumeroContratoDepositoVisible(contratoDeposito, contratosDeposito),
      depositante: depositario?.nombre || 'Sin depositante',
      identificacionExpediente:
        obtenerNumeroIdentificacionDepositante(depositario, contratoDeposito) || 'Sin registrar',
      documentoDepositante: depositario
        ? `${depositario.tipoDocumento} ${depositario.numeroDocumento}`
        : 'Sin registrar',
      calidad: contratoDeposito.calidadContratante || 'Propietario',
      tipoComision: contratoDeposito.tipoComision,
      porcentajeComision: contratoDeposito.porcentajeComision,
      formaPago: normalizarTipoPagoLiquidacionDeposito(contratoDeposito.tipoPagoLiquidacion),
      criterioLiquidacionCanon: normalizarCriterioLiquidacionCanonDeposito(
        contratoDeposito.criterioLiquidacionCanon
      ),
      seguimientoPredial:
        contratoDeposito.tipoComision === 'Administración'
          ? contratoDeposito.incluyeSeguimientoPredial || 'No'
          : 'No aplica',
      polizaAseguradora: normalizarIncluyeAseguradoraDeposito(
        contratoDeposito.incluyeAseguradora
      ),
      fechaInicio: contratoDeposito.fechaInicio || 'Sin registrar',
      fechaFin: contratoDeposito.fechaFin || 'Vigente',
      estado: contratoDeposito.estado || '',
      observaciones: contratoDeposito.observaciones || 'Sin observaciones',
      observacionesAutorizacion: contratoDeposito.observacionesAutorizacionPago || '',
    },
    arriendo: {
      arrendatario: contratoArriendo.arrendatario || '—',
      documento:
        `${contratoArriendo.tipoDocumento || ''} ${contratoArriendo.numeroDocumento || ''}`.trim() ||
        '—',
      unidad: contratoArriendo.nombreUnidad || '—',
      telefono: contratoArriendo.telefono || 'Sin registrar',
      whatsapp: contratoArriendo.whatsapp || 'Sin registrar',
      correo: contratoArriendo.correo || 'Sin registrar',
      direccion: predio?.direccion || 'Sin dirección',
      barrioCiudad: [predio?.barrio, predio?.ciudad].filter(Boolean).join(' — ') || '—',
      canonMensualContrato: Number(contratoArriendo.canonMensual || 0),
      aplicaIva: contratoArriendo.aplicaIva === 'Sí' ? 'Sí' : 'No',
      aplicaAdministracion:
        contratoArriendo.aplicaAdministracion === 'Sí' ? 'Sí' : 'No',
      interesMora: Number(contratoArriendo.porcentajeInteresMora || 0),
      gastosCobranza: textoDescriptivoGastosCobranzaContratoArriendo(contratoArriendo),
      aseguradora: contratoArriendo.aseguradora || '',
      numeroPoliza: contratoArriendo.numeroPoliza || '',
      fechaInicio: contratoArriendo.fechaInicio || 'Sin registrar',
      fechaFin: contratoArriendo.fechaFin || 'Vigente',
      estado: contratoArriendo.estado || '',
    },
  }
}

const construirExtractoLiquidacionDepositoUnidad = ({
  idContratoArriendo,
  idPropietario,
  idContratoDeposito = null,
  liquidacionesDepositoHistorial,
  pagosLiquidacionDeposito,
  pagosArriendo = [],
  contratosArriendo,
  contratosDeposito,
  predios,
  propietarios,
  predioPropietarios = [],
  unidadesNegocio = [],
  facturasServiciosPublicos = [],
  pagosServiciosPublicos = [],
  incrementosArriendo = [],
  ajustesAdministracion = [],
  gestionesCartera = [],
}) => {
  const contratoArriendo = contratosArriendo.find(
    (contrato) => obtenerIdContrato(contrato) === idContratoArriendo
  )
  if (!contratoArriendo) return null

  const claveUnidad = obtenerClaveUnidadLiquidacion({
    idUnidad: contratoArriendo.idUnidad,
    unidad: contratoArriendo.nombreUnidad,
    idContratoArriendo: idContratoArriendo,
  })

  const contratoDeposito =
    (idContratoDeposito
      ? contratosDeposito.find((item) => item.id === idContratoDeposito)
      : null) ||
    obtenerContratoDepositoPredio(contratoArriendo.codigoPredio, contratosDeposito)
  if (!contratoDeposito) return null

  const propietario = propietarios.find((item) => item.id === idPropietario)
  if (!propietario) return null

  const liquidacionesUnidad = obtenerLiquidacionesDepositoUnidadExtracto({
    liquidacionesDepositoHistorial,
    contratoDeposito,
    contratoArriendo,
    idContratoArriendo,
    idPropietario,
    claveUnidad,
    predioPropietarios,
    propietarios,
    predios,
    contratosDeposito,
    contratosArriendo,
    pagosArriendo,
    pagosLiquidacionDeposito,
    incrementosArriendo,
    ajustesAdministracion,
    gestionesCartera,
  })

  const predio = predios.find((item) => item.codigo === contratoArriendo.codigoPredio)
  const esPagoFijoMensualExtracto = esPagoFijoLiquidacionCanonDeposito(contratoDeposito)
  const mesesCortesVigentes = obtenerMesesCortesVigentesExtractoLiquidacionDeposito({
    contratoDeposito,
    contratoArriendo,
    contratosArriendo,
    pagosArriendo,
  })

  if (liquidacionesUnidad.length === 0 && mesesCortesVigentes.length === 0) return null

  const movimientos = construirMovimientosExtractoLiquidacionDeposito({
    liquidacionesUnidad,
    pagosLiquidacionDeposito,
    idPropietario,
    claveUnidad,
    idContratoDeposito: contratoDeposito.id,
    contratoArriendo,
    unidadesNegocio,
    facturasServiciosPublicos,
    pagosServiciosPublicos,
    mesesVigentes: mesesCortesVigentes,
    esPagosParciales: !esPagoFijoMensualExtracto,
  })

  const cortesBase = construirCortesExtractoLiquidacionDeposito({
    liquidacionesUnidad,
    movimientos,
    contratoArriendo,
    unidadesNegocio,
    facturasServiciosPublicos,
    pagosServiciosPublicos,
  })

  const cortes = completarCortesExtractoLiquidacionDeposito({
    cortes: cortesBase,
    contratoDeposito,
    contratoArriendo,
    contratosArriendo,
    pagosArriendo,
    porcentajeComision: contratoDeposito.porcentajeComision || 0,
    esPagoFijoMensual: esPagoFijoMensualExtracto,
  })

  const deudaPorCortes = construirDeudaDiscriminadaCortesExtractoLiquidacionDeposito(cortes)
  const pendienteConsolidado = construirConsolidadoPendienteExtractoLiquidacionDeposito({
    cortes,
    esPagoFijoMensual: esPagoFijoMensualExtracto,
    porcentajeComision: contratoDeposito.porcentajeComision || 0,
  })
  const ultimosCortesPagados = construirUltimosCortesPagadosExtractoLiquidacionDeposito({
    cortes,
    pagosLiquidacionDeposito,
    idPropietario,
    claveUnidad,
    idContratoDeposito: contratoDeposito.id,
  })

  const mesesSaldoArrendatarioPendiente =
    obtenerMesesSaldoArrendatarioPendienteLiquidacionDeposito({
      contratoArriendo,
      pagosArriendo,
      incrementosArriendo,
      ajustesAdministracion,
      gestionesCartera,
      fechaCorte: obtenerFechaLocalISO(),
    })

  const saldoFinalCortes = cortes.length
    ? obtenerTotalPendienteDesdeCortesExtractoLiquidacionDeposito(cortes)
    : liquidacionesUnidad.reduce(
        (total, item) => total + obtenerDeudaPendienteLiquidacionDeposito(item),
        0
      )
  const saldoFinalMovimientos = obtenerSaldoFinalMovimientosExtractoLiquidacionDeposito(movimientos)
  const saldoFinal =
    saldoFinalMovimientos !== null
      ? Math.min(saldoFinalCortes, saldoFinalMovimientos)
      : saldoFinalCortes

  const extracto = {
    idPropietario,
    propietario,
    esContratante: liquidacionesUnidad[0]?.esContratante,
    idContratoArriendo,
    contratoArriendo,
    unidad: contratoArriendo.nombreUnidad || 'Sin unidad',
    claveUnidad,
    codigoPredio: contratoArriendo.codigoPredio,
    predio,
    idContratoDeposito: contratoDeposito.id,
    contratoDeposito,
    numeroContratoDeposito: obtenerNumeroContratoDepositoVisible(contratoDeposito, contratosDeposito),
    numeroContratoArriendo: obtenerNumeroContratoVisible(
      contratoArriendo,
      predios,
      contratosArriendo
    ),
    tipoComision: contratoDeposito.tipoComision,
    porcentajeComision: contratoDeposito.porcentajeComision,
    tipoPagoLiquidacion: normalizarTipoPagoLiquidacionDeposito(contratoDeposito.tipoPagoLiquidacion),
    criterioLiquidacionCanon: normalizarCriterioLiquidacionCanonDeposito(
      contratoDeposito.criterioLiquidacionCanon
    ),
    esPagoFijoMensual: esPagoFijoMensualExtracto,
    esPagosParciales: !esPagoFijoMensualExtracto,
    condicionesPagoInh: normalizarCondicionesPagoInh(contratoDeposito.condicionesPagoInh),
    calidadContratante: contratoDeposito.calidadContratante || 'Propietario',
    observacionesAutorizacionPago: contratoDeposito.observacionesAutorizacionPago || '',
    participacion: Number(liquidacionesUnidad[0]?.participacion || 0),
    informacionContratos: construirInformacionContratosExtractoLiquidacionDeposito({
      contratoDeposito,
      contratoArriendo,
      liquidacionesUnidad,
      propietarios,
      contratosDeposito,
      predio,
    }),
    liquidacionesUnidad,
    movimientos,
    cortes,
    deudaPorCortes,
    pendienteConsolidado,
    ultimosCortesPagados,
    mesesSaldoArrendatarioPendiente,
    saldoFinal,
    totalDeuda: liquidacionesUnidad.reduce(
      (total, item) => total + obtenerDeudaPendienteLiquidacionDeposito(item),
      0
    ),
    totalAbonado: liquidacionesUnidad.reduce(
      (total, item) => total + Number(item.abonoLiquidacionRealizado || 0),
      0
    ),
    totalCanonLiquidado: liquidacionesUnidad.reduce(
      (total, item) => total + Number(item.totalRecaudadoPredio || 0),
      0
    ),
  }

  return {
    ...extracto,
    resumen: construirResumenExtractoLiquidacionDeposito(extracto),
  }
}

const obtenerLiquidacionesPendientesContratoDeposito = (liquidaciones, idContratoDeposito) =>
  (liquidaciones || []).filter(
    (item) =>
      item.idContratoDeposito === idContratoDeposito &&
      obtenerDeudaPendienteLiquidacionDeposito(item) > 0 &&
      liquidacionDepositoTieneRecaudoArrendatario(item)
  )

// =============================================================================
// LIQUIDACION DEPOSITARIO - DEUDA PENDIENTE POR UNIDAD Y BENEFICIARIO
// Totales del corte actual, cortes anteriores y deuda acumulada para pago INH.
// =============================================================================

const obtenerLiquidacionesPendientesUnidadBeneficiarioDeposito = (
  liquidaciones = [],
  { idContratoDeposito, claveUnidad = '', idPropietario = '' }
) =>
  obtenerLiquidacionesPendientesContratoDeposito(liquidaciones, idContratoDeposito).filter(
    (item) =>
      (item.claveUnidad || '') === (claveUnidad || '') &&
      item.idPropietario === idPropietario
  )

// =============================================================================
// LIQUIDACION DEPOSITARIO - DEUDA CORTES ANTERIORES PAGO
// Suma de liquidaciones pendientes con mes anterior al corte seleccionado.
// =============================================================================

const obtenerDeudaCortesAnterioresPagoDepositante = (
  liquidaciones = [],
  { idContratoDeposito, claveUnidad = '', idPropietario = '', mesReferencia = '' }
) =>
  obtenerLiquidacionesPendientesUnidadBeneficiarioDeposito(liquidaciones, {
    idContratoDeposito,
    claveUnidad,
    idPropietario,
  })
    .filter((item) => mesReferencia && String(item.mes) < String(mesReferencia))
    .reduce((total, item) => total + obtenerDeudaPendienteLiquidacionDeposito(item), 0)

// =============================================================================
// LIQUIDACION DEPOSITARIO - MESES CAUSADOS FORMULARIO PAGO
// Meses con liquidacion por unidad y beneficiario (pagados y pendientes).
// =============================================================================

const obtenerMesesCausadosLiquidacionPagoDepositante = (
  liquidaciones = [],
  { idContratoDeposito, claveUnidad = '', idPropietario = '' }
) => {
  const mesesVistos = new Set()

  return (liquidaciones || [])
    .filter(
      (item) =>
        item.idContratoDeposito === idContratoDeposito &&
        (item.claveUnidad || '') === (claveUnidad || '') &&
        item.idPropietario === idPropietario &&
        liquidacionDepositoTieneRecaudoArrendatario(item) &&
        item.mes
    )
    .sort((a, b) => String(b.mes).localeCompare(String(a.mes)))
    .filter((item) => {
      if (mesesVistos.has(item.mes)) return false
      mesesVistos.add(item.mes)
      return true
    })
    .map((item) => ({
      mes: item.mes,
      pagado: obtenerDeudaPendienteLiquidacionDeposito(item) <= 0,
      liquidacion: item,
    }))
}

// =============================================================================
// LIQUIDACION DEPOSITARIO - RESOLVER MES CAUSADO PAGO
// Mantiene el mes elegido o selecciona el primer corte pendiente al cambiar unidad o beneficiario.
// =============================================================================

const resolverMesCausadoPagoDepositante = ({
  liquidaciones = [],
  idContratoDeposito,
  claveUnidad = '',
  idPropietario = '',
  mesPreferido = '',
}) => {
  const meses = obtenerMesesCausadosLiquidacionPagoDepositante(liquidaciones, {
    idContratoDeposito,
    claveUnidad,
    idPropietario,
  })

  if (!meses.length) return ''

  if (mesPreferido && meses.some((item) => String(item.mes) === String(mesPreferido))) {
    return mesPreferido
  }

  const primerPendiente = meses.find((item) => !item.pagado)
  return primerPendiente?.mes || meses[0]?.mes || ''
}

// =============================================================================
// LIQUIDACION DEPOSITARIO - DEUDA DEL CORTE SELECCIONADO
// Saldo pendiente INH unicamente del mes causado elegido en el pago.
// =============================================================================

const obtenerDeudaPendienteCorteMesPagoDepositante = (
  liquidaciones = [],
  { idContratoDeposito, claveUnidad = '', idPropietario = '', mesReferencia = '' }
) => {
  if (!mesReferencia) return 0

  const liquidacion = encontrarLiquidacionDeposito(liquidaciones, {
    idContratoDeposito,
    claveUnidad,
    idPropietario,
    mes: mesReferencia,
  })

  return obtenerDeudaPendienteLiquidacionDeposito(liquidacion)
}

// =============================================================================
// LIQUIDACION DEPOSITARIO - DEUDA HASTA CORTE PAGO
// Cortes anteriores mas el corte seleccionado (sin meses posteriores).
// =============================================================================

const obtenerDeudaHastaCortePagoDepositante = (
  liquidaciones = [],
  { idContratoDeposito, claveUnidad = '', idPropietario = '', mesReferencia = '' }
) => {
  if (!mesReferencia) return 0

  return obtenerLiquidacionesPendientesUnidadBeneficiarioDeposito(liquidaciones, {
    idContratoDeposito,
    claveUnidad,
    idPropietario,
  })
    .filter((item) => String(item.mes) <= String(mesReferencia))
    .reduce((total, item) => total + obtenerDeudaPendienteLiquidacionDeposito(item), 0)
}

// =============================================================================
// LIQUIDACION DEPOSITARIO - VALOR PENDIENTE FORMULARIO PAGO
// Texto numerico del saldo hasta corte para precargar el valor del pago INH.
// =============================================================================

const calcularValorPendienteFormularioPagoDepositante = (
  liquidaciones = [],
  { idContratoDeposito, claveUnidad = '', idPropietario = '', mesReferencia = '' } = {}
) => {
  if (!idContratoDeposito || !claveUnidad || !idPropietario || !mesReferencia) return ''

  const deuda = obtenerDeudaHastaCortePagoDepositante(liquidaciones, {
    idContratoDeposito,
    claveUnidad,
    idPropietario,
    mesReferencia,
  })

  return deuda > 0 ? String(Math.round(deuda)) : ''
}

// =============================================================================
// LIQUIDACION DEPOSITARIO - MES CAUSADO TRAS ABONO
// Mantiene el mes con saldo o pasa al siguiente pendiente despues de registrar un pago.
// =============================================================================

const resolverMesCausadoTrasAbonoPagoDepositante = ({
  liquidaciones = [],
  idContratoDeposito,
  claveUnidad = '',
  idPropietario = '',
  mesReferencia = '',
}) => {
  const meses = obtenerMesesCausadosLiquidacionPagoDepositante(liquidaciones, {
    idContratoDeposito,
    claveUnidad,
    idPropietario,
  })

  if (!meses.length) return ''

  if (mesReferencia) {
    const deudaMesActual = obtenerDeudaPendienteCorteMesPagoDepositante(liquidaciones, {
      idContratoDeposito,
      claveUnidad,
      idPropietario,
      mesReferencia,
    })
    if (deudaMesActual > 0) return mesReferencia
  }

  const primerPendiente = meses.find((item) => !item.pagado)
  return primerPendiente?.mes || ''
}

const obtenerDeudaTotalPendientePagoDepositanteUnidad = (
  liquidaciones = [],
  { idContratoDeposito, claveUnidad = '', idPropietario = '' }
) =>
  obtenerLiquidacionesPendientesUnidadBeneficiarioDeposito(liquidaciones, {
    idContratoDeposito,
    claveUnidad,
    idPropietario,
  }).reduce((total, item) => total + obtenerDeudaPendienteLiquidacionDeposito(item), 0)

// =============================================================================
// LIQUIDACION DEPOSITARIO - RESOLVER LIQUIDACION PAGO
// Localiza la liquidacion pendiente del mes o del corte mas antiguo para registrar el pago.
// =============================================================================

const resolverLiquidacionPagoDepositante = (
  liquidaciones = [],
  { idContratoDeposito, claveUnidad = '', idPropietario = '', mesPreferido = '' }
) => {
  if (mesPreferido) {
    const liquidacionMes = encontrarLiquidacionDeposito(liquidaciones, {
      idContratoDeposito,
      claveUnidad,
      idPropietario,
      mes: mesPreferido,
    })
    if (liquidacionMes && obtenerDeudaPendienteLiquidacionDeposito(liquidacionMes) > 0) {
      return liquidacionMes
    }
  }

  const pendientesUnidad = obtenerLiquidacionesPendientesUnidadBeneficiarioDeposito(liquidaciones, {
    idContratoDeposito,
    claveUnidad,
    idPropietario,
  })
    .filter((item) => !mesPreferido || String(item.mes) <= String(mesPreferido))
    .sort((a, b) => String(a.mes).localeCompare(String(b.mes)))

  for (const item of pendientesUnidad) {
    const liquidacion = encontrarLiquidacionDeposito(liquidaciones, {
      idContratoDeposito,
      claveUnidad,
      idPropietario,
      mes: item.mes,
    })
    if (liquidacion) return liquidacion
  }

  return null
}

// =============================================================================
// LIQUIDACION DEPOSITARIO - PENDIENTES POR CORTE MENSUAL
// Resumen y listado de liquidaciones con saldo por pagar al depositante.
// =============================================================================

const construirLiquidacionesPendientesPagoDepositantes = (
  liquidaciones = [],
  contratosDeposito = [],
  propietarios = []
) => {
  const mapaUnicas = new Map()

  ;(liquidaciones || [])
    .filter(
      (item) =>
        obtenerDeudaPendienteLiquidacionDeposito(item) > 0 &&
        liquidacionDepositoTieneRecaudoArrendatario(item)
    )
    .forEach((item) => {
      const claveUnica = [
        item.idContratoDeposito,
        item.mes,
        item.idPropietario,
        item.idContratoArriendo || item.claveUnidad || item.unidad || '',
      ].join('::')
      const actual = mapaUnicas.get(claveUnica)
      if (
        !actual ||
        obtenerDeudaPendienteLiquidacionDeposito(item) >=
          obtenerDeudaPendienteLiquidacionDeposito(actual)
      ) {
        mapaUnicas.set(claveUnica, item)
      }
    })

  return [...mapaUnicas.values()]
    .map((item) => {
      const contratoDeposito = (contratosDeposito || []).find(
        (contrato) => contrato.id === item.idContratoDeposito
      )
      const idDepositante = obtenerIdDepositanteContrato(contratoDeposito)
      const depositante = (propietarios || []).find((persona) => persona.id === idDepositante)
      const saldoPendiente = obtenerDeudaPendienteLiquidacionDeposito(item)

      return {
        ...item,
        saldoPendiente,
        estadoPago:
          saldoPendiente <= 0
            ? 'Pagado'
            : Number(item.abonoLiquidacionRealizado || 0) > 0
              ? 'Pendiente parcial'
              : item.estadoPago,
        depositante,
        claveLista: `${item.idContratoDeposito}-${item.mes}-${item.claveUnidad}-${item.idPropietario}`,
      }
    })
    .sort((a, b) => {
      const porMes = b.mes.localeCompare(a.mes)
      if (porMes !== 0) return porMes
      const porContrato = String(a.numeroContrato || '').localeCompare(String(b.numeroContrato || ''))
      if (porContrato !== 0) return porContrato
      return String(a.unidad || '').localeCompare(String(b.unidad || ''))
    })
}

const construirResumenLiquidacionesPendientesPorCorte = (liquidacionesPendientes = []) => {
  const mapa = new Map()

  liquidacionesPendientes.forEach((item) => {
    const mes = item.mes || 'Sin mes'
    if (!mapa.has(mes)) {
      mapa.set(mes, { mes, cantidad: 0, saldoTotal: 0 })
    }
    const grupo = mapa.get(mes)
    grupo.cantidad += 1
    grupo.saldoTotal += Number(item.saldoPendiente || 0)
  })

  return [...mapa.values()].sort((a, b) => b.mes.localeCompare(a.mes))
}

const generarLiquidacionesDepositoMes = ({
  mes,
  contratosDeposito,
  predioPropietarios,
  propietarios,
  predios,
  contratosArriendo,
  pagosArriendo,
  pagosLiquidacionDeposito,
  gestionesCartera = [],
  incrementosArriendo = [],
  ajustesAdministracion = [],
  idPropietarioFiltro = null,
}) =>
  generarLiquidacionesDepositoHistorial({
    contratosDeposito,
    predioPropietarios,
    propietarios,
    predios,
    contratosArriendo,
    pagosArriendo,
    pagosLiquidacionDeposito,
    gestionesCartera,
    incrementosArriendo,
    ajustesAdministracion,
    idPropietarioFiltro,
    mesFiltro: mes,
  })

const obtenerPorcentajeGastosCobranzaContrato = (contrato) => {
  const porcentaje = Number(contrato?.porcentajeGastosCobranza)
  return Number.isFinite(porcentaje) && porcentaje >= 0
    ? porcentaje
    : PORCENTAJE_GASTOS_COBRANZA_DEFECTO
}

const textoDescriptivoGastosCobranzaContratoArriendo = (contrato) =>
  `${obtenerPorcentajeGastosCobranzaContrato(contrato)}% del canon base del periodo en mora`

// =============================================================================
// ARRIENDOS - GASTOS DE COBRANZA
// Porcentaje y calculo de gastos de cobranza sobre canon del periodo en mora.
// =============================================================================

const calcularGastosCobranza = (base, porcentaje = PORCENTAJE_GASTOS_COBRANZA_DEFECTO) =>
  Math.round(Number(base || 0) * (Number(porcentaje || 0) / 100))

const MS_POR_DIA = 86400000

const DIA_VENCIMIENTO_CANON_ARRIENDO = 5
const DIAS_GRACIA_DESPUES_VENCIMIENTO_MORA_ARRIENDO = 5
const DIAS_DESPUES_VENCIMIENTO_INICIO_CALCULO_INTERES_ARRIENDO =
  DIAS_GRACIA_DESPUES_VENCIMIENTO_MORA_ARRIENDO
const DIAS_DESPUES_VENCIMIENTO_INICIO_LIQUIDACION_INTERES_ARRIENDO =
  DIAS_GRACIA_DESPUES_VENCIMIENTO_MORA_ARRIENDO

const contratoAplicaIvaArriendo = (contrato) => contrato?.aplicaIva === 'Sí'

const obtenerDiaVencimientoCanonContrato = (contrato = null) => {
  const diaExplicito = contrato?.diaVencimientoCanon ?? contrato?.diaPagoCanon
  if (diaExplicito != null && diaExplicito !== '') {
    const dia = Number(diaExplicito)
    if (Number.isFinite(dia) && dia >= 1 && dia <= 31) return dia
  }

  const fechaInicio = contrato?.fechaInicio
  if (fechaInicio) {
    const diaInicio = Number(String(fechaInicio).slice(8, 10))
    if (Number.isFinite(diaInicio) && diaInicio >= 1 && diaInicio <= 31) return diaInicio
  }

  return DIA_VENCIMIENTO_CANON_ARRIENDO
}

const calcularIvaArriendo = (base, contrato = null) =>
  contratoAplicaIvaArriendo(contrato) ? Math.round(Number(base || 0) * 0.19) : 0

// =============================================================================
// LIQUIDACION DEPOSITO - CANON E IVA BENEFICIARIO POR MES
// Canon completo e IVA del mes para extracto y desglose (pago fijo mensual).
// =============================================================================

const obtenerCanonIvaBeneficiarioLiquidacionDepositoMes = ({
  liquidacion = null,
  detallePago = null,
  participacion = 100,
}) => {
  const participacionEfectiva = Number(participacion || liquidacion?.participacion || 100)
  const detalle = detallePago || liquidacion?.detallePagos?.[0] || null
  const ivaMes = Number(detalle?.ivaCanonMes ?? liquidacion?.ivaCanonMes ?? 0)
  const adminPredio = Number(
    detalle?.valorAdministracionDescontada ??
      liquidacion?.valorAdministracionDescontadaPredio ??
      0
  )
  const montoLiquidable = Number(
    detalle?.montoLiquidablePropietario ?? liquidacion?.montoLiquidablePropietarioMes ?? 0
  )
  const canonBaseMes = Number(
    detalle?.canonBaseMes ?? Math.max(0, montoLiquidable - ivaMes + adminPredio)
  )
  const canonBaseBeneficiario = Math.round(canonBaseMes * (participacionEfectiva / 100))
  const ivaBeneficiario = Math.round(ivaMes * (participacionEfectiva / 100))

  return {
    canonBaseMes,
    ivaMes,
    canonBaseBeneficiario,
    ivaBeneficiario,
    valorBrutoBeneficiario: canonBaseBeneficiario + ivaBeneficiario,
  }
}

const calcularIvaComisionInh = (comision) => Math.round(Number(comision || 0) * 0.19)

const compararFechasISO = (fechaA = '', fechaB = '') =>
  String(fechaA || '').localeCompare(String(fechaB || ''))

// =============================================================================
// ARRIENDOS - ROLES Y FECHA RECIBO PAGO
// Fecha local, limite de 20 dias para Digitador y validacion del recibo.
// =============================================================================

const obtenerFechaLocalISO = (fecha = new Date()) => {
  const referencia = fecha instanceof Date ? fecha : new Date(fecha)
  const anio = referencia.getFullYear()
  const mes = String(referencia.getMonth() + 1).padStart(2, '0')
  const dia = String(referencia.getDate()).padStart(2, '0')
  return `${anio}-${mes}-${dia}`
}

const formatearFechaLocalHumana = (fechaISO = '') => {
  if (!fechaISO) return 'Sin fecha'
  const [anio, mes, dia] = String(fechaISO).split('-')
  if (!anio || !mes || !dia) return fechaISO
  return `${dia}/${mes}/${anio}`
}

const DIAS_MAX_ANTIGUEDAD_RECIBO_DIGITADOR = 20

const normalizarRolUsuarioPagoArriendo = (rol = '') => {
  if (rol === 'Digitador' || rol === 'Operador') return 'Digitador'
  if (rol === 'Administrador') return 'Administrador'
  return String(rol || '').trim()
}

const esDigitadorReciboPagoArriendo = (rol = '') =>
  normalizarRolUsuarioPagoArriendo(rol) === 'Digitador'

const esAdministradorReciboPagoArriendo = (rol = '') =>
  normalizarRolUsuarioPagoArriendo(rol) === 'Administrador'

const calcularFechaMinimaReciboDigitador = (
  fechaDigitacion = obtenerFechaLocalISO()
) => agregarDiasFechaISO(fechaDigitacion, -DIAS_MAX_ANTIGUEDAD_RECIBO_DIGITADOR)

const validarFechaReciboPagoArriendo = (
  fechaRecibo,
  fechaDigitacion = obtenerFechaLocalISO(),
  rolUsuario = 'Administrador'
) => {
  if (!fechaRecibo) {
    return { valido: false, mensaje: 'Debe registrar la fecha del recibo.' }
  }

  if (compararFechasISO(fechaRecibo, fechaDigitacion) > 0) {
    return {
      valido: false,
      mensaje:
        'La fecha del recibo no puede ser posterior a la fecha de digitación (hoy).',
    }
  }

  if (esDigitadorReciboPagoArriendo(rolUsuario)) {
    const fechaMinima = calcularFechaMinimaReciboDigitador(fechaDigitacion)
    if (compararFechasISO(fechaRecibo, fechaMinima) < 0) {
      return {
        valido: false,
        mensaje:
          'El Digitador únicamente puede registrar pagos con una antigüedad máxima de 20 días calendario.',
      }
    }
  }

  return { valido: true, mensaje: '' }
}

// =============================================================================
// ARRIENDOS - HISTORIAL MODIFICACION RECIBO
// Entrada inmutable de auditoria al editar recibos de arriendo.
// =============================================================================

const construirEntradaHistorialModificacionReciboPagoArriendo = ({
  usuario = {},
  motivo = '',
  fechaReciboAnterior = '',
  fechaReciboNueva = '',
  auditoriaAnterior = null,
  auditoriaNueva = null,
  cambiosAdicionales = {},
}) => ({
  id: `MOD-REC-${Date.now()}-${Math.floor(Math.random() * 10000)}`,
  fechaHora: new Date().toISOString(),
  usuario: usuario.usuario || 'sistema',
  nombreUsuario: usuario.nombre || 'Sistema',
  rol: usuario.rol || '',
  motivo: String(motivo || '').trim(),
  fechaReciboAnterior,
  fechaReciboNueva,
  moraAntes: Number(auditoriaAnterior?.moraRecalculada || 0),
  moraDespues: Number(auditoriaNueva?.moraRecalculada || 0),
  gastosCobranzaAntes: Number(auditoriaAnterior?.gastosCobranzaRecalculados || 0),
  gastosCobranzaDespues: Number(auditoriaNueva?.gastosCobranzaRecalculados || 0),
  ivaMoraCobranzaAntes: Number(auditoriaAnterior?.ivaMoraCobranzaRecalculado || 0),
  ivaMoraCobranzaDespues: Number(auditoriaNueva?.ivaMoraCobranzaRecalculado || 0),
  auditoriaAnterior,
  auditoriaNueva,
  ...cambiosAdicionales,
})

const construirAuditoriaLiquidacionReciboPagoArriendo = ({
  fechaRecibo,
  fechaDigitacion,
  desglosePago = {},
}) => {
  const fechaCalculoIntereses = fechaRecibo || fechaDigitacion

  return {
    fechaDigitacion,
    fechaRecibo: fechaRecibo || fechaDigitacion,
    fechaCalculoIntereses,
    recalculoPorFechaRecibo: fechaRecibo !== fechaDigitacion,
    moraRecalculada: Number(desglosePago.moraPendiente || 0),
    gastosCobranzaRecalculados: Number(desglosePago.gastosCobranza || 0),
    ivaMoraCobranzaRecalculado: Number(desglosePago.ivaMoraCobranza || 0),
    liquidacionResultante: {
      canonIvaPendiente: Number(desglosePago.canonIvaPendiente || 0),
      moraPendiente: Number(desglosePago.moraPendiente || 0),
      gastosCobranza: Number(desglosePago.gastosCobranza || 0),
      ivaMoraCobranza: Number(desglosePago.ivaMoraCobranza || 0),
      totalPendiente: Number(desglosePago.totalPendiente || 0),
    },
  }
}

const obtenerDiasDelMesCalendario = (anio, mesCalendario) =>
  new Date(anio, mesCalendario, 0).getDate()

const agregarDiasFechaISO = (fechaISO, dias) => {
  if (!fechaISO) return ''
  const fecha = new Date(`${fechaISO}T00:00:00`)
  fecha.setDate(fecha.getDate() + Number(dias || 0))
  return fecha.toISOString().slice(0, 10)
}

const calcularNuevaFechaFinRenovacionContrato = (contrato) => {
  if (!contrato?.fechaFin) return ''
  if (!contrato.fechaInicio) {
    return agregarDiasFechaISO(contrato.fechaFin, 365)
  }

  const inicio = new Date(`${contrato.fechaInicio}T00:00:00`)
  const fin = new Date(`${contrato.fechaFin}T00:00:00`)
  const duracionMs = Math.max(0, fin.getTime() - inicio.getTime())
  const nuevaFin = new Date(fin.getTime() + duracionMs)

  return nuevaFin.toISOString().slice(0, 10)
}

const calcularInicioVigenciaRenovacionContrato = (contrato, nuevaFechaInicio = '') => {
  if (nuevaFechaInicio) return nuevaFechaInicio
  if (contrato?.fechaFin) return agregarDiasFechaISO(contrato.fechaFin, 1)
  return new Date().toISOString().slice(0, 10)
}

const ejecutarRenovacionContratoArriendo = (
  contrato,
  {
    nuevaFechaFin = '',
    nuevaFechaInicioVigencia = '',
    nuevoCanon = null,
    nuevoIncremento = null,
    nuevoPreaviso = null,
    observacion = '',
    automatica = false,
  } = {}
) => {
  if (!contrato) return contrato

  const canonAnterior = Number(contrato.canonMensual || 0)
  const canonNuevo =
    nuevoCanon != null && nuevoCanon !== '' ? Number(nuevoCanon) : canonAnterior
  const cambioCanon = canonNuevo !== canonAnterior
  const inicioVigencia = calcularInicioVigenciaRenovacionContrato(
    contrato,
    nuevaFechaInicioVigencia
  )
  const fechaFinFinal =
    nuevaFechaFin || calcularNuevaFechaFinRenovacionContrato(contrato)

  return {
    ...contrato,
    fechaFin: fechaFinFinal,
    canonMensual: canonNuevo,
    incrementoAnual: Number(
      nuevoIncremento != null && nuevoIncremento !== ''
        ? nuevoIncremento
        : contrato.incrementoAnual || 0
    ),
    diasPreavisoRenovacion: Number(
      nuevoPreaviso != null && nuevoPreaviso !== ''
        ? nuevoPreaviso
        : contrato.diasPreavisoRenovacion || 0
    ),
    estado: 'Activo',
    estadoRenovacion: automatica ? 'Renovado automáticamente' : 'Renovado',
    fechaRenovacion: new Date().toISOString().slice(0, 10),
    observacionRenovacion: observacion.trim(),
    ...(cambioCanon
      ? {
          canonMensualAnterior:
            contrato.canonMensualAnterior != null
              ? contrato.canonMensualAnterior
              : canonAnterior,
          fechaRenovacionCanon: inicioVigencia,
        }
      : {}),
  }
}

const procesarRenovacionesAutomaticasContratos = (
  contratos = [],
  fechaReferencia = new Date()
) => {
  const hoyISO = fechaReferencia.toISOString().slice(0, 10)
  let huboCambios = false

  const actualizados = contratos.map((contrato) => {
    if (contrato.estado !== 'Activo') return contrato
    if (contrato.estadoRenovacion === 'No renovado') return contrato
    if (!contrato.fechaFin || contrato.fechaFin >= hoyISO) return contrato

    huboCambios = true
    return ejecutarRenovacionContratoArriendo(contrato, {
      automatica: true,
      observacion:
        'Renovación automática por vencimiento de vigencia sin cambios registrados.',
    })
  })

  return huboCambios ? actualizados : contratos
}

const obtenerFechaVencimientoMesArriendo = (mesCausado, contrato = null) => {
  if (!mesCausado) return ''

  const [anio, mes] = mesCausado.split('-').map(Number)
  const diaObjetivo = obtenerDiaVencimientoCanonContrato(contrato)
  const diasEnMes = obtenerDiasDelMesCalendario(anio, mes)
  const dia = Math.min(diaObjetivo, diasEnMes)

  return `${mesCausado}-${String(dia).padStart(2, '0')}`
}

const obtenerFechaInicioCalculoInteresMoraMesArriendo = (mesCausado, contrato = null) =>
  agregarDiasFechaISO(
    obtenerFechaVencimientoMesArriendo(mesCausado, contrato),
    DIAS_DESPUES_VENCIMIENTO_INICIO_CALCULO_INTERES_ARRIENDO
  )

const obtenerFechaInicioLiquidacionMoraMesArriendo = (mesCausado, contrato = null) =>
  agregarDiasFechaISO(
    obtenerFechaVencimientoMesArriendo(mesCausado, contrato),
    DIAS_DESPUES_VENCIMIENTO_INICIO_LIQUIDACION_INTERES_ARRIENDO
  )

const puedeLiquidarInteresesMoraMesArriendo = (
  mesCausado,
  fechaReferencia = '',
  contrato = null
) => {
  const fechaLiquidacion = obtenerFechaInicioLiquidacionMoraMesArriendo(mesCausado, contrato)
  const fecha = fechaReferencia || new Date().toISOString().slice(0, 10)
  if (!fechaLiquidacion || !fecha) return false
  return compararFechasISO(fecha, fechaLiquidacion) >= 0
}

const obtenerAbonoCapitalPagoArriendo = (pago) => {
  const moraExplicita = Number(pago?.mora || 0)
  return Math.max(0, Number(pago?.valorPagado || 0) - moraExplicita)
}

const mesArriendoPagadoEnFechaVencimientoSinMora = ({
  mesCausado = '',
  saldoCapitalInicial = 0,
  pagos = [],
  contrato = null,
  canonBase = 0,
  ivaCanonMes = 0,
  moraSobreCanonSinIva = false,
}) => {
  const vencimiento = obtenerFechaVencimientoMesArriendo(mesCausado, contrato)
  if (!vencimiento || saldoCapitalInicial <= 0) return false

  let saldo = Number(saldoCapitalInicial || 0)
  const pagosOrdenados = ordenarPagosArriendoCronologico(pagos)

  for (const pago of pagosOrdenados) {
    if (!pago?.fechaPago) continue
    if (compararFechasISO(pago.fechaPago, vencimiento) > 0) return false
    saldo -= reducirCapitalMoraPorPagoArriendo(pago, {
      canonBase,
      ivaCanonMes,
      moraSobreCanonSinIva,
    })
    if (saldo <= 0) return true
  }

  return false
}

const mesArriendoSinInteresesMora = ({
  mesCausado = '',
  saldoCapitalInicial = 0,
  pagos = [],
  contrato = null,
  canonBase = 0,
  ivaCanonMes = 0,
  moraSobreCanonSinIva = false,
}) => {
  if (
    mesArriendoPagadoEnFechaVencimientoSinMora({
      mesCausado,
      saldoCapitalInicial,
      pagos,
      contrato,
      canonBase,
      ivaCanonMes,
      moraSobreCanonSinIva,
    })
  ) {
    return true
  }

  const vencimiento = obtenerFechaVencimientoMesArriendo(mesCausado, contrato)
  if (!vencimiento || saldoCapitalInicial <= 0) return false

  const pagosOrdenados = ordenarPagosArriendoCronologico(pagos).filter((pago) => pago?.fechaPago)
  if (!pagosOrdenados.length) return false

  let saldo = Number(saldoCapitalInicial || 0)
  pagosOrdenados.forEach((pago) => {
    saldo -= reducirCapitalMoraPorPagoArriendo(pago, {
      canonBase,
      ivaCanonMes,
      moraSobreCanonSinIva,
    })
  })

  if (saldo > 0) return false

  const ultimoPago = pagosOrdenados[pagosOrdenados.length - 1]
  return compararFechasISO(ultimoPago.fechaPago, vencimiento) <= 0
}

// =============================================================================
// ARRIENDOS - GASTOS DE COBRANZA POR PERIODO
// Causacion sobre el canon base del periodo cuando hay mora (no sobre saldo pendiente).
// =============================================================================

const calcularSancionGastosCobranzaPeriodoArriendo = ({
  contrato,
  mesCausado = '',
  canonBase = 0,
  ivaCanonMes = 0,
  baseMoraCanon = 0,
  totalDescuento = 0,
  pagosLiquidacion = [],
  fechaCorte = '',
}) => {
  const porcentajeGastosCobranza = obtenerPorcentajeGastosCobranzaContrato(contrato)
  const fechaCorteEfectiva = fechaCorte || new Date().toISOString().slice(0, 10)
  const diasMora = calcularDiasMoraArriendo(mesCausado, fechaCorteEfectiva, contrato)
  const baseGastosCobranza = Math.max(0, Number(canonBase || 0) - Number(totalDescuento || 0))
  const enEstadoCobranza =
    diasMora > 0 &&
    puedeLiquidarInteresesMoraMesArriendo(mesCausado, fechaCorteEfectiva, contrato)
  const capitalMora = Number(baseMoraCanon || canonBase || 0) - Number(totalDescuento || 0)
  const pagoATiempo =
    baseGastosCobranza > 0 &&
    mesArriendoSinInteresesMora({
      mesCausado,
      saldoCapitalInicial: capitalMora,
      pagos: pagosLiquidacion,
      contrato,
      canonBase,
      ivaCanonMes,
      moraSobreCanonSinIva: true,
    })
  const sancionCobranza =
    enEstadoCobranza && baseGastosCobranza > 0 && !pagoATiempo
      ? calcularGastosCobranza(baseGastosCobranza, porcentajeGastosCobranza)
      : 0

  return {
    sancionCobranza,
    porcentajeGastosCobranza,
    baseGastosCobranza,
    enEstadoCobranza,
  }
}

const obtenerFechaMoraLiquidadaExtractoArriendo = ({
  mesCausado = '',
  pagos = [],
  fechaCorte = '',
  contrato = null,
}) => {
  const vencimiento = obtenerFechaVencimientoMesArriendo(mesCausado, contrato)
  const fechaLiquidacion = obtenerFechaInicioLiquidacionMoraMesArriendo(mesCausado, contrato)
  const fechaCorteEfectiva = fechaCorte || new Date().toISOString().slice(0, 10)
  if (!fechaLiquidacion) return fechaCorteEfectiva

  const ultimoPagoTardio = ordenarPagosArriendoCronologico(pagos)
    .filter(
      (pago) =>
        pago?.fechaPago &&
        vencimiento &&
        compararFechasISO(pago.fechaPago, vencimiento) > 0 &&
        puedeLiquidarInteresesMoraMesArriendo(mesCausado, pago.fechaPago, contrato)
    )
    .pop()

  if (ultimoPagoTardio?.fechaPago) return ultimoPagoTardio.fechaPago

  if (puedeLiquidarInteresesMoraMesArriendo(mesCausado, fechaCorteEfectiva, contrato)) {
    return fechaCorteEfectiva
  }

  return fechaLiquidacion
}

const formatearRangoFechasLiquidacionMoraExtractoArriendo = ({
  mesCausado = '',
  pagos = [],
  fechaCorte = '',
  contrato = null,
}) => {
  const fechaInicio = obtenerFechaInicioCalculoInteresMoraMesArriendo(mesCausado, contrato)
  const fechaFin = obtenerFechaMoraLiquidadaExtractoArriendo({
    mesCausado,
    pagos,
    fechaCorte,
    contrato,
  })
  if (!fechaInicio || !fechaFin) return ''
  if (compararFechasISO(fechaInicio, fechaFin) > 0) return ''
  return `${formatearFechaReciboLista(fechaInicio)} al ${formatearFechaReciboLista(fechaFin)}`
}

// =============================================================================
// ARRIENDOS - MORA E INTERESES DE MORA
// Calculo de mora proporcional y liquidada en extractos.
// =============================================================================

const calcularMoraLiquidadaExtractoArriendo = ({
  contrato,
  movimiento,
  fechaCorte = '',
}) => {
  const mesCausado = movimiento?.mes || ''
  const pagosMes =
    movimiento?.pagosLiquidacionArriendoMes || movimiento?.pagosMes || []
  const { canonBase, ivaCanonMes, baseMoraCanon } =
    calcularBaseLiquidacionEstadoCuentaArriendoMes(movimiento, contrato)
  const totalDescuentoMes = Number(movimiento?.descuento || 0)
  const moraGestionFallback = Number(
    movimiento?.moraGestion ??
      Math.max(0, Number(movimiento?.mora || 0) - Number(movimiento?.moraContrato || 0))
  )
  const porcentajeInteresMora = Number(contrato?.porcentajeInteresMora || 0)
  const fechaCorteEfectiva = fechaCorte || new Date().toISOString().slice(0, 10)

  if (!mesCausado || !baseMoraCanon || !porcentajeInteresMora) {
    return {
      moraContrato: 0,
      moraGestion: moraGestionFallback,
      moraTotal: moraGestionFallback,
      fechaMora: obtenerFechaVencimientoMesArriendo(mesCausado, contrato),
    }
  }

  if (
    mesArriendoSinInteresesMora({
      mesCausado,
      saldoCapitalInicial: baseMoraCanon - totalDescuentoMes,
      pagos: pagosMes,
      contrato,
      canonBase,
      ivaCanonMes,
      moraSobreCanonSinIva: true,
    })
  ) {
    return {
      moraContrato: 0,
      moraGestion: moraGestionFallback,
      moraTotal: moraGestionFallback,
      fechaMora: obtenerFechaVencimientoMesArriendo(mesCausado, contrato),
    }
  }

  const moraContrato = calcularMoraAcumuladaMesArriendo({
    baseMora: baseMoraCanon,
    porcentajeInteresMora,
    mesCausado,
    pagos: pagosMes,
    totalDescuento: totalDescuentoMes,
    fechaCorte: fechaCorteEfectiva,
    contrato,
    canonBase,
    ivaCanonMes,
    moraSobreCanonSinIva: true,
  })
  const moraGestion = moraGestionFallback

  return {
    moraContrato,
    moraGestion,
    moraTotal: moraContrato + moraGestion,
    fechaMora: obtenerFechaMoraLiquidadaExtractoArriendo({
      mesCausado,
      pagos: pagosMes,
      fechaCorte: fechaCorteEfectiva,
      contrato,
    }),
  }
}

// =============================================================================
// ARRIENDOS - CARGOS LIQUIDADOS EXTRACTO
// Canon, mora, cobranza e IVA por periodo a fecha de corte.
// =============================================================================

const calcularCargosLiquidadosPeriodoExtractoArriendo = ({
  contrato,
  movimiento,
  fechaCorte = '',
}) => {
  const fechaCorteEfectiva = fechaCorte || new Date().toISOString().slice(0, 10)
  const moraLiquidada = calcularMoraLiquidadaExtractoArriendo({
    contrato,
    movimiento,
    fechaCorte: fechaCorteEfectiva,
  })
  const pagosMes = movimiento?.pagosLiquidacionArriendoMes || movimiento?.pagosMes || []
  const { canonBase, ivaCanonMes } =
    calcularBaseLiquidacionEstadoCuentaArriendoMes(movimiento, contrato)
  const aplicaIva = contratoAplicaIvaArriendo(contrato)
  const totalDescuentoMes = Number(movimiento?.descuento || 0)
  const totalPagadoMes = Number(
    movimiento?.totalPagadoLiquidacionArriendo ?? movimiento?.pagado ?? 0
  )
  const gastosCobranzaPeriodo = calcularSancionGastosCobranzaPeriodoArriendo({
    contrato,
    mesCausado: movimiento?.mes || '',
    canonBase,
    ivaCanonMes,
    baseMoraCanon: canonBase,
    totalDescuento: totalDescuentoMes,
    pagosLiquidacion: pagosMes,
    fechaCorte: fechaCorteEfectiva,
  })
  const { sancionCobranza, porcentajeGastosCobranza, baseGastosCobranza } =
    gastosCobranzaPeriodo
  const porcentajeInteresMora = Number(contrato?.porcentajeInteresMora || 0)
  const ivaMora = aplicaIva ? calcularIvaArriendo(moraLiquidada.moraTotal, contrato) : 0
  const ivaGastosCobranza = aplicaIva ? calcularIvaArriendo(sancionCobranza, contrato) : 0
  const rangoFechasMora = formatearRangoFechasLiquidacionMoraExtractoArriendo({
    mesCausado: movimiento?.mes || '',
    pagos: pagosMes,
    fechaCorte: fechaCorteEfectiva,
    contrato,
  })

  return {
    ...moraLiquidada,
    sancionCobranza,
    ivaCanonMes,
    ivaMora,
    ivaGastosCobranza,
    ivaInteresesSancion: ivaMora + ivaGastosCobranza,
    rangoFechasMora,
    porcentajeGastosCobranza,
    porcentajeInteresMora,
    aplicaIva,
    fechaCorteEfectiva,
    canonPendienteGastosCobranza: baseGastosCobranza,
    baseGastosCobranza,
    baseMoraCanon: canonBase,
    totalCargosPeriodo:
      canonBase +
      ivaCanonMes +
      moraLiquidada.moraContrato +
      moraLiquidada.moraGestion +
      ivaMora +
      sancionCobranza +
      ivaGastosCobranza,
    saldoPeriodo: Math.max(
      0,
      canonBase +
        ivaCanonMes +
        moraLiquidada.moraContrato +
        moraLiquidada.moraGestion +
        ivaMora +
        sancionCobranza +
        ivaGastosCobranza -
        totalDescuentoMes -
        totalPagadoMes
    ),
  }
}

// =============================================================================
// ARRIENDOS - SALDO DEUDA POR PERIODO
// Saldo pendiente de liquidación mes a mes (canon, mora, cobranza, IVA, abonos).
// =============================================================================

const calcularSaldoDeudaPeriodoArriendo = (
  contrato,
  movimiento,
  fechaCorte = ''
) =>
  calcularCargosLiquidadosPeriodoExtractoArriendo({
    contrato,
    movimiento,
    fechaCorte,
  }).saldoPeriodo

const calcularSaldoDeudaLiquidacionArriendoContrato = ({
  contrato,
  movimientos = [],
  fechaCorte = '',
} = {}) =>
  movimientos.reduce(
    (total, movimiento) =>
      total + calcularSaldoDeudaPeriodoArriendo(contrato, movimiento, fechaCorte),
    0
  )

// =============================================================================
// ARRIENDOS - MESES DEL CONTRATO Y MOVIMIENTO MENSUAL
// Generacion de meses y movimientos con pagos y fecha de corte explicitos.
// =============================================================================

const calcularCanonArriendoMes = (
  contrato,
  mes,
  incrementosArriendo = [],
  ajustesAdministracion = []
) => {
  if (!contrato || !mes) {
    return {
      canonBase: 0,
      incrementoAplicado: 0,
      iva: 0,
      canonCausado: 0,
    }
  }

  if (!contrato.fechaInicio) {
    return {
      canonBase: 0,
      administracion: 0,
      incrementoAplicado: 0,
      iva: 0,
      canonCausado: 0,
    }
  }

  const anioPago = Number(mes.substring(0, 4))
  const { canonBase, incrementoAplicado } = resolverCanonBaseMesArriendo(
    contrato,
    mes,
    incrementosArriendo
  )
  const administracion = obtenerAdministracionContratoPuro(
    contrato,
    anioPago,
    ajustesAdministracion
  )
  const administracionCobro = obtenerAdministracionCobroArrendatario(contrato, administracion)
  const iva = contrato.aplicaIva === 'Sí' ? Math.round(canonBase * 0.19) : 0
  const canonCausado = canonBase + administracionCobro + iva

  return {
    canonBase,
    administracion,
    administracionCobro,
    administracionIncluidaEnCanon: administracionIncluidaEnCanonContrato(contrato),
    incrementoAplicado,
    iva,
    canonCausado,
  }
}

// =============================================================================
// ARRIENDOS - MESES DEL CONTRATO Y MOVIMIENTO MENSUAL
// Generacion de meses y movimientos con pagos y fecha de corte explicitos.
// =============================================================================

const generarMesesContrato = (contrato) => {
  if (!contrato?.fechaInicio) return []

  const meses = []
  const fechaInicio = new Date(`${contrato.fechaInicio}T00:00:00`)
  const fechaFinContrato = contrato.fechaFin
    ? new Date(`${contrato.fechaFin}T00:00:00`)
    : new Date()
  const hoy = new Date(`${obtenerFechaLocalISO()}T00:00:00`)
  const fechaFinal = fechaFinContrato < hoy ? fechaFinContrato : hoy

  let anio = fechaInicio.getFullYear()
  let mes = fechaInicio.getMonth()
  const anioFinal = fechaFinal.getFullYear()
  const mesFinal = fechaFinal.getMonth()

  while (anio < anioFinal || (anio === anioFinal && mes <= mesFinal)) {
    meses.push(`${anio}-${String(mes + 1).padStart(2, '0')}`)
    mes += 1
    if (mes > 11) {
      mes = 0
      anio += 1
    }
  }

  return meses
}

const calcularMovimientoArriendoMes = (contrato, mes, opciones = {}) => {
  const {
    idContrato: idContratoActual = null,
    fechaCorteMora: fechaCorteMoraReferencia = null,
    pagosArriendo: pagosArriendoFuente = [],
    incrementosArriendo: incrementosArriendoFuente = [],
    ajustesAdministracion: ajustesAdministracionFuente = [],
    gestionesCartera: gestionesCarteraFuente = [],
  } = opciones

  const idContrato = idContratoActual || obtenerIdContrato(contrato)

  const aplicacion = obtenerAplicacionPagosArriendoMes(
    contrato,
    mes,
    pagosArriendoFuente,
    incrementosArriendoFuente,
    ajustesAdministracionFuente,
    gestionesCarteraFuente
  )

  const {
    pagosDelMes,
    pagosLiquidacionArriendoMes,
    totalPagadoMes,
    totalPagadoLiquidacionArriendo,
    totalDescuentoMes,
    pagosDetalle,
    pagosDetalleLiquidacionArriendo,
    ultimoPago,
    recibosDelMes,
  } = aplicacion

  const gestionesDelMes = gestionesCarteraFuente.filter(
    (gestion) => gestion.idContrato === idContrato && gestion.mes === mes
  )

  const totalMoraGestionMes = gestionesDelMes.reduce(
    (total, gestion) => total + Number(gestion.mora || 0),
    0
  )

  const calculo = calcularCanonArriendoMes(
    contrato,
    mes,
    incrementosArriendoFuente,
    ajustesAdministracionFuente
  )
  const ivaCanonCalculo = Number(calculo.iva || 0)

  const canonCausadoBase = calcularMontoCanonArrendatarioMes({
    canonBase: Number(calculo.canonBase || 0),
    administracion: Number(calculo.administracion || 0),
    ivaCanon: ivaCanonCalculo,
    contrato,
  })

  const { canonBase, ivaCanonMes, baseLiquidacion, baseMoraCanon } =
    calcularBaseLiquidacionEstadoCuentaArriendoMes(
      { canonBase: calculo.canonBase },
      contrato
    )

  const porcentajeInteresMora = Number(contrato.porcentajeInteresMora || 0)
  const fechaCorteMora = fechaCorteMoraReferencia || obtenerFechaLocalISO()
  let moraContratoMes = calcularMoraAcumuladaMesArriendo({
    baseMora: baseMoraCanon,
    porcentajeInteresMora,
    mesCausado: mes,
    pagos: pagosLiquidacionArriendoMes,
    totalDescuento: totalDescuentoMes,
    fechaCorte: fechaCorteMora,
    contrato,
    canonBase,
    ivaCanonMes,
    moraSobreCanonSinIva: true,
  })

  if (
    mesArriendoSinInteresesMora({
      mesCausado: mes,
      saldoCapitalInicial: baseMoraCanon - totalDescuentoMes,
      pagos: pagosLiquidacionArriendoMes,
      contrato,
      canonBase,
      ivaCanonMes,
      moraSobreCanonSinIva: true,
    })
  ) {
    moraContratoMes = 0
  }

  const moraTotalMes = moraContratoMes + totalMoraGestionMes

  const gastosCobranzaPeriodo = calcularSancionGastosCobranzaPeriodoArriendo({
    contrato,
    mesCausado: mes,
    canonBase,
    ivaCanonMes,
    baseMoraCanon,
    totalDescuento: totalDescuentoMes,
    pagosLiquidacion: pagosLiquidacionArriendoMes,
    fechaCorte: fechaCorteMora,
  })
  const sancionContratoMes = gastosCobranzaPeriodo.sancionCobranza

  const deudaVigenteMes = Math.max(
    0,
    baseLiquidacion + moraTotalMes + sancionContratoMes - totalDescuentoMes - totalPagadoLiquidacionArriendo
  )

  const sancionTotalMes = sancionContratoMes
  const ivaMoraMes = calcularIvaArriendo(moraTotalMes, contrato)
  const ivaGastosCobranzaMes = calcularIvaArriendo(sancionTotalMes, contrato)
  const ivaInteresesSancionMes = ivaMoraMes + ivaGastosCobranzaMes

  const totalLiquidacionMes =
    baseLiquidacion + moraTotalMes + sancionTotalMes + ivaInteresesSancionMes
  const canonCausado = totalLiquidacionMes

  const movimientoParcial = {
    mes,
    fechaPago: ultimoPago?.fechaPago || 'Sin pago',
    recibo:
      recibosDelMes.length > 0
        ? recibosDelMes.join(', ')
        : ultimoPago?.recibo || 'Sin recibo',
    pagosDetalle,
    pagosDetalleLiquidacionArriendo,
    pagosMes: pagosDelMes,
    pagosLiquidacionArriendoMes,
    canonCausadoBase,
    canonCausadoBaseLiquidacion: baseLiquidacion,
    moraGestion: totalMoraGestionMes,
    moraContrato: moraContratoMes,
    canonBase: calculo.canonBase,
    administracion: calculo.administracion,
    administracionIncluidaEnCanon: calculo.administracionIncluidaEnCanon,
    incrementoAplicado: calculo.incrementoAplicado,
    iva: ivaCanonMes + ivaInteresesSancionMes,
    ivaCanon: ivaCanonMes,
    ivaMora: ivaMoraMes,
    ivaGastosCobranza: ivaGastosCobranzaMes,
    ivaInteresesSancion: ivaInteresesSancionMes,
    totalLiquidacionMes,
    canonCausado,
    pagado: totalPagadoMes,
    totalPagadoLiquidacionArriendo,
    mora: moraTotalMes,
    sancionCobranza: sancionTotalMes,
    deudaVigenteMes,
    descuento: totalDescuentoMes,
  }

  const saldoDeuda = calcularSaldoDeudaPeriodoArriendo(
    contrato,
    movimientoParcial,
    fechaCorteMoraReferencia || ''
  )

  let estadoMovimiento = 'Pagado'

  if (saldoDeuda > 0 && totalPagadoMes > 0) {
    estadoMovimiento = 'Abono registrado'
  }

  if (saldoDeuda > 0 && totalPagadoMes === 0) {
    estadoMovimiento = 'Pendiente'
  }

  return {
    ...movimientoParcial,
    saldoDeuda,
    estadoMovimiento,
  }
}

const construirContextoCalculoArriendo = ({
  pagosArriendo = [],
  incrementosArriendo = [],
  ajustesAdministracion = [],
  gestionesCartera = [],
} = {}) => ({
  pagosArriendo,
  incrementosArriendo,
  ajustesAdministracion,
  gestionesCartera,
})

// =============================================================================
// ARRIENDOS - EXTRACTOS PARA ALERTAS Y CARTERA
// Consolida saldos de arriendo con pagos y fecha de corte del recibo.
// =============================================================================

const construirExtractosArriendoContratos = ({
  contratosArriendo = [],
  pagosArriendo = [],
  incrementosArriendo = [],
  ajustesAdministracion = [],
  gestionesCartera = [],
  fechaCorte = '',
} = {}) => {
  const fechaCorteEfectiva = fechaCorte || obtenerFechaLocalISO()
  const contextoCalculo = construirContextoCalculoArriendo({
    pagosArriendo,
    incrementosArriendo,
    ajustesAdministracion,
    gestionesCartera,
  })

  return contratosArriendo.map((contrato) => {
    const idContratoActual = obtenerIdContrato(contrato)
    const mesesContrato = generarMesesContrato(contrato)
    const movimientos = mesesContrato.map((mes) =>
      calcularMovimientoArriendoMes(contrato, mes, {
        idContrato: idContratoActual,
        fechaCorteMora: fechaCorteEfectiva,
        ...contextoCalculo,
      })
    )
    const resumenDeudaEstadoCuenta = calcularResumenDeudaEstadoCuentaArriendo({
      contrato,
      movimientos,
      fechaCorte: fechaCorteEfectiva,
    })

    return {
      contrato,
      movimientos: movimientos.sort((a, b) => b.mes.localeCompare(a.mes)),
      resumen: resumenDeudaEstadoCuenta,
    }
  })
}

const movimientoArriendoTieneSaldoPendiente = (
  contrato,
  movimiento,
  fechaCorte = ''
) => calcularSaldoDeudaPeriodoArriendo(contrato, movimiento, fechaCorte) > 0

// =============================================================================
// ARRIENDOS - SALDOS RECIBO DE PAGO
// Solo deuda de arriendo (canon, mora, cobranza); administración y servicios van aparte.
// =============================================================================

const calcularSaldosReciboPagoArriendo = ({
  desglosePago = {},
  valorPagado = 0,
} = {}) => {
  const deudaArriendoPendiente = Number(desglosePago.totalPendiente || 0)
  const pago = Number(valorPagado || 0)
  const saldoArriendoPosterior = Math.max(0, deudaArriendoPendiente - pago)

  return {
    saldoAnterior: deudaArriendoPendiente,
    saldoPosterior: saldoArriendoPosterior,
  }
}

// =============================================================================
// ARRIENDOS - RESUMEN DEUDA ESTADO DE CUENTA
// Totales pendientes por concepto y deuda consolidada.
// =============================================================================

const calcularPendientesDeudaPeriodoEstadoCuentaArriendo = (
  contrato,
  movimiento,
  fechaCorte = ''
) => {
  const liquidacion = calcularCargosLiquidadosPeriodoExtractoArriendo({
    contrato,
    movimiento,
    fechaCorte,
  })

  if (liquidacion.saldoPeriodo <= 0) {
    return {
      pendienteCanon: 0,
      pendienteIvaCanon: 0,
      pendienteMora: 0,
      pendienteGastos: 0,
      pendienteIvaMora: 0,
      pendienteIvaGastos: 0,
      saldoPeriodo: 0,
    }
  }

  const { canonBase, ivaCanonMes } = calcularBaseLiquidacionEstadoCuentaArriendoMes(
    movimiento,
    contrato
  )
  const pagosMes = movimiento?.pagosLiquidacionArriendoMes || movimiento?.pagosMes || []
  const pagosCapital = pagosMes.filter((pago) => Number(pago?.mora || 0) <= 0)
  const pagadoMora = pagosMes.reduce((total, pago) => total + Number(pago.mora || 0), 0)
  const pagadoCanonBase = calcularPagadoCanonBaseArriendoMes({
    pagos: pagosCapital,
    canonBase,
    ivaCanonMes,
  })
  const pagadoCapitalTotal = pagosCapital.reduce(
    (total, pago) => total + obtenerAbonoCapitalPagoArriendo(pago),
    0
  )
  const pagadoIvaCanon = Math.max(0, pagadoCapitalTotal - pagadoCanonBase)
  const descuento = Number(movimiento?.descuento || 0)

  const pendienteCanon = Math.max(0, canonBase - descuento - pagadoCanonBase)
  const pendienteIvaCanon = Math.max(0, ivaCanonMes - pagadoIvaCanon)
  const pendienteMora = Math.max(
    0,
    liquidacion.moraContrato + liquidacion.moraGestion - pagadoMora
  )

  let saldoRestante = Math.max(
    0,
    liquidacion.saldoPeriodo - pendienteCanon - pendienteIvaCanon - pendienteMora
  )
  const pendienteGastos = Math.min(liquidacion.sancionCobranza, saldoRestante)
  saldoRestante -= pendienteGastos
  const pendienteIvaMora = Math.min(liquidacion.ivaMora, saldoRestante)
  saldoRestante -= pendienteIvaMora
  const pendienteIvaGastos = Math.min(liquidacion.ivaGastosCobranza, saldoRestante)

  return {
    pendienteCanon,
    pendienteIvaCanon,
    pendienteMora,
    pendienteGastos,
    pendienteIvaMora,
    pendienteIvaGastos,
    saldoPeriodo: liquidacion.saldoPeriodo,
  }
}

// =============================================================================
// ARRIENDOS - RESUMEN DEUDA ESTADO DE CUENTA
// Totales pendientes por concepto y deuda consolidada.
// =============================================================================

const calcularResumenDeudaEstadoCuentaArriendo = ({
  contrato,
  movimientos = [],
  fechaCorte = '',
}) => {
  const resumen = {
    totalCanonBaseDeuda: 0,
    totalIvaDeuda: 0,
    totalMoraDeuda: 0,
    totalGastosCobranzaDeuda: 0,
    totalDeuda: 0,
  }

  movimientos.forEach((movimiento) => {
    const pendientes = calcularPendientesDeudaPeriodoEstadoCuentaArriendo(
      contrato,
      movimiento,
      fechaCorte
    )
    resumen.totalCanonBaseDeuda += pendientes.pendienteCanon
    resumen.totalIvaDeuda +=
      pendientes.pendienteIvaCanon +
      pendientes.pendienteIvaMora +
      pendientes.pendienteIvaGastos
    resumen.totalMoraDeuda += pendientes.pendienteMora
    resumen.totalGastosCobranzaDeuda += pendientes.pendienteGastos
    resumen.totalDeuda += pendientes.saldoPeriodo
  })

  return {
    ...resumen,
    totalCanonBase: resumen.totalCanonBaseDeuda,
    totalIva: resumen.totalIvaDeuda,
    totalMora: resumen.totalMoraDeuda,
    totalSancionCobranza: resumen.totalGastosCobranzaDeuda,
    saldoDeudaTotal: resumen.totalDeuda,
    saldoPendiente: resumen.totalDeuda,
    estadoGeneral: resumen.totalDeuda > 0 ? 'Con deuda' : 'Al día',
  }
}

// =============================================================================
// ARRIENDOS - SERVICIOS PUBLICOS RESUMEN DEUDA
// Valor en deuda o pendiente para servicios publicos de la unidad.
// =============================================================================

const obtenerValorServiciosPublicosResumenDeuda = (
  resumenServicios = {},
  extractosServiciosUnidad = []
) => {
  if (!resumenServicios.tieneServicios) {
    return { tipo: 'pendiente', etiqueta: 'Pendiente' }
  }

  const saldoDeuda = Number(resumenServicios.saldoTotal || 0)
  if (saldoDeuda > 0) {
    return { tipo: 'valor', monto: saldoDeuda }
  }

  const tieneCargaPendiente = extractosServiciosUnidad.some(
    (extracto) =>
      extracto.sinContratoActivo ||
      (extracto.movimientos || []).some(
        (movimiento) => movimiento.faltaFactura || movimiento.faltaRecibo
      )
  )

  if (tieneCargaPendiente) {
    return { tipo: 'pendiente', etiqueta: 'Pendiente' }
  }

  return { tipo: 'valor', monto: 0 }
}

// =============================================================================
// ARRIENDOS - ENRIQUECER RESUMEN CON SERVICIOS
// Agrega servicios publicos al resumen de deuda del extracto.
// =============================================================================

const enriquecerResumenDeudaServiciosPublicosExtractoArriendo = (
  extracto,
  extractosServicios = []
) => {
  const contrato = extracto?.contrato || {}
  const resumenServicios = obtenerResumenServiciosPublicosUnidad(
    {
      id: contrato.idUnidad,
      codigoPredio: contrato.codigoPredio,
    },
    extractosServicios
  )
  const serviciosPublicos = obtenerValorServiciosPublicosResumenDeuda(
    resumenServicios,
    resumenServicios.extractos
  )

  return {
    ...extracto,
    resumen: {
      ...extracto.resumen,
      serviciosPublicosDeuda:
        serviciosPublicos.tipo === 'valor' ? serviciosPublicos.monto : null,
      serviciosPublicosPendiente: serviciosPublicos.tipo === 'pendiente',
    },
  }
}

const obtenerFechaInicioMoraMesArriendo = (mesCausado, contrato = null) =>
  obtenerFechaInicioCalculoInteresMoraMesArriendo(mesCausado, contrato)

const calcularMoraArriendoProporcionalRango = ({
  base = 0,
  porcentajeInteresMora = 0,
  fechaInicio = '',
  fechaFin = '',
}) => {
  const capital = Number(base || 0)
  const tasaMensual = Number(porcentajeInteresMora || 0)
  if (capital <= 0 || tasaMensual <= 0 || !fechaInicio || !fechaFin) return 0

  const inicio = new Date(`${fechaInicio}T00:00:00`)
  const finInclusivo = new Date(`${fechaFin}T00:00:00`)
  const finExclusivo = new Date(finInclusivo)
  finExclusivo.setDate(finExclusivo.getDate() + 1)

  if (!(inicio < finExclusivo)) return 0

  let mora = 0
  let cursor = new Date(inicio)

  while (cursor < finExclusivo) {
    const anio = cursor.getFullYear()
    const mesCalendario = cursor.getMonth() + 1
    const diasEnMes = obtenerDiasDelMesCalendario(anio, mesCalendario)
    const ultimoDiaMes = new Date(anio, cursor.getMonth(), diasEnMes)
    ultimoDiaMes.setDate(ultimoDiaMes.getDate() + 1)
    const finTramo = finExclusivo < ultimoDiaMes ? finExclusivo : ultimoDiaMes
    const diasTramo = Math.floor((finTramo - cursor) / MS_POR_DIA)

    if (diasTramo > 0) {
      mora += capital * (tasaMensual / 100) * (diasTramo / diasEnMes)
    }

    cursor = new Date(finTramo)
  }

  return Math.round(mora)
}

const sumarMoraArriendoHastaFecha = ({
  saldoCapital = 0,
  porcentajeInteresMora = 0,
  fechaInicio = '',
  fechaFin = '',
}) => {
  if (saldoCapital <= 0 || !fechaInicio || !fechaFin) return 0
  if (compararFechasISO(fechaInicio, fechaFin) > 0) return 0

  return calcularMoraArriendoProporcionalRango({
    base: saldoCapital,
    porcentajeInteresMora,
    fechaInicio,
    fechaFin,
  })
}

const calcularDiasMoraArriendo = (mesCausado, fechaReferencia = '', contrato = null) => {
  const inicio = obtenerFechaInicioLiquidacionMoraMesArriendo(mesCausado, contrato)
  if (!inicio) return 0

  const fin = fechaReferencia || new Date().toISOString().slice(0, 10)
  if (fin < inicio) return 0
  if (fin === inicio) return 0

  return (
    Math.floor(
      (new Date(`${fin}T00:00:00`) - new Date(`${inicio}T00:00:00`)) / MS_POR_DIA
    ) + 1
  )
}

const calcularMoraAcumuladaMesArriendo = ({
  baseMora = 0,
  porcentajeInteresMora = 0,
  mesCausado = '',
  pagos = [],
  totalDescuento = 0,
  fechaCorte = '',
  contrato = null,
  canonBase = 0,
  ivaCanonMes = 0,
  moraSobreCanonSinIva = false,
}) => {
  const saldoCapitalInicial = Number(baseMora || 0) - Number(totalDescuento || 0)
  if (saldoCapitalInicial <= 0 || !mesCausado) return 0

  const fechaCorteEfectiva = fechaCorte || new Date().toISOString().slice(0, 10)
  const vencimiento = obtenerFechaVencimientoMesArriendo(mesCausado, contrato)
  const pagosOrdenados = ordenarPagosArriendoCronologico(pagos)
  const opcionesAbono = {
    canonBase: canonBase || baseMora,
    ivaCanonMes,
    moraSobreCanonSinIva,
  }

  if (
    mesArriendoSinInteresesMora({
      mesCausado,
      saldoCapitalInicial,
      pagos: pagosOrdenados,
      contrato,
      ...opcionesAbono,
    })
  ) {
    return 0
  }

  const fechaLiquidacionReferencia =
    pagosOrdenados
      .map((pago) => pago.fechaPago)
      .filter(Boolean)
      .sort((a, b) => compararFechasISO(b, a))[0] || fechaCorteEfectiva

  if (
    !puedeLiquidarInteresesMoraMesArriendo(mesCausado, fechaLiquidacionReferencia, contrato) &&
    !puedeLiquidarInteresesMoraMesArriendo(mesCausado, fechaCorteEfectiva, contrato)
  ) {
    return 0
  }

  let saldoCapital = saldoCapitalInicial
  let cursorFecha = obtenerFechaInicioCalculoInteresMoraMesArriendo(mesCausado, contrato)
  let moraTotal = 0

  pagosOrdenados.forEach((pago) => {
    if (saldoCapital <= 0 || !pago.fechaPago) return

    if (compararFechasISO(pago.fechaPago, vencimiento) <= 0) {
      saldoCapital -= reducirCapitalMoraPorPagoArriendo(pago, {
        ...opcionesAbono,
        saldoCapital,
      })
      if (saldoCapital > 0) {
        cursorFecha = agregarDiasFechaISO(pago.fechaPago, 1)
      }
      return
    }

    const fechaFinTramo = agregarDiasFechaISO(pago.fechaPago, -1)
    moraTotal += sumarMoraArriendoHastaFecha({
      saldoCapital,
      porcentajeInteresMora,
      fechaInicio: cursorFecha,
      fechaFin: fechaFinTramo,
    })

    saldoCapital -= reducirCapitalMoraPorPagoArriendo(pago, {
      ...opcionesAbono,
      saldoCapital,
    })
    cursorFecha = agregarDiasFechaISO(pago.fechaPago, 1)
  })

  if (
    saldoCapital > 0 &&
    puedeLiquidarInteresesMoraMesArriendo(mesCausado, fechaCorteEfectiva, contrato)
  ) {
    moraTotal += sumarMoraArriendoHastaFecha({
      saldoCapital,
      porcentajeInteresMora,
      fechaInicio: cursorFecha,
      fechaFin: fechaCorteEfectiva,
    })
  }

  return Math.round(moraTotal)
}

const DESGLOSE_PAGO_ARRIENDO_VACIO = {
  canonIvaPendiente: 0,
  moraPendiente: 0,
  gastosCobranza: 0,
  ivaMoraCobranza: 0,
  totalPendiente: 0,
}

const pendientesADesglosePagoArriendo = (pendientes = {}) => {
  const canonIvaPendiente =
    Number(pendientes.pendienteCanon || 0) + Number(pendientes.pendienteIvaCanon || 0)
  const moraPendiente = Number(pendientes.pendienteMora || 0)
  const gastosCobranza = Number(pendientes.pendienteGastos || 0)
  const ivaMoraCobranza =
    Number(pendientes.pendienteIvaMora || 0) + Number(pendientes.pendienteIvaGastos || 0)

  return {
    canonIvaPendiente,
    moraPendiente,
    gastosCobranza,
    ivaMoraCobranza,
    totalPendiente: canonIvaPendiente + moraPendiente + gastosCobranza + ivaMoraCobranza,
  }
}

const construirDesglosePendientePagoArriendo = ({
  movimiento = null,
  contrato = null,
  fechaCorte = '',
} = {}) => {
  if (!movimiento || !contrato) {
    return { ...DESGLOSE_PAGO_ARRIENDO_VACIO }
  }

  const pendientes = calcularPendientesDeudaPeriodoEstadoCuentaArriendo(
    contrato,
    movimiento,
    fechaCorte
  )

  if (pendientes.saldoPeriodo <= 0) {
    return { ...DESGLOSE_PAGO_ARRIENDO_VACIO }
  }

  return pendientesADesglosePagoArriendo(pendientes)
}

const construirDesglosePendientePagoArriendoContrato = ({
  contrato = null,
  movimientos = [],
  fechaCorte = '',
} = {}) => {
  if (!contrato || !movimientos.length) {
    return { ...DESGLOSE_PAGO_ARRIENDO_VACIO }
  }

  return movimientos
    .filter((movimiento) =>
      movimientoArriendoTieneSaldoPendiente(contrato, movimiento, fechaCorte)
    )
    .reduce((acumulado, movimiento) => {
      const pendientes = calcularPendientesDeudaPeriodoEstadoCuentaArriendo(
        contrato,
        movimiento,
        fechaCorte
      )

      if (pendientes.saldoPeriodo <= 0) {
        return acumulado
      }

      const parcial = pendientesADesglosePagoArriendo(pendientes)

      return {
        canonIvaPendiente: acumulado.canonIvaPendiente + parcial.canonIvaPendiente,
        moraPendiente: acumulado.moraPendiente + parcial.moraPendiente,
        gastosCobranza: acumulado.gastosCobranza + parcial.gastosCobranza,
        ivaMoraCobranza: acumulado.ivaMoraCobranza + parcial.ivaMoraCobranza,
        totalPendiente: acumulado.totalPendiente + parcial.totalPendiente,
      }
    }, { ...DESGLOSE_PAGO_ARRIENDO_VACIO })
}

const calcularMoraSugeridaPagoArriendo = ({
  contrato,
  mesCausado,
  fechaPago,
  canonCausadoBase,
  pagosPrevios = [],
  totalDescuentoPrevio = 0,
}) => {
  const porcentajeInteresMora = Number(contrato?.porcentajeInteresMora || 0)
  if (!mesCausado || !fechaPago || !canonCausadoBase || !porcentajeInteresMora) return 0

  const vencimiento = obtenerFechaVencimientoMesArriendo(mesCausado, contrato)
  if (compararFechasISO(fechaPago, vencimiento) <= 0) return 0
  if (!puedeLiquidarInteresesMoraMesArriendo(mesCausado, fechaPago, contrato)) return 0

  const pagosAnteriores = ordenarPagosArriendoCronologico(pagosPrevios)
  let saldoCapital = Number(canonCausadoBase || 0) - Number(totalDescuentoPrevio || 0)
  let cursorFecha = obtenerFechaInicioCalculoInteresMoraMesArriendo(mesCausado, contrato)

  pagosAnteriores.forEach((pago) => {
    if (!pago.fechaPago || saldoCapital <= 0) return

    if (compararFechasISO(pago.fechaPago, vencimiento) <= 0) {
      saldoCapital -= obtenerAbonoCapitalPagoArriendo(pago)
      if (saldoCapital > 0) {
        cursorFecha = agregarDiasFechaISO(pago.fechaPago, 1)
      }
      return
    }

    saldoCapital -= obtenerAbonoCapitalPagoArriendo(pago)
    cursorFecha = agregarDiasFechaISO(pago.fechaPago, 1)
  })

  if (saldoCapital <= 0) return 0

  const fechaFinTramo = agregarDiasFechaISO(fechaPago, -1)

  return sumarMoraArriendoHastaFecha({
    saldoCapital,
    porcentajeInteresMora,
    fechaInicio: cursorFecha,
    fechaFin: fechaFinTramo,
  })
}

const obtenerMesPendienteMasAntiguoExtracto = (extracto) => {
  if (!extracto?.movimientos?.length) return ''

  const mesesPendientes = extracto.movimientos.filter((movimiento) =>
    movimientoArriendoTieneSaldoPendiente(
      extracto.contrato,
      movimiento,
      extracto.fechaCorte || ''
    )
  )
    .map((movimiento) => movimiento.mes)
    .sort()

  return mesesPendientes[0] || ''
}

const ESTADOS_PREDIO = [
  'Registrado',
  'En revisión',
  'Documentación pendiente',
  'En negociación',
  'Contratado',
  'Con pago parcial',
  'Pagado',
  'Cerrado',
]

const normalizarEstadoPredio = (estado) => {
  if (!estado || estado === 'Activo') return 'Registrado'
  if (estado === 'Inactivo') return 'Cerrado'
  if (ESTADOS_PREDIO.includes(estado)) return estado
  return 'Registrado'
}

const normalizarPredios = (lista) =>
  (lista || []).map((predio) => ({
    ...predio,
    estado: normalizarEstadoPredio(predio.estado),
  }))

const normalizarEsDepositantePropietarios = (lista = [], contratosDeposito = []) => {
  const idsDepositantePropietario = new Set()

  ;(contratosDeposito || []).forEach((contrato) => {
    if (contrato.calidadContratante !== 'Propietario') return

    ;[contrato.idDepositante, contrato.idContratante, contrato.idPropietario]
      .filter(Boolean)
      .forEach((id) => idsDepositantePropietario.add(id))
  })

  return lista.map((persona) =>
    idsDepositantePropietario.has(persona.id)
      ? { ...persona, esDepositante: true }
      : persona
  )
}

