function InputValor({ value, onChange, className = '', placeholder, disabled, readOnly }) {
  return (
    <input
      type="text"
      inputMode="numeric"
      className={className ? `input-valor-monetario ${className}` : 'input-valor-monetario'}
      placeholder={placeholder}
      disabled={disabled}
      readOnly={readOnly}
      value={formatearNumeroMiles(value)}
      onChange={(evento) => {
        if (readOnly || disabled) return
        onChange(parsearNumeroMiles(evento.target.value))
      }}
    />
  )
}

// =============================================================================
// COMPONENTE - CONDICIONES DE PAGO INH
// Detalle de condiciones y medios de pago INH.
// =============================================================================

function DetalleCondicionesPagoInh({
  condiciones,
  tipoPagoLiquidacion,
  idPropietario,
  numeroDocumento,
  nombreBeneficiario,
  participacion,
  esContratante,
  calidadContratante,
  observacionesAutorizacionPago,
  variant = 'compact',
  sinEncabezadoMedioPago = false,
}) {
  const datos = normalizarCondicionesPagoInh(condiciones)
  const esTransferencia = requiereCuentaBancariaPagoInh(datos.medioPago)
  const esChequeEfectivo = datos.medioPago === 'Cheque o efectivo'

  const cuentaBeneficiario =
    idPropietario || numeroDocumento
      ? obtenerCuentaPagoBeneficiario(datos, { idPropietario, numeroDocumento })
      : null

  const cuentaPago =
    cuentaBeneficiario ||
    (esTransferencia && (datos.numeroCuenta || datos.banco || datos.nombreCuenta) ? datos : null)

  const mostrarTodasLasCuentas =
    !pagoEsSoloAlDepositario(tipoPagoLiquidacion) &&
    datos.cuentasPropietarios.length > 1 &&
    !cuentaBeneficiario

  const renderCuenta = (cuenta, prefijo = '') => (
    <>
      <div>
        <span>{prefijo}Número de cuenta</span>
        <strong>{cuenta.numeroCuenta}</strong>
      </div>
      <div>
        <span>{prefijo}Tipo de cuenta</span>
        <strong>{cuenta.tipoCuenta}</strong>
      </div>
      <div>
        <span>{prefijo}Banco</span>
        <strong>{cuenta.banco}</strong>
      </div>
      <div>
        <span>{prefijo}Nombre de la cuenta</span>
        <strong>{cuenta.nombreCuenta}</strong>
      </div>
    </>
  )

  if (!datos.medioPago) {
    if (variant === 'bloque' && !sinEncabezadoMedioPago) {
      return (
        <>
          <div className="form-section-title full medio-pago-acordado-titulo">
            Medio de pago acordado
          </div>
          <section className="bloque-forma-pago-liquidacion sin-configurar">
            <p className="forma-pago-descripcion forma-pago-descripcion-sola">
              No se registró el medio de pago en el documento de administración.
            </p>
          </section>
        </>
      )
    }
    if (variant === 'bloque' && sinEncabezadoMedioPago) {
      return null
    }
    return null
  }

  if (variant === 'bloque') {
    const pagoSoloDepositario = pagoEsSoloAlDepositario(tipoPagoLiquidacion)
    const esAutorizado = calidadContratante === 'Autorizado'
    const nombreDestinatario = nombreBeneficiario || cuentaPago?.nombrePropietario || ''

    let destinatarioLabel = 'Beneficiario del pago'
    if (pagoSoloDepositario) {
      destinatarioLabel = esAutorizado
        ? `Depositario autorizado${nombreDestinatario ? `: ${nombreDestinatario}` : ''}`
        : `Depositario${nombreDestinatario ? `: ${nombreDestinatario}` : ''}`
    } else if (nombreDestinatario) {
      const rol = esContratante ? 'Depositario / propietario' : 'Propietario'
      destinatarioLabel = `${rol}: ${nombreDestinatario}${
        participacion != null ? ` (${participacion}%)` : ''
      }`
    }

    return (
      <>
        {!sinEncabezadoMedioPago && (
          <div className="form-section-title full medio-pago-acordado-titulo">
            Medio de pago acordado
          </div>
        )}
        <section
          className={`bloque-forma-pago-liquidacion${
            esTransferencia ? ' es-transferencia' : ' es-cheque-efectivo'
          }`}
        >
        <div className="forma-pago-liquidacion-grid">
          <div className="forma-pago-item">
            <span>Destinatario del pago</span>
            <strong>{destinatarioLabel}</strong>
          </div>
          <div className="forma-pago-item">
            <span>Distribución mensual</span>
            <strong>{normalizarTipoPagoLiquidacionDeposito(tipoPagoLiquidacion)}</strong>
          </div>
          {!sinEncabezadoMedioPago && (
            <div className="forma-pago-item forma-pago-medio">
              <span>Tipo de pago</span>
              <strong
                className={`etiqueta-medio-pago ${
                  esTransferencia ? 'medio-transferencia' : 'medio-cheque-efectivo'
                }`}
              >
                {datos.medioPago}
              </strong>
            </div>
          )}
        </div>

        {esTransferencia && cuentaPago && (
          <div className="cuenta-pago-liquidacion-detalle">
            <p className="forma-pago-descripcion">
              INH realizará el pago mediante transferencia o consignación a la siguiente cuenta
              {nombreDestinatario ? ` de ${nombreDestinatario}` : ''}:
            </p>
            <div className="campos-cuenta-pago-inh campos-cuenta-pago-liquidacion">
              <div>
                <span>Número de cuenta</span>
                <strong>{cuentaPago.numeroCuenta}</strong>
              </div>
              <div>
                <span>Tipo de cuenta</span>
                <strong>{cuentaPago.tipoCuenta}</strong>
              </div>
              <div>
                <span>Banco</span>
                <strong>{cuentaPago.banco}</strong>
              </div>
              <div>
                <span>Nombre de la cuenta</span>
                <strong>{cuentaPago.nombreCuenta}</strong>
              </div>
            </div>
          </div>
        )}

        {esTransferencia && !cuentaPago && (
          <p className="forma-pago-advertencia">
            No hay cuenta bancaria registrada para este beneficiario en el documento de administración.
          </p>
        )}

        {esChequeEfectivo && (
          <p className="forma-pago-descripcion forma-pago-cheque-efectivo">
            El pago se realizará en <strong>cheque o efectivo</strong> directamente al beneficiario.
            No aplica consignación ni transferencia bancaria.
          </p>
        )}

        {observacionesAutorizacionPago && (
          <div className="forma-pago-autorizacion">
            <span>Autorización de pagos</span>
            <strong>{observacionesAutorizacionPago}</strong>
          </div>
        )}
        </section>
      </>
    )
  }

  return (
    <>
      <div>
        <span>{obtenerEtiquetaPagoInhContrato(tipoPagoLiquidacion)}</span>
        <strong>{datos.medioPago}</strong>
      </div>
      {esTransferencia && cuentaBeneficiario && renderCuenta(cuentaBeneficiario)}
      {esTransferencia &&
        mostrarTodasLasCuentas &&
        datos.cuentasPropietarios.map((cuenta) => (
          <React.Fragment key={cuenta.clave || cuenta.idPropietario || cuenta.numeroDocumento}>
            <div className="full-detail">
              <span>Cuenta de pago</span>
              <strong>
                {cuenta.nombrePropietario} ({cuenta.porcentaje}%)
              </strong>
            </div>
            {renderCuenta(cuenta)}
          </React.Fragment>
        ))}
      {esTransferencia &&
        !cuentaBeneficiario &&
        !mostrarTodasLasCuentas &&
        datos.numeroCuenta &&
        renderCuenta(datos)}
    </>
  )
}

function AdjuntoArchivoInline({
  etiqueta,
  adjunto,
  onSeleccionarArchivo,
  onQuitar,
  textoBoton,
  ocultarEtiqueta = false,
}) {
  const inputRef = useRef(null)

  return (
    <div className={`adjunto-archivo-inline${ocultarEtiqueta ? ' sin-etiqueta' : ''}`}>
      {!ocultarEtiqueta && <label>{etiqueta}</label>}
      {adjunto ? (
        <div className="adjunto-archivo-chip" title={adjunto.nombreArchivo}>
          <span>{adjunto.nombreArchivo}</span>
          <button type="button" className="btn-chip-quitar" onClick={onQuitar} aria-label="Quitar">
            ×
          </button>
        </div>
      ) : (
        <>
          <button
            type="button"
            className="btn-primary btn-adjunto-archivo"
            onClick={() => inputRef.current?.click()}
          >
            {textoBoton || `Subir ${etiqueta.toLowerCase()}`}
          </button>
          <input
            ref={inputRef}
            type="file"
            accept=".pdf,.jpg,.jpeg,.png,.webp,.doc,.docx"
            className="input-archivo-oculto"
            onChange={onSeleccionarArchivo}
          />
        </>
      )}
    </div>
  )
}

