function PanelDetalleContratoDepositoPredio({
  contrato,
  contratosDeposito,
  propietarios,
  puedeEditar = false,
  puedeAdjuntar = false,
  onEditar,
  onAdjuntar,
}) {
  if (!contrato) {
    return (
      <>
        <p className="form-description">
          Este inmueble no tiene un documento de administración vinculado. Puede registrar uno para
          administrar comisiones, pagos y liquidación del predio.
        </p>
        {puedeAdjuntar && onAdjuntar && (
          <div className="form-actions form-actions-embedded">
            <button type="button" className="btn-primary" onClick={onAdjuntar}>
              Vincular documento de administración
            </button>
          </div>
        )}
      </>
    )
  }

  const depositario = propietarios.find(
    (item) => item.id === (contrato.idContratante || contrato.idPropietario)
  )

  return (
    <>
      <p className="form-description">
        Este inmueble se administra mediante un <strong>documento de administración</strong>.
        Las condiciones siguientes corresponden al acuerdo vigente con el depositante.
      </p>

      <div className="detail-grid">
        <div>
          <span>Tipo de contrato</span>
          <strong>Contrato de depósito</strong>
        </div>
        <div>
          <span>Documento de administración</span>
          <strong>
            {obtenerNumeroContratoDepositoVisible(contrato, contratosDeposito)}
          </strong>
        </div>
        <div>
          <span>Depositante</span>
          <strong>{depositario?.nombre || 'Sin depositante'}</strong>
        </div>
        <div>
          <span>Identificación expediente</span>
          <strong>
            {obtenerNumeroIdentificacionDepositante(depositario, contrato) || 'Sin registrar'}
          </strong>
        </div>
        <div>
          <span>Documento depositante</span>
          <strong>
            {depositario
              ? `${depositario.tipoDocumento} - ${depositario.numeroDocumento}`
              : 'Sin registrar'}
          </strong>
        </div>
        <div>
          <span>Calidad del depositante</span>
          <strong>{contrato.calidadContratante || 'Propietario'}</strong>
        </div>
        <div>
          <span>Tipo de comisión</span>
          <strong>{contrato.tipoComision}</strong>
        </div>
        <div>
          <span>Porcentaje de comisión</span>
          <strong>{contrato.porcentajeComision}%</strong>
        </div>
        <div>
          <span>Forma de pago mensual</span>
          <strong>{normalizarTipoPagoLiquidacionDeposito(contrato.tipoPagoLiquidacion)}</strong>
        </div>
        <div>
          <span>Criterio liquidación canon</span>
          <strong>
            {normalizarCriterioLiquidacionCanonDeposito(contrato.criterioLiquidacionCanon)}
          </strong>
        </div>
        <DetalleCondicionesPagoInh
          condiciones={contrato.condicionesPagoInh}
          tipoPagoLiquidacion={contrato.tipoPagoLiquidacion}
        />
        <div>
          <span>Seguimiento predial</span>
          <strong>
            {contrato.tipoComision === 'Administración'
              ? contrato.incluyeSeguimientoPredial || 'No'
              : 'No aplica'}
          </strong>
        </div>
        <div>
          <span>Póliza con aseguradora</span>
          <strong>{normalizarIncluyeAseguradoraDeposito(contrato.incluyeAseguradora)}</strong>
        </div>
        <div>
          <span>Fecha inicio</span>
          <strong>{contrato.fechaInicio || 'Sin registrar'}</strong>
        </div>
        <div>
          <span>Fecha finalización</span>
          <strong>{contrato.fechaFin || 'Vigente'}</strong>
        </div>
        <div>
          <span>Estado del contrato</span>
          <strong>{contrato.estado}</strong>
        </div>
        {contrato.observacionesAutorizacionPago && (
          <div className="full-detail">
            <span>Autorización de pagos</span>
            <strong>{contrato.observacionesAutorizacionPago}</strong>
          </div>
        )}
        <div className="full-detail">
          <span>Observaciones del documento de administración</span>
          <strong>{contrato.observaciones || 'Sin observaciones'}</strong>
        </div>
      </div>

      {puedeEditar && onEditar && (
        <div className="form-actions form-actions-embedded">
          <button type="button" className="btn-gold" onClick={onEditar}>
            Editar documento
          </button>
        </div>
      )}
    </>
  )
}

const obtenerCodigoCiudad = (texto) => {
  const ciudadLimpia = normalizarTexto(texto)

  if (ciudadLimpia === 'bogotá' || ciudadLimpia === 'bogota') return 'BOG'
  if (ciudadLimpia === 'medellín' || ciudadLimpia === 'medellin') return 'MED'
  if (ciudadLimpia === 'cali') return 'CAL'
  if (ciudadLimpia === 'barranquilla') return 'BAQ'
  if (ciudadLimpia === 'villavicencio') return 'VIL'

  return ciudadLimpia.replace(/[^a-z]/g, '').substring(0, 3).toUpperCase()
}

const obtenerIdContrato = (contrato) => {
  if (!contrato) return ''
  if (contrato.id) return contrato.id
  return (
    contrato.idContrato ||
    `${contrato.codigoPredio}-${contrato.idUnidad || 'SIN-UNIDAD'}-${contrato.numeroDocumento}-${contrato.fechaInicio || ''}`
  )
}

const coincideContratoArriendo = (contrato, referencia) => {
  if (!contrato || !referencia) return false
  if (referencia.id && contrato.id) return contrato.id === referencia.id
  return obtenerIdContrato(contrato) === obtenerIdContrato(referencia)
}

const CONCEPTO_PAGO_CANON_ARRIENDO = 'Pago canon de arriendo'
const CONCEPTO_ABONO_CANON_ARRIENDO = 'Abono a canon de arriendo'

const CONCEPTOS_RECIBO_ARRIENDO = [
  CONCEPTO_PAGO_CANON_ARRIENDO,
  CONCEPTO_ABONO_CANON_ARRIENDO,
]

const RECIBO_IMPRESION_ROOT_ID = 'recibo-impresion-root'
const EXTRACTO_IMPRESION_ROOT_ID = 'extracto-impresion-root'
const EXTRACTO_PREDIOS_IMPRESION_ROOT_ID = 'extracto-predios-impresion-root'

const escapeHtml = (texto) =>
  String(texto ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;')

const MM_A_PX = 96 / 25.4
const CARTA_MARGEN_MM = 8

const obtenerAreaUtilCartaPx = () => {
  const anchoMm = 215.9 - CARTA_MARGEN_MM * 2
  const altoMm = 279.4 - CARTA_MARGEN_MM * 2
  return {
    ancho: Math.floor(anchoMm * MM_A_PX),
    alto: Math.floor(altoMm * MM_A_PX),
  }
}

const reiniciarEscalaImpresionUnaCarta = (elemento) => {
  if (!elemento) return
  elemento.style.transform = ''
  elemento.style.width = ''
  elemento.classList.remove('impresion-una-carta-escala')
}

const ajustarImpresionUnaCarta = (elemento) => {
  if (!elemento) return
  reiniciarEscalaImpresionUnaCarta(elemento)

  const { alto, ancho } = obtenerAreaUtilCartaPx()
  const altoContenido = elemento.scrollHeight
  const tablaAncha = elemento.querySelector('table, .extracto-card, .extracto-predios-propietario-print')
  const anchoContenido = Math.max(
    elemento.scrollWidth,
    elemento.offsetWidth,
    tablaAncha?.scrollWidth || 0,
    tablaAncha?.offsetWidth || 0
  )

  const necesitaAlto = altoContenido > alto
  const necesitaAncho = anchoContenido > ancho
  if (!necesitaAlto && !necesitaAncho) return

  const escalaAlto = necesitaAlto ? (alto / altoContenido) * 0.98 : 1
  const escalaAncho = necesitaAncho ? (ancho / anchoContenido) * 0.98 : 1
  let escala = Math.min(escalaAlto, escalaAncho, 1)
  escala = Math.max(0.35, escala)

  if (escala >= 0.999) return

  elemento.classList.add('impresion-una-carta-escala')
  elemento.style.transform = `scale(${escala})`
  elemento.style.transformOrigin = 'top left'
  elemento.style.width = `${100 / escala}%`
}

const limpiarImpresionUnaCartaPorPaginas = (contenedor) => {
  if (!contenedor) return
  contenedor.querySelectorAll('.impresion-una-carta-contenido').forEach(reiniciarEscalaImpresionUnaCarta)
  contenedor.querySelectorAll('.impresion-una-carta-pagina').forEach((pagina) => {
    pagina.style.height = ''
    pagina.style.maxHeight = ''
    pagina.style.width = ''
    pagina.style.maxWidth = ''
    pagina.style.overflow = ''
    pagina.style.position = ''
  })
}

const ajustarImpresionUnaCartaPorPaginas = (contenedor) => {
  if (!contenedor) return

  const { alto, ancho } = obtenerAreaUtilCartaPx()

  contenedor.querySelectorAll('.impresion-una-carta-pagina').forEach((pagina) => {
    const contenido = pagina.querySelector(':scope > .impresion-una-carta-contenido')
    if (!contenido) return

    reiniciarEscalaImpresionUnaCarta(contenido)
    pagina.style.height = `${alto}px`
    pagina.style.maxHeight = `${alto}px`
    pagina.style.width = `${ancho}px`
    pagina.style.maxWidth = `${ancho}px`
    pagina.style.overflow = 'hidden'
    pagina.style.position = 'relative'
    pagina.style.boxSizing = 'border-box'

    ajustarImpresionUnaCarta(contenido)
  })
}

const ejecutarImpresionUnaCartaPorPaginas = (obtenerContenedor) => {
  const contenedor =
    typeof obtenerContenedor === 'function' ? obtenerContenedor() : obtenerContenedor

  const limpiar = () => {
    limpiarImpresionUnaCartaPorPaginas(contenedor)
    window.removeEventListener('afterprint', limpiar)
  }

  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      ajustarImpresionUnaCartaPorPaginas(contenedor)
      window.addEventListener('afterprint', limpiar)
      window.print()
    })
  })
}

const ejecutarImpresionUnaCarta = (obtenerElemento) => {
  const elemento =
    typeof obtenerElemento === 'function' ? obtenerElemento() : obtenerElemento

  const limpiar = () => {
    reiniciarEscalaImpresionUnaCarta(elemento)
    window.removeEventListener('afterprint', limpiar)
  }

  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      ajustarImpresionUnaCarta(elemento)
      window.addEventListener('afterprint', limpiar)
      window.print()
    })
  })
}

const envolverCuerpoVentanaUnaCarta = (doc) => {
  const body = doc?.body
  if (!body) return null
  const existente = body.querySelector('.impresion-una-carta-envoltorio')
  if (existente) return existente

  const envoltorio = doc.createElement('div')
  envoltorio.className = 'impresion-una-carta-envoltorio'
  while (body.firstChild) {
    envoltorio.appendChild(body.firstChild)
  }
  body.appendChild(envoltorio)
  return envoltorio
}

// =============================================================================
// IMPRESION - VENTANA UNA CARTA
// Abre y dispara impresion en ventana emergente.
// =============================================================================

const imprimirVentanaUnaCarta = (ventana) => {
  if (!ventana?.document) return

  const envoltorio = envolverCuerpoVentanaUnaCarta(ventana.document)

  ventana.requestAnimationFrame(() => {
    ventana.requestAnimationFrame(() => {
      ajustarImpresionUnaCarta(envoltorio)
      ventana.focus()
      ventana.print()
      ventana.close()
    })
  })
}

