const cerrarReciboImpresion = () => {
  document.body.classList.remove('imprimiendo-recibo')
  const root = document.getElementById(RECIBO_IMPRESION_ROOT_ID)
  if (root) root.innerHTML = ''
}

const abrirVentanaReciboMediaCarta = (titulo, cuerpoHtml) => {
  let root = document.getElementById(RECIBO_IMPRESION_ROOT_ID)
  if (!root) {
    root = document.createElement('div')
    root.id = RECIBO_IMPRESION_ROOT_ID
    document.body.appendChild(root)
  }

  root.innerHTML = `
    <div class="recibo-impresion-modal">
      <div class="recibo-impresion-toolbar">
        <strong>${escapeHtml(titulo)}</strong>
        <div class="recibo-impresion-botones">
          <button type="button" class="btn-imprimir-recibo">Imprimir recibo</button>
          <button type="button" class="btn-cerrar-recibo">Cerrar</button>
        </div>
      </div>
      <style>${ESTILOS_RECIBO_MEDIA_CARTA}${ESTILOS_IMPRESION_UNA_CARTA}</style>
      <div class="recibo-impresion-contenido">${cuerpoHtml}</div>
    </div>
  `

  document.body.classList.add('imprimiendo-recibo')

  root.querySelector('.btn-imprimir-recibo')?.addEventListener('click', () => {
    ejecutarImpresionUnaCarta(() => root.querySelector('.recibo-impresion-contenido'))
  })
  root.querySelector('.btn-cerrar-recibo')?.addEventListener('click', cerrarReciboImpresion)

  const limpiarDespuesDeImprimir = () => {
    window.removeEventListener('afterprint', limpiarDespuesDeImprimir)
  }
  window.addEventListener('afterprint', limpiarDespuesDeImprimir)

  return true
}

const obtenerNumeroContratoVisible = (contrato, predios = [], contratosArriendo = []) => {
  if (!contrato) return 'Sin contrato'

  if (esNumeroContratoArriendoValido(contrato.idContrato || '')) {
    return contrato.idContrato
  }

  return generarNumeroContratoArriendo({
    contratosArriendo,
    predios,
    codigoPredio: contrato.codigoPredio,
    numeroDocumento: contrato.numeroDocumento,
  })
}

const textoCoincideBusquedaDocumentos = (busqueda, ...valores) => {
  const texto = normalizarTexto(busqueda)
  if (!texto) return false
  const soloDigitosBusqueda = texto.replace(/\D/g, '')

  return valores.some((valor) => {
    const normalizado = normalizarTexto(String(valor || ''))
    if (normalizado.includes(texto)) return true
    if (soloDigitosBusqueda.length >= 3) {
      const soloDigitosValor = String(valor || '').replace(/\D/g, '')
      return soloDigitosValor.includes(soloDigitosBusqueda)
    }
    return false
  })
}

const normalizarFechaReciboPago = (fecha) => String(fecha || '').slice(0, 10)

const formatearFechaReciboLista = (fecha) => {
  const normalizada = normalizarFechaReciboPago(fecha)
  const partes = normalizada.split('-')
  if (partes.length === 3) return `${partes[2]}/${partes[1]}/${partes[0]}`
  return normalizada || '—'
}

const obtenerNumeroReciboPago = (pago, tipo) => {
  if (tipo === 'predial' || tipo === 'liquidacion') {
    return String(pago.numeroRecibo || '').trim().toUpperCase()
  }
  return String(pago.recibo || '').trim().toUpperCase()
}

const numeroReciboCoincideBusqueda = (numeroRecibo, busqueda) => {
  const texto = normalizarTexto(busqueda)
  if (!texto) return false
  const numero = normalizarTexto(String(numeroRecibo || ''))
  if (numero.includes(texto)) return true
  const soloDigitosBusqueda = texto.replace(/\D/g, '')
  if (!soloDigitosBusqueda) return false
  const soloDigitosNumero = String(numeroRecibo || '').replace(/\D/g, '')
  return soloDigitosNumero.includes(soloDigitosBusqueda)
}

const fechaReciboEnRango = (fecha, desde, hasta) => {
  const normalizada = normalizarFechaReciboPago(fecha)
  if (!normalizada) return false
  if (desde && normalizada < desde) return false
  if (hasta && normalizada > hasta) return false
  return true
}

const obtenerNombrePagadorReciboPago = (
  pago,
  tipo,
  { contratosArriendo = [], propietarios = [], predioPropietarios = [] } = {}
) => {
  const buscarPropietarioPredio = (codigoPredio, idPropietarioPreferido = '') => {
    if (idPropietarioPreferido) {
      const propietarioDirecto = propietarios.find(
        (propietario) => propietario.idPropietario === idPropietarioPreferido
      )
      if (propietarioDirecto?.nombre) return String(propietarioDirecto.nombre).trim()
    }

    const relaciones = predioPropietarios.filter(
      (relacion) => relacion.codigoPredio === codigoPredio && relacion.activo !== false
    )
    const propietarioRelacionado = propietarios.find((propietario) =>
      relaciones.some((relacion) => relacion.idPropietario === propietario.idPropietario)
    )
    return String(propietarioRelacionado?.nombre || '').trim()
  }

  if (tipo === 'arriendo') {
    const nombre = String(pago.arrendatario || '').trim()
    if (nombre) return nombre
    const contrato = contratosArriendo.find(
      (contratoItem) => obtenerIdContrato(contratoItem) === pago.idContrato
    )
    return String(contrato?.arrendatario || '').trim() || 'Sin arrendatario'
  }

  if (tipo === 'administracion') {
    const contrato = contratosArriendo.find(
      (contratoItem) => obtenerIdContrato(contratoItem) === pago.idContrato
    )
    if (pago.origenFondo === 'Propietario') {
      return buscarPropietarioPredio(pago.codigoPredio) || 'Propietario'
    }
    return String(contrato?.arrendatario || '').trim() || 'Sin pagador'
  }

  if (tipo === 'servicios') {
    const contrato = contratosArriendo.find(
      (contratoItem) =>
        contratoItem.codigoPredio === pago.codigoPredio &&
        (contratoItem.idUnidad || '') === (pago.idUnidad || '')
    )
    return (
      String(contrato?.arrendatario || pago.nombreUnidad || '').trim() || 'Sin pagador'
    )
  }

  if (tipo === 'predial') {
    return buscarPropietarioPredio(pago.codigoPredio) || 'Propietario'
  }

  if (tipo === 'liquidacion') {
    return buscarPropietarioPredio(pago.codigoPredio, pago.idPropietario) || 'Propietario'
  }

  return '—'
}

const ETIQUETAS_TIPO_RECIBO_PAGO = {
  arriendo: 'Arriendo',
  administracion: 'Administración',
  servicios: 'Servicio público',
  predial: 'Predial',
  liquidacion: 'Liquidación depósito',
}

const OPCIONES_TIPO_FILTRO_REPORTE_RECIBOS = [
  { value: 'todos', label: 'Todos los tipos' },
  { value: 'arriendo', label: ETIQUETAS_TIPO_RECIBO_PAGO.arriendo },
  { value: 'administracion', label: ETIQUETAS_TIPO_RECIBO_PAGO.administracion },
  { value: 'servicios', label: ETIQUETAS_TIPO_RECIBO_PAGO.servicios },
  { value: 'predial', label: ETIQUETAS_TIPO_RECIBO_PAGO.predial },
  { value: 'liquidacion', label: ETIQUETAS_TIPO_RECIBO_PAGO.liquidacion },
]

const obtenerEtiquetaTipoFiltroReporteRecibos = (tipoFiltro = 'todos') => {
  if (!tipoFiltro || tipoFiltro === 'todos') return 'Todos los tipos'
  return ETIQUETAS_TIPO_RECIBO_PAGO[tipoFiltro] || 'Todos los tipos'
}

const reciboPasaFiltroTipoReporte = (item, tipoFiltro = 'todos') => {
  if (!tipoFiltro || tipoFiltro === 'todos') return true
  return item.tipo === tipoFiltro
}

const construirCatalogoRecibosPago = ({
  pagosArriendo = [],
  pagosAdministracion = [],
  pagosServiciosPublicos = [],
  pagosPrediales = [],
  pagosLiquidacionDeposito = [],
  contratosArriendo = [],
  propietarios = [],
  predioPropietarios = [],
}) => {
  const contextoPagador = { contratosArriendo, propietarios, predioPropietarios }
  const items = []

  pagosArriendo.filter(Boolean).forEach((pago) => {
    if (!pago?.id) return
    items.push({
      clave: `arriendo-${pago.id}`,
      tipo: 'arriendo',
      tipoLabel: ETIQUETAS_TIPO_RECIBO_PAGO.arriendo,
      idOrigen: pago.id,
      numeroRecibo: obtenerNumeroReciboPago(pago, 'arriendo'),
      fechaPago: normalizarFechaReciboPago(pago.fechaPago),
      concepto: `Arriendo – ${pago.concepto || 'Pago'} (${pago.mes || '—'})`,
      nombrePagador: obtenerNombrePagadorReciboPago(pago, 'arriendo', contextoPagador),
      valor: Number(pago.valorPagado || 0),
      pago,
    })
  })

  pagosAdministracion.forEach((pago) => {
    items.push({
      clave: `administracion-${pago.id}`,
      tipo: 'administracion',
      tipoLabel: ETIQUETAS_TIPO_RECIBO_PAGO.administracion,
      idOrigen: pago.id,
      numeroRecibo: obtenerNumeroReciboPago(pago, 'administracion'),
      fechaPago: normalizarFechaReciboPago(pago.fechaPago),
      concepto: `Administración – ${pago.nombreUnidad || 'Sin unidad'} (${pago.mes || '—'})`,
      nombrePagador: obtenerNombrePagadorReciboPago(pago, 'administracion', contextoPagador),
      valor: Number(pago.valorPagado || 0),
      pago,
    })
  })

  pagosServiciosPublicos.forEach((pago) => {
    items.push({
      clave: `servicios-${pago.id}`,
      tipo: 'servicios',
      tipoLabel: ETIQUETAS_TIPO_RECIBO_PAGO.servicios,
      idOrigen: pago.id,
      numeroRecibo: obtenerNumeroReciboPago(pago, 'servicios'),
      fechaPago: normalizarFechaReciboPago(pago.fechaPago),
      concepto: `${pago.tipoServicio || 'Servicio'} – ${pago.empresa || ''} (${pago.periodo || '—'})`,
      nombrePagador: obtenerNombrePagadorReciboPago(pago, 'servicios', contextoPagador),
      valor: Number(pago.valorPagado || 0),
      pago,
    })
  })

  pagosPrediales.forEach((pago) => {
    items.push({
      clave: `predial-${pago.id}`,
      tipo: 'predial',
      tipoLabel: ETIQUETAS_TIPO_RECIBO_PAGO.predial,
      idOrigen: pago.id,
      numeroRecibo: obtenerNumeroReciboPago(pago, 'predial'),
      fechaPago: normalizarFechaReciboPago(pago.fechaPago),
      concepto: `Impuesto predial ${pago.anio || '—'} – Predio ${pago.codigoPredio || '—'}`,
      nombrePagador: obtenerNombrePagadorReciboPago(pago, 'predial', contextoPagador),
      valor: Number(pago.valorPagado || 0),
      pago,
    })
  })

  pagosLiquidacionDeposito.forEach((pago) => {
    items.push({
      clave: `liquidacion-${pago.id}`,
      tipo: 'liquidacion',
      tipoLabel: ETIQUETAS_TIPO_RECIBO_PAGO.liquidacion,
      idOrigen: pago.id,
      numeroRecibo: obtenerNumeroReciboPago(pago, 'liquidacion'),
      fechaPago: normalizarFechaReciboPago(pago.fechaPago),
      concepto: `Liquidación depósito – ${pago.unidad || 'Sin unidad'} (${pago.mes || '—'}) – Predio ${pago.codigoPredio || '—'}`,
      nombrePagador: obtenerNombrePagadorReciboPago(pago, 'liquidacion', contextoPagador),
      valor: Number(pago.valorNetoPropietario || 0),
      pago,
    })
  })

  return items.sort((a, b) => {
    if (a.fechaPago !== b.fechaPago) return b.fechaPago.localeCompare(a.fechaPago)
    return a.numeroRecibo.localeCompare(b.numeroRecibo, undefined, { numeric: true })
  })
}

const imprimirListadoCorteRecibos = ({
  recibos = [],
  fechaDesde = '',
  fechaHasta = '',
  tipoFiltro = 'todos',
  formatearDinero,
}) => {
  if (!recibos.length) {
    alert('No hay recibos en el corte seleccionado para imprimir.')
    return
  }

  const total = recibos.reduce((suma, item) => suma + Number(item.valor || 0), 0)
  const tipoTexto = obtenerEtiquetaTipoFiltroReporteRecibos(tipoFiltro)
  const filas = recibos
    .map(
      (item) => `
        <tr>
          <td>${escapeHtml(formatearFechaReciboLista(item.fechaPago))}</td>
          <td>${escapeHtml(item.numeroRecibo || '—')}</td>
          <td>${escapeHtml(item.tipoLabel || ETIQUETAS_TIPO_RECIBO_PAGO[item.tipo] || '—')}</td>
          <td>${escapeHtml(item.concepto || '')}</td>
          <td>${escapeHtml(item.nombrePagador || '—')}</td>
          <td class="valor">${escapeHtml(formatearDinero(item.valor || 0))}</td>
        </tr>
      `
    )
    .join('')

  const ventana = window.open('', '_blank', 'width=1000,height=800')
  if (!ventana) {
    alert('El navegador bloqueó la ventana de impresión. Permita ventanas emergentes para este sitio.')
    return
  }

  ventana.document.write(`
    <!DOCTYPE html>
    <html>
      <head>
        <title>Corte de recibos de pago</title>
        <style>${ESTILOS_IMPRESION_VENTANA_BANCARIA}${ESTILOS_IMPRESION_UNA_CARTA}</style>
      </head>
      <body>
        <div class="doc-banda"></div>
        <header class="doc-encabezado">
          <div class="doc-encabezado-texto">
            <span class="doc-etiqueta">Comprobante administrativo</span>
            <h1>Corte de recibos de pago</h1>
            <p>INH Constructores · Control de Predios y Arriendos</p>
          </div>
          <div class="doc-logo">
            <img src="${obtenerUrlAbsolutaLogoInh()}" alt="INH Constructores" />
          </div>
        </header>
        <p class="doc-meta">
          Periodo: <strong>${escapeHtml(formatearFechaReciboLista(fechaDesde))}</strong>
          al <strong>${escapeHtml(formatearFechaReciboLista(fechaHasta))}</strong>
          · Tipo: <strong>${escapeHtml(tipoTexto)}</strong>
          · ${recibos.length} recibo(s) registrados
        </p>
        <table>
          <thead>
            <tr>
              <th>Fecha</th>
              <th>N° recibo</th>
              <th>Tipo</th>
              <th>Concepto</th>
              <th>Quien pagó</th>
              <th>Valor</th>
            </tr>
          </thead>
          <tbody>
            ${filas}
          </tbody>
        </table>
        <div class="total-doc">
          <span>Total del corte</span>
          <span>${escapeHtml(formatearDinero(total))}</span>
        </div>
      </body>
    </html>
  `)

  ventana.document.close()
  setTimeout(() => imprimirVentanaUnaCarta(ventana), 500)
}

const agregarOpcionConsultaDocumento = (opciones, claves, opcion) => {
  if (claves.has(opcion.clave)) return
  claves.add(opcion.clave)
  opciones.push(opcion)
}

const crearOpcionContratoDeposito = (contrato, contratosDeposito, propietarios, descripcionExtra = '') => {
  const numero = obtenerNumeroContratoDepositoVisible(contrato, contratosDeposito)
  const depositante = resolverDepositanteDesdeContrato(contrato, propietarios)

  return {
    clave: `deposito-${contrato.id}`,
    tipo: 'contratoDeposito',
    contratoDepositoId: contrato.id,
    codigoPredio: contrato.codigoPredio || '',
    titulo: 'Contrato de depósito',
    referencia: numero,
    descripcion:
      descripcionExtra ||
      `${depositante?.nombre || 'Sin depositante'} · ${contrato.codigoPredio || 'Sin predio'}`,
  }
}

const filtrarDocumentosAgrupadosPorUnidad = (
  agrupados = [],
  idUnidad = '',
  contratosArriendo = []
) => {
  if (!idUnidad) return agrupados

  const contratoArriendoUnidad = (contratosArriendo || []).find(
    (item) => item.idUnidad === idUnidad
  )
  const idContratoArriendo = contratoArriendoUnidad
    ? obtenerIdContrato(contratoArriendoUnidad)
    : ''

  return agrupados.map((nivel) => {
    if (nivel.clave === 'unidad') {
      const subgrupos = (nivel.subgrupos || []).filter((subgrupo) =>
        subgrupo.documentos.some((documento) => documento.idUnidad === idUnidad)
      )
      const documentos = (nivel.documentos || []).filter(
        (documento) => documento.idUnidad === idUnidad
      )
      return { ...nivel, documentos, subgrupos }
    }

    if (nivel.clave === 'contratoArriendo') {
      const subgrupos = idContratoArriendo
        ? (nivel.subgrupos || []).filter((subgrupo) =>
            subgrupo.documentos.some((documento) => documento.idContrato === idContratoArriendo)
          )
        : []
      const documentos = idContratoArriendo
        ? (nivel.documentos || []).filter(
            (documento) => documento.idContrato === idContratoArriendo
          )
        : []
      return { ...nivel, documentos, subgrupos }
    }

    return nivel
  })
}

const construirOpcionesConsultaDocumentos = ({
  busqueda = '',
  propietarios = [],
  contratosDeposito = [],
  predios = [],
  contratosArriendo = [],
  predioPropietarios = [],
  unidadesNegocio = [],
}) => {
  const texto = busqueda.trim()
  if (!texto) return []

  const opciones = []
  const claves = new Set()
  const contratosAgregados = new Set()
  const depositantesRegistrados = obtenerDepositantesRegistrados(contratosDeposito, propietarios)
  const clavesDepositantesRegistrados = new Set(
    depositantesRegistrados.map((item) => claveUnicaDepositante(item)).filter(Boolean)
  )

  const registrarContrato = (contrato, descripcionExtra = '') => {
    if (!contrato?.id || contratosAgregados.has(contrato.id)) return
    contratosAgregados.add(contrato.id)
    agregarContratoDepositoOpcionConsulta(
      opciones,
      claves,
      contrato,
      contratosDeposito,
      propietarios,
      descripcionExtra
    )
  }

  depositantesRegistrados
    .filter((depositante) => depositanteCoincideBusquedaDocumentos(depositante, texto, propietarios))
    .forEach((depositante) => {
      obtenerContratosDepositoPorDepositante(
        depositante,
        contratosDeposito,
        propietarios,
        predioPropietarios
      ).forEach((contrato) => {
        registrarContrato(
          contrato,
          `${depositante.nombre} (${depositante.numeroDocumento})`
        )
      })
    })

  ;(propietarios || [])
    .filter((persona) => persona?.esDepositante)
    .filter(
      (depositante) =>
        depositanteCoincideBusquedaDocumentos(depositante, texto, propietarios) &&
        !clavesDepositantesRegistrados.has(claveUnicaDepositante(depositante))
    )
    .forEach((depositante) => {
      obtenerContratosDepositoPorDepositante(
        depositante,
        contratosDeposito,
        propietarios,
        predioPropietarios
      ).forEach((contrato) => {
        registrarContrato(
          contrato,
          `${depositante.nombre} (${depositante.numeroDocumento})`
        )
      })
    })

  ;(contratosDeposito || []).forEach((contrato) => {
    if (contratoCoincideBusquedaDocumentosAdmin(contrato, texto, contratosDeposito, propietarios)) {
      registrarContrato(contrato)
    }
  })

  predios.forEach((predio) => {
    if (
      !textoCoincideBusquedaDocumentos(
        texto,
        predio.codigo,
        predio.direccion,
        predio.ciudad,
        predio.barrio,
        predio.matricula,
        predio.chip
      )
    ) {
      return
    }

    const contratoDepositoPredio =
      (contratosDeposito || []).find((item) => item.id === predio.idDocumento) ||
      obtenerContratoDepositoPredio(predio.codigo, contratosDeposito)

    if (contratoDepositoPredio) {
      registrarContrato(contratoDepositoPredio, `Inmueble ${predio.codigo}`)
    }
  })

  contratosArriendo.forEach((contrato) => {
    const numeroContrato = obtenerNumeroContratoVisible(contrato, predios, contratosArriendo)
    const predioContrato = predios.find((item) => item.codigo === contrato.codigoPredio)

    if (
      !textoCoincideBusquedaDocumentos(
        texto,
        numeroContrato,
        contrato.arrendatario,
        contrato.codigoPredio,
        contrato.numeroDocumento,
        contrato.nombreUnidad,
        contrato.idUnidad,
        predioContrato?.direccion,
        predioContrato?.barrio,
        predioContrato?.ciudad
      )
    ) {
      return
    }

    const contratoDepositoPredio = (contratosDeposito || []).find(
      (item) => item.codigoPredio === contrato.codigoPredio
    )

    if (contratoDepositoPredio) {
      registrarContrato(
        contratoDepositoPredio,
        `Arriendo ${numeroContrato} · ${contrato.nombreUnidad || 'Sin unidad'}`
      )
    }
  })

  ;(unidadesNegocio || []).forEach((unidad) => {
    const predioUnidad = predios.find((item) => item.codigo === unidad.codigoPredio)

    if (
      !textoCoincideBusquedaDocumentos(
        texto,
        unidad.id,
        unidad.nombre,
        unidad.codigoPredio,
        unidad.tipo,
        predioUnidad?.direccion,
        predioUnidad?.barrio,
        predioUnidad?.ciudad,
        predioUnidad?.matricula
      )
    ) {
      return
    }

    const contratoDepositoPredio =
      (contratosDeposito || []).find(
        (item) =>
          item.codigoPredio === unidad.codigoPredio &&
          (item.estado === 'Activo' || item.estado === 'Pendiente inmueble')
      ) || obtenerContratoDepositoPredio(unidad.codigoPredio, contratosDeposito)

    if (contratoDepositoPredio) {
      registrarContrato(contratoDepositoPredio, `Unidad ${unidad.id} · ${unidad.nombre}`)
    }
  })

  return opciones.sort((a, b) => a.referencia.localeCompare(b.referencia, 'es'))
}

const construirTodasOpcionesConsultaDocumentos = ({
  propietarios = [],
  contratosDeposito = [],
}) => {
  const opciones = []
  const claves = new Set()

  ;(contratosDeposito || []).forEach((contrato) => {
    agregarContratoDepositoOpcionConsulta(
      opciones,
      claves,
      contrato,
      contratosDeposito,
      propietarios
    )
  })

  return opciones.sort((a, b) => a.referencia.localeCompare(b.referencia, 'es'))
}

const NIVELES_CADENA_DOCUMENTOS = [
  { clave: 'depositario', titulo: 'Documento del depositario' },
  { clave: 'predio', titulo: 'Predio' },
  { clave: 'contratoDeposito', titulo: 'Contrato de depósito' },
  { clave: 'unidad', titulo: 'Unidad de negocio' },
  { clave: 'contratoArriendo', titulo: 'Contrato de arriendo unidad' },
]

const TIPOS_DOCUMENTO_DEPOSITARIO = new Set([
  'Documento depositante',
  'Identidad',
  'Cédula de ciudadanía',
  'Cédula',
])

const TIPOS_DOCUMENTO_PREDIO = new Set([
  'Certificado de tradición',
  'Tradición',
  'Escritura',
  'Fotografías',
  'Impuesto predial',
  'Servicios públicos',
  'Inventario',
])

const TIPOS_DOCUMENTO_CONTRATO_DEPOSITO = new Set(['Contrato de administración', 'Contrato'])

const construirContextoCadenaContratoDeposito = ({
  contrato,
  contratosDeposito = [],
  propietarios = [],
  predios = [],
  unidadesNegocio = [],
  contratosArriendo = [],
}) => {
  if (!contrato) return null

  const codigoPredio = contrato.codigoPredio || ''
  const predio = (predios || []).find((item) => item.codigo === codigoPredio) || null
  const depositante =
    resolverDepositanteDesdeContrato(contrato, propietarios) ||
    obtenerDepositantePorId(obtenerIdDepositanteContrato(contrato), propietarios)
  const numeroContrato = obtenerNumeroContratoDepositoVisible(contrato, contratosDeposito)
  const unidades = (unidadesNegocio || []).filter((item) => item.codigoPredio === codigoPredio)
  const arriendos = (contratosArriendo || []).filter((item) => item.codigoPredio === codigoPredio)

  return {
    contrato,
    contratoDepositoId: contrato.id,
    codigoPredio,
    predio,
    depositante,
    numeroContrato,
    unidades,
    arriendos,
    idsArriendo: new Set(arriendos.map((item) => obtenerIdContrato(item)).filter(Boolean)),
    idsUnidad: new Set(unidades.map((item) => item.id)),
    idDepositante: depositante?.id || obtenerIdDepositanteContrato(contrato),
  }
}

const clasificarDocumentoCadenaOrganizacional = (documento, contexto) => {
  if (!documento || !contexto) return null
  if (documento.nivelCadenaOrganizacional) return documento.nivelCadenaOrganizacional

  const { contrato, codigoPredio, idDepositante, idsArriendo, idsUnidad, numeroContrato } =
    contexto

  if (documento.idContrato && idsArriendo.has(documento.idContrato)) return 'contratoArriendo'
  if (documento.idUnidad && idsUnidad.has(documento.idUnidad)) return 'unidad'

  const enContratoDeposito =
    documento.idContratoDeposito === contrato.id ||
    (numeroContrato && documento.numeroContratoDeposito === numeroContrato)

  if (documento.tipo === 'Documento depositante') return 'depositario'

  if (TIPOS_DOCUMENTO_CONTRATO_DEPOSITO.has(documento.tipo) && enContratoDeposito) {
    return 'contratoDeposito'
  }

  if (
    TIPOS_DOCUMENTO_DEPOSITARIO.has(documento.tipo) &&
    (documento.idPropietario === idDepositante || enContratoDeposito)
  ) {
    return 'depositario'
  }

  if (codigoPredio && documento.codigoPredio === codigoPredio) {
    if (TIPOS_DOCUMENTO_PREDIO.has(documento.tipo)) return 'predio'
    if (!documento.idContrato && !documento.idContratoDeposito) return 'predio'
    if (enContratoDeposito && documento.tipo === 'Certificado de tradición') return 'predio'
  }

  if (enContratoDeposito) {
    return TIPOS_DOCUMENTO_DEPOSITARIO.has(documento.tipo) ? 'depositario' : 'contratoDeposito'
  }

  return null
}

const documentoPerteneceCadenaContratoDeposito = (documento, contexto) =>
  Boolean(clasificarDocumentoCadenaOrganizacional(documento, contexto))

const obtenerDocumentosAgrupadosCadenaContratoDeposito = ({
  contrato,
  documentos = [],
  contratosDeposito = [],
  propietarios = [],
  predios = [],
  unidadesNegocio = [],
  contratosArriendo = [],
}) => {
  const contexto = construirContextoCadenaContratoDeposito({
    contrato,
    contratosDeposito,
    propietarios,
    predios,
    unidadesNegocio,
    contratosArriendo,
  })

  if (!contexto) {
    return NIVELES_CADENA_DOCUMENTOS.map((nivel, index) => ({
      ...nivel,
      orden: index + 1,
      documentos: [],
      subgrupos: [],
    }))
  }

  const agrupados = Object.fromEntries(
    NIVELES_CADENA_DOCUMENTOS.map((nivel) => [nivel.clave, []])
  )

  ;(documentos || []).forEach((documento) => {
    const nivel = clasificarDocumentoCadenaOrganizacional(documento, contexto)
    if (nivel && agrupados[nivel]) agrupados[nivel].push(documento)
  })

  const ordenarPorFecha = (lista) =>
    [...lista].sort(
      (a, b) => new Date(b.fechaCarga || 0).getTime() - new Date(a.fechaCarga || 0).getTime()
    )

  return NIVELES_CADENA_DOCUMENTOS.map((nivel, index) => {
    const documentosNivel = ordenarPorFecha(agrupados[nivel.clave])
    let subgrupos = []

    if (nivel.clave === 'unidad') {
      subgrupos = contexto.unidades.map((unidad) => ({
        referencia: unidad.nombre || unidad.id,
        documentos: ordenarPorFecha(
          documentosNivel.filter(
            (documento) =>
              documento.idUnidad === unidad.id ||
              String(documento.descripcion || '').includes(unidad.id)
          )
        ),
      }))
      const idsAsignados = new Set(
        subgrupos.flatMap((grupo) => grupo.documentos.map((documento) => documento.id))
      )
      const sueltos = documentosNivel.filter((documento) => !idsAsignados.has(documento.id))
      if (sueltos.length) {
        subgrupos.push({ referencia: 'Documentos generales de unidades', documentos: sueltos })
      }
    }

    if (nivel.clave === 'contratoArriendo') {
      subgrupos = contexto.arriendos.map((contratoArriendo) => {
        const idContrato = obtenerIdContrato(contratoArriendo)
        return {
          referencia: obtenerNumeroContratoVisible(
            contratoArriendo,
            predios,
            contratosArriendo
          ),
          documentos: ordenarPorFecha(
            documentosNivel.filter((documento) => documento.idContrato === idContrato)
          ),
        }
      })
    }

    return {
      ...nivel,
      orden: index + 1,
      documentos: documentosNivel,
      subgrupos,
      referenciaCadena:
        nivel.clave === 'depositario'
          ? obtenerDocumentoDepositarioVisible(contexto.depositante, contexto.contrato)
          : nivel.clave === 'predio'
          ? contexto.codigoPredio || 'Sin predio'
          : nivel.clave === 'contratoDeposito'
          ? contexto.numeroContrato
          : '',
    }
  })
}

const construirCatalogoExtractosPredio = ({
  codigoPredio,
  contratosDeposito = [],
  contratosArriendo = [],
  extractosPredialesSeguimiento = [],
  extractosArriendo = [],
  extractosAdministracion = [],
  extractosServiciosPublicos = [],
  liquidacionesDepositoHistorial = [],
  pagosLiquidacionDeposito = [],
  pagosArriendo = [],
  predios = [],
  propietarios = [],
  predioPropietarios = [],
  incrementosArriendo = [],
  ajustesAdministracion = [],
  gestionesCartera = [],
  unidadesNegocio = [],
  facturasServiciosPublicos = [],
  pagosServiciosPublicos = [],
}) => {
  if (!codigoPredio) return []

  const reportes = []

  if (predioRequiereInformacionPredial(codigoPredio, contratosDeposito)) {
    const extractoPredial = extractosPredialesSeguimiento.find(
      (item) => item.predio?.codigo === codigoPredio
    )
    if (extractoPredial) {
      reportes.push({
        id: `predial-${codigoPredio}`,
        tipo: 'predial',
        titulo: 'Estado de cuenta predial',
        detalle: extractoPredial.resumen?.estadoGeneral || 'Predial',
        codigoPredio,
      })
    }
  }

  extractosArriendo
    .filter((item) => item.contrato?.codigoPredio === codigoPredio)
    .forEach((extracto) => {
      const idContrato = obtenerIdContrato(extracto.contrato)
      reportes.push({
        id: `arriendo-${idContrato}`,
        tipo: 'arriendo',
        titulo: 'Estado de cuenta de arrendamiento',
        detalle: `${extracto.contrato.nombreUnidad || extracto.contrato.idUnidad} · ${extracto.contrato.arrendatario}`,
        saldoDeudaTotal: Number(extracto.resumen?.saldoDeudaTotal || 0),
        idContrato,
        codigoPredio,
      })
    })

  extractosAdministracion
    .filter((item) => item.contrato?.codigoPredio === codigoPredio)
    .forEach((extracto) => {
      const idContrato = obtenerIdContrato(extracto.contrato)
      reportes.push({
        id: `admin-${idContrato}`,
        tipo: 'administracion',
        titulo: 'Estado de cuenta de administración',
        detalle: `${extracto.contrato.nombreUnidad || ''} · ${extracto.resumen?.estadoGeneral || ''}`,
        idContrato,
        codigoPredio,
      })
    })

  extractosServiciosPublicos
    .filter((item) => item.unidad?.codigoPredio === codigoPredio)
    .forEach((extracto) => {
      reportes.push({
        id: `servicio-${extracto.unidad.id}::${extracto.idServicio}`,
        tipo: 'servicios',
        titulo: 'Estado de cuenta de servicios',
        detalle: `${extracto.unidad.nombre} · ${extracto.servicio.tipo} · ${extracto.servicio.empresa || ''}`,
        claveServicio: `${extracto.unidad.id}::${extracto.idServicio}`,
        codigoPredio,
      })
    })

  contratosArriendo
    .filter((contrato) => contrato.codigoPredio === codigoPredio)
    .forEach((contrato) => {
      const idContrato = obtenerIdContrato(contrato)
      const extractosLiquidacion = construirExtractosLiquidacionDepositoUnidad({
        idContratoArriendo: idContrato,
        liquidacionesDepositoHistorial,
        pagosLiquidacionDeposito,
        pagosArriendo,
        contratosArriendo,
        contratosDeposito,
        predios,
        propietarios,
        predioPropietarios,
        unidadesNegocio,
        facturasServiciosPublicos,
        pagosServiciosPublicos,
        incrementosArriendo,
        ajustesAdministracion,
        gestionesCartera,
      })

      if (extractosLiquidacion.length) {
        reportes.push({
          id: `liquidacion-${idContrato}`,
          tipo: 'liquidacion',
          titulo: 'Liquidación al depositario',
          detalle: `${contrato.nombreUnidad || contrato.idUnidad} · ${extractosLiquidacion.length} beneficiario(s)`,
          idContrato,
          codigoPredio,
        })
      }
    })

  return reportes
}

const resolverContratoDepositoConsultaDocumentos = (
  entidad,
  contratosDeposito = [],
  predios = []
) => {
  if (!entidad) return null

  if (entidad.tipo === 'contratoDeposito') {
    return (
      (contratosDeposito || []).find((item) => item.id === entidad.contratoDepositoId) || null
    )
  }

  if (entidad.tipo === 'predio' && entidad.codigoPredio) {
    return (
      (contratosDeposito || []).find(
        (item) =>
          item.codigoPredio === entidad.codigoPredio ||
          predios.find((predio) => predio.codigo === entidad.codigoPredio)?.idDocumento ===
            item.id
      ) || null
    )
  }

  if (entidad.tipo === 'contratoArriendo' && entidad.codigoPredio) {
    return (contratosDeposito || []).find((item) => item.codigoPredio === entidad.codigoPredio) || null
  }

  return null
}

const agregarContratoDepositoOpcionConsulta = (
  opciones,
  claves,
  contrato,
  contratosDeposito,
  propietarios,
  descripcionExtra = ''
) => {
  if (!contrato) return
  agregarOpcionConsultaDocumento(
    opciones,
    claves,
    crearOpcionContratoDeposito(contrato, contratosDeposito, propietarios, descripcionExtra)
  )
}

const migrarModeloPropietarios = (propietariosLista, predioPropietariosLista) => {
  if (Array.isArray(predioPropietariosLista) && predioPropietariosLista.length > 0) {
    return {
      propietarios: (propietariosLista || []).map((propietario) => ({
        id: propietario.id || generarIdPropietario(),
        nombre: propietario.nombre || '',
        tipoPersona: propietario.tipoPersona || 'Persona natural',
        tipoDocumento: propietario.tipoDocumento || '',
        numeroDocumento: (propietario.numeroDocumento || '').trim(),
        telefono: propietario.telefono || '',
        whatsapp: propietario.whatsapp || '',
        correo: propietario.correo || '',
        direccion: propietario.direccion || '',
        esDepositante: !!propietario.esDepositante,
        rolDepositante: propietario.rolDepositante || '',
        idRepresentanteLegal: propietario.idRepresentanteLegal || '',
      })),
      predioPropietarios: predioPropietariosLista,
    }
  }

  const maestro = new Map()
  const relaciones = []

  ;(propietariosLista || []).forEach((propietario) => {
    const docKey = `${propietario.tipoDocumento || ''}|${(propietario.numeroDocumento || '').trim()}`
    let id = propietario.id

    if (!id) {
      if (docKey !== '|' && maestro.has(docKey)) {
        id = maestro.get(docKey).id
      } else {
        id = generarIdPropietario()
        maestro.set(docKey, {
          id,
          nombre: propietario.nombre || '',
          tipoDocumento: propietario.tipoDocumento || '',
          numeroDocumento: (propietario.numeroDocumento || '').trim(),
          telefono: propietario.telefono || '',
          whatsapp: propietario.whatsapp || '',
          correo: propietario.correo || '',
          direccion: propietario.direccion || '',
        })
      }
    } else if (!maestro.has(id)) {
      maestro.set(id, {
        id,
        nombre: propietario.nombre || '',
        tipoDocumento: propietario.tipoDocumento || '',
        numeroDocumento: (propietario.numeroDocumento || '').trim(),
        telefono: propietario.telefono || '',
        whatsapp: propietario.whatsapp || '',
        correo: propietario.correo || '',
        direccion: propietario.direccion || '',
      })
    }

    if (propietario.codigoPredio) {
      relaciones.push({
        codigoPredio: propietario.codigoPredio,
        idPropietario: id,
        porcentaje: Number(propietario.porcentaje || 0),
        fechaInicio: propietario.fechaInicio || new Date().toISOString().slice(0, 10),
      })
    }
  })

  return {
    propietarios: Array.from(maestro.values()),
    predioPropietarios: relaciones,
  }
}

const obtenerPagosDetalleMovimientoArriendo = (movimiento) => {
  if (Array.isArray(movimiento?.pagosDetalle) && movimiento.pagosDetalle.length > 0) {
    return movimiento.pagosDetalle
  }

  if (Number(movimiento?.pagado || 0) > 0) {
    return [
      {
        fechaPago: movimiento.fechaPago,
        recibo: movimiento.recibo,
        valorPagado: Number(movimiento.pagado || 0),
        concepto: '',
      },
    ]
  }

  return []
}

const ordenarPagosArriendoCronologico = (pagos = []) =>
  pagos
    .slice()
    .sort((a, b) => {
      const fechaA = a.fechaPago || ''
      const fechaB = b.fechaPago || ''
      if (fechaA !== fechaB) return fechaA.localeCompare(fechaB)
      return String(a.id || a.recibo || '').localeCompare(String(b.id || b.recibo || ''))
    })

const obtenerImpactoSaldoFila = (item) => {
  if (item.valorMovimiento !== undefined && item.valorMovimiento !== null) {
    return Number(item.valorMovimiento)
  }
  if (item.tipo === 'cargo') return Number(item.valor || 0)
  if (item.tipo === 'pago' || item.tipo === 'descuento') {
    return -Number(item.descuento || 0)
  }
  return 0
}

const formatearValorMovimientoExtracto = (item, formatearDinero) => {
  const impacto = obtenerImpactoSaldoFila(item)
  if (!impacto) return '$ 0'
  const monto = formatearDinero(Math.abs(impacto))
  return impacto < 0 ? `- ${monto}` : monto
}

const etiquetaDocumentoEstadoCuentaPredial = (tipoDocumento) => {
  const texto = String(tipoDocumento || '').trim()
  if (/^c[eé]dula de ciudadan[ií]a$/i.test(texto)) return 'ID'
  return texto || 'Doc.'
}

const formatearDocumentoPropietarioExtractoPredial = (propietario) => {
  const etiqueta = etiquetaDocumentoEstadoCuentaPredial(propietario?.tipoDocumento)
  const numero = String(propietario?.numeroDocumento || '').trim()
  return numero ? `${etiqueta} ${numero}` : etiqueta
}

// =============================================================================
// ARRIENDOS - FILAS ESTADO DE CUENTA
// Movimientos, mora y saldos por mes en arriendo.
// =============================================================================

const construirFilasEstadoCuentaArriendo = (contrato, movimientos, fechaCorte = '') => {
  const fechaCorteEfectiva = fechaCorte || new Date().toISOString().slice(0, 10)

  return movimientos
    .slice()
    .sort((a, b) => a.mes.localeCompare(b.mes))
    .flatMap((movimiento) => {
      const fechaVencimiento =
        obtenerFechaVencimientoMesArriendo(movimiento.mes, contrato) ||
        `${movimiento.mes}-05`
      const filas = []
      const pagosDetalleLiquidacion = movimiento?.pagosDetalleLiquidacionArriendo || []
      const fechaCortePeriodo = obtenerFechaCorteLiquidacionPeriodoArriendo(
        pagosDetalleLiquidacion,
        fechaCorteEfectiva
      )
      const movimientoParaCargos = {
        ...movimiento,
        pagosLiquidacionArriendoMes: [],
        pagosMes: [],
        pagado: 0,
        totalPagadoLiquidacionArriendo: 0,
      }
      const liquidacion = calcularCargosLiquidadosPeriodoExtractoArriendo({
        contrato,
        movimiento: movimientoParaCargos,
        fechaCorte: fechaCortePeriodo,
      })
      const {
        moraContrato,
        moraGestion,
        fechaMora,
        sancionCobranza,
        ivaCanonMes,
        ivaMora,
        ivaGastosCobranza,
        rangoFechasMora,
        porcentajeGastosCobranza,
        porcentajeInteresMora,
        aplicaIva,
      } = liquidacion
      const sufijoRangoMora = rangoFechasMora ? ` (${rangoFechasMora})` : ''
      const agregarCargo = (detalle, valor, fecha = fechaVencimiento) => {
        filas.push({
          mes: movimiento.mes,
          fecha,
          detalle,
          valorMovimiento: Number(valor || 0),
          tipo: 'cargo',
        })
      }

      agregarCargo(
        `Canon de arriendo periodo ${movimiento.mes}`,
        movimiento.canonBase
      )

      if (aplicaIva) {
        agregarCargo(`IVA canon periodo ${movimiento.mes}`, ivaCanonMes)
      }

      agregarCargo(
        `Intereses de mora periodo ${movimiento.mes} (${porcentajeInteresMora}% mensual${sufijoRangoMora})`,
        moraContrato,
        fechaMora
      )

      if (moraGestion > 0) {
        agregarCargo(
          `Intereses de mora (gestión) periodo ${movimiento.mes}${sufijoRangoMora}`,
          moraGestion,
          fechaMora
        )
      }

      if (aplicaIva) {
        agregarCargo(`IVA intereses de mora periodo ${movimiento.mes}`, ivaMora, fechaMora)
      }

      agregarCargo(
        `Gastos de cobranza periodo ${movimiento.mes} (${porcentajeGastosCobranza}% sobre canon de arriendo)`,
        sancionCobranza,
        fechaMora
      )

      if (aplicaIva) {
        agregarCargo(
          `IVA gastos de cobranza periodo ${movimiento.mes}`,
          ivaGastosCobranza,
          fechaMora
        )
      }

      if (Number(movimiento.descuento || 0) > 0) {
        filas.push({
          mes: movimiento.mes,
          fecha:
            movimiento.fechaPago && movimiento.fechaPago !== 'Sin pago'
              ? movimiento.fechaPago
              : fechaVencimiento,
          detalle: `Descuento aplicado periodo ${movimiento.mes}`,
          valorMovimiento: -Number(movimiento.descuento || 0),
          tipo: 'descuento',
        })
      }

      const totalCargosPeriodo = calcularTotalCargosFilasLiquidacionPeriodoArriendo(
        liquidacion,
        movimientoParaCargos
      )
      const totalDescuentoPeriodo = Number(movimiento?.descuento || 0)
      let cupoAbonoPeriodo = Math.max(0, totalCargosPeriodo - totalDescuentoPeriodo)

      pagosDetalleLiquidacion.forEach((pago) => {
        const numeroRecibo =
          pago.recibo && pago.recibo !== 'Sin recibo' ? pago.recibo : 'Sin recibo'
        const conceptoExtra = pago.concepto ? ` - ${pago.concepto}` : ''
        const valorAsignadoCascade = Math.max(0, Number(pago.valorPagado || 0))
        const valorAbono = Math.min(valorAsignadoCascade, cupoAbonoPeriodo)
        cupoAbonoPeriodo = Math.max(0, cupoAbonoPeriodo - valorAbono)
        const periodoLiquidadoTotal = valorAbono > 0 && cupoAbonoPeriodo === 0
        const fechaPago =
          pago.fechaPago && pago.fechaPago !== 'Sin pago' ? pago.fechaPago : fechaVencimiento
        const etiquetaLiquidacion = periodoLiquidadoTotal
          ? ' (periodo liquidado en su totalidad)'
          : valorAbono > 0 && valorAbono < valorAsignadoCascade
          ? ' (abono parcial del periodo)'
          : ''

        if (valorAbono > 0) {
          filas.push({
            mes: movimiento.mes,
            fecha: fechaPago,
            detalle: `Abono arriendo periodo ${movimiento.mes} - Recibo ${numeroRecibo}${conceptoExtra}${etiquetaLiquidacion}`,
            valorMovimiento: -valorAbono,
            tipo: 'pago',
            esAbonoDestacado: true,
          })
        }
      })

      return filas
    })
}

// =============================================================================
// IMPRESION - TABLA ESTADO DE CUENTA ARRIENDO
// Regenera filas con la misma logica de liquidacion que la vista en pantalla.
// =============================================================================

const construirHtmlTablaEstadoCuentaArriendo = ({
  contrato,
  movimientos,
  formatearDinero,
  fechaCorte,
  estadoCartera,
  extracto,
}) => {
  const filasEstadoCuenta = construirFilasEstadoCuentaArriendo(
    contrato,
    movimientos,
    fechaCorte
  )
  const extractoReferencia =
    extracto || (movimientos ? { contrato, movimientos, resumen: {} } : null)
  const marcarSaldoAtraso = esSaldoEnAtraso({
    estadoCartera,
    extracto: extractoReferencia,
    fechaCorte,
  })
  const filasConSaldo = acumularSaldoFilasEstadoCuenta(filasEstadoCuenta)
  const saldoAcumuladoTabla = filasConSaldo.length
    ? Number(filasConSaldo[filasConSaldo.length - 1].saldoAcumulado || 0)
    : 0
  const saldoLiquidacionPeriodos = calcularSaldoDeudaLiquidacionArriendoContrato({
    contrato,
    movimientos,
    fechaCorte,
  })
  const saldoTotalArrendatario = filasConSaldo.length
    ? saldoAcumuladoTabla
    : Number(extracto?.resumen?.saldoDeudaTotal ?? saldoLiquidacionPeriodos)

  const filasHtml = filasConSaldo
    .map((item) => {
      const claseAbono = item.esAbonoDestacado ? ' class="fila-abono-arriendo"' : ''
      const claseSaldo =
        item.saldoAcumulado > 0 && marcarSaldoAtraso ? ' saldo-atraso' : ''

      return `<tr${claseAbono}>
        <td>${escapeHtml(item.mes || '—')}</td>
        <td>${escapeHtml(item.fecha)}</td>
        <td>${escapeHtml(item.detalle)}</td>
        <td class="col-monto-predial col-valor-arriendo">${escapeHtml(
          formatearValorMovimientoExtracto(item, formatearDinero)
        )}</td>
        <td class="col-monto-predial col-saldo-arriendo${claseSaldo}">${escapeHtml(
          formatearDinero(item.saldoAcumulado)
        )}</td>
      </tr>`
    })
    .join('')

  const pieSaldoClase =
    saldoTotalArrendatario > 0 && marcarSaldoAtraso ? ' saldo-atraso' : ''
  const pieHtml = `<tr>
    <td colspan="3"><strong>Saldo total adeudado del arrendatario</strong></td>
    <td></td>
    <td class="col-monto-predial col-saldo-arriendo${pieSaldoClase}"><strong>${escapeHtml(
      formatearDinero(saldoTotalArrendatario)
    )}</strong></td>
  </tr>`

  return { filasHtml, pieHtml }
}

// =============================================================================
// IMPRESION - SINCRONIZAR TABLA ARRIENDO
// Actualiza la tabla del extracto antes de imprimir con liquidacion y abonos en cascada.
// =============================================================================

const aplicarTablaEstadoCuentaArriendoImpresion = (
  contenedor,
  formatearDinero,
  opciones = {}
) => {
  if (!contenedor || !formatearDinero) return false

  const tabla = contenedor.querySelector('.extracto-table-arriendo')
  const datosNode = contenedor.querySelector('.extracto-arriendo-impresion-datos')
  if (!tabla || !datosNode) return false

  let datos = {}
  try {
    datos = JSON.parse(datosNode.textContent || '{}')
  } catch {
    return false
  }

  const contrato = opciones.contrato || datos.contrato
  const movimientos = opciones.movimientos || datos.movimientos
  if (!contrato || !movimientos) return false

  const { filasHtml, pieHtml } = construirHtmlTablaEstadoCuentaArriendo({
    contrato,
    movimientos,
    formatearDinero,
    fechaCorte: opciones.fechaCorte ?? datos.fechaCorte ?? '',
    estadoCartera: opciones.estadoCartera ?? datos.estadoCartera,
    extracto: {
      contrato,
      movimientos,
      resumen: opciones.resumen ?? datos.resumen ?? {},
    },
  })

  const tbody = tabla.querySelector('tbody')
  const tfoot = tabla.querySelector('tfoot')
  if (tbody) tbody.innerHTML = filasHtml
  if (tfoot) tfoot.innerHTML = pieHtml

  return true
}

// =============================================================================
// ARRIENDOS - FILAS DE EXTRACTO
// Detalle de cargos y abonos para extracto de arriendo.
// =============================================================================

const generarFilasExtractoArriendo = (movimiento) => {
  const pagosDetalle = obtenerPagosDetalleMovimientoArriendo(movimiento)

  if (pagosDetalle.length <= 1) {
    const pago = pagosDetalle[0]
    return [
      {
        key: `${movimiento.mes}-resumen`,
        mes: movimiento.mes,
        fechaPago: pago?.fechaPago || movimiento.fechaPago,
        recibo: pago?.recibo || movimiento.recibo,
        pagado: Number(pago?.valorPagado ?? movimiento.pagado ?? 0),
        mostrarCanon: true,
        saldoDeuda: movimiento.saldoDeuda,
        estadoMovimiento: movimiento.estadoMovimiento,
        movimiento,
      },
    ]
  }

  return [
    {
      key: `${movimiento.mes}-causacion`,
      mes: movimiento.mes,
      fechaPago: '—',
      recibo: '—',
      pagado: 0,
      mostrarCanon: true,
      saldoDeuda: null,
      estadoMovimiento: '',
      movimiento,
    },
    ...pagosDetalle.map((pago, indice) => ({
      key: `${movimiento.mes}-pago-${pago.id || pago.recibo || indice}`,
      mes: '',
      fechaPago: pago.fechaPago || 'Sin pago',
      recibo: pago.recibo || 'Sin recibo',
      pagado: Number(pago.valorPagado || 0),
      mostrarCanon: false,
      saldoDeuda: indice === pagosDetalle.length - 1 ? movimiento.saldoDeuda : null,
      estadoMovimiento:
        indice === pagosDetalle.length - 1 ? movimiento.estadoMovimiento : '',
      movimiento,
    })),
  ]
}

const obtenerContratoActivoUnidad = (idUnidad, contratos, codigoPredio = '') =>
  contratos.find(
    (contrato) =>
      contrato.idUnidad === idUnidad &&
      contrato.estado === 'Activo' &&
      (!codigoPredio || contrato.codigoPredio === codigoPredio)
  )

const obtenerPredioDeUnidad = (unidad, predios = []) =>
  predios.find((predio) => predio.codigo === unidad?.codigoPredio) || null

const unidadDisponibleSinContratoArriendo = (unidad, contratosArriendo = []) => {
  if (!unidad) return false
  const estado = String(unidad.estado || '').trim()
  if (estado && estado !== 'Disponible') return false
  return !obtenerContratoActivoUnidad(
    unidad.id,
    contratosArriendo,
    unidad.codigoPredio
  )
}

const construirFilaUnidadDisponible = (unidad, predios = []) => {
  const predio = obtenerPredioDeUnidad(unidad, predios)
  return {
    unidad,
    predio,
    ciudad: predio?.ciudad || 'Sin ciudad',
    barrio: predio?.barrio || 'Sin barrio',
    direccion: predio?.direccion || '',
  }
}

const filtrarUnidadesDisponiblesConsulta = ({
  unidadesNegocio = [],
  contratosArriendo = [],
  predios = [],
  ciudad = '',
  barrio = '',
  tipoUnidad = '',
}) => {
  const ciudadNorm = normalizarTexto(ciudad || '')
  const barrioNorm = normalizarTexto(barrio || '')
  const tipoLimpio = String(tipoUnidad || '').trim()

  return unidadesNegocio
    .filter((unidad) => unidadDisponibleSinContratoArriendo(unidad, contratosArriendo))
    .map((unidad) => construirFilaUnidadDisponible(unidad, predios))
    .filter((fila) => {
      if (ciudadNorm && normalizarTexto(fila.ciudad) !== ciudadNorm) return false
      if (barrioNorm && normalizarTexto(fila.barrio) !== barrioNorm) return false
      if (tipoLimpio && String(fila.unidad.tipo || '').trim() !== tipoLimpio) return false
      return true
    })
    .sort((a, b) => {
      const porCiudad = String(a.ciudad).localeCompare(String(b.ciudad), 'es')
      if (porCiudad !== 0) return porCiudad
      const porBarrio = String(a.barrio).localeCompare(String(b.barrio), 'es')
      if (porBarrio !== 0) return porBarrio
      return String(a.unidad.nombre || '').localeCompare(String(b.unidad.nombre || ''), 'es')
    })
}

const obtenerCatalogoUnidadesDisponibles = ({
  unidadesNegocio = [],
  contratosArriendo = [],
  predios = [],
  ciudadSeleccionada = '',
}) => {
  const filas = unidadesNegocio
    .filter((unidad) => unidadDisponibleSinContratoArriendo(unidad, contratosArriendo))
    .map((unidad) => construirFilaUnidadDisponible(unidad, predios))

  const ciudades = [
    ...new Set(filas.map((fila) => fila.ciudad).filter((valor) => valor && valor !== 'Sin ciudad')),
  ].sort((a, b) => a.localeCompare(b, 'es'))

  const ciudadNorm = normalizarTexto(ciudadSeleccionada || '')
  const barrios = [
    ...new Set(
      filas
        .filter((fila) => !ciudadNorm || normalizarTexto(fila.ciudad) === ciudadNorm)
        .map((fila) => fila.barrio)
        .filter((valor) => valor && valor !== 'Sin barrio')
    ),
  ].sort((a, b) => a.localeCompare(b, 'es'))

  const tipos = [...new Set(filas.map((fila) => fila.unidad.tipo).filter(Boolean))].sort((a, b) =>
    a.localeCompare(b, 'es')
  )

  return { ciudades, barrios, tipos }
}

const obtenerResumenServiciosPublicosUnidad = (unidad, extractosServicios) => {
  const extractosUnidad = extractosServicios.filter((extracto) =>
    coincideUnidadNegocio(extracto.unidad, unidad)
  )

  if (extractosUnidad.length === 0) {
    return {
      tieneServicios: false,
      estadoServicios: 'Sin servicios',
      saldoTotal: 0,
      totalCausado: 0,
      totalPagado: 0,
      cantidadServicios: 0,
      extractos: [],
    }
  }

  const saldoTotal = extractosUnidad.reduce(
    (total, extracto) => total + Number(extracto.resumen.saldoDeudaTotal || 0),
    0
  )
  const totalCausado = extractosUnidad.reduce(
    (total, extracto) => total + Number(extracto.resumen.totalCausado || 0),
    0
  )
  const totalPagado = extractosUnidad.reduce(
    (total, extracto) => total + Number(extracto.resumen.totalPagado || 0),
    0
  )

  const sinContrato = extractosUnidad.some((extracto) => extracto.sinContratoActivo)

  let estadoServicios = 'Al día'
  if (sinContrato) estadoServicios = 'Sin contrato'
  else if (saldoTotal > 0) estadoServicios = 'Con deuda'

  return {
    tieneServicios: true,
    estadoServicios,
    saldoTotal,
    totalCausado,
    totalPagado,
    cantidadServicios: extractosUnidad.length,
    extractos: extractosUnidad,
  }
}

const obtenerClaseEstadoServiciosPublicos = (estadoServicios) => {
  if (estadoServicios === 'Al día') return 'status active'
  if (estadoServicios === 'Con deuda') return 'status inactive'
  if (estadoServicios === 'Sin contrato') return 'status warning'
  return 'status warning'
}

const construirFacturasCobroFijoFaltantes = (
  unidades,
  contratos,
  facturasActuales
) => {
  const nuevasFacturas = []

  unidades.forEach((unidad) => {
    ;(unidad.serviciosPublicos || []).forEach((servicio, index) => {
      if (servicio.tipoCobro !== 'Valor fijo mensual') return
      if (!Number(servicio.valorFijo || 0)) return

      const contratoActivo = obtenerContratoActivoUnidad(unidad.id, contratos, unidad.codigoPredio)
      if (!contratoActivo?.fechaInicio) return

      const idServicio = generarIdServicioUnidad(unidad, index)
      const meses = generarMesesRango(
        contratoActivo.fechaInicio,
        contratoActivo.fechaFin || null
      )
      const diaPago = String(servicio.diaPago || 1).padStart(2, '0')

      meses.forEach((mes) => {
        const existeFactura = facturasActuales.some((factura) =>
          facturaPerteneceAUnidadServicio(factura, unidad, index, idServicio) &&
          factura.periodo === mes
        )

        if (existeFactura) return

        nuevasFacturas.push({
          id: `FAC-SER-FIJO-${unidad.id}-${index}-${mes}`,
          idUnidad: unidad.id,
          codigoPredio: unidad.codigoPredio,
          nombreUnidad: unidad.nombre,
          tipoUnidad: unidad.tipo,
          idServicio,
          tipoServicio: servicio.tipo,
          empresa: servicio.empresa,
          numeroCuenta: servicio.numeroCuenta,
          responsable: servicio.responsable,
          tipoCobro: servicio.tipoCobro,
          generaReciboIndependiente: servicio.generaReciboIndependiente,
          periodo: mes,
          valorFactura: Number(servicio.valorFijo || 0),
          fechaLimite: `${mes}-${diaPago}`,
          numeroFactura: 'COBRO-FIJO',
          observacion:
            'Factura generada automáticamente por cobro fijo mensual desde inicio del contrato',
          estado: 'Pendiente',
        })
      })
    })
  })

  return nuevasFacturas
}

const aplicarFacturasCobroFijoFaltantes = (
  unidades,
  contratos,
  facturasActuales = []
) => {
  const nuevasFacturas = construirFacturasCobroFijoFaltantes(
    unidades,
    contratos,
    facturasActuales
  )
  if (nuevasFacturas.length === 0) return facturasActuales
  return [...nuevasFacturas, ...facturasActuales]
}

const generarMesesRango = (fechaInicio, fechaFin = null) => {
  if (!fechaInicio) return []

  const meses = []
  const fechaInicioDate = new Date(`${fechaInicio}T00:00:00`)
  const fechaFinDate = fechaFin ? new Date(`${fechaFin}T00:00:00`) : new Date()
  const hoy = new Date()
  hoy.setHours(0, 0, 0, 0)

  const fechaFinal = fechaFinDate < hoy ? fechaFinDate : hoy

  let anio = fechaInicioDate.getFullYear()
  let mes = fechaInicioDate.getMonth()
  const anioFinal = fechaFinal.getFullYear()
  const mesFinal = fechaFinal.getMonth()

  while (anio < anioFinal || (anio === anioFinal && mes <= mesFinal)) {
    meses.push(`${anio}-${String(mes + 1).padStart(2, '0')}`)
    mes += 1
    if (mes > 11) {
      mes = 0
      anio += 1
    }
  }

  return meses
}

const obtenerMesActualServicios = (fechaReferencia = new Date()) =>
  `${fechaReferencia.getFullYear()}-${String(fechaReferencia.getMonth() + 1).padStart(2, '0')}`

const construirServiciosPublicosSinActualizarMes = (
  unidadesNegocio = [],
  contratosArriendo = [],
  facturasServiciosPublicos = [],
  mesReferencia = null
) => {
  const mesActual = mesReferencia || obtenerMesActualServicios()
  const resultados = []

  unidadesNegocio.forEach((unidad) => {
    ;(unidad.serviciosPublicos || []).forEach((servicio, index) => {
      const idServicio = generarIdServicioUnidad(unidad, index)
      const contratoActivo = obtenerContratoActivoUnidad(
        unidad.id,
        contratosArriendo,
        unidad.codigoPredio
      )

      const mesesContrato = contratoActivo?.fechaInicio
        ? generarMesesRango(
            contratoActivo.fechaInicio,
            contratoActivo.fechaFin || null
          )
        : []

      const mesesEvaluar = mesesContrato.length > 0 ? mesesContrato : [mesActual]

      mesesEvaluar.forEach((periodo) => {
        const contratoVigenteMes =
          mesesContrato.length > 0 && mesesContrato.includes(periodo)

        const tieneFacturaMes = facturasServiciosPublicos.some(
          (factura) =>
            facturaPerteneceAUnidadServicio(factura, unidad, index, idServicio) &&
            factura.periodo === periodo
        )

        if (tieneFacturaMes) return

        const itemBase = {
          idUnidad: unidad.id,
          nombreUnidad: unidad.nombre,
          tipoUnidad: unidad.tipo || 'Sin tipo',
          codigoPredio: unidad.codigoPredio,
          idServicio,
          tipoServicio: servicio.tipo,
          empresa: servicio.empresa,
          numeroCuenta: servicio.numeroCuenta,
          responsable: servicio.responsable,
          tipoCobro: servicio.tipoCobro,
          periodo,
          diaPago: servicio.diaPago,
          valorReferencia:
            servicio.tipoCobro === 'Valor fijo mensual'
              ? Number(servicio.valorFijo || 0)
              : null,
          unidad,
          servicio,
          sinContratoActivo: !contratoVigenteMes,
        }

        if (servicio.tipoCobro === 'Valor fijo mensual') {
          if (!contratoVigenteMes && Number(servicio.valorFijo || 0) > 0) {
            resultados.push(itemBase)
          }
          return
        }

        resultados.push(itemBase)
      })
    })
  })

  return resultados.sort((a, b) => {
    const porPredio = String(a.codigoPredio || '').localeCompare(String(b.codigoPredio || ''))
    if (porPredio !== 0) return porPredio
    const porUnidad = String(a.nombreUnidad || '').localeCompare(String(b.nombreUnidad || ''))
    if (porUnidad !== 0) return porUnidad
    const porServicio = String(a.tipoServicio || '').localeCompare(String(b.tipoServicio || ''))
    if (porServicio !== 0) return porServicio
    return String(a.periodo || '').localeCompare(String(b.periodo || ''))
  })
}

const construirServiciosPublicosPendientesPagoMes = (
  unidadesNegocio = [],
  contratosArriendo = [],
  facturasServiciosPublicos = [],
  pagosServiciosPublicos = [],
  mesReferencia = null
) => {
  const resultados = []

  unidadesNegocio.forEach((unidad) => {
    ;(unidad.serviciosPublicos || []).forEach((servicio, index) => {
      const idServicio = generarIdServicioUnidad(unidad, index)
      const contratoActivo = obtenerContratoActivoUnidad(
        unidad.id,
        contratosArriendo,
        unidad.codigoPredio
      )

      if (!contratoActivo?.fechaInicio) return

      const mesesContrato = generarMesesRango(
        contratoActivo.fechaInicio,
        contratoActivo.fechaFin || null
      )

      mesesContrato.forEach((periodo) => {
        const movimiento = calcularMovimientoServicioMes(
          periodo,
          servicio,
          contextoMovimientoServicioUnidad(unidad, index),
          facturasServiciosPublicos,
          pagosServiciosPublicos
        )

        if (Number(movimiento.saldoDeuda || 0) <= 0) return
        if (movimiento.faltaFactura) return

        resultados.push({
          idUnidad: unidad.id,
          nombreUnidad: unidad.nombre,
          tipoUnidad: unidad.tipo || 'Sin tipo',
          codigoPredio: unidad.codigoPredio,
          idServicio,
          tipoServicio: servicio.tipo,
          empresa: servicio.empresa,
          periodo,
          saldoPendiente: Number(movimiento.saldoDeuda || 0),
          unidad,
          servicio,
        })
      })
    })
  })

  return resultados.sort((a, b) => {
    const porPredio = String(a.codigoPredio || '').localeCompare(String(b.codigoPredio || ''))
    if (porPredio !== 0) return porPredio
    const porUnidad = String(a.nombreUnidad || '').localeCompare(String(b.nombreUnidad || ''))
    if (porUnidad !== 0) return porUnidad
    const porServicio = String(a.tipoServicio || '').localeCompare(String(b.tipoServicio || ''))
    if (porServicio !== 0) return porServicio
    return String(a.periodo || '').localeCompare(String(b.periodo || ''))
  })
}

// =============================================================================
// SERVICIOS PUBLICOS - PENDIENTES Y ALERTAS
// Servicios sin facturar o con saldo pendiente.
// =============================================================================

const construirServiciosPublicosPendientesAlerta = (
  unidadesNegocio = [],
  contratosArriendo = [],
  facturasServiciosPublicos = [],
  pagosServiciosPublicos = [],
  mesReferencia = null
) => {
  const sinActualizar = construirServiciosPublicosSinActualizarMes(
    unidadesNegocio,
    contratosArriendo,
    facturasServiciosPublicos,
    mesReferencia
  )
  const pendientesPago = construirServiciosPublicosPendientesPagoMes(
    unidadesNegocio,
    contratosArriendo,
    facturasServiciosPublicos,
    pagosServiciosPublicos,
    mesReferencia
  )
  const servicios = new Map()

  sinActualizar.forEach((item) => {
    const clave = `${item.idUnidad}::${item.idServicio}::${item.periodo}`
    servicios.set(clave, {
      ...item,
      sinActualizar: true,
      pendientePago: false,
      saldoPendiente: 0,
    })
  })

  pendientesPago.forEach((item) => {
    const clave = `${item.idUnidad}::${item.idServicio}::${item.periodo}`
    const existente = servicios.get(clave)

    if (existente) {
      servicios.set(clave, {
        ...existente,
        pendientePago: true,
        saldoPendiente: item.saldoPendiente,
      })
      return
    }

    servicios.set(clave, {
      ...item,
      sinActualizar: false,
      pendientePago: true,
    })
  })

  return Array.from(servicios.values()).sort((a, b) => {
    const porPredio = String(a.codigoPredio || '').localeCompare(String(b.codigoPredio || ''))
    if (porPredio !== 0) return porPredio
    const porUnidad = String(a.nombreUnidad || '').localeCompare(String(b.nombreUnidad || ''))
    if (porUnidad !== 0) return porUnidad
    const porServicio = String(a.tipoServicio || '').localeCompare(String(b.tipoServicio || ''))
    if (porServicio !== 0) return porServicio
    return String(a.periodo || '').localeCompare(String(b.periodo || ''))
  })
}

const administracionRequiereAjusteAnio = (contrato, anio, ajustesAdministracion = []) => {
  if (!contrato?.fechaInicio) return false

  const anioInicio = Number(contrato.fechaInicio.substring(0, 4))
  if (Number(anio) <= anioInicio) return false

  const idContrato = obtenerIdContrato(contrato)
  const tieneAjuste = (ajustesAdministracion || []).some(
    (ajuste) =>
      ajuste.idContrato === idContrato && Number(ajuste.anio) === Number(anio)
  )

  return !tieneAjuste
}

const construirAdministracionesSinActualizarMes = (
  contratosArriendo = [],
  ajustesAdministracion = [],
  mesReferencia = null
) => {
  const mesActual = mesReferencia || obtenerMesActualServicios()
  const anioMes = Number(mesActual.substring(0, 4))
  const resultados = []

  contratosArriendo.forEach((contrato) => {
    if (!contratoAplicaAdministracion(contrato) || contrato.estado !== 'Activo') return

    const mesesContrato = generarMesesRango(
      contrato.fechaInicio,
      contrato.fechaFin || null
    )

    if (!mesesContrato.includes(mesActual)) return
    if (!administracionRequiereAjusteAnio(contrato, anioMes, ajustesAdministracion)) return

    resultados.push({
      idContrato: obtenerIdContrato(contrato),
      idUnidad: contrato.idUnidad || '',
      nombreUnidad: contrato.nombreUnidad || 'Sin unidad',
      codigoPredio: contrato.codigoPredio,
      arrendatario: contrato.arrendatario || '',
      mes: mesActual,
      anio: anioMes,
      valorReferencia: Number(contrato.valorAdministracion || 0),
      contrato,
    })
  })

  return resultados.sort((a, b) => {
    const porPredio = String(a.codigoPredio || '').localeCompare(String(b.codigoPredio || ''))
    if (porPredio !== 0) return porPredio
    return String(a.nombreUnidad || '').localeCompare(String(b.nombreUnidad || ''))
  })
}

const construirAdministracionesPendientesPagoMes = (
  contratosArriendo = [],
  ajustesAdministracion = [],
  pagosAdministracion = [],
  pagosArriendo = [],
  incrementosArriendo = [],
  mesReferencia = null
) => {
  const resultados = []

  contratosArriendo.forEach((contrato) => {
    if (!contratoAplicaAdministracion(contrato) || contrato.estado !== 'Activo') return
    if (!contrato.fechaInicio) return

    const mesesContrato = generarMesesRango(
      contrato.fechaInicio,
      contrato.fechaFin || null
    )

    mesesContrato.forEach((mes) => {
      const anioMes = Number(mes.substring(0, 4))
      if (administracionRequiereAjusteAnio(contrato, anioMes, ajustesAdministracion)) return

      const movimiento = calcularMovimientoAdministracionMes(
        contrato,
        mes,
        pagosAdministracion,
        pagosArriendo,
        incrementosArriendo,
        ajustesAdministracion
      )

      if (!movimiento || Number(movimiento.valorCausado || 0) <= 0) return
      if (Number(movimiento.saldoDeuda || 0) <= 0) return

      resultados.push({
        idContrato: obtenerIdContrato(contrato),
        idUnidad: contrato.idUnidad || '',
        nombreUnidad: contrato.nombreUnidad || 'Sin unidad',
        codigoPredio: contrato.codigoPredio,
        arrendatario: contrato.arrendatario || '',
        mes,
        anio: anioMes,
        saldoPendiente: Number(movimiento.saldoDeuda || 0),
        saldoDeudaTotal: calcularSaldoDeudaTotalAdministracionContrato(
          contrato,
          pagosAdministracion,
          pagosArriendo,
          incrementosArriendo,
          ajustesAdministracion
        ),
        valorAdministracion: Number(movimiento.valorCausado || 0),
        origenFondo: movimiento.origenFondo || '',
        contrato,
      })
    })
  })

  return resultados.sort((a, b) => {
    const porPredio = String(a.codigoPredio || '').localeCompare(String(b.codigoPredio || ''))
    if (porPredio !== 0) return porPredio
    const porUnidad = String(a.nombreUnidad || '').localeCompare(String(b.nombreUnidad || ''))
    if (porUnidad !== 0) return porUnidad
    return String(a.mes || '').localeCompare(String(b.mes || ''))
  })
}

const construirAdministracionesPendientesAlerta = (
  contratosArriendo = [],
  ajustesAdministracion = [],
  pagosAdministracion = [],
  pagosArriendo = [],
  incrementosArriendo = [],
  mesReferencia = null
) => {
  const sinActualizar = construirAdministracionesSinActualizarMes(
    contratosArriendo,
    ajustesAdministracion,
    mesReferencia
  )
  const pendientesPago = construirAdministracionesPendientesPagoMes(
    contratosArriendo,
    ajustesAdministracion,
    pagosAdministracion,
    pagosArriendo,
    incrementosArriendo,
    mesReferencia
  )
  const unidades = new Map()

  sinActualizar.forEach((item) => {
    unidades.set(item.idContrato, {
      ...item,
      sinActualizar: true,
      pendientePago: false,
      saldoPendiente: 0,
    })
  })

  pendientesPago.forEach((item) => {
    const existente = unidades.get(item.idContrato)

    if (existente) {
      unidades.set(item.idContrato, {
        ...existente,
        pendientePago: true,
        saldoPendiente: item.saldoDeudaTotal ?? item.saldoPendiente,
        saldoDeudaTotal: item.saldoDeudaTotal,
        valorAdministracion: item.valorAdministracion,
        origenFondo: item.origenFondo,
      })
      return
    }

    unidades.set(item.idContrato, {
      ...item,
      sinActualizar: false,
      pendientePago: true,
      saldoPendiente: item.saldoDeudaTotal ?? item.saldoPendiente,
    })
  })

  return Array.from(unidades.values())
    .map((item) => {
      const saldoDeudaTotal = calcularSaldoDeudaTotalAdministracionContrato(
        item.contrato,
        pagosAdministracion,
        pagosArriendo,
        incrementosArriendo,
        ajustesAdministracion
      )

      return {
        ...item,
        saldoDeudaTotal,
        pendientePago: saldoDeudaTotal > 0 || item.pendientePago,
        saldoPendiente: saldoDeudaTotal > 0 ? saldoDeudaTotal : item.saldoPendiente,
      }
    })
    .filter((item) => item.sinActualizar || Number(item.saldoDeudaTotal || 0) > 0)
    .sort((a, b) => {
    const porPredio = String(a.codigoPredio || '').localeCompare(String(b.codigoPredio || ''))
    if (porPredio !== 0) return porPredio
    return String(a.nombreUnidad || '').localeCompare(String(b.nombreUnidad || ''))
  })
}

const calcularPromedioGastoUltimosMeses = (movimientos, limiteMeses = 6) => {
  const mesesCausados = movimientos
    .filter((movimiento) => Number(movimiento.valorCausado || 0) > 0)
    .slice()
    .sort((a, b) => b.mes.localeCompare(a.mes))

  const mesesParaPromedio = mesesCausados.slice(0, limiteMeses)

  if (!mesesParaPromedio.length) {
    return { promedio: 0, meses: 0 }
  }

  const total = mesesParaPromedio.reduce(
    (suma, movimiento) => suma + Number(movimiento.valorCausado || 0),
    0
  )

  return {
    promedio: total / mesesParaPromedio.length,
    meses: mesesParaPromedio.length,
  }
}

const ordenarPagosServicioCronologico = (pagos = []) =>
  pagos
    .slice()
    .sort((a, b) => {
      const fechaA = a.fechaPago || ''
      const fechaB = b.fechaPago || ''
      if (fechaA !== fechaB) return fechaA.localeCompare(fechaB)
      return String(a.id || a.recibo || '').localeCompare(String(b.id || b.recibo || ''))
    })

const obtenerPagosServicioMes = (
  { idUnidad, idServicio, mes, facturaId = null, codigoPredio = '' },
  pagosServiciosPublicos = []
) => {
  if (facturaId) {
    return pagosServiciosPublicos.filter((pago) => pago.idFactura === facturaId)
  }

  return pagosServiciosPublicos.filter(
    (pago) =>
      pago.idUnidad === idUnidad &&
      pago.idServicio === idServicio &&
      pago.periodo === mes &&
      (!pago.codigoPredio || !codigoPredio || pago.codigoPredio === codigoPredio)
  )
}

const calcularSaldoDeudaMesServicio = (movimiento = {}) =>
  Math.max(
    0,
    Number(movimiento.valorCausado || 0) - Number(movimiento.pagado || 0)
  )

const calcularSaldoDeudaTotalServicio = (movimientos = []) =>
  movimientos.reduce(
    (total, movimiento) => total + calcularSaldoDeudaMesServicio(movimiento),
    0
  )

const calcularSaldosAcumuladosAdeudadoServicio = (movimientos = []) => {
  let acumulado = 0

  return movimientos.map((movimiento) => {
    acumulado += calcularSaldoDeudaMesServicio(movimiento)
    return acumulado
  })
}

const calcularMovimientoServicioMes = (
  mes,
  servicio,
  { idUnidad, idServicio, codigoPredio = '', unidad = null, servicioIndex = null },
  facturasServiciosPublicos,
  pagosServiciosPublicos
) => {
  let factura = facturasServiciosPublicos.find(
    (item) =>
      item.idUnidad === idUnidad &&
      item.idServicio === idServicio &&
      item.periodo === mes &&
      (!item.codigoPredio || !codigoPredio || item.codigoPredio === codigoPredio)
  )

  if (!factura && unidad != null && servicioIndex != null) {
    factura = facturasServiciosPublicos.find(
      (item) =>
        facturaPerteneceAUnidadServicio(item, unidad, servicioIndex) && item.periodo === mes
    )
  }

  const idServicioPago = factura?.idServicio || idServicio

  const pagosDelMes = ordenarPagosServicioCronologico(
    obtenerPagosServicioMes(
      {
        idUnidad,
        idServicio: idServicioPago,
        mes,
        facturaId: factura?.id || null,
        codigoPredio,
      },
      pagosServiciosPublicos
    )
  )

  const totalPagado = pagosDelMes.reduce(
    (total, pago) => total + Number(pago.valorPagado || 0),
    0
  )
  const ultimoPago = pagosDelMes[pagosDelMes.length - 1]

  let valorCausado = 0
  let faltaFactura = false

  if (factura) {
    valorCausado = Number(factura.valorFactura || 0)
  } else if (servicio.tipoCobro === 'Valor fijo mensual') {
    valorCausado = Number(servicio.valorFijo || 0)
  } else {
    faltaFactura = true
  }

  const saldoDeuda = Math.max(0, valorCausado - totalPagado)
  const diaPago = String(servicio.diaPago || 1).padStart(2, '0')
  const fechaLimite = factura?.fechaLimite || `${mes}-${diaPago}`

  let estadoMovimiento = 'Pagado'

  if (faltaFactura) {
    estadoMovimiento = 'Falta registrar factura'
  } else if (saldoDeuda > 0 && totalPagado > 0) {
    estadoMovimiento = 'Abono registrado'
  } else if (saldoDeuda > 0) {
    estadoMovimiento = 'Pendiente'
  }

  const faltaRecibo =
    totalPagado > 0 && (!ultimoPago?.recibo || ultimoPago.recibo === 'Sin recibo')

  if (faltaRecibo) {
    estadoMovimiento = 'Falta recibo de pago'
  }

  return {
    mes,
    facturaId: factura?.id || null,
    numeroFactura: factura?.numeroFactura || 'Sin factura',
    fechaLimite,
    valorCausado,
    pagado: totalPagado,
    saldoDeuda,
    saldoPendiente: saldoDeuda,
    fechaPago: ultimoPago?.fechaPago || 'Sin pago',
    recibo: ultimoPago?.recibo || 'Sin recibo',
    observacion: ultimoPago?.observacion || '',
    estadoMovimiento,
    tipoCobro: servicio.tipoCobro,
    faltaFactura,
    faltaRecibo,
  }
}

const calcularCreditoAdministracionDesdePagoArriendo = (
  contrato,
  mes,
  pago,
  incrementosArriendo = [],
  ajustesAdministracion = []
) => {
  if (!contrato || contratoAplicaAdministracion(contrato) === false) return 0
  if (administracionIncluidaEnCanonContrato(contrato)) return 0

  const calculo = calcularCanonArriendoPuro(
    contrato,
    mes,
    incrementosArriendo,
    ajustesAdministracion
  )
  const canonTotal = calcularMontoCanonArrendatarioMes({
    canonBase: calculo.canonBase,
    administracion: calculo.administracion,
    ivaCanon: calculo.iva,
    contrato,
  })
  const adminMes = Number(calculo.administracion || 0)
  if (adminMes <= 0 || canonTotal <= 0) return 0

  const pagado = Math.max(0, Number(pago.valorPagado || 0) - Number(pago.mora || 0))
  return Math.min(Math.round(pagado * (adminMes / canonTotal)), adminMes)
}

const calcularCreditoAdministracionArriendoMes = () => {
  // Los abonos de administración se registran solo con pagosAdministracion.
  // Si va incluida en el canon, el descuento se refleja en la liquidación al depositario.
  return 0
}

const calcularMovimientoAdministracionMes = (
  contrato,
  mes,
  pagosAdministracion = [],
  pagosArriendo = [],
  incrementosArriendo = [],
  ajustesAdministracion = []
) => {
  if (!contratoAplicaAdministracion(contrato)) return null

  const idContrato = obtenerIdContrato(contrato)
  const anioPago = Number(mes.substring(0, 4))
  const valorCausado = obtenerAdministracionContratoPuro(
    contrato,
    anioPago,
    ajustesAdministracion
  )
  const incluidaEnCanon = administracionIncluidaEnCanonContrato(contrato)
  const origenFondo = incluidaEnCanon ? 'Propietario' : 'Arrendatario'

  const pagosDirectos = (pagosAdministracion || []).filter(
    (pago) => pago.idContrato === idContrato && pago.mes === mes
  )
  const pagosDetalle = pagosDirectos.map((pago) => ({
    id: pago.id,
    fechaPago: pago.fechaPago || 'Sin pago',
    recibo: pago.recibo || 'Sin recibo',
    valorPagado: Number(pago.valorPagado || 0),
    origenFondo: pago.origenFondo || origenFondo,
    idPagoArriendo: pago.idPagoArriendo || '',
    observaciones: pago.observaciones || '',
  }))

  const pagosArriendoMes = (pagosArriendo || []).filter(
    (pago) => pago.idContrato === idContrato && (pago.mesAsignado || pago.mes) === mes
  )
  const creditoArriendo = 0

  const totalPagadoDirecto = pagosDirectos.reduce(
    (total, pago) => total + Number(pago.valorPagado || 0),
    0
  )
  const totalPagado = Math.min(valorCausado, totalPagadoDirecto + creditoArriendo)
  const saldoDeuda = Math.max(0, valorCausado - totalPagado)
  const ultimoPago = pagosDirectos[0] || pagosArriendoMes[pagosArriendoMes.length - 1]

  let estadoMovimiento = 'Pagado'
  if (valorCausado <= 0) {
    estadoMovimiento = 'Sin valor'
  } else if (saldoDeuda > 0 && totalPagado > 0) {
    estadoMovimiento = 'Abono registrado'
  } else if (saldoDeuda > 0) {
    estadoMovimiento = 'Pendiente'
  }

  const faltaRecibo =
    totalPagado > 0 &&
    pagosDirectos.length === 0 &&
    pagosArriendoMes.every((pago) => !pago.recibo)

  if (faltaRecibo && !incluidaEnCanon) {
    estadoMovimiento = 'Falta recibo de pago'
  }

  return {
    mes,
    valorCausado,
    pagado: totalPagado,
    pagadoDirecto: totalPagadoDirecto,
    creditoArriendo,
    saldoDeuda,
    fechaPago: ultimoPago?.fechaPago || 'Sin pago',
    recibo: pagosDetalle.map((pago) => pago.recibo).filter(Boolean).join(', ') || 'Sin recibo',
    pagosDetalle,
    estadoMovimiento,
    origenFondo,
    administracionIncluidaEnCanon: incluidaEnCanon,
    faltaRecibo,
  }
}

const calcularSaldoDeudaTotalAdministracionContrato = (
  contrato,
  pagosAdministracion = [],
  pagosArriendo = [],
  incrementosArriendo = [],
  ajustesAdministracion = []
) => {
  if (!contrato || !contratoAplicaAdministracion(contrato) || !contrato.fechaInicio) return 0

  const meses = generarMesesRango(contrato.fechaInicio, contrato.fechaFin || null)

  return meses.reduce((total, mes) => {
    const anioMes = Number(mes.substring(0, 4))
    if (administracionRequiereAjusteAnio(contrato, anioMes, ajustesAdministracion)) return total

    const movimiento = calcularMovimientoAdministracionMes(
      contrato,
      mes,
      pagosAdministracion,
      pagosArriendo,
      incrementosArriendo,
      ajustesAdministracion
    )

    return total + Number(movimiento?.saldoDeuda || 0)
  }, 0)
}

const obtenerPrimerMesPendienteAdministracionContrato = (
  contrato,
  pagosAdministracion = [],
  pagosArriendo = [],
  incrementosArriendo = [],
  ajustesAdministracion = []
) => {
  if (!contrato?.fechaInicio) return null

  const meses = generarMesesRango(contrato.fechaInicio, contrato.fechaFin || null)

  for (const mes of meses) {
    const anioMes = Number(mes.substring(0, 4))
    if (administracionRequiereAjusteAnio(contrato, anioMes, ajustesAdministracion)) continue

    const movimiento = calcularMovimientoAdministracionMes(
      contrato,
      mes,
      pagosAdministracion,
      pagosArriendo,
      incrementosArriendo,
      ajustesAdministracion
    )

    if (Number(movimiento?.saldoDeuda || 0) > 0) return mes
  }

  return null
}

const construirPagosAdministracionDistribuidos = ({
  contrato,
  montoTotal,
  datosBase,
  pagosAdministracionExistentes = [],
  pagosArriendo = [],
  incrementosArriendo = [],
  ajustesAdministracion = [],
  mesInicio = null,
}) => {
  const meses = generarMesesRango(contrato.fechaInicio, contrato.fechaFin || null)
  const idxInicio = mesInicio ? meses.indexOf(mesInicio) : 0
  const mesesRecorrer = idxInicio >= 0 ? meses.slice(idxInicio) : meses

  let restante = Number(montoTotal || 0)
  const pagosAcumulados = [...pagosAdministracionExistentes]
  const pagosNuevos = []
  const idGrupoPago = `GRUPO-ADM-${Date.now()}`

  mesesRecorrer.forEach((mes) => {
    if (restante <= 0) return

    const anioMes = Number(mes.substring(0, 4))
    if (administracionRequiereAjusteAnio(contrato, anioMes, ajustesAdministracion)) return

    const movimiento = calcularMovimientoAdministracionMes(
      contrato,
      mes,
      pagosAcumulados,
      pagosArriendo,
      incrementosArriendo,
      ajustesAdministracion
    )
    const saldo = Number(movimiento?.saldoDeuda || 0)
    if (saldo <= 0) return

    const aplicar = Math.min(restante, saldo)
    const nuevoPago = {
      ...datosBase,
      id: `PAG-ADM-${Date.now()}-${Math.floor(Math.random() * 10000)}-${mes}`,
      mes,
      valorCausado: Number(movimiento.valorCausado || 0),
      valorPagado: aplicar,
      idGrupoPago,
    }

    pagosNuevos.push(nuevoPago)
    pagosAcumulados.unshift(nuevoPago)
    restante -= aplicar
  })

  return { pagosNuevos, sobrante: restante }
}

// =============================================================================
// ADMINISTRACION - FILAS ESTADO DE CUENTA
// Movimientos de administracion por contrato.
// =============================================================================

const construirFilasEstadoCuentaAdministracion = (contrato, movimientos) => {
  const diaCobro = contrato?.fechaInicio?.slice(8, 10) || '01'

  return movimientos
    .slice()
    .sort((a, b) => a.mes.localeCompare(b.mes))
    .flatMap((movimiento) => {
      const fechaCausacion = `${movimiento.mes}-${diaCobro}`
      const filas = []

      if (Number(movimiento.valorCausado || 0) > 0) {
        filas.push({
          fecha: fechaCausacion,
          detalle: `Provisión administración periodo ${movimiento.mes}`,
          mesPeriodo: movimiento.mes,
          valor: Number(movimiento.valorCausado || 0),
          descuento: 0,
          tipo: 'cargo',
        })
      }

      if (Number(movimiento.creditoArriendo || 0) > 0) {
        filas.push({
          fecha:
            movimiento.fechaPago && movimiento.fechaPago !== 'Sin pago'
              ? movimiento.fechaPago
              : fechaCausacion,
          detalle: `Descuento con recibo de arriendo periodo ${movimiento.mes}`,
          valor: 0,
          descuento: Number(movimiento.creditoArriendo || 0),
          tipo: 'pago',
        })
      }

      ;(movimiento.pagosDetalle || []).forEach((pago) => {
        if (Number(pago.valorPagado || 0) <= 0) return

        const numeroRecibo =
          pago.recibo && pago.recibo !== 'Sin recibo' ? pago.recibo : 'Sin recibo'

        filas.push({
          fecha:
            pago.fechaPago && pago.fechaPago !== 'Sin pago' ? pago.fechaPago : fechaCausacion,
          detalle: `Pago administración periodo ${movimiento.mes} - Recibo ${numeroRecibo}`,
          valor: 0,
          descuento: Number(pago.valorPagado || 0),
          tipo: 'pago',
        })
      })

      return filas
    })
}

// =============================================================================
// SERVICIOS PUBLICOS - FILAS ESTADO DE CUENTA
// Facturas y pagos por servicio publico.
// =============================================================================

const construirFilasEstadoCuentaServicio = (servicio, movimientos) =>
  movimientos
    .slice()
    .sort((a, b) => a.mes.localeCompare(b.mes))
    .flatMap((movimiento) => {
      const diaPago = String(servicio.diaPago || 1).padStart(2, '0')
      const fechaCausacion = `${movimiento.mes}-${diaPago}`
      const filas = []

      if (Number(movimiento.valorCausado || 0) > 0) {
        const detalleFactura =
          movimiento.numeroFactura && movimiento.numeroFactura !== 'Sin factura'
            ? ` - Recibo servicio ${movimiento.numeroFactura}`
            : ''

        filas.push({
          fecha: fechaCausacion,
          detalle:
            servicio.tipoCobro === 'Valor fijo mensual'
              ? `Cobro fijo ${servicio.tipo} periodo ${movimiento.mes}`
              : `Factura ${servicio.tipo} periodo ${movimiento.mes}${detalleFactura}`,
          mesPeriodo: movimiento.mes,
          esServicioFijo: servicio.tipoCobro === 'Valor fijo mensual',
          valor: Number(movimiento.valorCausado || 0),
          descuento: 0,
          tipo: 'cargo',
        })
      }

      if (Number(movimiento.pagado || 0) > 0) {
        const numeroRecibo =
          movimiento.recibo && movimiento.recibo !== 'Sin recibo'
            ? movimiento.recibo
            : 'Sin recibo'

        filas.push({
          fecha:
            movimiento.fechaPago && movimiento.fechaPago !== 'Sin pago'
              ? movimiento.fechaPago
              : fechaCausacion,
          detalle: `Pago ${servicio.tipo} periodo ${movimiento.mes} - Recibo ${numeroRecibo}`,
          valor: 0,
          descuento: Number(movimiento.pagado || 0),
          tipo: 'pago',
        })
      }

      return filas
    })

const esMovimientoSaldoAtraso = (movimiento, fechaCorte, contrato = null) => {
  const saldo = Number(
    movimiento?.saldoDeuda ??
      movimiento?.saldoPendiente ??
      movimiento?.saldoAcumulado ??
      0
  )
  if (saldo <= 0) return false

  const fecha = fechaCorte || new Date().toISOString().slice(0, 10)

  if (movimiento?.fechaLimite && movimiento.fechaLimite !== 'Sin registrar') {
    return fecha > movimiento.fechaLimite
  }

  if (movimiento?.mes) {
    return fecha > obtenerFechaVencimientoMesArriendo(movimiento.mes, contrato)
  }

  if (movimiento?.anio) {
    return fecha > `${movimiento.anio}-12-31`
  }

  return true
}

// =============================================================================
// IMPUESTO PREDIAL - CALCULOS Y EXTRACTO
// Total a pagar, abonos por vigencia, intereses y descuentos.
// =============================================================================

const calcularTotalAPagarPredial = (movimiento) => {
  if (movimiento.valorAPagar === null || movimiento.valorAPagar === undefined) {
    return null
  }

  return (
    Number(movimiento.valorAPagar || 0) -
    Number(movimiento.descuento || 0) +
    Number(movimiento.intereses || 0)
  )
}

const calcularResumenVigenciaPredial = (
  codigoPredio,
  anio,
  valoresPrediales = [],
  pagosPrediales = [],
  descuentoNuevo = 0,
  interesesNuevo = 0,
  valorPagadoNuevo = 0
) => {
  const valorAnual = valoresPrediales.find(
    (item) => item.codigoPredio === codigoPredio && Number(item.anio) === Number(anio)
  )

  if (!valorAnual) return null

  const pagosDelAnio = pagosPrediales.filter(
    (item) => item.codigoPredio === codigoPredio && Number(item.anio) === Number(anio)
  )

  const totalDescuentoPrevio = pagosDelAnio.reduce(
    (total, pago) => total + Number(pago.descuento || 0),
    0
  )
  const totalInteresesPrevio = pagosDelAnio.reduce(
    (total, pago) => total + Number(pago.intereses || 0),
    0
  )
  const totalPagadoPrevio = pagosDelAnio.reduce(
    (total, pago) => total + Number(pago.valorPagado || 0),
    0
  )

  const valorImpuesto = Number(valorAnual.valorImpuesto || 0)
  const descuentoAbono = Number(descuentoNuevo || 0)
  const interesesAbono = Number(interesesNuevo || 0)
  const valorAbono = Number(valorPagadoNuevo || 0)
  const totalDescuento = totalDescuentoPrevio + descuentoAbono
  const totalIntereses = totalInteresesPrevio + interesesAbono
  const totalAPagar = valorImpuesto - totalDescuento + totalIntereses
  const totalPagado = totalPagadoPrevio + valorAbono
  const saldoPendiente = totalAPagar - totalPagado

  return {
    valorImpuesto,
    fechaLimite: valorAnual.fechaLimite || '',
    totalDescuentoPrevio,
    totalInteresesPrevio,
    totalPagadoPrevio,
    totalDescuento,
    totalIntereses,
    totalAPagar,
    totalPagado,
    saldoPendiente,
    pagosDelAnio,
    vigenciaCompleta: saldoPendiente <= 0 && totalPagado > 0,
  }
}

const obtenerAniosVigenciaPredialPredio = (codigoPredio, valoresPrediales = []) =>
  valoresPrediales
    .filter((item) => item.codigoPredio === codigoPredio)
    .map((item) => Number(item.anio))
    .filter((anio) => Number.isFinite(anio))
    .sort((a, b) => b - a)

const ordenarPagosPredialCronologico = (pagos = []) =>
  pagos
    .slice()
    .sort((a, b) => String(a.fechaPago || '').localeCompare(String(b.fechaPago || '')))

const obtenerPagosDetalleMovimientoPredial = (movimiento) => {
  if (Array.isArray(movimiento?.pagosDetalle) && movimiento.pagosDetalle.length > 0) {
    return ordenarPagosPredialCronologico(movimiento.pagosDetalle)
  }

  if (Number(movimiento.valorPagado || 0) > 0) {
    return [
      {
        id: `${movimiento.anio}-pago-unico`,
        fechaPago: movimiento.fechaPago || 'Sin pago',
        recibo: movimiento.recibo || 'Sin recibo',
        descuento: Number(movimiento.descuento || 0),
        intereses: Number(movimiento.intereses || 0),
        valorPagado: Number(movimiento.valorPagado || 0),
        documentoPago: movimiento.documentoPago || null,
      },
    ]
  }

  return []
}

const calcularSaldoLiquidadoAnioPredial = (movimiento) => {
  if (movimiento?.valorAPagar === null || movimiento?.valorAPagar === undefined) {
    return null
  }

  if (movimiento?.saldoPendiente !== null && movimiento?.saldoPendiente !== undefined) {
    return Number(movimiento.saldoPendiente || 0)
  }

  const totalAPagar = calcularTotalAPagarPredial(movimiento)
  return Number(totalAPagar || 0) - Number(movimiento.valorPagado || 0)
}

const construirFilasAnioExtractoPredial = (movimiento) => {
  const fechaLimite =
    movimiento.fechaLimite && movimiento.fechaLimite !== 'Sin registrar'
      ? movimiento.fechaLimite
      : `${movimiento.anio}-12-31`
  const pagosDetalle = obtenerPagosDetalleMovimientoPredial(movimiento)
  const filas = []

  const agregarFila = (fila) => {
    filas.push(fila)
  }

  if (movimiento.valorAPagar === null || movimiento.valorAPagar === undefined) {
    agregarFila({
      fecha: fechaLimite,
      detalle: `Impuesto predial vigencia ${movimiento.anio} sin valor registrado`,
      valorMovimiento: 0,
      tipo: 'info',
    })
    return filas
  }

  if (Number(movimiento.valorAPagar || 0) > 0) {
    agregarFila({
      fecha: fechaLimite,
      detalle: `Impuesto predial vigencia ${movimiento.anio}`,
      valorMovimiento: Number(movimiento.valorAPagar || 0),
      tipo: 'cargo',
    })
  }

  pagosDetalle.forEach((pago) => {
    if (Number(pago.intereses || 0) > 0) {
      agregarFila({
        fecha: pago.fechaPago || fechaLimite,
        detalle: 'Intereses',
        valorMovimiento: Number(pago.intereses || 0),
        tipo: 'cargo',
      })
    }

    if (Number(pago.descuento || 0) > 0) {
      agregarFila({
        fecha: pago.fechaPago || fechaLimite,
        detalle: 'Descuento',
        valorMovimiento: -Number(pago.descuento || 0),
        tipo: 'descuento',
      })
    }

    if (Number(pago.valorPagado || 0) > 0) {
      const numeroRecibo =
        pago.recibo && pago.recibo !== 'Sin recibo' ? pago.recibo : 'Sin recibo'

      agregarFila({
        fecha: pago.fechaPago || fechaLimite,
        detalle: `Abono - Recibo ${numeroRecibo}`,
        valorMovimiento: -Number(pago.valorPagado || 0),
        tipo: 'pago',
        pagoId: pago.id,
        documentoPago: pago.documentoPago || null,
      })
    }
  })

  if (pagosDetalle.length === 0 && Number(movimiento.intereses || 0) > 0) {
    agregarFila({
      fecha: fechaLimite,
      detalle: 'Intereses',
      valorMovimiento: Number(movimiento.intereses || 0),
      tipo: 'cargo',
    })
  }

  if (pagosDetalle.length === 0 && Number(movimiento.descuento || 0) > 0) {
    agregarFila({
      fecha: movimiento.fechaPago || fechaLimite,
      detalle: 'Descuento',
      valorMovimiento: -Number(movimiento.descuento || 0),
      tipo: 'descuento',
    })
  }

  return filas
}

const construirBloquesExtractoPredialPorAnio = (movimientos) =>
  movimientos
    .slice()
    .sort((a, b) => Number(b.anio) - Number(a.anio))
    .map((movimiento, indiceAnio) => ({
      anio: movimiento.anio,
      tono: indiceAnio % 2,
      movimiento,
      filas: construirFilasAnioExtractoPredial(movimiento),
      saldoAnio: calcularSaldoLiquidadoAnioPredial(movimiento),
      estadoMovimiento: movimiento.estadoMovimiento,
    }))

const obtenerSaldoAcumuladoPredial = (movimientos) =>
  movimientos.reduce(
    (total, movimiento) => total + Number(calcularSaldoLiquidadoAnioPredial(movimiento) || 0),
    0
  )

const opcionesAtrasoServicio = (item, fechaCorte = null) => ({
  saldoPendiente: item?.saldoPendiente ?? item?.valorFactura,
  fechaLimite: item?.fechaLimite,
  fechaCorte: fechaCorte || new Date().toISOString().slice(0, 10),
})

const obtenerGestionesContratoCartera = (gestionesCartera, idContrato) =>
  gestionesCartera
    .filter((gestion) => gestion.idContrato === idContrato)
    .sort((a, b) => new Date(b.fechaGestion) - new Date(a.fechaGestion))

const obtenerUltimaGestionContratoCartera = (gestionesCartera, idContrato) =>
  obtenerGestionesContratoCartera(gestionesCartera, idContrato)[0] || null

const obtenerPromesaVigenteCartera = (gestionesCartera, idContrato) =>
  gestionesCartera
    .filter(
      (gestion) =>
        gestion.idContrato === idContrato &&
        gestion.estadoGestion === 'Promesa de pago' &&
        gestion.fechaPromesaPago
    )
    .sort((a, b) => {
      const diferenciaFechaGestion = new Date(b.fechaGestion) - new Date(a.fechaGestion)
      if (diferenciaFechaGestion !== 0) return diferenciaFechaGestion
      return String(b.fechaPromesaPago).localeCompare(String(a.fechaPromesaPago))
    })[0] || null

const debePosponerCarteraPorAcuerdo = (gestionesCartera, idContrato, fechaCorte) => {
  const promesa = obtenerPromesaVigenteCartera(gestionesCartera, idContrato)
  if (!promesa) return false
  return fechaCorte < promesa.fechaPromesaPago
}

const calcularEstadoCarteraContrato = ({
  saldoTotalCliente,
  saldoMes,
  promesaVigente,
  fechaCorte,
  fechaLimiteNormal,
}) => {
  if (saldoTotalCliente <= 0) return 'Al día'

  if (promesaVigente) {
    if (fechaCorte > promesaVigente.fechaPromesaPago) return 'Incumplió promesa'
    if (fechaCorte === promesaVigente.fechaPromesaPago) return 'Promesa de pago'
    return 'Promesa de pago'
  }

  if (saldoMes > 0 && fechaCorte <= fechaLimiteNormal) return 'En plazo'
  return 'Vencido'
}

const obtenerEtiquetaSeguimientoCartera = (item, gestionesCartera, fechaCorte) => {
  if (debePosponerCarteraPorAcuerdo(gestionesCartera, item.idContrato, fechaCorte)) {
    return {
      texto: `Acuerdo hasta ${item.promesaVigente?.fechaPromesaPago || 'Sin fecha'}`,
      clase: 'status warning',
    }
  }

  if (Number(item.diasSinGestion || 0) > 0) {
    return {
      texto: `${Number(item.diasSinGestion || 0)} días sin gestión`,
      clase: 'status inactive',
    }
  }

  return {
    texto: 'Pendiente de gestión hoy',
    clase: 'status active',
  }
}

const crearFilaTablaCarteraArriendo = ({
  item,
  rowKey,
  fechaCorteCartera,
  extractosArriendo,
  extractosServiciosPublicos,
  gestionesCartera,
  formatearDinero,
  puedeRegistrar,
  mostrarAccion = false,
  mostrarSeguimiento = false,
  onGestionar = null,
}) => {
  const extractoItem = extractosArriendo.find(
    (extracto) => obtenerIdContrato(extracto.contrato) === item.idContrato
  )
  const opcionesAtraso = opcionesAtrasoCartera(item, extractoItem, fechaCorteCartera)
  const resumenServiciosUnidad = obtenerResumenServiciosPublicosUnidad(
    { id: item.idUnidad, codigoPredio: item.codigoPredio },
    extractosServiciosPublicos
  )
  const seguimiento = obtenerEtiquetaSeguimientoCartera(
    item,
    gestionesCartera,
    fechaCorteCartera
  )

  return (
    <tr key={rowKey || `${item.idContrato}-${item.mes}`}>
      <td>{item.numeroContrato}</td>
      <td>{item.codigoPredio}</td>
      <td>{item.nombreUnidad || 'Sin unidad'}</td>
      <td>{item.arrendatario}</td>
      <td className={claseSaldoAtraso(opcionesAtraso)}>
        {formatearDinero(item.saldoArriendoCliente ?? item.saldoTotalCliente ?? 0)}
      </td>
      <td>
        {Number(item.saldoAdministracionCliente || 0) > 0 ? (
          <strong className="saldo-atraso">
            {formatearDinero(item.saldoAdministracionCliente)}
          </strong>
        ) : (
          formatearDinero(0)
        )}
      </td>
      <td>
        {!resumenServiciosUnidad.tieneServicios ? (
          <span className="status warning">Sin servicios</span>
        ) : resumenServiciosUnidad.estadoServicios === 'Sin contrato' ? (
          <span className="status warning">Sin contrato</span>
        ) : (
          <strong
            className={claseSaldoAtraso({
              saldoPendiente: resumenServiciosUnidad.saldoTotal,
            })}
          >
            {formatearDinero(resumenServiciosUnidad.saldoTotal)}
          </strong>
        )}
      </td>
      {!mostrarSeguimiento && (
        <td>
          <span
            className={
              Number(item.diasSinGestion || 0) === 0 ? 'status active' : 'status inactive'
            }
          >
            {Number(item.diasSinGestion || 0) === 0
              ? '0 días'
              : `${Number(item.diasSinGestion || 0)} días`}
          </span>
        </td>
      )}
      <td>
        <span className={obtenerClaseEstadoCartera(item.estadoCartera, opcionesAtraso)}>
          {item.estadoCartera}
        </span>
      </td>
      {mostrarSeguimiento && (
        <td>{item.promesaVigente?.fechaPromesaPago || 'Sin acuerdo'}</td>
      )}
      {mostrarSeguimiento && (
        <td>
          <span className={seguimiento.clase}>{seguimiento.texto}</span>
        </td>
      )}
      {mostrarAccion && (
        <td>
          {puedeRegistrar ? (
            <button type="button" className="btn-small" onClick={() => onGestionar?.(item)}>
              Gestionar llamada
            </button>
          ) : (
            <span className="status inactive">Solo consulta</span>
          )}
        </td>
      )}
    </tr>
  )
}

const opcionesAtrasoCartera = (item, extracto = null, fechaCorte = null) => ({
  estadoCartera: item?.estadoCartera,
  saldoMes: item?.saldoMes,
  saldo: item?.saldoArriendoCliente ?? item?.saldoTotalCliente ?? item?.saldo ?? item?.saldoPendiente,
  saldoTotalCliente: item?.saldoArriendoCliente ?? item?.saldoTotalCliente ?? item?.saldo,
  saldoPendiente: item?.saldoPendiente,
  fechaCorte: item?.fechaCorte ?? fechaCorte,
  fechaLimiteNormal: item?.fechaLimiteNormal,
  extracto,
})

const opcionesAtrasoExtracto = (extracto, extra = {}) => ({
  extracto,
  saldo: extracto?.resumen?.saldoDeudaTotal ?? extracto?.resumen?.saldoPendiente,
  saldoTotalCliente: extracto?.resumen?.saldoDeudaTotal,
  saldoPendiente: extracto?.resumen?.saldoPendiente,
  ...extra,
})

const esSaldoEnAtraso = ({
  estadoCartera,
  saldo,
  saldoMes,
  saldoTotalCliente,
  saldoPendiente,
  fechaCorte,
  fechaLimite,
  fechaLimiteNormal,
  extracto,
} = {}) => {
  const montoDeuda = Number(
    saldo ??
      saldoTotalCliente ??
      saldoMes ??
      saldoPendiente ??
      extracto?.resumen?.saldoDeudaTotal ??
      extracto?.resumen?.saldoPendiente ??
      0
  )

  const movimientos = extracto?.movimientos || []
  const movimientosConDeuda = movimientos.filter(
    (movimiento) =>
      Number(movimiento.saldoDeuda ?? movimiento.saldoPendiente ?? 0) > 0
  )

  if (montoDeuda <= 0 && movimientosConDeuda.length === 0) {
    return false
  }

  const fecha = fechaCorte || new Date().toISOString().slice(0, 10)

  if (
    estadoCartera === 'Vencido' ||
    estadoCartera === 'Incumplió promesa' ||
    estadoCartera === 'Promesa de pago'
  ) {
    return true
  }

  if (fechaLimiteNormal && montoDeuda > 0 && fecha > fechaLimiteNormal) {
    return true
  }

  if (fechaLimite && montoDeuda > 0 && !extracto && !estadoCartera) {
    return fecha > fechaLimite
  }

  const contratoExtracto = extracto?.contrato || null
  if (
    movimientosConDeuda.some((movimiento) =>
      esMovimientoSaldoAtraso(movimiento, fecha, contratoExtracto)
    )
  ) {
    return true
  }

  const estadoGeneral = extracto?.resumen?.estadoGeneral
  if (
    montoDeuda > 0 &&
    (estadoGeneral === 'Con deuda' ||
      estadoGeneral === 'Con saldo pendiente' ||
      estadoGeneral === 'Pendiente de actualización')
  ) {
    return true
  }

  if (
    Number(saldoPendiente ?? 0) > 0 &&
    estadoGeneral !== 'Al día' &&
    !fechaLimite
  ) {
    return true
  }

  if (estadoCartera === 'Al día') {
    return false
  }

  if (estadoCartera === 'En plazo') {
    return false
  }

  return montoDeuda > 0
}

const claseSaldoAtraso = (opciones) => (esSaldoEnAtraso(opciones) ? 'saldo-atraso' : '')

const claseTarjetaPanelInicio = (tienePendiente) =>
  `estado-cuenta-tipo-card panel-inicio-card ${
    tienePendiente ? 'panel-inicio-card--alert' : 'panel-inicio-card--ok'
  }`

// =============================================================================
// ESTADOS Y CLASES UI - HELPERS VISUALES
// Clases de estado para cartera, mora y alertas.
// =============================================================================

const obtenerClaseEstadoCartera = (estado, opcionesAtraso = null) => {
  if (opcionesAtraso != null && esSaldoEnAtraso(opcionesAtraso)) {
    return 'status inactive'
  }

  if (
    estado === 'Vencido' ||
    estado === 'Incumplió promesa' ||
    estado === 'Promesa de pago'
  ) {
    return 'status inactive'
  }

  if (estado === 'En plazo') return 'status active'
  return 'status active'
}

const obtenerClaseEstadoGeneral = (estadoGeneral, opcionesAtraso = null) => {
  if (opcionesAtraso != null && esSaldoEnAtraso(opcionesAtraso)) {
    return 'status inactive'
  }

  if (estadoGeneral === 'Al día' || estadoGeneral === 'Pagada') return 'status active'
  if (estadoGeneral === 'Pendiente de actualización') return 'status inactive'
  if (estadoGeneral === 'Con deuda' || estadoGeneral === 'Con saldo pendiente') {
    return 'status inactive'
  }

  return 'status warning'
}

// =============================================================================
// COMPONENTE - FORMULARIO SERVICIO POR UNIDAD
// Alta y edicion inline de servicios publicos en unidades.
