const esOperador =
  usuarioActual?.rol === 'Operador' || usuarioActual?.rol === 'Digitador'
const esConsulta = usuarioActual?.rol === 'Consulta'

const puedeRegistrar = esAdministrador || esOperador
const puedeAdministrar = esAdministrador
const soloConsulta = esConsulta

const obtenerDescripcionRol = (rol) => {
  if (rol === 'Administrador') {
    return 'Acceso completo: crear, editar, usuarios y respaldos.'
  }
  if (rol === 'Operador' || rol === 'Digitador') {
    return 'Puede registrar pagos con fecha de recibo hasta 20 días de antigüedad. No edita recibos ni administra usuarios.'
  }
  if (rol === 'Consulta') {
    return 'Solo consulta, busca e imprime. No registra ni edita.'
  }
  return ''
}

const obtenerClaseRol = (rol) => {
  if (rol === 'Administrador') return 'role-badge role-admin'
  if (rol === 'Operador') return 'role-badge role-operator'
  return 'role-badge role-consulta'
}

const obtenerIniciales = (nombre = '') => {
  const partes = nombre.trim().split(/\s+/).filter(Boolean)
  if (partes.length === 0) return '?'
  if (partes.length === 1) return partes[0].slice(0, 2).toUpperCase()
  return `${partes[0][0]}${partes[partes.length - 1][0]}`.toUpperCase()
}

const obtenerClaseEstadoPredio = (estado) => {
  const estadoNormalizado = normalizarEstadoPredio(estado)
  if (estadoNormalizado === 'Cerrado') return 'status inactive'
  if (estadoNormalizado === 'Pagado' || estadoNormalizado === 'Contratado') {
    return 'status active'
  }
  if (estadoNormalizado === 'Con pago parcial' || estadoNormalizado === 'En negociación') {
    return 'status warning'
  }
  return 'status active'
}

