// PERSISTENCIA - CARGAR DATOS EN ESTADO
// Hidrata el estado de React desde localStorage o API.
// =============================================================================

  const cargarDatosEnEstado = (datos) => {
    const prediosCargados = normalizarPredios(datos.predios)
    const modeloPropietarios = migrarModeloPropietarios(
      datos.propietarios,
      datos.predioPropietarios
    )
    setPredioPropietarios(modeloPropietarios.predioPropietarios)
    setHistorialCambios(datos.historialCambios || [])
    const datosMigradosUnidades = migrarIdsUnidadesNegocio({
      unidadesNegocio: datos.unidadesNegocio || [],
      contratosArriendo: datos.contratosArriendo || [],
      pagosArriendo: datos.pagosArriendo || [],
      pagosAdministracion: datos.pagosAdministracion || [],
      facturasServiciosPublicos: datos.facturasServiciosPublicos || [],
      pagosServiciosPublicos: datos.pagosServiciosPublicos || [],
      documentos: datos.documentos || [],
      gestionesCartera: datos.gestionesCartera || [],
      ajustesAdministracion: datos.ajustesAdministracion || [],
    })
    setUnidadesNegocio(datosMigradosUnidades.unidadesNegocio || [])
    const contratosMigrados = migrarReferenciasContratosArriendo(
      normalizarCodigosContratosArriendo(
        asignarIdsInternosContratosArriendo(datosMigradosUnidades.contratosArriendo || []),
        prediosCargados
      ),
      datosMigradosUnidades.pagosArriendo || [],
      datosMigradosUnidades.ajustesAdministracion || [],
      datosMigradosUnidades.gestionesCartera || []
    )
    setContratosArriendo(contratosMigrados.contratos)
    setIncrementosArriendo(datos.incrementosArriendo || [])
    setAjustesAdministracion(contratosMigrados.ajustesAdministracion)
    setPagosArriendo(contratosMigrados.pagosArriendo)
    setPagosAdministracion(datosMigradosUnidades.pagosAdministracion || [])
    setGestionesCartera(contratosMigrados.gestionesCartera)
    setFacturasServiciosPublicos(datosMigradosUnidades.facturasServiciosPublicos || [])
    setPagosServiciosPublicos(datosMigradosUnidades.pagosServiciosPublicos || [])
    setDocumentos(datosMigradosUnidades.documentos || [])
    setValoresPrediales(datos.valoresPrediales || [])
    setPagosPrediales(datos.pagosPrediales || [])
    const contratosDepositoCargados = asignarNumerosContratosDepositoFaltantes(
      normalizarContratosDeposito(datos.contratosDeposito || []),
      modeloPropietarios.propietarios
    )
    setPropietarios(
      normalizarEsDepositantePropietarios(
        modeloPropietarios.propietarios,
        contratosDepositoCargados
      )
    )
    const jerarquiaMigrada = migrarJerarquiaDocumental(
      prediosCargados,
      contratosDepositoCargados,
      modeloPropietarios.propietarios
    )
    setContratosDeposito(jerarquiaMigrada.contratosDeposito)
    setPredios(jerarquiaMigrada.predios)
    setPagosLiquidacionDeposito(datos.pagosLiquidacionDeposito || [])
    setUsuariosSistema(
      (Array.isArray(datos.usuariosSistema) ? datos.usuariosSistema : usuariosIniciales).map(
        (usuario) => ({
          ...usuario,
          id: usuario.id || usuario.usuario,
          usuario: usuario.usuario || usuario.id,
          rol: usuario.rol === 'Digitador' ? 'Operador' : usuario.rol,
          activo: usuario.activo !== false,
        })
      )
    )
  }

  useEffect(() => {
    let cancelado = false

    const cargarDatosIniciales = async () => {
      if (usaApiRemota()) {
        const token = getTokenSesion()
        if (token) {
          try {
            const datos = await cargarDatosApi()
            if (!cancelado) {
              cargarDatosEnEstado(datos)
              const usuarioGuardado = getUsuarioSesion()
              if (usuarioGuardado) setUsuarioActual(usuarioGuardado)
            }
          } catch (error) {
            console.error('Error al cargar datos del servidor:', error)
            limpiarTokenSesion()
          }
        }
      } else {
        try {
          const datos = await cargarDatosLocales()
          if (!cancelado && datos) cargarDatosEnEstado(datos)
        } catch (error) {
          console.error('Error al cargar los datos guardados:', error)
          if (!cancelado) {
            alert('No se pudieron cargar los datos guardados. Si tiene un respaldo, impórtelo desde Reportes y respaldos.')
          }
        }
      }

      if (!cancelado) setDatosCargados(true)
    }

    cargarDatosIniciales()

    return () => {
      cancelado = true
    }
  }, [])

useEffect(() => {
  if (!datosCargados || !contratosArriendo.length) return

  const contratosConIds = asignarIdsInternosContratosArriendo(contratosArriendo)
  const contratosNormalizados = normalizarCodigosContratosArriendo(contratosConIds, predios)
  const huboCambios = contratosNormalizados.some(
    (contrato, index) =>
      contrato.id !== contratosArriendo[index]?.id ||
      contrato.idContrato !== contratosArriendo[index]?.idContrato
  )

  if (huboCambios) {
    setContratosArriendo(contratosNormalizados)
  }
}, [datosCargados, contratosArriendo, predios])

useEffect(() => {
  setMostrarEstadoCuentaGestionCartera(false)
  setMostrarEstadoCuentaServiciosGestionCartera(false)
  setMostrarEstadoCuentaAdministracionGestionCartera(false)
}, [contratoGestionCartera?.idContrato])

useEffect(() => {
  if (!datosCargados) return

  setFacturasServiciosPublicos((prev) =>
    aplicarFacturasCobroFijoFaltantes(unidadesNegocio, contratosArriendo, prev)
  )
}, [datosCargados, unidadesNegocio, contratosArriendo])

useEffect(() => {
  if (!datosCargados) return

  setContratosArriendo((prev) => procesarRenovacionesAutomaticasContratos(prev))
}, [datosCargados])

// =============================================================================
// PERSISTENCIA - ARMAR PAYLOAD Y GUARDADO INMEDIATO
// Construye el objeto completo y permite guardar sin esperar el debounce.
// =============================================================================

  const construirDatosParaGuardar = (parches = {}) => ({
    predios,
    propietarios,
    predioPropietarios,
    documentos,
    historialCambios,
    unidadesNegocio,
    contratosArriendo,
    incrementosArriendo,
    ajustesAdministracion,
    pagosArriendo,
    pagosAdministracion,
    gestionesCartera,
    facturasServiciosPublicos,
    pagosServiciosPublicos,
    valoresPrediales,
    pagosPrediales,
    contratosDeposito,
    pagosLiquidacionDeposito,
    usuariosSistema,
    ...parches,
  })

  const persistirDatosSistemaInmediato = async (parches = {}) => {
    const datosParaGuardar = construirDatosParaGuardar(parches)
    if (usaApiRemota()) {
      if (getTokenSesion()) {
        programarGuardadoDatosApi(datosParaGuardar)
      }
      return { ok: true }
    }
    return guardarDatosLocales(datosParaGuardar, { inmediato: true })
  }

useEffect(() => {
  if (!datosCargados) return

  const datosParaGuardar = construirDatosParaGuardar()
  if (usaApiRemota()) {
    if (getTokenSesion()) {
      programarGuardadoDatosApi(datosParaGuardar)
    }
    return
  }

  let cancelado = false

  guardarDatosLocales(datosParaGuardar).then((resultado) => {
    if (!cancelado && resultado && !resultado.ok) {
      alert(resultado.mensaje)
    }
  })

  return () => {
    cancelado = true
    cancelarGuardadoDatosLocalesPendiente()
  }
}, [
  datosCargados,
  predios,
  propietarios,
  predioPropietarios,
  documentos,
  historialCambios,
  unidadesNegocio,
  contratosArriendo,
  incrementosArriendo,
  ajustesAdministracion,
  pagosArriendo,
  pagosAdministracion,
  gestionesCartera,
  facturasServiciosPublicos,
  pagosServiciosPublicos,
  valoresPrediales,
  pagosPrediales,
  contratosDeposito,
  pagosLiquidacionDeposito,
  usuariosSistema,
])

// =============================================================================
// PERSISTENCIA - FLUSH AL CERRAR PESTAÑA
// Evita perder el guardado diferido si el usuario cierra el navegador.
// =============================================================================

useEffect(() => {
  if (usaApiRemota()) return undefined

  const sincronizarAlSalir = () => {
    void flushGuardadoDatosLocalesPendiente()
  }

  window.addEventListener('pagehide', sincronizarAlSalir)
  window.addEventListener('beforeunload', sincronizarAlSalir)

  return () => {
    window.removeEventListener('pagehide', sincronizarAlSalir)
    window.removeEventListener('beforeunload', sincronizarAlSalir)
  }
}, [])

// =============================================================================
// ACCIONES - RESPALDOS DEL SISTEMA
// Descargar y restaurar copias de seguridad JSON.
// =============================================================================

const descargarRespaldo = () => {
    if (!puedeAdministrar) {
    alert('Solo el administrador puede descargar respaldos.')
    return
   }
  const datos = {
  fechaRespaldo: new Date().toISOString(),
  predios,
  propietarios,
  predioPropietarios,
  documentos,
  historialCambios,
  unidadesNegocio,
  contratosArriendo,
  incrementosArriendo,
  ajustesAdministracion,
  pagosArriendo,
  pagosAdministracion,
  gestionesCartera,
  facturasServiciosPublicos,
  pagosServiciosPublicos,
  valoresPrediales,
  pagosPrediales,
  contratosDeposito,
  pagosLiquidacionDeposito,
  usuariosSistema,
}

  const archivo = new Blob([JSON.stringify(datos, null, 2)], {
    type: 'application/json',
  })

  const url = URL.createObjectURL(archivo)
  const enlace = document.createElement('a')

  enlace.href = url
  enlace.download = `respaldo-inh-control-predios-${new Date()
    .toISOString()
    .slice(0, 10)}.json`

  enlace.click()
  URL.revokeObjectURL(url)
}

const importarRespaldo = (event) => {
    if (!puedeAdministrar) {
    alert('Solo el administrador puede importar respaldos.')
    return
   }
  const archivo = event.target.files[0]

  if (!archivo) return

  const lector = new FileReader()

  lector.onload = (e) => {
    try {
      const datos = JSON.parse(e.target.result)

      const confirmar = window.confirm(
        'Esta acción reemplazará la información actual por la del respaldo. ¿Desea continuar?'
      )

      if (!confirmar) return

     const prediosImportados = normalizarPredios(datos.predios)
     const modeloImportado = migrarModeloPropietarios(
       datos.propietarios,
       datos.predioPropietarios
     )
     setPropietarios(modeloImportado.propietarios)
     setPredioPropietarios(modeloImportado.predioPropietarios)
     setHistorialCambios(datos.historialCambios || [])
     const datosMigradosUnidades = migrarIdsUnidadesNegocio({
       unidadesNegocio: datos.unidadesNegocio || [],
       contratosArriendo: datos.contratosArriendo || [],
       pagosArriendo: datos.pagosArriendo || [],
       pagosAdministracion: datos.pagosAdministracion || [],
       facturasServiciosPublicos: datos.facturasServiciosPublicos || [],
       pagosServiciosPublicos: datos.pagosServiciosPublicos || [],
       documentos: datos.documentos || [],
       gestionesCartera: datos.gestionesCartera || [],
       ajustesAdministracion: datos.ajustesAdministracion || [],
     })
     setUnidadesNegocio(datosMigradosUnidades.unidadesNegocio || [])
     const contratosImportados = migrarReferenciasContratosArriendo(
       normalizarCodigosContratosArriendo(
         asignarIdsInternosContratosArriendo(datosMigradosUnidades.contratosArriendo || []),
         prediosImportados
       ),
       datosMigradosUnidades.pagosArriendo || [],
       datosMigradosUnidades.ajustesAdministracion || [],
       datosMigradosUnidades.gestionesCartera || []
     )
     setContratosArriendo(contratosImportados.contratos)
     setIncrementosArriendo(datos.incrementosArriendo || [])
     setAjustesAdministracion(contratosImportados.ajustesAdministracion)
     setPagosArriendo(contratosImportados.pagosArriendo)
     setPagosAdministracion(datosMigradosUnidades.pagosAdministracion || [])
     setGestionesCartera(contratosImportados.gestionesCartera)
     setFacturasServiciosPublicos(datosMigradosUnidades.facturasServiciosPublicos || [])
     setPagosServiciosPublicos(datosMigradosUnidades.pagosServiciosPublicos || [])
     setDocumentos(datosMigradosUnidades.documentos || [])
     setValoresPrediales(datos.valoresPrediales || [])
     setPagosPrediales(datos.pagosPrediales || [])
     const contratosDepositoImportados = asignarNumerosContratosDepositoFaltantes(
       normalizarContratosDeposito(datos.contratosDeposito || []),
       modeloImportado.propietarios
     )
     const jerarquiaImportada = migrarJerarquiaDocumental(
       prediosImportados,
       contratosDepositoImportados,
       modeloImportado.propietarios
     )
     setContratosDeposito(jerarquiaImportada.contratosDeposito)
     setPredios(jerarquiaImportada.predios)
     setPagosLiquidacionDeposito(datos.pagosLiquidacionDeposito || [])
    setUsuariosSistema(
  (datos.usuariosSistema || usuariosIniciales).map((usuario) => ({
    ...usuario,
    id: usuario.id || usuario.usuario,
    usuario: usuario.usuario || usuario.id,
    rol: usuario.rol === 'Digitador' ? 'Operador' : usuario.rol,
    activo: usuario.activo !== false,
  }))
)

      alert('Respaldo importado correctamente.')
    } catch (error) {
      console.error('Error al importar respaldo:', error)
      alert('El archivo seleccionado no es válido.')
    }
  }

  lector.readAsText(archivo)
  event.target.value = ''
}


  const formatearDinero = (valor) => {
    return new Intl.NumberFormat('es-CO', {
      style: 'currency',
      currency: 'COP',
      maximumFractionDigits: 0,
    }).format(Number(valor || 0))
  }

  const abreviarTipoDocumento = (tipoDocumento) => {
  if (tipoDocumento === 'Cédula de ciudadanía') return 'CC'
  if (tipoDocumento === 'Cédula de extranjería') return 'CE'
  if (tipoDocumento === 'Pasaporte') return 'PAS'
  if (tipoDocumento === 'NIT') return 'NIT'

  return tipoDocumento || ''
}

  const obtenerCodigoBarrio = (texto) => {
    return normalizarTexto(texto).replace(/[^a-z]/g, '').substring(0, 3).toUpperCase()
  }

  const codigoPredioAutomatico = () => {
    if (!ciudad || !barrio) return ''

    const prefijo = `${obtenerCodigoCiudad(ciudad)}-${obtenerCodigoBarrio(barrio)}`
    const cantidad = predios.filter((predio) => predio.codigo.startsWith(prefijo)).length + 1
    return `${prefijo}-${String(cantidad).padStart(3, '0')}`
  }

  const totalPorcentajeTemporal = propietariosTemporales.reduce(
    (total, propietario) => total + Number(propietario.porcentaje || 0),
    0
  )

  const porcentajeFaltante = 100 - totalPorcentajeTemporal

  const depTotalPorcentajePropietarios = depPropietariosContrato.reduce(
    (total, propietario) => total + Number(propietario.porcentaje || 0),
    0
  )

  const depPorcentajeFaltantePropietarios = 100 - depTotalPorcentajePropietarios

  const depRequiereObservacionesAutorizacion = requiereObservacionesAutorizacionPago({
    idContratante: depIdContratante,
    propietariosContrato: depPropietariosContrato,
    tipoPagoLiquidacion: depTipoPagoLiquidacion,
    calidadContratante: depCalidadContratante,
  })

  const mostrarPredialEnFormularioContratoDeposito =
    depTipoComision === 'Administración' && depIncluyeSeguimientoPredial === 'Sí'

  const depContratanteEsPropietarioInmueble = depCalidadContratante === 'Propietario'

  const obtenerBeneficiariosPagoInhFormulario = () => {
    if (pagoEsSoloAlDepositario(depTipoPagoLiquidacion)) {
      const clave = depIdContratante || depContratanteDocumento.trim() || 'depositario'
      return [
        {
          clave,
          idPropietario: depIdContratante || '',
          nombre: depContratanteNombre.trim(),
          numeroDocumento: depContratanteDocumento.trim(),
          porcentaje: 100,
        },
      ]
    }

    if (depContratanteEsPropietarioInmueble) {
      const clave = depIdContratante || depContratanteDocumento.trim() || 'propietario-depositario'
      return [
        {
          clave,
          idPropietario: depIdContratante || '',
          nombre: depContratanteNombre.trim(),
          numeroDocumento: depContratanteDocumento.trim(),
          porcentaje: 100,
        },
      ]
    }

    if (contratoDepositoEditando?.codigoPredio || depCodigoPredio) {
      const codigoPredioReferencia = contratoDepositoEditando?.codigoPredio || depCodigoPredio
      const contratoReferencia = contratoDepositoEditando || { codigoPredio: codigoPredioReferencia }

      return obtenerPropietariosContratoDeposito(contratoReferencia, predioPropietarios).map(
        (item) => {
          const propietario = propietarios.find((registro) => registro.id === item.idPropietario)
          return {
            clave: item.idPropietario,
            idPropietario: item.idPropietario,
            nombre: propietario?.nombre || 'Propietario',
            numeroDocumento: propietario?.numeroDocumento || '',
            porcentaje: Number(item.porcentaje || 0),
          }
        }
      )
    }

    return propietariosTemporales.map((item) => ({
      clave: item.idPropietario || item.numeroDocumento,
      idPropietario: item.idPropietario || '',
      nombre: item.nombre || '',
      numeroDocumento: item.numeroDocumento || '',
      porcentaje: Number(item.porcentaje || 0),
    }))
  }

  const beneficiariosPagoInhFormulario = obtenerBeneficiariosPagoInhFormulario()

  const actualizarCuentaPagoInhBeneficiario = (clave, campo, valor) => {
    setDepCuentasPagoInhPorBeneficiario((previo) => ({
      ...previo,
      [clave]: {
        numeroCuenta: '',
        tipoCuenta: '',
        banco: '',
        nombreCuenta: '',
        ...(previo[clave] || {}),
        [campo]: valor,
      },
    }))
  }

// =============================================================================
// ACCIONES - LOGIN Y SESION
// Inicio de sesion, cierre y restablecimiento de clave.
// =============================================================================

  const iniciarSesion = async () => {
  const loginIdLimpio = loginUsuario.trim().toLowerCase()
  const claveLimpia = loginClave.trim()

  if (usaApiRemota()) {
    try {
      const resultado = await loginApi(loginIdLimpio, claveLimpia)
      setSesionApi(resultado.token, resultado.usuario)
      cargarDatosEnEstado(resultado.datos)
      setDatosCargados(true)
      setUsuarioActual(resultado.usuario)
      setLoginUsuario('')
      setLoginClave('')
      setErrorLogin('')
    } catch (error) {
      const mensaje = String(error?.message || '')
      if (mensaje === 'Failed to fetch' || mensaje.includes('NetworkError')) {
        setErrorLogin(
          'No se pudo conectar al servidor. Inicie la API con npm run dev:api o use VITE_USE_API=false en .env.local.'
        )
      } else {
        setErrorLogin(mensaje || 'ID de usuario o clave incorrectos.')
      }
    }
    return
  }

  const usuarioEncontrado = usuariosSistema.find(
    (usuario) =>
      (usuario.usuario?.toLowerCase() === loginIdLimpio ||
        usuario.id?.toLowerCase() === loginIdLimpio) &&
      usuario.clave === claveLimpia
  )

  if (!usuarioEncontrado) {
    setErrorLogin('ID de usuario o clave incorrectos.')
    return
  }
  if (usuarioEncontrado.activo === false) {
  setErrorLogin('Este usuario está inactivo. Comuníquese con el administrador.')
  return
  }

  setUsuarioActual(usuarioEncontrado)
  setLoginUsuario('')
  setLoginClave('')
  setErrorLogin('')
}

const limpiarFormularioRestablecerClaveLogin = () => {
  setResetUsuarioId('')
  setResetClaveNueva('')
  setResetClaveConfirmacion('')
  setResetAdminId('')
  setResetAdminClave('')
  setErrorResetClave('')
}

const limpiarSeguridadRestablecerSesion = () => {
  setConfirmacionIdRestablecer('')
  setAutorizacionAdminIdRestablecer('')
  setAutorizacionAdminClaveRestablecer('')
}

const validarAutorizacionAdministrador = (idAdmin, claveAdmin) => {
  const id = String(idAdmin || '').trim().toLowerCase()
  const clave = String(claveAdmin || '').trim()

  if (!id || !clave) {
    return {
      valido: false,
      mensaje: 'Indique el ID y la clave del administrador autorizador.',
    }
  }

  const administrador = usuariosSistema.find(
    (usuario) =>
      (usuario.usuario?.toLowerCase() === id || usuario.id?.toLowerCase() === id) &&
      usuario.rol === 'Administrador' &&
      usuario.clave === clave &&
      usuario.activo !== false
  )

  if (!administrador) {
    return {
      valido: false,
      mensaje: 'La autorización del administrador no es válida.',
    }
  }

  return { valido: true, administrador }
}

const restablecerClaveDesdeLogin = () => {
  if (usaApiRemota()) {
    setErrorResetClave('El restablecimiento desde acceso aún no está disponible con servidor remoto.')
    return
  }

  const idUsuario = resetUsuarioId.trim().toLowerCase()
  const claveNueva = resetClaveNueva.trim()
  const confirmacion = resetClaveConfirmacion.trim()
  const idAdmin = resetAdminId.trim().toLowerCase()
  const claveAdmin = resetAdminClave.trim()

  if (!idUsuario || !claveNueva || !confirmacion || !idAdmin || !claveAdmin) {
    setErrorResetClave('Complete todos los campos para restablecer la clave.')
    return
  }

  if (claveNueva.length < 4) {
    setErrorResetClave('La nueva clave debe tener mínimo 4 caracteres.')
    return
  }

  if (claveNueva !== confirmacion) {
    setErrorResetClave('La nueva clave y la confirmación no coinciden.')
    return
  }

  const autorizacion = validarAutorizacionAdministrador(idAdmin, claveAdmin)
  if (!autorizacion.valido) {
    setErrorResetClave(autorizacion.mensaje)
    return
  }

  const administrador = autorizacion.administrador

  const usuarioObjetivo = usuariosSistema.find(
    (usuario) =>
      usuario.usuario?.toLowerCase() === idUsuario || usuario.id?.toLowerCase() === idUsuario
  )

  if (!usuarioObjetivo) {
    setErrorResetClave('No existe un usuario con ese ID.')
    return
  }

  if (usuarioObjetivo.activo === false) {
    setErrorResetClave('Ese usuario está inactivo. El administrador debe activarlo primero.')
    return
  }

  const usuariosActualizados = usuariosSistema.map((usuario) =>
    usuario.usuario === usuarioObjetivo.usuario
      ? { ...usuario, clave: claveNueva }
      : usuario
  )

  setUsuariosSistema(usuariosActualizados)
  setHistorialCambios((prev) => [
    {
      id: `HIST-${Date.now()}`,
      fecha: new Date().toISOString(),
      usuario: administrador.usuario,
      nombreUsuario: administrador.nombre,
      accion: 'Restablecimiento de clave',
      modulo: 'Usuarios',
      entidadId: usuarioObjetivo.usuario,
      detalle: `Clave restablecida desde acceso para ${usuarioObjetivo.usuario}`,
      valorAnterior: '',
      valorNuevo: 'Clave actualizada',
    },
    ...prev,
  ])

  limpiarFormularioRestablecerClaveLogin()
  setMostrarRestablecerClaveLogin(false)
  setLoginUsuario(usuarioObjetivo.usuario)
  setLoginClave('')
  setErrorLogin('')
  alert(
    `Clave restablecida para ${usuarioObjetivo.usuario}. Ya puede iniciar sesión con la nueva clave.`
  )
}

const cerrarSesion = () => {
  if (usaApiRemota()) limpiarTokenSesion()
  setUsuarioActual(null)
  setSeccionActiva('inicio')
  cerrarFormularios()
}
const cambiarClaveUsuario = () => {
  if (!claveActual || !claveNueva || !claveConfirmacion) {
    alert('Complete la clave actual, la nueva clave y la confirmación.')
    return
  }

  if (claveActual !== usuarioActual.clave) {
    alert('La clave actual no es correcta.')
    return
  }

  if (claveNueva.length < 4) {
    alert('La nueva clave debe tener mínimo 4 caracteres.')
    return
  }

  if (claveNueva !== claveConfirmacion) {
    alert('La nueva clave y la confirmación no coinciden.')
    return
  }

  const usuariosActualizados = usuariosSistema.map((usuario) =>
    usuario.usuario === usuarioActual.usuario
      ? { ...usuario, clave: claveNueva }
      : usuario
  )

  const usuarioActualizado = {
    ...usuarioActual,
    clave: claveNueva,
  }

  setUsuariosSistema(usuariosActualizados)
  setUsuarioActual(usuarioActualizado)

  setClaveActual('')
  setClaveNueva('')
  setClaveConfirmacion('')
  setMostrarCambioClave(false)

  alert('Clave actualizada correctamente.')
}

const restablecerClaveUsuarioSesion = () => {
  if (!confirmacionIdRestablecer.trim()) {
    alert('Confirme su ID de usuario para continuar.')
    return
  }

  const idConfirmado = confirmacionIdRestablecer.trim().toLowerCase()
  const idSesion = String(usuarioActual.usuario || usuarioActual.id || '')
    .trim()
    .toLowerCase()

  if (idConfirmado !== idSesion) {
    alert('El ID confirmado no coincide con su usuario en sesión.')
    return
  }

  const autorizacion = validarAutorizacionAdministrador(
    autorizacionAdminIdRestablecer,
    autorizacionAdminClaveRestablecer
  )
  if (!autorizacion.valido) {
    alert(autorizacion.mensaje)
    return
  }

  if (!claveNueva || !claveConfirmacion) {
    alert('Indique la nueva clave y su confirmación.')
    return
  }

  if (claveNueva.length < 4) {
    alert('La nueva clave debe tener mínimo 4 caracteres.')
    return
  }

  if (claveNueva !== claveConfirmacion) {
    alert('La nueva clave y la confirmación no coinciden.')
    return
  }

  const usuariosActualizados = usuariosSistema.map((usuario) =>
    usuario.usuario === usuarioActual.usuario
      ? { ...usuario, clave: claveNueva.trim() }
      : usuario
  )

  setUsuariosSistema(usuariosActualizados)
  setUsuarioActual({
    ...usuarioActual,
    clave: claveNueva.trim(),
  })

  registrarHistorial({
    modulo: 'Usuarios',
    accion: 'Restablecimiento de clave',
    entidadId: usuarioActual.usuario,
    detalle: `Clave restablecida con autorización de ${autorizacion.administrador.usuario}`,
    valorAnterior: '',
    valorNuevo: 'Clave actualizada',
  })

  setClaveActual('')
  setClaveNueva('')
  setClaveConfirmacion('')
  limpiarSeguridadRestablecerSesion()
  setModoClaveSesion('cambiar')
  setMostrarCambioClave(false)

  alert('Clave restablecida correctamente.')
}

