   const cambiarSeccion = (seccion, opciones = {}) => {
  const { claveSubmenu = null, grupoMenu = null, vista = null, limpiarContexto = true } = opciones
  const esCambioModulo = seccion !== seccionActiva

  if (limpiarContexto && esCambioModulo) {
    setPredioSeleccionado(null)
    setContratoSeleccionado(null)
    setUnidadSeleccionadaServicios(null)
    setMostrarFormularioNuevoServicioUnidad(false)
    setServicioUnidadEditandoIndex(null)
  }

  if (limpiarContexto) {
    cerrarFormularios()
  }

  if (seccion === 'estados' && esCambioModulo) {
    setTipoEstadoCuentaActivo('')
    setBusquedaEstadoCuentaPredial('')
    setCodigoPredioEstadoCuenta('')
    setBusquedaEstadoCuentaArriendo('')
    setIdContratoEstadoCuenta('')
    setBusquedaEstadoCuentaServicios('')
    setClaveExtractoServicioEstadoCuenta('')
  }

  if (esCambioModulo) {
    if (claveSubmenu) {
      activarSubmenu(seccion, claveSubmenu, grupoMenu || undefined)
    } else {
      setModuloMenuActivo(seccion === 'inicio' ? '' : seccion)
      setClaveSubmenuActiva('')
      setGrupoMenuActivoPersistente('')
      sincronizarMenuAbierto(seccion, grupoMenu || GRUPO_POR_SECCION[seccion] || '')
    }
  } else if (claveSubmenu) {
    activarSubmenu(seccion, claveSubmenu, grupoMenu || undefined)
  }

  setSeccionActiva(seccion)
  setVistaActiva(vista || seccion)
  if (!claveSubmenu && !esCambioModulo) {
    sincronizarMenuAbierto(seccion, grupoMenuActivoPersistente)
  }
  window.scrollTo({ top: 0, behavior: 'smooth' })
}

