  const obtenerPropietariosEnriquecidos = (codigoPredio = null) => {
    let relaciones = predioPropietarios
    if (codigoPredio) {
      relaciones = relaciones.filter((rel) => rel.codigoPredio === codigoPredio)
    }

    return relaciones
      .map((rel) => {
        const propietario = propietarios.find((item) => item.id === rel.idPropietario)
        if (!propietario) return null
        return {
          ...propietario,
          codigoPredio: rel.codigoPredio,
          porcentaje: rel.porcentaje,
          fechaInicio: rel.fechaInicio,
        }
      })
      .filter(Boolean)
  }

  const obtenerPrediosDelPropietario = (idPropietario) =>
    predioPropietarios
      .filter((rel) => rel.idPropietario === idPropietario)
      .map((rel) => {
        const predio = predios.find((item) => item.codigo === rel.codigoPredio)
        return {
          ...rel,
          predio,
        }
      })

