  const vincularPropietariosAPredio = (
    codigoPredio,
    listaTemporales,
    propietariosBase = null
  ) => {
    let propietariosActualizados = [...(propietariosBase || propietarios)]
    const relacionesNuevas = []

    listaTemporales.forEach((temporal) => {
      let idPropietario = temporal.idPropietario

      if (!idPropietario) {
        const existente = propietariosActualizados.find(
          (item) =>
            item.tipoDocumento === temporal.tipoDocumento &&
            item.numeroDocumento === (temporal.numeroDocumento || '').trim()
        )

        if (existente) {
          idPropietario = existente.id
          propietariosActualizados = propietariosActualizados.map((item) =>
            item.id === idPropietario
              ? {
                  ...item,
                  nombre: (temporal.nombre || item.nombre || '').trim().toUpperCase() || item.nombre,
                  telefono: temporal.telefono?.trim() || item.telefono || '',
                  correo: (temporal.correo || item.correo || '').trim().toUpperCase() || item.correo,
                  direccion: temporal.direccion?.trim() || item.direccion || '',
                  esDepositante: Boolean(item.esDepositante || temporal.esDepositante),
                }
              : item
          )
        } else {
          idPropietario = generarIdPropietario()
          propietariosActualizados.push({
            id: idPropietario,
            nombre: temporal.nombre.trim().toUpperCase(),
            tipoDocumento: temporal.tipoDocumento,
            numeroDocumento: temporal.numeroDocumento.trim(),
            telefono: temporal.telefono.trim(),
            correo: temporal.correo.trim().toUpperCase(),
            direccion: temporal.direccion || '',
            esDepositante: Boolean(temporal.esDepositante),
          })
        }
      } else {
        propietariosActualizados = propietariosActualizados.map((item) =>
          item.id === idPropietario
            ? {
                ...item,
                nombre: (temporal.nombre || item.nombre || '').trim().toUpperCase() || item.nombre,
                telefono: temporal.telefono?.trim() || item.telefono || '',
                correo: (temporal.correo || item.correo || '').trim().toUpperCase() || item.correo,
                direccion: temporal.direccion?.trim() || item.direccion || '',
                esDepositante: Boolean(item.esDepositante || temporal.esDepositante),
              }
            : item
        )
      }

      relacionesNuevas.push({
        codigoPredio,
        idPropietario,
        porcentaje: Number(temporal.porcentaje || 0),
        fechaInicio: temporal.fechaInicio || new Date().toISOString().slice(0, 10),
      })
    })

    return {
      propietariosActualizados,
      relacionesNuevas,
    }
  }

  const obtenerArrendadoresContrato = (contrato) => {
  if (!contrato) return []

  return obtenerPropietariosEnriquecidos(contrato.codigoPredio).map((propietario) => ({
      ...propietario,
      valorCanonCorrespondiente:
        (Number(contrato.canonMensual || 0) * Number(propietario.porcentaje || 0)) / 100,
    }))
}

  const obtenerAdministracionContrato = (contrato, anioPago) => {
  if (!contrato || contrato.aplicaAdministracion !== 'Sí') return 0

  const idContratoActual = obtenerIdContrato(contrato)

  const ajusteAplicable = ajustesAdministracion
    .filter(
      (ajuste) =>
        ajuste.idContrato === idContratoActual &&
        Number(ajuste.anio) <= Number(anioPago)
    )
    .sort((a, b) => Number(b.anio) - Number(a.anio))[0]

  if (ajusteAplicable) {
    return Number(ajusteAplicable.valorAdministracion || 0)
  }

  return Number(contrato.valorAdministracion || 0)
}

  const calcularDiasSinGestion = (fechaBase, fechaReferencia = '') => {
  if (!fechaBase) return 0

  const fechaCorte = fechaReferencia
    ? new Date(`${fechaReferencia}T00:00:00`)
    : new Date()
  const fecha = new Date(`${fechaBase}T00:00:00`)

  fechaCorte.setHours(0, 0, 0, 0)

  const diferencia = fechaCorte - fecha
  const dias = Math.floor(diferencia / (1000 * 60 * 60 * 24))

  return dias > 0 ? dias : 0
}

