  const actualizarInmuebleVinculadoContratoDeposito = (codigoPredio, idContratoDeposito) => {
    if (!ciudad || !barrio || !direccion || !matricula || !chip || !cedulaCatastral) {
      alert(
        'Complete los datos del inmueble: ciudad, barrio, dirección, matrícula, CHIP y cédula catastral.'
      )
      return false
    }

    const predioExistente = predios.find((item) => item.codigo === codigoPredio)
    if (!predioExistente) {
      alert('No se encontró el inmueble vinculado al documento de administración.')
      return false
    }

    const prediosActualizados = predios.map((predio) =>
      predio.codigo === codigoPredio
        ? {
            ...predio,
            idDocumento: idContratoDeposito || predio.idDocumento || '',
            ciudad: ciudad.trim().toUpperCase(),
            barrio: barrio.trim().toUpperCase(),
            direccion: direccion.trim().toUpperCase(),
            cantidadUnidades: Number(cantidadUnidadesPredio || 1),
            matricula: matricula.trim().toUpperCase(),
            chip: chip.trim().toUpperCase(),
            cedulaCatastral: cedulaCatastral.trim(),
            numeroLotePredio: numeroLotePredio.trim(),
            avaluoCatastral: avaluoCatastralPredio ? Number(avaluoCatastralPredio) : null,
            observaciones: observacionesPredio.trim(),
          }
        : predio
    )

    setPredios(prediosActualizados)

    let propietariosParaVincular = propietariosTemporales

    if (
      !propietariosParaVincular.length &&
      depCalidadContratante === 'Propietario' &&
      depIdContratante
    ) {
      propietariosParaVincular = prepararPropietariosInmuebleContrato(
        depIdContratante,
        propietarios
      )
    }

    if (propietariosParaVincular.length) {
      const totalParticipacion = propietariosParaVincular.reduce(
        (total, item) => total + Number(item.porcentaje || 0),
        0
      )

      if (totalParticipacion !== 100) {
        alert(
          `Los propietarios del inmueble deben sumar 100%. Actualmente suman ${totalParticipacion}%.`
        )
        return false
      }

      const { propietariosActualizados, relacionesNuevas } = vincularPropietariosAPredio(
        codigoPredio,
        propietariosParaVincular,
        propietarios
      )

      setPropietarios(propietariosActualizados)
      setPredioPropietarios((relacionesActuales) => [
        ...relacionesActuales.filter((relacion) => relacion.codigoPredio !== codigoPredio),
        ...relacionesNuevas,
      ])
    }

    return true
  }

