    setDepContratanteTipoDoc(contratante.tipoDocumento || 'Cédula de ciudadanía')
    setDepContratanteDocumento(contratante.numeroDocumento || '')
    setDepContratanteTelefono(contratante.telefono || '')
    setDepContratanteWhatsapp(contratante.whatsapp || '')
