    setDepContratanteDireccion(contratante.direccion || '')
    setDepRepLegalNombre(representanteLegal?.nombre || '')
    setDepRepLegalTipoDoc(representanteLegal?.tipoDocumento || 'Cédula de ciudadanía')
    setDepRepLegalDocumento(representanteLegal?.numeroDocumento || '')
    setDepRepLegalTelefono(representanteLegal?.telefono || '')
