  const registrarContratanteEnMaestro = (idContratanteActual = null) => {
    const tipoDocumentoDepositante = depContratanteTipoDoc
    const documentoLimpio = depContratanteDocumento.trim()
    const payloadDepositante = {
      nombre: depContratanteNombre.trim().toUpperCase(),
      tipoDocumento: tipoDocumentoDepositante,
      numeroDocumento: documentoLimpio,
      telefono: depContratanteTelefono.trim(),
      whatsapp: depContratanteWhatsapp.trim(),
      correo: depContratanteCorreo.trim().toUpperCase(),
      direccion: depContratanteDireccion.trim(),
      esDepositante: true,
    }

    const existente =
      propietarios.find(
        (item) =>
          item.tipoDocumento === tipoDocumentoDepositante &&
          item.numeroDocumento === documentoLimpio
      ) ||
      (idContratanteActual
        ? propietarios.find((item) => item.id === idContratanteActual)
        : null)

    let propietariosActualizados = [...propietarios]
    let idContratante = existente?.id

    if (existente) {
      propietariosActualizados = propietariosActualizados.map((item) =>
        item.id === existente.id ? { ...item, ...payloadDepositante } : item
      )
    } else {
      idContratante = generarIdPropietario()
      propietariosActualizados = [
        { id: idContratante, ...payloadDepositante },
        ...propietariosActualizados,
      ]
    }

    let idRepresentanteLegal = ''

    propietariosActualizados = propietariosActualizados.map((item) =>
      item.id === idContratante ? { ...item, idRepresentanteLegal: '' } : item
    )

    return {
      idContratante,
      idRepresentanteLegal,
      numeroIdentificacionDepositante: documentoLimpio,
      propietariosActualizados,
    }
  }

