const abrirEstadoCuentaServicioDesdeUnidad = (unidad, servicioIndex, origenVista) => {
  const extractoServicio = extractosServiciosPublicos.find((extracto) =>
    extractoPerteneceAUnidadServicio(extracto, unidad, servicioIndex)
  )

  if (!extractoServicio) {
    alert('No se encontró el estado de cuenta de este servicio.')
    return
  }

  cerrarFormularios()
  setOrigenEstadoCuentaServicios({
    vista: origenVista,
    idUnidad: unidad.id,
    codigoPredio: unidad.codigoPredio,
    busquedaPredios: origenVista === 'predios' ? busquedaPredios : '',
    mostrarTodosPredios: origenVista === 'predios' ? mostrarTodosPredios : false,
    busquedaUnidades: origenVista === 'unidades' ? busquedaUnidades : '',
    mostrarTodasUnidades: origenVista === 'unidades' ? mostrarTodasUnidades : false,
  })
  setContratoSeleccionado(null)

  if (origenVista !== 'predios') {
    setPredioSeleccionado(null)
  }

  setSeccionActiva('servicios')
  setVistaActiva('estadoCuentaServicios')
  setBusquedaServicios(unidad.id)
  setServicioEstadoCuentaSeleccionado(extractoServicio)
  window.scrollTo({ top: 0, behavior: 'smooth' })
}

const regresarVistaUnidadServicios = () => {
  if (!origenEstadoCuentaServicios) return

  const origen = origenEstadoCuentaServicios
  const unidad = unidadesNegocio.find(
    (item) =>
      item.id === origen.idUnidad && item.codigoPredio === origen.codigoPredio
  )

  cancelarFormularioServicioUnidad()
  setServicioEstadoCuentaSeleccionado(null)
  setBusquedaServicios('')
  setOrigenEstadoCuentaServicios(null)

  if (origen.vista === 'predios') {
    const predio = predios.find((item) => item.codigo === origen.codigoPredio)

    setSeccionActiva('depositos')
    setVistaActiva('predios')
    setBusquedaPredios(origen.busquedaPredios || '')
    setMostrarTodosPredios(!!origen.mostrarTodosPredios)
    setPredioSeleccionado(predio || null)
    setContratoSeleccionado(null)

    if (unidad) {
      setUnidadSeleccionadaServicios(unidad)
    }
  } else if (origen.vista === 'unidades') {
    setSeccionActiva('arriendos')
    setVistaActiva('unidades')
    setBusquedaUnidades(origen.busquedaUnidades || '')
    setMostrarTodasUnidades(!!origen.mostrarTodasUnidades)
    setPredioSeleccionado(null)
    setContratoSeleccionado(null)

    if (unidad) {
      setUnidadSeleccionadaServicios(unidad)
    }
  }

  window.scrollTo({ top: 0, behavior: 'smooth' })
}

