const guardarServicioUnidadExistente = () => {
  if (!puedeRegistrar) {
    alert('No tiene permisos para guardar servicios.')
    return
  }

  if (!unidadSeleccionadaServicios) {
    alert('Seleccione una unidad de negocio.')
    return
  }

  if (servicioUnidadEditandoIndex != null && !puedeAdministrar) {
    alert('Solo el administrador puede editar servicios.')
    return
  }

  const nuevoServicio = construirServicioDesdeFormularioUnidad()
  if (!nuevoServicio) return

  const serviciosActuales = [...(unidadSeleccionadaServicios.serviciosPublicos || [])]

  if (servicioUnidadEditandoIndex != null) {
    serviciosActuales[servicioUnidadEditandoIndex] = nuevoServicio
    actualizarServiciosUnidadSeleccionada(serviciosActuales)
    cancelarFormularioServicioUnidad()
    alert('Servicio actualizado correctamente.')
    return
  }

  actualizarServiciosUnidadSeleccionada([...serviciosActuales, nuevoServicio])
  cancelarFormularioServicioUnidad()
  alert('Servicio agregado correctamente a la unidad.')
}

const eliminarServicioUnidadExistente = (index) => {
  if (!puedeAdministrar) {
    alert('Solo el administrador puede eliminar servicios.')
    return
  }

  if (!unidadSeleccionadaServicios) return

  const idServicio = generarIdServicioUnidad(unidadSeleccionadaServicios, index)
  const facturasAsociadas = facturasServiciosPublicos.filter(
    (factura) =>
      facturaPerteneceAUnidadServicio(factura, unidadSeleccionadaServicios, index, idServicio)
  )

  if (facturasAsociadas.length > 0) {
    const continuar = confirm(
      `Este servicio tiene ${facturasAsociadas.length} factura(s) registrada(s). ¿Desea eliminarlo de todas formas?`
    )
    if (!continuar) return
  } else if (
    !confirm('¿Desea eliminar este servicio de la unidad?')
  ) {
    return
  }

  const serviciosActualizados = (unidadSeleccionadaServicios.serviciosPublicos || []).filter(
    (_, servicioIndex) => servicioIndex !== index
  )

  actualizarServiciosUnidadSeleccionada(serviciosActualizados)
  cancelarFormularioServicioUnidad()
  alert('Servicio eliminado correctamente.')
}

