const reimprimirReciboPagoCatalogo = ({
  item,
  contratosArriendo,
  predios,
  formatearDinero,
  imprimirReciboPagoArriendo,
  imprimirReciboServicioPublico,
}) => {
  if (!item) {
    alert('Seleccione un recibo para imprimir.')
    return
  }

  if (item.tipo === 'arriendo') {
    const contrato = contratosArriendo.find(
      (registro) => obtenerIdContrato(registro) === item.pago.idContrato
    )
    imprimirReciboPagoArriendo({
      ...item.pago,
      predio: predios.find((predio) => predio.codigo === item.pago.codigoPredio),
      contrato,
    })
    return
  }

  if (item.tipo === 'servicios') {
    imprimirReciboServicioPublico(item.pago)
    return
  }

  imprimirReciboPagoGenerico(item, formatearDinero)
}

  const limpiarFormularioPagoArriendo = () => {
    setIdContratoPagoArriendo('')
    setConceptoPagoArriendo(CONCEPTO_PAGO_CANON_ARRIENDO)
    setCodigoPredioPagoArriendo('')
    setMesPagoArriendo('')
    setFechaPagoArriendo('')
    setValorPagadoArriendo('')
    setDescuentoArriendo('')
    setMedioPagoArriendo('Transferencia')
    setReciboPagoArriendo('')
    setObservacionesPagoArriendo('')
  }

  const limpiarEstadoPagoArriendo = () => {
    limpiarFormularioPagoArriendo()
    setBusquedaContratoPagoArriendo('')
    setMostrarTodosContratosPagoArriendo(false)
    setReciboArriendoImprimir(null)
  }

// =============================================================================
// ACCIONES - CARTERA DE ARRIENDOS
// Gestion de cobranza, llamadas y promesas de pago.
// =============================================================================

  const guardarGestionCartera = () => {
  if (!puedeRegistrar) {
    alert('No tiene permisos para registrar gestiones de cartera.')
    return
  }

  if (!contratoGestionCartera) {
    alert('Seleccione un contrato para gestionar.')
    return
  }

  if (!estadoGestionCartera || !observacionGestionCartera.trim()) {
    alert('Seleccione el estado de la gestión y escriba la observación de la llamada.')
    return
  }

  if (estadoGestionCartera === 'Promesa de pago' && !fechaPromesaPagoCartera) {
  alert('Debe registrar la fecha prometida de pago.')
  return
}

if (
  estadoGestionCartera === 'Promesa de pago' &&
  fechaPromesaPagoCartera < fechaCorteCartera
) {
  alert('La fecha prometida de pago no puede ser anterior a la fecha de gestión.')
  return
}

  const contratoGestion = contratosArriendo.find(
    (contrato) => obtenerIdContrato(contrato) === contratoGestionCartera.idContrato
  )
  const movimientoGestionCartera = contratoGestion
    ? calcularMovimientoArriendoMes(contratoGestion, contratoGestionCartera.mes, {
        idContrato: obtenerIdContrato(contratoGestion),
        fechaCorteMora: fechaCorteCartera || obtenerFechaLocalISO(),
        ...construirContextoCalculoArriendo({
          pagosArriendo,
          incrementosArriendo,
          ajustesAdministracion,
          gestionesCartera,
        }),
      })
    : null
  const gastosCobranzaGestion = Number(movimientoGestionCartera?.sancionCobranza || 0)

  const nuevaGestion = {
    id: `GES-${Date.now()}`,
    idContrato: contratoGestionCartera.idContrato,
    numeroContrato: contratoGestionCartera.numeroContrato,
    codigoPredio: contratoGestionCartera.codigoPredio,
    idUnidad: contratoGestionCartera.idUnidad,
    nombreUnidad: contratoGestionCartera.nombreUnidad,
    tipoUnidad: contratoGestionCartera.tipoUnidad,
    mes: contratoGestionCartera.mes,
    fechaGestion: fechaCorteCartera,
    usuarioGestion: usuarioActual?.nombre || 'Sin usuario',
    arrendatario: contratoGestionCartera.arrendatario,
    telefono: contratoGestionCartera.telefono,
    correo: contratoGestionCartera.correo,
    whatsapp: contratoGestionCartera.whatsapp || '',
    estadoGestion: estadoGestionCartera,
    fechaPromesaPago: fechaPromesaPagoCartera,
    mora: Number(moraGestionCartera || 0),
    sancionCobranza: gastosCobranzaGestion,
    observacion: observacionGestionCartera.trim(),
  }

  setGestionesCartera([nuevaGestion, ...gestionesCartera])

  setContratoGestionCartera(null)
  setEstadoGestionCartera('Contactado')
  setFechaPromesaPagoCartera('')
  setMoraGestionCartera('')
  setObservacionGestionCartera('')

  if (estadoGestionCartera === 'Promesa de pago' && fechaPromesaPagoCartera) {
  alert(
    `Gestión guardada. El contrato volverá a cartera el ${fechaPromesaPagoCartera} si no registra pago.`
  )
} else {
  alert('Gestión de cartera guardada correctamente.')
}
}

// =============================================================================
// ACCIONES - INCREMENTOS DE ARRIENDO
// Registrar incrementos contractuales de canon.
// =============================================================================

  const guardarIncremento = () => {
      if (!puedeRegistrar) {
    alert('No tiene permisos para actualizar incrementos.')
    return
    }
    if (!codigoPredioIncremento || !anioIncremento || !porcentajeIncremento) {
      alert('Complete predio, año y porcentaje.')
      return
    }

    const nuevoIncremento = {
  codigoPredio: codigoPredioIncremento,
  anio: Number(anioIncremento),
  porcentaje: Number(porcentajeIncremento),
  observaciones: observacionesIncremento.trim(),
}

    const sinRepetido = incrementosArriendo.filter(
      (item) =>
        !(item.codigoPredio === codigoPredioIncremento && Number(item.anio) === Number(anioIncremento))
    )

    setIncrementosArriendo([nuevoIncremento, ...sinRepetido])
    setCodigoPredioIncremento('')
    setAnioIncremento(anioActual)
    setPorcentajeIncremento('')
    setObservacionesIncremento('')
    setMostrarFormularioIncremento(false)
    setVistaActiva('arriendos')
  }

// =============================================================================
// ACCIONES - ADMINISTRACION DE ARRIENDO
// Ajustes y pagos de administracion.
// =============================================================================

  const guardarAjusteAdministracion = () => {
  if (!puedeRegistrar) {
    alert('No tiene permisos para actualizar administración.')
    return
  }

  if (!idContratoAdministracion || !anioAdministracion || !valorAdministracionNueva) {
    alert('Complete contrato, año y nuevo valor de administración.')
    return
  }

  const contrato = contratosArriendo.find(
    (contrato) => obtenerIdContrato(contrato) === idContratoAdministracion
  )

  if (!contrato) {
    alert('El contrato seleccionado no existe.')
    return
  }

  const nuevoAjuste = {
    idContrato: obtenerIdContrato(contrato),
    codigoPredio: contrato.codigoPredio,
    idUnidad: contrato.idUnidad || '',
    nombreUnidad: contrato.nombreUnidad || '',
    anio: Number(anioAdministracion),
    valorAdministracion: Number(valorAdministracionNueva || 0),
    observaciones: observacionesAdministracion.trim(),
  }

  const sinRepetido = ajustesAdministracion.filter(
    (item) =>
      !(
        item.idContrato === nuevoAjuste.idContrato &&
        Number(item.anio) === Number(nuevoAjuste.anio)
      )
  )

  setAjustesAdministracion([nuevoAjuste, ...sinRepetido])

  setIdContratoAdministracion('')
  setAnioAdministracion(anioActual)
  setValorAdministracionNueva('')
  setObservacionesAdministracion('')
  setMostrarFormularioAdministracion(false)
  setVistaActiva('arriendos')

  alert('Administración actualizada correctamente.')
}

// =============================================================================
// ACCIONES - IMPUESTO PREDIAL - VALOR ANUAL
// Registrar valor predial y avaluo por vigencia.
// =============================================================================

  const guardarValorPredial = () => {
      if (!puedeRegistrar) {
    alert('No tiene permisos para registrar valores prediales.')
    return
    }
    if (!codigoPredioValorPredial || !anioValorPredial || !valorPredialAnual || !valorAvaluoCatastralPredial) {
      alert('Complete predio, año, valor predial y avalúo catastral del año.')
      return
    }

    const existe = valoresPrediales.some(
      (item) => item.codigoPredio === codigoPredioValorPredial && Number(item.anio) === Number(anioValorPredial)
    )

    if (existe) {
      alert('Ese año ya tiene valor predial registrado.')
      return
    }

    const valorAvaluoCatastral = Number(valorAvaluoCatastralPredial || 0)

    setValoresPrediales([
  {
    codigoPredio: codigoPredioValorPredial,
    anio: Number(anioValorPredial),
    valorImpuesto: Number(valorPredialAnual || 0),
    valorAvaluoCatastral,
    fechaLimite: fechaLimitePredial || '',
  },
  ...valoresPrediales,
])

    setPredios((prev) =>
      prev.map((predio) =>
        predio.codigo === codigoPredioValorPredial
          ? { ...predio, avaluoCatastral: valorAvaluoCatastral }
          : predio
      )
    )

    setCodigoPredioValorPredial('')
    setAnioValorPredial(anioActual)
    setValorPredialAnual('')
    setValorAvaluoCatastralPredial('')
    setFechaLimitePredial('')
    setMostrarFormularioValorPredial(false)
  }

  const claveActualizacionPredial = (codigoPredio, anio) => `${codigoPredio}-${anio}`

  const cambiarFormularioActualizacionPredial = (codigoPredio, anio, campo, valor) => {
    const clave = claveActualizacionPredial(codigoPredio, anio)
    setFormulariosActualizacionPredial((prev) => ({
      ...prev,
      [clave]: {
        valorImpuesto: '',
        valorAvaluoCatastral: '',
        fechaLimite: '',
        ...prev[clave],
        [campo]: valor,
      },
    }))
  }

// =============================================================================
// ACCIONES - IMPUESTO PREDIAL - ACTUALIZAR VIGENCIA
// Actualizar vigencias prediales pendientes.
// =============================================================================

  const guardarActualizacionPredialAnio = (codigoPredio, anio) => {
    if (!puedeRegistrar) {
      alert('No tiene permisos para actualizar valores prediales.')
      return
    }

    const clave = claveActualizacionPredial(codigoPredio, anio)
    const formulario = formulariosActualizacionPredial[clave] || {}

    if (!formulario.valorImpuesto) {
      alert('Indique el valor del impuesto predial para esta vigencia.')
      return
    }

    if (!formulario.valorAvaluoCatastral) {
      alert('Indique el avalúo catastral correspondiente a esta vigencia.')
      return
    }

    const existe = valoresPrediales.some(
      (item) => item.codigoPredio === codigoPredio && Number(item.anio) === Number(anio)
    )

    if (existe) {
      alert('Esa vigencia ya tiene valor predial registrado.')
      return
    }

    const valorImpuesto = Number(formulario.valorImpuesto || 0)
    const valorAvaluoCatastral = Number(formulario.valorAvaluoCatastral || 0)
    const fechaLimite = formulario.fechaLimite || ''

    setValoresPrediales([
      {
        codigoPredio,
        anio: Number(anio),
        valorImpuesto,
        valorAvaluoCatastral,
        fechaLimite,
      },
      ...valoresPrediales,
    ])

    setPredios((prev) =>
      prev.map((predio) =>
        predio.codigo === codigoPredio ? { ...predio, avaluoCatastral: valorAvaluoCatastral } : predio
      )
    )

    const pagosDelAnio = pagosPrediales.filter(
      (item) => item.codigoPredio === codigoPredio && Number(item.anio) === Number(anio)
    )
    const totalPagado = pagosDelAnio.reduce(
      (total, pago) => total + Number(pago.valorPagado || 0),
      0
    )
    const totalDescuento = pagosDelAnio.reduce(
      (total, pago) => total + Number(pago.descuento || 0),
      0
    )
    const totalIntereses = pagosDelAnio.reduce(
      (total, pago) => total + Number(pago.intereses || 0),
      0
    )
    const totalAPagar = valorImpuesto - totalDescuento + totalIntereses
    const saldoPendiente = totalAPagar - totalPagado

    setFormulariosActualizacionPredial((prev) => {
      const copia = { ...prev }
      delete copia[clave]
      return copia
    })

    alert(
      `Vigencia ${anio} actualizada.\n` +
        `Total a pagar: ${formatearDinero(totalAPagar)}\n` +
        `Pagado: ${formatearDinero(totalPagado)}\n` +
        `Saldo pendiente: ${formatearDinero(saldoPendiente)}`
    )
  }

