  const extractosPrediales = predios.map((predio) => {
    const movimientos = []
    const anioInicio = obtenerAnioInicioVigenciasPredial(
      predio,
      contratosDeposito,
      anioActual
    )

    for (let anio = anioInicio; anio <= anioActual; anio++) {
      const valorAnual = valoresPrediales.find(
        (item) => item.codigoPredio === predio.codigo && Number(item.anio) === Number(anio)
      )

      const pagosDelAnio = pagosPrediales.filter(
        (item) => item.codigoPredio === predio.codigo && Number(item.anio) === Number(anio)
      )

      const pagosDetalle = ordenarPagosPredialCronologico(pagosDelAnio).map((pago, index) => ({
        id: pago.id || `PAG-PRED-${predio.codigo}-${anio}-${index}`,
        fechaPago: pago.fechaPago || 'Sin pago',
        recibo: pago.numeroRecibo || 'Sin recibo',
        descuento: Number(pago.descuento || 0),
        intereses: Number(pago.intereses || 0),
        valorPagado: Number(pago.valorPagado || 0),
        documentoPago: pago.documentoPago || null,
      }))

      const totalPagado = pagosDetalle.reduce(
        (total, pago) => total + Number(pago.valorPagado || 0),
        0
      )
      const totalDescuento = pagosDetalle.reduce(
        (total, pago) => total + Number(pago.descuento || 0),
        0
      )
      const totalIntereses = pagosDetalle.reduce(
        (total, pago) => total + Number(pago.intereses || 0),
        0
      )
      const ultimoPago = pagosDetalle[pagosDetalle.length - 1]

      let valorAPagar = null
      let saldoPendiente = null
      let estadoMovimiento = 'Falta actualizar valor'

      let totalAPagar = null

      if (valorAnual) {
        valorAPagar = Number(valorAnual.valorImpuesto || 0)
        totalAPagar = valorAPagar - totalDescuento + totalIntereses
        saldoPendiente = totalAPagar - totalPagado

        if (saldoPendiente <= 0) estadoMovimiento = 'Pagado / Al día'
        else if (totalPagado > 0) estadoMovimiento = 'Abono registrado'
        else estadoMovimiento = 'Pendiente de pago'
      }

      movimientos.push({
        anio,
        fechaLimite: valorAnual?.fechaLimite || 'Sin registrar',
        fechaPago: ultimoPago?.fechaPago || 'Sin pago',
        recibo: ultimoPago?.recibo || 'Sin recibo',
        pagosDetalle,
        valorAPagar,
        descuento: totalDescuento,
        intereses: totalIntereses,
        totalAPagar,
        valorPagado: totalPagado,
        saldoPendiente,
        estadoMovimiento,
      })
    }

    const totalImpuesto = movimientos.reduce((total, item) => total + Number(item.valorAPagar || 0), 0)
    const totalDescuento = movimientos.reduce((total, item) => total + Number(item.descuento || 0), 0)
    const totalIntereses = movimientos.reduce((total, item) => total + Number(item.intereses || 0), 0)
    const totalPagado = movimientos.reduce((total, item) => total + Number(item.valorPagado || 0), 0)
    const saldoPendiente = movimientos.reduce((total, item) => total + Number(item.saldoPendiente || 0), 0)

    const propietariosDelPredio = obtenerPropietariosEnriquecidos(predio.codigo)
    const totalParticipacion = propietariosDelPredio.reduce((total, item) => total + Number(item.porcentaje || 0), 0)
    const tienePendienteActualizar = movimientos.some((item) => item.estadoMovimiento === 'Falta actualizar valor')

    let estadoGeneral = 'Al día'
    if (tienePendienteActualizar) estadoGeneral = 'Pendiente de actualización'
    else if (saldoPendiente > 0) estadoGeneral = 'Con saldo pendiente'

    return {
      predio,
      propietarios: propietariosDelPredio,
      totalParticipacion,
      movimientos: movimientos.sort((a, b) => b.anio - a.anio),
      resumen: {
        totalImpuesto,
        totalDescuento,
        totalIntereses,
        totalPagado,
        saldoPendiente,
        estadoGeneral,
      },
    }
  })

  const extractosPredialesSeguimiento = extractosPrediales.filter((extracto) =>
    predioRequiereInformacionPredial(extracto.predio?.codigo, contratosDeposito)
  )

  const propietariosConPredios = propietarios.filter((propietario) =>
    predioPropietarios.some((rel) => rel.idPropietario === propietario.id)
  )

  const textoBusquedaPropietarioPredios = busquedaPropietarioPredios.trim().toLowerCase()

  const propietariosPrediosFiltrados =
    textoBusquedaPropietarioPredios || mostrarTodosPropietariosPredios
      ? propietariosConPredios.filter((propietario) => {
          if (mostrarTodosPropietariosPredios && !textoBusquedaPropietarioPredios) return true

          return [propietario.nombre, propietario.numeroDocumento, propietario.tipoDocumento].some(
            (valor) => String(valor || '').toLowerCase().includes(textoBusquedaPropietarioPredios)
          )
        })
      : []

  const extractoPrediosPorPropietarioActivo = propietarioExtractoPredios
    ? construirExtractoPrediosPorPropietario({
        idPropietario: propietarioExtractoPredios.id,
        predioPropietarios,
        predios,
        unidadesNegocio,
        extractosPrediales,
        valoresPrediales,
        contratosDeposito,
      })
    : null

