const textoBusquedaServicioFactura = busquedaServicioFactura.trim().toLowerCase()

const serviciosFacturaFiltrados = textoBusquedaServicioFactura
  ? serviciosPublicosDisponibles.filter((item) =>
      String(item.unidad.id || '').toLowerCase().includes(textoBusquedaServicioFactura) ||
      String(item.unidad.codigoPredio || '').toLowerCase().includes(textoBusquedaServicioFactura) ||
      String(item.unidad.nombre || '').toLowerCase().includes(textoBusquedaServicioFactura) ||
      String(item.unidad.tipo || '').toLowerCase().includes(textoBusquedaServicioFactura) ||
      String(item.servicio.tipo || '').toLowerCase().includes(textoBusquedaServicioFactura) ||
      String(item.servicio.empresa || '').toLowerCase().includes(textoBusquedaServicioFactura) ||
      String(item.servicio.numeroCuenta || '').toLowerCase().includes(textoBusquedaServicioFactura) ||
      String(item.servicio.responsable || '').toLowerCase().includes(textoBusquedaServicioFactura)
    )
  : []

  const textoBusquedaFacturaPagoServicio = busquedaFacturaPagoServicio.trim().toLowerCase()

const facturasPagoServicioFiltradas = textoBusquedaFacturaPagoServicio
  ? facturasServiciosPublicos
      .filter((factura) => factura.estado !== 'Pagada')
      .filter((factura) =>
        String(factura.nombreUnidad || '').toLowerCase().includes(textoBusquedaFacturaPagoServicio) ||
        String(factura.codigoPredio || '').toLowerCase().includes(textoBusquedaFacturaPagoServicio) ||
        String(factura.tipoServicio || '').toLowerCase().includes(textoBusquedaFacturaPagoServicio) ||
        String(factura.empresa || '').toLowerCase().includes(textoBusquedaFacturaPagoServicio) ||
        String(factura.numeroCuenta || '').toLowerCase().includes(textoBusquedaFacturaPagoServicio) ||
        String(factura.periodo || '').toLowerCase().includes(textoBusquedaFacturaPagoServicio) ||
        String(factura.numeroFactura || '').toLowerCase().includes(textoBusquedaFacturaPagoServicio)
      )
  : []

  const textoBusquedaServicios = busquedaServicios.trim().toLowerCase()

const resumenServiciosPublicos = serviciosPublicosDisponibles.map((item) => {
  const facturasServicio = facturasServiciosPublicos.filter((factura) =>
    facturaPerteneceAUnidadServicio(
      factura,
      item.unidad,
      item.servicioIndex,
      item.idServicio
    )
  )

  if (facturasServicio.length === 0) {
    if (item.servicio.tipoCobro === 'Valor fijo mensual') {
      const contratoActivo = obtenerContratoActivoUnidad(
        item.unidad.id,
        contratosArriendo,
        item.unidad.codigoPredio
      )

      if (contratoActivo?.fechaInicio) {
        const meses = generarMesesRango(
          contratoActivo.fechaInicio,
          contratoActivo.fechaFin || null
        )

        return meses.map((mes) => {
          const movimiento = calcularMovimientoServicioMes(
            mes,
            item.servicio,
            contextoMovimientoServicioUnidad(item.unidad, item.servicioIndex),
            facturasServiciosPublicos,
            pagosServiciosPublicos
          )

          let estadoResumen = 'Pendiente'
          if (Number(movimiento.saldoDeuda || 0) <= 0) estadoResumen = 'Pagada'
          else if (Number(movimiento.pagado || 0) > 0) estadoResumen = 'Abono registrado'

          return {
            id: `RES-SER-FIJO-${item.idServicio}-${mes}`,
            idUnidad: item.unidad.id,
            nombreUnidad: item.unidad.nombre,
            codigoPredio: item.unidad.codigoPredio,
            idServicio: item.idServicio,
            tipoServicio: item.servicio.tipo,
            empresa: item.servicio.empresa,
            numeroCuenta: item.servicio.numeroCuenta,
            periodo: mes,
            fechaLimite: movimiento.fechaLimite,
            valorFactura: movimiento.valorCausado,
            totalPagado: movimiento.pagado,
            saldoPendiente: movimiento.saldoDeuda,
            estadoResumen,
          }
        })
      }
    }

    return {
      idUnidad: item.unidad.id,
      nombreUnidad: item.unidad.nombre,
      codigoPredio: item.unidad.codigoPredio,
      idServicio: item.idServicio,
      tipoServicio: item.servicio.tipo,
      empresa: item.servicio.empresa,
      numeroCuenta: item.servicio.numeroCuenta,
      periodo: 'Sin factura',
      valorFactura: 0,
      totalPagado: 0,
      saldoPendiente: 0,
      estadoResumen: 'Sin factura registrada',
    }
  }

  return facturasServicio.map((factura) => {
    const pagosFactura = pagosServiciosPublicos.filter(
      (pago) => pago.idFactura === factura.id
    )

    const totalPagado = pagosFactura.reduce(
      (total, pago) => total + Number(pago.valorPagado || 0),
      0
    )

    const saldoPendiente = Math.max(0, Number(factura.valorFactura || 0) - totalPagado)

    let estadoResumen = 'Pendiente'
    if (saldoPendiente <= 0) estadoResumen = 'Pagada'
    else if (totalPagado > 0) estadoResumen = 'Abono registrado'

    return {
      ...factura,
      totalPagado,
      saldoPendiente,
      estadoResumen,
    }
  })
}).flat()

const resumenServiciosFiltrados = textoBusquedaServicios
